// ============================================================================
// SECURITY — Prevent direct file access
// ============================================================================

if ( ! defined( 'ABSPATH' ) ) {
    exit;
}

// ============================================================================
// CONSTANTS
// ============================================================================

define( 'SOCIETYPRESS_VERSION', '0.29d' );
define( 'SOCIETYPRESS_PLUGIN_DIR', plugin_dir_path( __FILE__ ) );
define( 'SOCIETYPRESS_PLUGIN_URL', plugin_dir_url( __FILE__ ) );
define( 'SOCIETYPRESS_PLUGIN_FILE', __FILE__ );

// ============================================================================
// ACTIVATION
// ============================================================================

/**
 * Runs when the plugin is first activated.
 *
 * WHY: We create the settings option up front so the installer (and the
 *      Settings page) always have a known structure to work with. We also
 *      set sensible WordPress defaults so the site looks professional from
 *      day one without anyone needing to dig through WordPress settings.
 */
register_activation_hook( __FILE__, function () {

    // Only create the option if it doesn't already exist.
    // This protects against data loss if someone deactivates and reactivates.
    if ( false === get_option( 'societypress_settings' ) ) {
        add_option( 'societypress_settings', [
            'organization_name'       => '',
            'organization_address'    => '',
            'organization_phone'      => '',
            'organization_email'      => '',
            'membership_period_type'  => 'annual',
            'membership_start_month'  => 7,
            'late_join_months'        => 5,
            'grace_period_months'     => 2,
            // Directory — what shows up on the membership listing page
            'dir_show_city_state'     => 1,
            'dir_show_phone'          => 1,
            'dir_show_email'          => 1,
            'dir_show_website'        => 1,
            'dir_show_tier'           => 1,
            'dir_show_join_date'      => 1,
            'dir_show_surnames'       => 1,
            'dir_per_page'            => 25,
            // Events — defaults for the event system
            'events_default_visibility'    => 'public',
            'events_default_registration'  => 0,
            'events_guest_registration'    => 0,
            'events_per_page'              => 12,
            'events_calendar_start_day'    => 0,        // 0 = Sunday, 1 = Monday
            'events_reminder_1_day'        => 1,
            'events_reminder_3_days'       => 1,
            'events_reminder_1_week'       => 0,
            'events_confirmation_subject'  => 'Registration Confirmed: {event_title}',
            'events_reminder_subject'      => 'Reminder: {event_title} is coming up',
            // Payments — Stripe integration for online event payments
            'stripe_test_mode'             => 1,           // 1 = test mode (safe), 0 = live
            'stripe_test_publishable_key'  => '',
            'stripe_test_secret_key'       => '',
            'stripe_live_publishable_key'  => '',
            'stripe_live_secret_key'       => '',
            'stripe_currency'              => 'usd',
            // Community forum URL — Feature 1
            'community_forum_url'          => '',
            // Renewal reminders — Feature 3
            'renewal_reminder_30d'         => 1,
            'renewal_reminder_15d'         => 1,
            'renewal_reminder_7d'          => 1,
            'renewal_reminder_subject'     => 'Your membership expires soon',
            // Help requests — Feature 10
            'help_requests_notify_all'     => 0,
            // Email notifications
            'welcome_email_enabled'        => 0,
            'welcome_email_subject'        => 'Welcome to our society!',
            'expired_notice_enabled'       => 0,
            'expired_notice_subject'       => 'Your membership has expired',
            'email_from_name'              => '',
            'email_from_email'             => '',
            'email_reply_to'               => '',
            // Design — site-wide appearance customization
            'design_color_primary'         => '#1e3a5f',
            'design_color_primary_hover'   => '#2c5282',
            'design_color_accent'          => '#667eea',
            'design_color_header_bg'       => '#1e3a5f',
            'design_color_header_text'     => '#ffffff',
            'design_color_footer_bg'       => '#1e3a5f',
            'design_color_footer_text'     => '#ffffff',
            'design_font_body'             => 'system',
            'design_font_heading'          => 'inherit',
            'design_font_size'             => 'comfortable',
            'design_heading_scale'         => 'normal',
            'design_content_width'         => 'standard',
        ]);
    }

    // Set permalinks to "Post name" (e.g., /about-us/ instead of ?p=123)
    // WHY: Clean URLs are more professional and better for search engines.
    //      No society website should ever use ?p=123 style URLs.
    if ( get_option( 'permalink_structure' ) !== '/%postname%/' ) {
        update_option( 'permalink_structure', '/%postname%/' );
        flush_rewrite_rules();
    }

    // Create essential pages if they don't exist yet.
    // WHY: Every society website needs at least a homepage and a privacy
    //      policy page. The installer wizard can customize these later, but
    //      the plugin should guarantee they exist so the Settings dropdowns
    //      aren't empty and the site isn't a blank canvas after activation.
    sp_maybe_create_default_pages();

    // Create database tables for member management.
    // WHY: Members are the core of SocietyPress. These tables store everything
    //      about a society's membership — personal info, contact details,
    //      research interests, payment history, and admin notes.
    sp_create_tables();

    // Seed default membership tiers so Harold has something to assign
    // members to right away. He can rename, re-price, reorder, or delete
    // these later — but an empty Plan dropdown on day one is confusing.
    sp_maybe_seed_default_tiers();

    // Seed default event categories (General Meeting, Workshop, SIG, etc.)
    // so the Events section is ready to use from day one.
    sp_maybe_seed_event_categories();

    // Create the "Newsletter" post category so the admin can start filing
    // posts as newsletters immediately. The newsletter archive widget
    // filters by this category slug.
    sp_maybe_create_newsletter_category();

    // Seed default resource link categories so the Library > Resources page
    // has useful categories from day one (Genealogy Databases, etc.).
    sp_maybe_seed_resource_categories();

    // Seed default library item categories so the catalog has sensible
    // classification from day one (Books, Periodicals, Maps, etc.).
    sp_maybe_seed_library_categories();

    // Set a transient to trigger the setup wizard redirect on first admin visit.
    // WHY: We can't redirect during activation (headers already sent), so we
    //      set a flag and check it on the next admin_init.
    set_transient( 'sp_activation_redirect', 1, 30 );

});


/**
 * Create the essential default pages if no published pages exist.
 *
 * WHY: WordPress starts with a "Sample Page" that may or may not still be
 *      around. Rather than guessing, we check for any published pages. If
 *      none exist, we create a Home page and a Privacy Policy page, set the
 *      Home page as the static front page, and wire the Privacy Policy into
 *      WordPress's privacy settings. This means the Settings dropdowns will
 *      always have something to choose from, and the site has a foundation
 *      to build on.
 *
 * SAFETY: We only run this if there are zero published pages. If someone
 *         already has pages (from the installer, or from manual setup), we
 *         leave everything alone.
 */
function sp_maybe_create_default_pages(): void {

    // If there are already published pages, don't touch anything.
    // Someone (the installer, the user, WordPress itself) already set things up.
    $existing = get_pages( [ 'number' => 1 ] );
    if ( ! empty( $existing ) ) {
        return;
    }

    // Clean up WordPress's default starter content — "Sample Page" and the
    // default "Hello world!" post are not useful for a society website and
    // would clutter the Pages/Posts lists alongside our real content.
    $sample = get_page_by_title( 'Sample Page', OBJECT, 'page' );
    if ( $sample ) {
        wp_delete_post( $sample->ID, true );
    }
    $hello = get_page_by_title( 'Hello world!', OBJECT, 'post' );
    if ( $hello ) {
        wp_delete_post( $hello->ID, true );
    }

    // WordPress also ships with a default comment ("Hi, this is a comment…")
    // on the Hello World post. If it still exists, remove it.
    $default_comment = get_comment( 1 );
    if ( $default_comment ) {
        wp_delete_comment( 1, true );
    }

    // ---- Home Page ----
    $home_id = wp_insert_post( [
        'post_title'   => 'Home',
        'post_content' => '<!-- wp:paragraph -->'
                        . '<p>Welcome to our website. This page can be customized '
                        . 'from the Pages menu in your admin panel.</p>'
                        . '<!-- /wp:paragraph -->',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'home',
    ] );

    // Set it as the static front page so visitors see it first
    if ( $home_id && ! is_wp_error( $home_id ) ) {
        update_option( 'show_on_front', 'page' );
        update_option( 'page_on_front', $home_id );
    }

    // ---- Privacy Policy Page ----
    // WordPress creates its own "Privacy Policy" draft on install. If it
    // exists (in any status — draft, publish, trash), we publish it and
    // use it instead of creating a duplicate. If it doesn't exist, we
    // create one from scratch.
    $existing_privacy = get_page_by_path( 'privacy-policy', OBJECT, 'page' );
    if ( ! $existing_privacy ) {
        // Also check by title in case the slug was changed
        $existing_privacy = get_page_by_title( 'Privacy Policy', OBJECT, 'page' );
    }

    if ( $existing_privacy ) {
        // WordPress's default privacy page exists — publish it if it's a draft
        $privacy_id = $existing_privacy->ID;
        if ( $existing_privacy->post_status !== 'publish' ) {
            wp_update_post( [
                'ID'          => $privacy_id,
                'post_status' => 'publish',
            ] );
        }
    } else {
        // No existing privacy page — create one
        $privacy_id = wp_insert_post( [
            'post_title'   => 'Privacy Policy',
            'post_content' => '<!-- wp:paragraph -->'
                            . '<p>This website collects minimal personal information. '
                            . 'Your information is never shared with third parties '
                            . 'without your consent.</p>'
                            . '<!-- /wp:paragraph -->'
                            . '<!-- wp:paragraph -->'
                            . '<p>Please update this page with your organization\'s '
                            . 'full privacy policy.</p>'
                            . '<!-- /wp:paragraph -->',
            'post_status'  => 'publish',
            'post_type'    => 'page',
            'post_name'    => 'privacy-policy',
        ] );
    }

    // Tell WordPress this is the official privacy policy page
    if ( $privacy_id && ! is_wp_error( $privacy_id ) ) {
        update_option( 'wp_page_for_privacy_policy', $privacy_id );
    }

    // ---- About Page ----
    // WHY: Every society needs an "About Us" page. We pre-populate it with
    //      common sections (mission, history, meetings) so the admin can
    //      fill in details rather than starting from a blank page.
    wp_insert_post( [
        'post_title'   => 'About',
        'post_content' => '<h2>Our Mission</h2>'
                        . '<p>[Describe your society\'s mission and purpose here.]</p>'
                        . '<h2>Our History</h2>'
                        . '<p>[When was your society founded? Share its story.]</p>'
                        . '<h2>Meetings</h2>'
                        . '<p>[Where and when does your society meet? Include address and schedule.]</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'about',
    ] );

    // ---- Membership Page ----
    // WHY: Societies need to explain membership benefits and how to join.
    //      This gives admins a head start with common sections.
    wp_insert_post( [
        'post_title'   => 'Membership',
        'post_content' => '<h2>Why Join?</h2>'
                        . '<p>[List the benefits of membership — access to resources, events, publications, networking, etc.]</p>'
                        . '<h2>Membership Levels</h2>'
                        . '<p>Our membership tiers and dues are shown on the join page.</p>'
                        . '<h2>How to Join</h2>'
                        . '<p>Visit our <a href="/join">Join</a> page to sign up online.</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'membership',
    ] );

    // ---- Events Page ----
    // WHY: A landing page for the events calendar and upcoming programs.
    wp_insert_post( [
        'post_title'   => 'Events',
        'post_content' => '<p>Check our calendar for upcoming meetings, workshops, and special events.</p>'
                        . '<h2>Regular Meetings</h2>'
                        . '<p>[Describe your regular meeting schedule — e.g., "We meet the first Saturday of every month at 10 AM."]</p>'
                        . '<h2>Special Programs</h2>'
                        . '<p>[Highlight any upcoming guest speakers, workshops, or special events.]</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'events',
    ] );

    // ---- Contact Us Page ----
    // WHY: Visitors and prospective members need a way to reach the society.
    wp_insert_post( [
        'post_title'   => 'Contact Us',
        'post_content' => '<p>We\'d love to hear from you. Use the information below to get in touch.</p>'
                        . '<h2>Mailing Address</h2>'
                        . '<p>[Your society\'s mailing address]</p>'
                        . '<h2>Email</h2>'
                        . '<p>[Your society\'s contact email address]</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'contact-us',
    ] );

    // ---- Member Portal Page ----
    // WHY: A hub page for logged-in members to access member-only content.
    //      The theme can restrict this page to logged-in users.
    wp_insert_post( [
        'post_title'   => 'Member Portal',
        'post_content' => '<p>Welcome, members! Use the links below to access your member resources.</p>'
                        . '<ul>'
                        . '<li><a href="/events">Events &amp; Calendar</a></li>'
                        . '<li><a href="/resources">Resources &amp; Documents</a></li>'
                        . '<li><a href="/directory">Member Directory</a></li>'
                        . '</ul>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'member-portal',
    ] );

    // ---- Resources Page ----
    // WHY: Societies often have research materials, guides, and documents
    //      to share with members.
    wp_insert_post( [
        'post_title'   => 'Resources',
        'post_content' => '<p>Browse our collection of research materials and guides.</p>'
                        . '<h2>Research Databases</h2>'
                        . '<p>[List any databases or online resources your society provides access to.]</p>'
                        . '<h2>How-To Guides</h2>'
                        . '<p>[Link to any beginner guides, research tips, or tutorials.]</p>'
                        . '<h2>Society Library</h2>'
                        . '<p>[Describe your society\'s library holdings and how members can access them.]</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'resources',
    ] );

    // ---- Leadership Page ----
    // WHY: Members and visitors want to know who runs the society.
    wp_insert_post( [
        'post_title'   => 'Leadership',
        'post_content' => '<p>Meet the people who keep our society running.</p>'
                        . '<h2>Officers</h2>'
                        . '<p>[This page will be populated automatically once officers are assigned in the admin panel.]</p>'
                        . '<h2>Committees</h2>'
                        . '<p>[Committee information will appear here once committees are set up.]</p>',
        'post_status'  => 'publish',
        'post_type'    => 'page',
        'post_name'    => 'leadership',
    ] );
}

// ============================================================================
// DATABASE TABLES
// ============================================================================

/**
 * Create all SocietyPress database tables.
 *
 * WHY: Members are the core of every genealogical society. We need structured,
 *      queryable storage for member data — not WordPress user meta (which is
 *      key-value and terrible for filtering/sorting). Custom tables give us
 *      proper columns, indexes, and fast queries when Harold searches for a
 *      member or filters by expiration date.
 *
 * ARCHITECTURE: Every SocietyPress member IS a WordPress user (1:1, no
 *      exceptions). The sp_members table uses user_id as its primary key.
 *      Email comes from wp_users.user_email — we don't duplicate it.
 *      WordPress handles authentication; we handle everything else.
 *
 * SAFETY: dbDelta() is WordPress's schema migration tool. It compares the
 *      desired schema to what exists in the database and only makes changes
 *      where needed. Safe to run on every activation — it won't destroy
 *      existing data.
 */
function sp_create_tables(): void {
    global $wpdb;

    $charset_collate = $wpdb->get_charset_collate();
    $prefix          = $wpdb->prefix . 'sp_';

    require_once ABSPATH . 'wp-admin/includes/upgrade.php';

    // ========================================================================
    // sp_membership_tiers — Plan definitions (Single, Joint, Lifetime, etc.)
    //
    // WHY: Every member belongs to a tier that determines their dues amount
    //      and renewal cycle. Tiers are defined by the society and can be
    //      added, edited, reordered, or deactivated without affecting
    //      existing members.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}membership_tiers (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name        VARCHAR(100)        NOT NULL,
        price       DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        duration_months INT UNSIGNED    NULL,
        sort_order  INT                 NOT NULL DEFAULT 0,
        active      TINYINT(1)          NOT NULL DEFAULT 1,
        created_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_members — One row per member, keyed by WordPress user ID
    //
    // WHY: This is the big one. Every piece of 1:1 data about a member lives
    //      here — personal info, contact details, seasonal address, mailing
    //      preferences, and directory visibility toggles. All in one table
    //      so loading a member is one query, saving is one query.
    //
    //      Email is NOT stored here — it lives on wp_users.user_email.
    //      We keep first_name/last_name here (not in WP user meta) because
    //      we need them for fast sorting and searching, plus we store
    //      genealogy-specific name fields (maiden name, preferred name)
    //      that WordPress doesn't have.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}members (
        user_id             BIGINT(20) UNSIGNED NOT NULL,
        household_id        BIGINT(20) UNSIGNED NULL,
        member_number       VARCHAR(50)         NULL,
        status              VARCHAR(20)         NOT NULL DEFAULT 'active',
        tier_id             BIGINT(20) UNSIGNED NULL,
        prefix              VARCHAR(20)         NULL,
        member_type         VARCHAR(20)         NOT NULL DEFAULT 'individual',
        organization_name   VARCHAR(255)        NULL,
        first_name          VARCHAR(100)        NOT NULL,
        preferred_name      VARCHAR(100)        NULL,
        middle_name         VARCHAR(100)        NULL,
        last_name           VARCHAR(100)        NOT NULL,
        maiden_name         VARCHAR(100)        NULL,
        suffix              VARCHAR(20)         NULL,
        date_of_birth       DATE                NULL,
        photo_url           VARCHAR(500)        NULL,
        gender              VARCHAR(10)         NULL,
        deceased            TINYINT(1)          NOT NULL DEFAULT 0,
        join_date           DATE                NOT NULL,
        expiration_date     DATE                NULL,
        address_1           VARCHAR(255)        NULL,
        address_2           VARCHAR(255)        NULL,
        city                VARCHAR(100)        NULL,
        state               VARCHAR(100)        NULL,
        postal_code         VARCHAR(20)         NULL,
        country             VARCHAR(100)        NULL,
        phone               VARCHAR(30)         NULL,
        cell                VARCHAR(30)         NULL,
        work_phone          VARCHAR(30)         NULL,
        fax                 VARCHAR(30)         NULL,
        alt_phone           VARCHAR(30)         NULL,
        alt_email           VARCHAR(255)        NULL,
        website             VARCHAR(255)        NULL,
        seasonal            TINYINT(1)          NOT NULL DEFAULT 0,
        seasonal_from       VARCHAR(5)          NULL,
        seasonal_to         VARCHAR(5)          NULL,
        seasonal_address_1  VARCHAR(255)        NULL,
        seasonal_city       VARCHAR(100)        NULL,
        seasonal_state      VARCHAR(100)        NULL,
        seasonal_postal_code VARCHAR(20)        NULL,
        seasonal_country    VARCHAR(100)        NULL,
        lifetime            TINYINT(1)          NOT NULL DEFAULT 0,
        volunteer           TINYINT(1)          NOT NULL DEFAULT 0,
        joint_member        TINYINT(1)          NOT NULL DEFAULT 0,
        joint_email         VARCHAR(255)        NULL,
        joint_phone         VARCHAR(30)         NULL,
        skills              TEXT                NULL,
        interests           TEXT                NULL,
        education           TEXT                NULL,
        label_name          VARCHAR(255)        NULL,
        login_username      VARCHAR(100)        NULL,
        receive_print       TINYINT(1)          NOT NULL DEFAULT 0,
        pref_email_notices      TINYINT(1)      NOT NULL DEFAULT 1,
        pref_email_events       TINYINT(1)      NOT NULL DEFAULT 1,
        pref_email_newsletters  TINYINT(1)      NOT NULL DEFAULT 1,
        pref_email_surnames     TINYINT(1)      NOT NULL DEFAULT 1,
        dir_show_name       TINYINT(1)          NOT NULL DEFAULT 1,
        dir_show_address    TINYINT(1)          NOT NULL DEFAULT 1,
        dir_show_phone      TINYINT(1)          NOT NULL DEFAULT 1,
        dir_show_email      TINYINT(1)          NOT NULL DEFAULT 1,
        dir_show_website    TINYINT(1)          NOT NULL DEFAULT 1,
        dir_show_photo      TINYINT(1)          NOT NULL DEFAULT 0,
        blast_email_opt_out TINYINT(1)          NOT NULL DEFAULT 0,
        created_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (user_id),
        KEY status (status),
        KEY tier_id (tier_id),
        KEY household_id (household_id),
        KEY last_name (last_name),
        KEY expiration_date (expiration_date)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_member_surnames — Surnames being researched (many per member)
    //
    // WHY: This is the genealogy-specific feature that no competitor has.
    //      Members register the surnames they're researching, along with
    //      geographic location and time period. Other members researching
    //      the same surname can find each other — that's the whole point
    //      of a genealogical society.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}member_surnames (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id     BIGINT(20) UNSIGNED NOT NULL,
        surname     VARCHAR(100)        NOT NULL,
        county      VARCHAR(100)        NULL,
        state       VARCHAR(100)        NULL,
        country     VARCHAR(100)        NULL,
        year_from   INT                 NULL,
        year_to     INT                 NULL,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY surname (surname)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_member_payments — Full payment ledger (many per member)
    //
    // WHY: The old system only stored the last payment. We keep the full
    //      history — every dues payment, every donation, with who recorded
    //      it and when. This gives the treasurer a complete audit trail
    //      and lets us show members their own payment history in the portal.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}member_payments (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id     BIGINT(20) UNSIGNED NOT NULL,
        amount      DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        type        VARCHAR(20)         NOT NULL DEFAULT 'dues',
        method      VARCHAR(50)         NULL,
        date        DATE                NOT NULL,
        note        TEXT                NULL,
        recorded_by BIGINT(20) UNSIGNED NULL,
        created_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY date (date),
        KEY type (type)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_member_notes — Admin notes timeline (many per member)
    //
    // WHY: Harold needs to jot down notes about members — "Called about
    //      renewal, will pay next month" or "Donated box of family bibles
    //      to library." Each note is timestamped with who wrote it, building
    //      a history that any board member can reference later.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}member_notes (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id     BIGINT(20) UNSIGNED NOT NULL,
        content     TEXT                NOT NULL,
        author_id   BIGINT(20) UNSIGNED NOT NULL,
        created_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY author_id (author_id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_member_meta — Flexible key/value pairs for any extra data
    //
    // WHY: Every society is different. SAGHS tracks skills, interests, and
    //      education. Another might track military service or DAR membership.
    //      Rather than adding a column for every possible field, meta stores
    //      whatever a society imports or creates. The export pulls all distinct
    //      meta_keys dynamically — no code changes when new fields appear.
    //      This is the same pattern WordPress uses for wp_usermeta/wp_postmeta.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}member_meta (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id     BIGINT(20) UNSIGNED NOT NULL,
        meta_key    VARCHAR(191)        NOT NULL,
        meta_value  LONGTEXT            NULL,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY meta_key (meta_key)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_categories — Event type classifications
    //
    // WHY: SAGHS runs different types of events — general meetings, workshops,
    //      SIG groups, seminars, classes. Categories let Harold filter and
    //      color-code events so members can quickly scan what's coming up.
    //      Each category gets a hex color for badges on the frontend calendar.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_categories (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name        VARCHAR(100)        NOT NULL,
        slug        VARCHAR(100)        NOT NULL,
        color       VARCHAR(7)          NOT NULL DEFAULT '#2271b1',
        sort_order  INT                 NOT NULL DEFAULT 0,
        active      TINYINT(1)          NOT NULL DEFAULT 1,
        created_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY slug (slug)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_events — The main events table
    //
    // WHY: Every event the society runs — meetings, workshops, seminars, SIG
    //      gatherings — lives here. One row per event (or per occurrence for
    //      recurring events). This table stores everything: when, where, what,
    //      who to contact, registration rules, pricing, and recurrence links.
    //
    //      We store dates and times separately (DATE + TIME) instead of a
    //      single DATETIME because many events have a date but no specific
    //      time (all-day events), and separating them makes date-only queries
    //      simpler and avoids timezone confusion.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}events (
        id                    BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        title                 VARCHAR(255)        NOT NULL,
        slug                  VARCHAR(255)        NOT NULL,
        description           LONGTEXT            NULL,
        category_id           BIGINT(20) UNSIGNED NULL,
        status                VARCHAR(20)         NOT NULL DEFAULT 'scheduled',
        event_date            DATE                NOT NULL,
        start_time            TIME                NULL,
        end_time              TIME                NULL,
        location_name         VARCHAR(255)        NULL,
        location_address      VARCHAR(500)        NULL,
        is_virtual            TINYINT(1)          NOT NULL DEFAULT 0,
        virtual_url           VARCHAR(500)        NULL,
        image_id              BIGINT(20) UNSIGNED NULL,
        visibility            VARCHAR(20)         NOT NULL DEFAULT 'public',
        registration_enabled  TINYINT(1)          NOT NULL DEFAULT 0,
        registration_limit    INT UNSIGNED        NULL,
        guest_registration    TINYINT(1)          NOT NULL DEFAULT 0,
        member_price          DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        nonmember_price       DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        payment_mode          VARCHAR(20)         NOT NULL DEFAULT 'none',
        price_description     VARCHAR(255)        NULL,
        contact_name          VARCHAR(200)        NULL,
        contact_email         VARCHAR(255)        NULL,
        contact_phone         VARCHAR(50)         NULL,
        recurrence_parent_id  BIGINT(20) UNSIGNED NULL,
        recurrence_rule       VARCHAR(100)        NULL,
        recurrence_end_date   DATE                NULL,
        created_by            BIGINT(20) UNSIGNED NULL,
        created_at            DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at            DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY event_date (event_date),
        KEY category_id (category_id),
        KEY status (status),
        KEY slug (slug),
        KEY recurrence_parent_id (recurrence_parent_id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_speakers — Reusable speaker/instructor profiles
    //
    // WHY: The same people present at multiple events — a genealogy instructor
    //      might teach six classes a year, or a board member moderates monthly
    //      meetings. Rather than re-typing their name and bio every time, we
    //      maintain a roster of speakers that can be assigned to any event.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_speakers (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name        VARCHAR(200)        NOT NULL,
        title       VARCHAR(200)        NULL,
        bio         TEXT                NULL,
        email       VARCHAR(255)        NULL,
        phone       VARCHAR(50)         NULL,
        website     VARCHAR(500)        NULL,
        photo_id    BIGINT(20) UNSIGNED NULL,
        active      TINYINT(1)          NOT NULL DEFAULT 1,
        created_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at  DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_speaker_assignments — Links speakers to events (many-to-many)
    //
    // WHY: An event can have multiple speakers (panel discussion, multi-part
    //      workshop), and a speaker can present at many events. The join table
    //      also tracks the speaker's role (speaker, instructor, moderator,
    //      panelist) and display order.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_speaker_assignments (
        id          BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        event_id    BIGINT(20) UNSIGNED NOT NULL,
        speaker_id  BIGINT(20) UNSIGNED NOT NULL,
        role        VARCHAR(100)        NOT NULL DEFAULT 'speaker',
        sort_order  INT                 NOT NULL DEFAULT 0,
        PRIMARY KEY (id),
        UNIQUE KEY event_speaker (event_id, speaker_id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_registrations — Who signed up for which event
    //
    // WHY: When registration is enabled for an event, members (and optionally
    //      guests) can sign up. We track their status (confirmed/waitlisted/
    //      cancelled), party size, payment info, and post-event attendance.
    //      This lets Harold know who's coming, manage capacity, and track
    //      who actually showed up for the treasurer's report.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_registrations (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        event_id        BIGINT(20) UNSIGNED NOT NULL,
        slot_id         BIGINT(20) UNSIGNED NULL,
        user_id         BIGINT(20) UNSIGNED NULL,
        guest_name      VARCHAR(200)        NULL,
        guest_email     VARCHAR(255)        NULL,
        guest_phone     VARCHAR(50)         NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'confirmed',
        party_size      INT UNSIGNED        NOT NULL DEFAULT 1,
        fee_amount      DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        payment_status  VARCHAR(20)         NOT NULL DEFAULT 'none',
        payment_method  VARCHAR(50)         NULL,
        payment_date    DATETIME            NULL,
        attended        TINYINT(1)          NULL,
        notes           TEXT                NULL,
        registered_at   DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY event_id (event_id),
        KEY slot_id (slot_id),
        KEY user_id (user_id),
        KEY status (status)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_slots — Time slots for events with multiple sessions
    //
    // WHY: Many society events (especially classes and workshops) need to offer
    //      multiple time slots on the same day. For example, a DNA workshop
    //      might have a 10-11 AM, 11-12 PM, and 12-1 PM session. Members pick
    //      the slot that fits their schedule, and each slot can have its own
    //      capacity limit. Without slots, you'd need separate events for each
    //      session, which is messy for Harold and confusing for members.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_slots (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        event_id        BIGINT(20) UNSIGNED NOT NULL,
        start_time      TIME                NOT NULL,
        end_time        TIME                NOT NULL,
        capacity        INT UNSIGNED        NULL,
        description     VARCHAR(255)        NULL,
        sort_order      INT UNSIGNED        NOT NULL DEFAULT 0,
        is_active       TINYINT(1)          NOT NULL DEFAULT 1,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY event_id (event_id),
        KEY is_active (is_active)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_event_reminders — Tracks which reminders have been sent
    //
    // WHY: We send email reminders before events (1 day, 3 days, 1 week).
    //      wp_cron runs periodically and checks which reminders are due. This
    //      table prevents duplicate sends — once a reminder is logged here,
    //      the cron job knows not to send it again even if it runs multiple
    //      times. Without this, members would get spammed with duplicates
    //      every time cron fires.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}event_reminders (
        id                BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        event_id          BIGINT(20) UNSIGNED NOT NULL,
        registration_id   BIGINT(20) UNSIGNED NOT NULL,
        reminder_type     VARCHAR(50)         NOT NULL,
        sent_at           DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY event_reg_type (event_id, registration_id, reminder_type)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_renewal_reminders — Tracks which membership renewal reminders
    //                        have been sent to prevent duplicates
    //
    // WHY: When the daily cron checks for upcoming expirations (30d/15d/7d),
    //      it needs to know which members already got their reminder. Without
    //      this table, every cron run would re-send reminders to the same
    //      members. The reminder_type stores a composite key like "30d_2026"
    //      so the same member can get fresh reminders each renewal cycle.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}renewal_reminders (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        reminder_type   VARCHAR(50)         NOT NULL,
        sent_at         DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY user_type (user_id, reminder_type)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_volunteer_roles — Standing volunteer assignments
    //
    // WHY: Board members, committee chairs, docents, library volunteers —
    //      these are ongoing commitments, not one-time events. This table
    //      tracks who is assigned to what role, which committee they serve on,
    //      and their tenure dates. It replaces the old Governance placeholder
    //      with real volunteer management.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}volunteer_roles (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        role_title      VARCHAR(200)        NOT NULL,
        committee       VARCHAR(200)        NULL,
        start_date      DATE                NULL,
        end_date        DATE                NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'active',
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY status (status)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_volunteer_hours — Activity log for volunteer time tracking
    //
    // WHY: Societies need to report volunteer hours to grantors, insurance
    //      companies, and the board. Every time a volunteer does something,
    //      it's logged here — what they did, which committee it was for,
    //      how many hours, and who recorded it (in case of disputes).
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}volunteer_hours (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        activity        VARCHAR(500)        NOT NULL,
        committee       VARCHAR(200)        NULL,
        hours           DECIMAL(5,2)        NOT NULL DEFAULT 0.00,
        activity_date   DATE                NOT NULL,
        recorded_by     BIGINT(20) UNSIGNED NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY activity_date (activity_date)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_volunteer_opportunities — Postings for volunteer needs
    //
    // WHY: Committee chairs and admins can post volunteer needs — "We need
    //      3 people to help at the book sale Saturday." Members browse these
    //      on the frontend and sign up. Each opportunity has a type (one-time,
    //      recurring, ongoing), optional capacity, optional date, and optional
    //      committee link. This replaces the old pattern of emailing the whole
    //      membership list and hoping someone replies.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}volunteer_opportunities (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        title           VARCHAR(200)        NOT NULL,
        description     TEXT                NULL,
        committee_id    BIGINT(20) UNSIGNED NULL,
        opportunity_type VARCHAR(20)        NOT NULL DEFAULT 'one_time',
        event_date      DATE                NULL,
        start_time      TIME                NULL,
        end_time        TIME                NULL,
        location        VARCHAR(255)        NULL,
        capacity        INT UNSIGNED        NULL,
        skills_needed   TEXT                NULL,
        contact_user_id BIGINT(20) UNSIGNED NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'open',
        sort_order      INT UNSIGNED        NOT NULL DEFAULT 0,
        created_by      BIGINT(20) UNSIGNED NOT NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY status (status),
        KEY committee_id (committee_id),
        KEY event_date (event_date)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_volunteer_signups — Who signed up for which opportunity
    //
    // WHY: Tracks member signups for volunteer opportunities. Supports
    //      confirmed/waitlisted/cancelled statuses (same pattern as event
    //      registrations). When someone cancels, the next person on the
    //      waitlist gets auto-promoted.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}volunteer_signups (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        opportunity_id  BIGINT(20) UNSIGNED NOT NULL,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'confirmed',
        notes           TEXT                NULL,
        signed_up_at    DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY opportunity_id (opportunity_id),
        KEY user_id (user_id),
        KEY status (status),
        UNIQUE KEY opp_user (opportunity_id, user_id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_member_relationships — Family/household connections between members
    //
    // WHY: Genealogical society members are often related — spouses who share
    //      a household membership, parents who bring children, siblings, etc.
    //      Tracking these relationships lets the admin see family units at a
    //      glance, supports joint/household billing in the future, and helps
    //      when one member calls about another ("I'm John's wife, can you
    //      update his email?"). The relationship is bidirectional — if A is
    //      B's spouse, B is A's spouse. We store it once (lower user_id first)
    //      and query both directions.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}member_relationships (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id_a       BIGINT(20) UNSIGNED NOT NULL,
        user_id_b       BIGINT(20) UNSIGNED NOT NULL,
        relationship    VARCHAR(50)         NOT NULL DEFAULT 'spouse',
        note            VARCHAR(255)        NULL,
        created_by      BIGINT(20) UNSIGNED NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY pair (user_id_a, user_id_b),
        KEY user_id_a (user_id_a),
        KEY user_id_b (user_id_b)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_audit_log — Activity audit trail
    //
    // WHY: Admins need to know who did what and when. This tracks key
    //      actions: member adds/edits/deletes, event changes, settings
    //      updates, login events, etc. Essential for accountability,
    //      troubleshooting, and governance. Entries older than 1 year
    //      can be pruned to keep the table manageable.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}audit_log (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id         BIGINT(20) UNSIGNED NULL,
        action          VARCHAR(100)        NOT NULL,
        object_type     VARCHAR(50)         NULL,
        object_id       BIGINT(20) UNSIGNED NULL,
        description     TEXT                NULL,
        ip_address      VARCHAR(45)         NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY action (action),
        KEY object_type (object_type, object_id),
        KEY created_at (created_at)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_groups — Interest groups / SIGs (Special Interest Groups)
    //
    // WHY: Many genealogical societies have informal interest groups that
    //      members can join — "DNA Interest Group", "German Research",
    //      "Irish Ancestry", etc. These are distinct from committees
    //      (which are governance-focused). Groups are casual, self-join,
    //      and don't have the overhead of committee management.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}groups (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name            VARCHAR(200)        NOT NULL,
        slug            VARCHAR(200)        NOT NULL,
        description     TEXT                NULL,
        leader_id       BIGINT(20) UNSIGNED NULL,
        meeting_info    VARCHAR(500)        NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'active',
        sort_order      INT                 NOT NULL DEFAULT 0,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY slug (slug),
        KEY status (status)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_group_members — Which members belong to which groups
    //
    // WHY: Many-to-many relationship. A member can be in multiple groups,
    //      a group can have many members. The joined_at date lets us show
    //      when they joined and sort by seniority if needed.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}group_members (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        group_id        BIGINT(20) UNSIGNED NOT NULL,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        joined_at       DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY group_id (group_id),
        KEY user_id (user_id),
        UNIQUE KEY group_user (group_id, user_id)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_photo_albums — Photo album containers
    //
    // WHY: Societies take photos at every event, field trip, and meeting.
    //      Albums group photos logically. Each album can optionally link to
    //      an event (via event_id FK) and can be restricted to members only.
    //      The cover_image_id points to a WP media attachment for the thumbnail.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}photo_albums (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        title           VARCHAR(255)        NOT NULL,
        slug            VARCHAR(255)        NOT NULL,
        description     TEXT                NULL,
        cover_image_id  BIGINT(20) UNSIGNED NULL,
        event_id        BIGINT(20) UNSIGNED NULL,
        visibility      VARCHAR(20)         NOT NULL DEFAULT 'public',
        sort_order      INT                 NOT NULL DEFAULT 0,
        created_by      BIGINT(20) UNSIGNED NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY slug (slug),
        KEY event_id (event_id),
        KEY visibility (visibility)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_photo_album_items — Individual photos within albums
    //
    // WHY: Each item links to a WordPress media library attachment (the real
    //      image lives in WP's uploads folder, not duplicated). sort_order
    //      allows drag-drop reordering in the admin. Caption is optional
    //      metadata displayed in the lightbox.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}photo_album_items (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        album_id        BIGINT(20) UNSIGNED NOT NULL,
        attachment_id   BIGINT(20) UNSIGNED NOT NULL,
        caption         VARCHAR(500)        NULL,
        sort_order      INT                 NOT NULL DEFAULT 0,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY album_id (album_id),
        KEY sort_order (sort_order)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_resource_categories — Categories for external resource links
    //
    // WHY: Genealogy researchers use dozens of online databases, archives,
    //      and reference sites. Categorising them (Genealogy Databases,
    //      County Records, National Archives, etc.) makes the resource
    //      directory useful instead of being one giant list.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}resource_categories (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name            VARCHAR(200)        NOT NULL,
        slug            VARCHAR(200)        NOT NULL,
        sort_order      INT                 NOT NULL DEFAULT 0,
        active          TINYINT(1)          NOT NULL DEFAULT 1,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY slug (slug)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_resources — External resource links
    //
    // WHY: Every genealogical society maintains a list of recommended
    //      websites — Ancestry, FamilySearch, county clerk sites, newspaper
    //      archives, etc. This table stores those curated links with
    //      descriptions, category assignments, and a "featured" flag for
    //      the most important ones.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}resources (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        title           VARCHAR(255)        NOT NULL,
        url             VARCHAR(500)        NOT NULL,
        description     TEXT                NULL,
        category_id     BIGINT(20) UNSIGNED NULL,
        featured        TINYINT(1)          NOT NULL DEFAULT 0,
        active          TINYINT(1)          NOT NULL DEFAULT 1,
        sort_order      INT                 NOT NULL DEFAULT 0,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY category_id (category_id),
        KEY active (active),
        KEY featured (featured)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_library_categories — Categories for physical library items
    //
    // WHY: Most genealogical societies maintain a small research library
    //      with books, periodicals, microfilm, maps, and manuscripts.
    //      Categories help volunteers and visitors find what they need.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}library_categories (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name            VARCHAR(200)        NOT NULL,
        slug            VARCHAR(200)        NOT NULL,
        sort_order      INT                 NOT NULL DEFAULT 0,
        active          TINYINT(1)          NOT NULL DEFAULT 1,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY slug (slug)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_library_items — Physical library catalog items
    //
    // WHY: A searchable catalog lets members know what's available before
    //      they visit. This expanded schema supports the full breadth of
    //      data genealogical society libraries actually track — publication
    //      details, acquisition history, donor records, geographic and
    //      subject classification, shelf locations, and call numbers.
    //
    //      The schema is modeled after real-world society library exports
    //      (SAGHS: 19,000+ items, 30 columns). Fields like system_id
    //      preserve the original catalog IDs from legacy systems so
    //      librarians don't lose their reference numbers during migration.
    //
    //      Two separate location fields exist because "where the book sits"
    //      (shelf_location) and "what geography it covers" (geographic_location)
    //      are fundamentally different questions that both need answering.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}library_items (
        id                  BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        system_id           INT UNSIGNED        NULL,
        title               VARCHAR(500)        NOT NULL,
        author              VARCHAR(255)        NULL,
        description         TEXT                NULL,
        publisher           VARCHAR(200)        NULL,
        publisher_location  VARCHAR(100)        NULL,
        pub_year            SMALLINT UNSIGNED   NULL,
        pub_month           TINYINT UNSIGNED    NULL,
        pub_day             TINYINT UNSIGNED    NULL,
        media_type          VARCHAR(50)         NULL,
        use_serials         TINYINT(1)          NOT NULL DEFAULT 0,
        isbn                VARCHAR(20)         NULL,
        call_number         VARCHAR(50)         NULL,
        lccn                VARCHAR(20)         NULL,
        category_id         BIGINT(20) UNSIGNED NULL,
        shelf_location      VARCHAR(100)        NULL,
        geographic_location VARCHAR(200)        NULL,
        acquisition_number  INT UNSIGNED        NULL,
        acq_year            SMALLINT UNSIGNED   NULL,
        acq_month           TINYINT UNSIGNED    NULL,
        acq_day             TINYINT UNSIGNED    NULL,
        acq_code            VARCHAR(30)         NULL,
        donor               VARCHAR(100)        NULL,
        item_value          DECIMAL(8,2)        NULL,
        county              VARCHAR(200)        NULL,
        state               VARCHAR(100)        NULL,
        surname             VARCHAR(255)        NULL,
        subject             VARCHAR(250)        NULL,
        librarian_notes     TEXT                NULL,
        updated_by          VARCHAR(50)         NULL,
        last_updated_date   DATE                NULL,
        item_condition      VARCHAR(20)         NOT NULL DEFAULT 'good',
        available           TINYINT(1)          NOT NULL DEFAULT 1,
        created_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY system_id (system_id),
        KEY category_id (category_id),
        KEY available (available),
        KEY call_number (call_number),
        KEY shelf_location (shelf_location),
        KEY media_type (media_type),
        KEY acq_code (acq_code),
        KEY surname (surname),
        KEY state (state),
        FULLTEXT KEY title_author_subject (title, author, subject)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_help_requests — Member research help questions
    //
    // WHY: Genealogical societies exist to help people with research. This
    //      lightweight Q&A system lets members post questions ("Looking for
    //      Smith family records in Bexar County") and get responses from
    //      other members. Deliberately simple — no threading, no voting.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}help_requests (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        title           VARCHAR(500)        NOT NULL,
        description     LONGTEXT            NOT NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'open',
        responses_count INT UNSIGNED        NOT NULL DEFAULT 0,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY user_id (user_id),
        KEY status (status),
        KEY created_at (created_at)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_help_responses — Replies to research help requests
    //
    // WHY: Each response is a simple text reply from a member. We track
    //      who posted it and when. The parent request's responses_count
    //      is updated via PHP (not a trigger) for simplicity. No nesting —
    //      responses are displayed in chronological order.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}help_responses (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        request_id      BIGINT(20) UNSIGNED NOT NULL,
        user_id         BIGINT(20) UNSIGNED NOT NULL,
        content         LONGTEXT            NOT NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY request_id (request_id),
        KEY user_id (user_id)
    ) {$charset_collate};" );


    // ========================================================================
    // EMAIL LOG
    // WHY: Every outgoing email needs to be recorded so admins can verify
    //      what communications went out, troubleshoot delivery issues, and
    //      maintain records. In dev mode (WP_DEBUG on non-production),
    //      emails are blocked but still logged so admins can preview them.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}email_log (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        recipient       VARCHAR(255)        NOT NULL,
        subject         VARCHAR(255)        NOT NULL DEFAULT '',
        body            LONGTEXT            NOT NULL,
        headers         TEXT                NOT NULL DEFAULT '',
        status          VARCHAR(20)         NOT NULL DEFAULT 'pending',
        error_message   TEXT                NULL,
        member_id       BIGINT(20) UNSIGNED NULL,
        email_type      VARCHAR(50)         NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        sent_at         DATETIME            NULL,
        PRIMARY KEY (id),
        KEY status (status),
        KEY email_type (email_type),
        KEY member_id (member_id),
        KEY created_at (created_at)
    ) {$charset_collate};" );

    // ========================================================================
    // NEWSLETTERS
    // WHY: Admins upload PDF newsletters and the system generates cover
    //      thumbnails so members can browse, preview, and download past
    //      issues. Non-members can see the archive grid but cannot open or
    //      download the actual PDFs.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}newsletters (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        title           VARCHAR(255)        NOT NULL,
        slug            VARCHAR(255)        NOT NULL,
        description     TEXT                NULL,
        pub_date        DATE                NULL,
        volume          SMALLINT UNSIGNED   NULL,
        issue_number    SMALLINT UNSIGNED   NULL,
        file_id         BIGINT(20) UNSIGNED NULL,
        cover_image_id  BIGINT(20) UNSIGNED NULL,
        visibility      VARCHAR(20)         NOT NULL DEFAULT 'members_only',
        created_by      BIGINT(20) UNSIGNED NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY slug (slug),
        KEY pub_date (pub_date),
        KEY visibility (visibility)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_campaigns — Fundraising campaign definitions
    //
    // WHY: SAGHS runs multiple donation campaigns throughout the year —
    //      building fund, memorial fund, annual fund drive, etc. Each
    //      campaign has a goal amount and a date range. Donations can be
    //      linked to a campaign so the treasurer can track how close each
    //      campaign is to its goal. Unlinked donations are general/unrestricted.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}campaigns (
        id              BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        name            VARCHAR(200)        NOT NULL,
        slug            VARCHAR(200)        NOT NULL,
        description     TEXT                NULL,
        goal_amount     DECIMAL(10,2)       NULL,
        start_date      DATE                NULL,
        end_date        DATE                NULL,
        status          VARCHAR(20)         NOT NULL DEFAULT 'active',
        created_by      BIGINT(20) UNSIGNED NULL,
        created_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at      DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        UNIQUE KEY slug (slug),
        KEY status (status)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_donations — Individual donation records
    //
    // WHY: Separate from sp_member_payments because donations have different
    //      tracking needs — campaign linkage, anonymous flag, in-kind support,
    //      acknowledgment tracking, and non-member donors. The member_payments
    //      table handles dues and membership-related payments; this table
    //      handles charitable giving, which SAGHS tracks heavily.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}donations (
        id                  BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        campaign_id         BIGINT(20) UNSIGNED NULL,
        user_id             BIGINT(20) UNSIGNED NULL,
        donor_name          VARCHAR(255)        NOT NULL,
        donor_email         VARCHAR(255)        NULL,
        amount              DECIMAL(10,2)       NOT NULL DEFAULT 0.00,
        type                VARCHAR(30)         NOT NULL DEFAULT 'cash',
        in_kind_description TEXT                NULL,
        date                DATE                NOT NULL,
        note                TEXT                NULL,
        is_anonymous        TINYINT(1)          NOT NULL DEFAULT 0,
        acknowledgment_sent TINYINT(1)          NOT NULL DEFAULT 0,
        acknowledgment_date DATETIME            NULL,
        recorded_by         BIGINT(20) UNSIGNED NULL,
        stripe_session_id   VARCHAR(255)        NULL,
        created_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY campaign_id (campaign_id),
        KEY user_id (user_id),
        KEY date (date),
        KEY type (type),
        KEY is_anonymous (is_anonymous)
    ) {$charset_collate};" );

    // ========================================================================
    // sp_blast_emails — Mass email campaigns sent to member groups
    //
    // WHY: SAGHS sends weekly blast emails to members — meeting reminders,
    //      research tips, event announcements. This table stores each blast
    //      with its content, targeting criteria, and delivery stats. The
    //      recipient_filter column stores JSON (group IDs, tier IDs, etc.)
    //      so we can target any combination without needing a join table.
    // ========================================================================
    dbDelta( "CREATE TABLE {$prefix}blast_emails (
        id                  BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        subject             VARCHAR(255)        NOT NULL,
        body                LONGTEXT            NOT NULL,
        sender_id           BIGINT(20) UNSIGNED NOT NULL,
        recipient_type      VARCHAR(30)         NOT NULL DEFAULT 'all_members',
        recipient_filter    TEXT                NULL,
        total_recipients    INT UNSIGNED        NOT NULL DEFAULT 0,
        total_sent          INT UNSIGNED        NOT NULL DEFAULT 0,
        total_failed        INT UNSIGNED        NOT NULL DEFAULT 0,
        status              VARCHAR(20)         NOT NULL DEFAULT 'draft',
        scheduled_at        DATETIME            NULL,
        sent_at             DATETIME            NULL,
        created_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP,
        updated_at          DATETIME            NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        PRIMARY KEY (id),
        KEY status (status),
        KEY sender_id (sender_id),
        KEY sent_at (sent_at)
    ) {$charset_collate};" );

    // Store the schema version so we can run migrations in future updates
    // without re-running the full dbDelta on every page load.
    update_option( 'societypress_db_version', '0.25d' );
}


/**
 * Seed default membership tiers if none exist yet.
 *
 * WHY: An empty "Membership Plan" dropdown is a terrible first experience.
 *      Harold needs tiers to exist before he can add members. These defaults
 *      cover the most common genealogical society membership levels. Harold
 *      can rename, re-price, reorder, or delete them from the Member Levels
 *      page — but at least he's not starting from zero.
 *
 * SAFETY: Only runs if the tiers table is empty. Deactivate/reactivate won't
 *         re-create tiers Harold has already customized.
 */
function sp_maybe_seed_default_tiers(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_membership_tiers';

    // Don't overwrite existing tiers
    $count = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$table}" );
    if ( $count > 0 ) {
        return;
    }

    $default_tiers = [
        [ 'name' => 'Individual',  'price' => 35.00, 'duration_months' => 12, 'sort_order' => 1 ],
        [ 'name' => 'Joint/Family','price' => 45.00, 'duration_months' => 12, 'sort_order' => 2 ],
        [ 'name' => 'Student',     'price' => 15.00, 'duration_months' => 12, 'sort_order' => 3 ],
        [ 'name' => 'Lifetime',    'price' => 500.00,'duration_months' => null,'sort_order' => 4 ],
        [ 'name' => 'Honorary',    'price' => 0.00,  'duration_months' => null,'sort_order' => 5 ],
    ];

    foreach ( $default_tiers as $tier ) {
        $wpdb->insert( $table, [
            'name'            => $tier['name'],
            'price'           => $tier['price'],
            'duration_months' => $tier['duration_months'],
            'sort_order'      => $tier['sort_order'],
            'active'          => 1,
        ] );
    }
}


