/**
 * Create the "Newsletter" post category if it doesn't exist.
 *
 * WHY: The Newsletter Archive widget filters posts by this category slug.
 *      Creating it on activation means Harold can immediately start categorising
 *      posts as newsletters without having to create the category manually.
 *
 * SAFETY: wp_insert_term() returns the existing term if the slug already exists,
 *         so this is safe to run on reactivation.
 */
function sp_maybe_create_newsletter_category(): void {
    if ( ! term_exists( 'newsletter', 'category' ) ) {
        wp_insert_term( 'Newsletter', 'category', [
            'slug'        => 'newsletter',
            'description' => 'Newsletter posts displayed in the Newsletter Archive widget.',
        ] );
    }
}


