<script id="sp-flyout-menu-js">
/**
 * SocietyPress Flyout Menu
 *
 * WHY: Restructures the flat WordPress submenu into grouped flyout panels.
 *      Reads spMenuConfig, creates group headers with dashicons, moves child
 *      items into nested <ul> flyout panels. Hover opens (with 200ms close
 *      delay), click toggles, keyboard (Enter/Space/Escape) works.
 */
(function() {
    'use strict';

    if (typeof spMenuConfig === 'undefined') return;

    var config = spMenuConfig;

    // Wait for DOM ready
    document.addEventListener('DOMContentLoaded', function() {

        // --- Find the SocietyPress submenu <ul> ---
        // WHY: WordPress generates a predictable ID for every top-level menu:
        //      "toplevel_page_{slug}". Using this is far more reliable than
        //      scanning <a> elements by class name (which varies across WP versions).
        var spMenuItem = document.getElementById('toplevel_page_societypress');
        if (!spMenuItem) return;
        var spSubmenu = spMenuItem.querySelector('ul.wp-submenu');
        if (!spSubmenu) return;

        // --- Extract slug from an <a> href ---
        function getSlug(href) {
            if (!href) return '';
            var m = href.match(/[?&]page=([^&]+)/);
            if (m) return m[1];
            var parts = href.split('/');
            return parts[parts.length - 1];
        }

        // --- Find which group a slug belongs to ---
        function findGroup(slug) {
            for (var g = 0; g < config.groups.length; g++) {
                if (config.groups[g].items.indexOf(slug) !== -1) return config.groups[g];
            }
            return null;
        }

        // --- Categorise every <li> in the submenu ---
        var lis = Array.prototype.slice.call(spSubmenu.children);
        var items = [];
        lis.forEach(function(li) {
            var a = li.querySelector('a');
            var href = a ? a.getAttribute('href') : '';
            var slug = getSlug(href);
            items.push({
                el:        li,
                slug:      slug,
                group:     findGroup(slug),
                isCurrent: li.classList.contains('current')
            });
        });

        // --- Create the scrim (click-to-close overlay behind panels) ---
        var scrim = document.createElement('div');
        scrim.className = 'sp-flyout-scrim';
        document.body.appendChild(scrim);

        // --- Helper: close all open panels ---
        // WHY: Flyout panels live on <body> (to escape #adminmenuwrap's stacking
        //      context), so we hide them directly via style.display rather than
        //      relying on a CSS parent-child selector.
        function closeAll() {
            document.querySelectorAll('.sp-menu-group.sp-flyout-open').forEach(function(g) {
                g.classList.remove('sp-flyout-open');
                g.querySelector('.sp-menu-group-header').setAttribute('aria-expanded', 'false');
            });
            document.querySelectorAll('.sp-menu-flyout').forEach(function(f) {
                f.style.display = 'none';
            });
            scrim.classList.remove('sp-scrim-visible');
        }

        // --- Build group elements ---
        var builtGroups = {};

        config.groups.forEach(function(gc) {
            var groupLi = document.createElement('li');
            groupLi.className = 'sp-menu-group';
            groupLi.setAttribute('data-group', gc.id);

            // Collect matching submenu items
            var childItems = [];
            var hasCurrent = false;
            gc.items.forEach(function(itemSlug) {
                for (var j = 0; j < items.length; j++) {
                    if (items[j].slug === itemSlug) {
                        childItems.push(items[j]);
                        if (items[j].isCurrent) hasCurrent = true;
                        break;
                    }
                }
            });

            // Group header in the sidebar
            var headerLink = document.createElement('a');
            headerLink.href = '#';
            headerLink.className = 'sp-menu-group-header';
            headerLink.setAttribute('role', 'button');
            headerLink.setAttribute('aria-expanded', 'false');
            headerLink.setAttribute('tabindex', '0');
            headerLink.innerHTML =
                '<span class="dashicons ' + gc.icon + ' sp-group-icon"></span>' +
                '<span class="sp-group-label">' + gc.label + '</span>' +
                '<span class="dashicons dashicons-arrow-right-alt2 sp-group-arrow"></span>';

            // Panel that opens over the content area
            var flyoutUl = document.createElement('ul');
            flyoutUl.className = 'sp-menu-flyout';
            flyoutUl.setAttribute('role', 'menu');

            // Group heading inside the panel — hide if only 1 item (redundant)
            var heading = document.createElement('li');
            heading.className = 'sp-flyout-heading';
            if (childItems.length <= 1) heading.className += ' sp-heading-hidden';
            heading.textContent = gc.label;
            flyoutUl.appendChild(heading);

            // Move child items into the panel
            childItems.forEach(function(ci) {
                flyoutUl.appendChild(ci.el);
            });

            if (hasCurrent) groupLi.classList.add('sp-group-has-current');
            groupLi.appendChild(headerLink);

            // WHY: Flyout panels must be on <body>, not inside the sidebar.
            //      WordPress's #adminmenuwrap has position: relative; z-index: 9990
            //      which creates a stacking context. Any child element — no matter
            //      how high its own z-index — can't render above elements outside
            //      that context (like our scrim at z-index: 99998). By appending
            //      the flyout to <body>, it's in the root stacking context and
            //      z-index: 99999 puts it above the scrim. We store a JS reference
            //      so the click handler can find it.
            document.body.appendChild(flyoutUl);
            groupLi._flyout = flyoutUl;

            builtGroups[gc.id] = groupLi;
        });

        // --- Clear the submenu and rebuild ---
        while (spSubmenu.firstChild) spSubmenu.removeChild(spSubmenu.firstChild);

        config.groups.forEach(function(gc) {
            if (builtGroups[gc.id]) {
                spSubmenu.appendChild(builtGroups[gc.id]);
            }
        });

        // Safety net: append any ungrouped items
        items.forEach(function(item) {
            if (!item.group && !item.el.parentNode) {
                spSubmenu.appendChild(item.el);
            }
        });

        // --- Click handler: toggle panels ---
        document.addEventListener('click', function(e) {
            var header = e.target.closest('.sp-menu-group-header');
            if (header) {
                e.preventDefault();
                e.stopPropagation();
                var group = header.closest('.sp-menu-group');
                var isOpen = group.classList.contains('sp-flyout-open');
                closeAll();
                if (!isOpen) {
                    // Position the panel next to the header that was clicked
                    // WHY: group._flyout is a reference stored when we appended
                    //      the flyout to <body> during build. Can't use querySelector
                    //      because the flyout isn't a child of the group anymore.
                    var flyout = group._flyout;
                    if (flyout) {
                        var rect = header.getBoundingClientRect();
                        var sidebar = document.getElementById('adminmenuback') || document.getElementById('adminmenuwrap');
                        var sidebarWidth = sidebar ? sidebar.getBoundingClientRect().right : 160;
                        flyout.style.left = sidebarWidth + 'px';
                        flyout.style.top = rect.top + 'px';
                        flyout.style.display = 'block';

                        // Keep panel on screen if it would go below the viewport
                        var flyoutRect = flyout.getBoundingClientRect();
                        if (flyoutRect.bottom > window.innerHeight) {
                            flyout.style.top = Math.max(32, window.innerHeight - flyoutRect.height) + 'px';
                        }
                    }
                    group.classList.add('sp-flyout-open');
                    header.setAttribute('aria-expanded', 'true');
                    scrim.classList.add('sp-scrim-visible');
                }
                return;
            }
            // Click on scrim or anywhere outside → close
            if (!e.target.closest('.sp-menu-flyout')) {
                closeAll();
            }
        });

        // Scrim click closes everything
        scrim.addEventListener('click', closeAll);

        // Keyboard support
        document.addEventListener('keydown', function(e) {
            var header = e.target.closest('.sp-menu-group-header');
            if (!header) return;
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                header.click();
            }
            if (e.key === 'Escape') {
                closeAll();
            }
        });
    });
})();
</script>
<?php
});


// ============================================================================
// REDIRECT — Send users to SocietyPress dashboard instead of WP dashboard
// ============================================================================

/**
 * Redirect the default WordPress dashboard to the SocietyPress dashboard.
 *
 * WHY: When someone logs in, WordPress sends them to /wp-admin/ (index.php).
 *      But we removed that page from the menu and replaced it with our own
 *      dashboard. So we redirect index.php to our dashboard page. Seamless —
 *      the user never sees the WordPress dashboard.
 */
add_action( 'admin_init', function () {
    global $pagenow;

    // Only redirect the main dashboard page, not AJAX requests or cron jobs
    if ( $pagenow === 'index.php' && ! wp_doing_ajax() && ! defined( 'DOING_CRON' ) ) {
        wp_redirect( admin_url( 'admin.php?page=societypress' ) );
        exit;
    }
});

/**
 * After login, go straight to SocietyPress dashboard.
 *
 * WHY: The login form defaults to redirecting to /wp-admin/. We override
 *      that so the user lands on our dashboard immediately after signing in.
 */
add_filter( 'login_redirect', function ( $redirect_to, $requested_redirect_to, $user ) {
    // Only override if they weren't trying to go somewhere specific
    // (e.g., they clicked a direct link that required login first)
    if ( empty( $requested_redirect_to ) || $requested_redirect_to === admin_url() ) {
        return admin_url( 'admin.php?page=societypress' );
    }
    return $redirect_to;
}, 10, 3 );


// ============================================================================
// SITE ACCESS LOCK — Require administrator login to view anything
// ============================================================================

/**
 * Lock down the entire frontend — only logged-in administrators can see it.
 *
 * WHY: During setup and initial migration, the site should not be publicly
 *      visible. Non-admins (including logged-in subscribers) and anonymous
 *      visitors get bounced to the login page. This keeps the site private
 *      while data is being imported and configured.
 *
 *      Controlled by Settings → Website → "Require Login" checkbox.
 *      The login page itself, admin-ajax, cron, and REST API are excluded
 *      so WordPress internals keep working normally.
 */
add_action( 'template_redirect', function () {
    $sp = get_option( 'societypress_settings', [] );
    if ( empty( $sp['website_require_login'] ) ) {
        return; // Setting is off — site is public
    }

    // Don't block the login page itself — that would be an infinite redirect
    if ( is_login() ) {
        return;
    }

    // Require login AND administrator role to see any frontend page
    if ( ! is_user_logged_in() || ! current_user_can( 'manage_options' ) ) {
        auth_redirect();
    }
} );

/**
 * Block non-admin access to the backend too.
 *
 * WHY: WordPress lets any logged-in user (including subscribers) access
 *      /wp-admin/. Subscribers see a stripped-down profile page, but we
 *      don't want anyone poking around. Non-admins get redirected to the
 *      login page. AJAX requests are excluded so frontend forms still work.
 */
add_action( 'admin_init', function () {
    if ( ! current_user_can( 'manage_options' ) && ! wp_doing_ajax() ) {
        wp_redirect( wp_login_url() );
        exit;
    }
} );


// ============================================================================
// CUSTOM LOGIN PAGE — Branded login with privacy notice
// ============================================================================
//
// WHY: The default WordPress login page exposes WP branding and says nothing
//      about the society's privacy expectations. Society admins like Harold
//      shouldn't see "WordPress" anywhere — and members need to see the
//      privacy notice BEFORE they log in. This replaces the WP login page
//      with a fully branded SocietyPress login that shows the society name,
//      colors, and the pre-login privacy notice.
//
//      We use WordPress's built-in login hooks rather than replacing the
//      login page entirely. This keeps all the auth logic, CSRF protection,
//      password reset flow, and error handling intact — we just restyle it
//      and add content.

/**
