        'lato'      => '"Lato", sans-serif',
        'open-sans' => '"Open Sans", sans-serif',
    ];
    $font_family = $font_map[ $font_body ] ?? $font_map['system'];
    ?>
    <style>
        /* ----------------------------------------------------------------
           LOGIN PAGE — Full restyle
           WHY: Replace WP branding with society branding. The entire page
           should feel like it belongs to the society, not to WordPress.
           ---------------------------------------------------------------- */

