// ============================================================================
// ADMIN BAR CLEANUP — Remove WordPress branding and irrelevant links
// ============================================================================

/**
 * Clean up the admin toolbar (the bar across the top of every page).
 *
 * WHY: The default toolbar has a WordPress logo, links to Comments, and
 *      shortcuts to create Posts and Users — all things we've hidden from
 *      the sidebar. Leaving them in the toolbar would be confusing and
 *      inconsistent. We keep the essentials: site name (to visit the site),
 *      the + New button (for Pages and Media only), and the user menu
 *      (to log out or edit profile).
 */
add_action( 'wp_before_admin_bar_render', function () {
    global $wp_admin_bar;

    $wp_admin_bar->remove_node( 'wp-logo' );    // WordPress logo + "About WordPress"
    $wp_admin_bar->remove_node( 'comments' );    // Comments shortcut
    $wp_admin_bar->remove_node( 'new-post' );    // + New → Post
    $wp_admin_bar->remove_node( 'new-user' );    // + New → User
    $wp_admin_bar->remove_node( 'updates' );     // Updates notification badge

    // Add "Log Out" to the user dropdown (the avatar + name flyout).
    // WHY: We removed the default "my-account" flyout items in a previous
    //      cleanup, so there was no way to log out. This adds it back as
    //      an item in that dropdown, right below Dashboard.
    $wp_admin_bar->add_node( [
        'parent' => 'user-actions',
        'id'     => 'sp-logout',
        'title'  => 'Log Out',
        'href'   => wp_logout_url(),
    ] );
});


// ============================================================================
// DASHBOARD WIDGET CLEANUP
// ============================================================================

/**
 * Remove default dashboard widgets that don't apply to SocietyPress.
 *
 * WHY: Even though we redirect away from the WordPress dashboard, these
 *      widgets can sometimes flash briefly during the redirect. Removing
 *      them is belt-and-suspenders — makes sure nothing confusing appears
 *      even if the redirect is slow.
 */
add_action( 'wp_dashboard_setup', function () {
    // "WordPress Events and News" — developer stuff, not relevant
    remove_meta_box( 'dashboard_primary', 'dashboard', 'side' );

    // "Welcome to WordPress!" — a tutorial for WordPress itself
    remove_action( 'welcome_panel', 'wp_welcome_panel' );
});


// ============================================================================
// AUTO-UPDATES — Keep the site current automatically
// ============================================================================

/**
 * Enable automatic updates for all plugins and themes.
 *
 * WHY: Non-technical users are not going to manually update plugins and
 *      themes. An outdated site with known security holes is far more
 *      dangerous than the small risk of an auto-update causing a
 *      compatibility issue.
 *
 *      WordPress minor/security updates (e.g., 6.7.1 → 6.7.2) are already
 *      auto-enabled by default and have been since WordPress 3.7. We add
 *      plugins and themes to that.
 *
 * NOTE: Major WordPress core updates (e.g., 6.x → 7.x) are NOT auto-updated.
 *       Those have historically caused site breakage and need a more careful
 *       approach — a future version will prompt the user with a backup step
 *       before proceeding with major core updates.
 */
add_filter( 'auto_update_plugin', '__return_true' );
add_filter( 'auto_update_theme', '__return_true' );


