// ============================================================================
// MEMBERS LIST TABLE
// ============================================================================

/**
 * WordPress List Table for displaying members.
 *
 * WHY: WP_List_Table is WordPress's built-in framework for admin list pages.
 *      It gives us sortable columns, pagination, search, bulk actions, and
 *      row actions for free — and it looks like native WordPress, so Harold
 *      doesn't have to learn a custom interface.
 *
 * HOW: We extend WP_List_Table and tell it how to fetch our data, what
 *      columns to show, how to sort, and what actions to offer on each row.
 *      WordPress handles the rest (rendering, pagination math, nonces, etc.).
 */
if ( ! class_exists( 'WP_List_Table' ) ) {
    require_once ABSPATH . 'wp-admin/includes/class-wp-list-table.php';
}

class SP_Members_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'member',
            'plural'   => 'members',
            'ajax'     => false,
        ] );
    }

    /**
     * Define the columns Harold sees in the member list.
     *
     * WHY each column:
     *   Name        — primary identifier, links to edit
     *   Email       — most common lookup, pulled from wp_users
     *   Phone       — Harold looks members up by phone constantly
     *   Plan        — which membership tier they're on
     *   Status      — active, expired, grace period, etc.
     *   Expiration  — when their membership runs out
     */
    public function get_columns(): array {
        return [
            'cb'         => '<input type="checkbox" />',
            'name'       => 'Name',
            'email'      => 'Email',
            'phone'      => 'Phone',
            'plan'       => 'Plan',
            'status'     => 'Status',
            'expiration' => 'Expiration',
        ];
    }

    /**
     * Which columns can be clicked to sort the list.
     */
    public function get_sortable_columns(): array {
        return [
            'name'       => [ 'last_name', true ],   // Default sort: last name A→Z
            'plan'       => [ 'tier_id', false ],
            'status'     => [ 'status', false ],
            'expiration' => [ 'expiration_date', false ],
        ];
    }

    /**
     * Bulk actions dropdown — appears above the table.
     *
     * WHY: "Assign to Group" lets Harold select a batch of members and add
     *      them to a group in one action — much faster than editing each
     *      group individually when building email lists for blast emails.
     */
    protected function get_bulk_actions(): array {
        return [
            'assign_to_group' => 'Assign to Group',
            'delete'          => 'Delete',
        ];
    }

    /**
     * Checkbox column for bulk actions.
     */
    protected function column_cb( $item ): string {
        return sprintf(
            '<input type="checkbox" name="member[]" value="%d" />',
            $item->user_id
        );
    }

    /**
     * Name column — the primary column with row actions.
     *
     * Format: "LAST, First (Preferred)" — matches what Harold is used to
     * from EasyNetSites. The preferred name in parentheses helps when the
     * legal name differs from what everyone calls them.
     */
    protected function column_name( $item ): string {
        // WHY: Organizational members (libraries, societies) display their
        //      organization name instead of LASTNAME, FirstName format.
        if ( ( $item->member_type ?? 'individual' ) === 'organization' && ! empty( $item->organization_name ) ) {
            $name = '<strong>' . esc_html( $item->organization_name ) . '</strong>'
                  . ' <span style="color: #787c82; font-size: 12px;">(org)</span>';
        } else {
            $name = esc_html( strtoupper( $item->last_name ) . ', ' . $item->first_name );
            if ( ! empty( $item->preferred_name ) && $item->preferred_name !== $item->first_name ) {
                $name .= ' <span style="color: #787c82;">(' . esc_html( $item->preferred_name ) . ')</span>';
            }
        }

        // Row actions: Edit and Delete links that appear on hover
        $edit_url = admin_url( 'admin.php?page=sp-member-edit&user_id=' . $item->user_id );

        $actions = [
            'edit' => sprintf( '<a href="%s">Edit</a>', esc_url( $edit_url ) ),
        ];

        // Don't show Delete on your own row or any administrator.
        // WHY: Self-deletion locks you out. Deleting another admin through
        //      Members is too easy to do accidentally — if you really need to
        //      remove them, demote their role first (Edit → change Role to
        //      Subscriber), then delete. That two-step process is intentional.
        if ( (int) $item->user_id !== get_current_user_id() && ! user_can( (int) $item->user_id, 'manage_options' ) ) {
            $delete_url = wp_nonce_url(
                admin_url( 'admin.php?page=sp-members&action=delete&member=' . $item->user_id ),
                'sp_delete_member_' . $item->user_id
            );
            $actions['delete'] = sprintf(
                '<a href="%s" onclick="return confirm(\'Are you sure you want to delete this member?\');">Delete</a>',
                esc_url( $delete_url )
            );
        }

        return $name . $this->row_actions( $actions );
    }

    /**
     * Email column — pulled from wp_users, not our table.
     */
    protected function column_email( $item ): string {
        $user = get_userdata( $item->user_id );
        if ( $user ) {
            return '<a href="mailto:' . esc_attr( $user->user_email ) . '">'
                 . esc_html( $user->user_email ) . '</a>';
        }
        return '—';
    }

    /**
     * Phone column — shows whichever phone number exists, cell as fallback.
     */
    protected function column_phone( $item ): string {
        $phone = $item->phone ?: $item->cell ?: '';
        if ( ! $phone ) {
            return '—';
        }
        // Format 10-digit US/CA numbers as (XXX) XXX-XXXX for readability.
        // WHY: Raw digit strings are hard for elderly users to scan in a list.
        //      Non-10-digit values (international) are shown as-is.
        $digits = preg_replace( '/\D/', '', $phone );
        if ( strlen( $digits ) === 10 ) {
            return esc_html(
                '(' . substr( $digits, 0, 3 ) . ') '
                . substr( $digits, 3, 3 ) . '-'
                . substr( $digits, 6 )
            );
        }
        return esc_html( $phone );
    }

    /**
     * Plan column — shows the tier name, looked up from sp_membership_tiers.
     */
    protected function column_plan( $item ): string {
        if ( ! $item->tier_id ) {
            return '—';
        }
        global $wpdb;
        $tier_name = $wpdb->get_var( $wpdb->prepare(
            "SELECT name FROM {$wpdb->prefix}sp_membership_tiers WHERE id = %d",
            $item->tier_id
        ) );
        return esc_html( $tier_name ?: '—' );
    }

    /**
     * Status column — color-coded badge so Harold can see at a glance.
     */
    protected function column_status( $item ): string {
        $colors = [
            'active'   => '#00a32a',
            'expired'  => '#d63638',
            'grace'    => '#dba617',
            'deceased' => '#787c82',
            'inactive' => '#787c82',
        ];
        $color = $colors[ $item->status ] ?? '#787c82';
        $label = ucfirst( $item->status );

        return sprintf(
            '<span style="color: %s; font-weight: 600;">%s</span>',
            esc_attr( $color ),
            esc_html( $label )
        );
    }

    /**
     * Expiration column — shows the date, or "Lifetime" if null.
     */
    protected function column_expiration( $item ): string {
        if ( empty( $item->expiration_date ) ) {
            return '<em>Lifetime</em>';
        }
        return esc_html( date_i18n( get_option( 'date_format', 'F j, Y' ), strtotime( $item->expiration_date ) ) );
    }

    /**
     * Extra controls between bulk actions and the table — filter dropdowns.
     *
     * WHY: Harold needs to quickly filter by status ("show me expired members")
     *      and by tier ("show me all Single members"). These dropdowns appear
     *      right above the table, next to the search box.
     *
     * @param string $which 'top' or 'bottom' of the table.
     */
    protected function extra_tablenav( $which ): void {
        if ( $which !== 'top' ) {
            return;
        }
        global $wpdb;

        $current_status = $_GET['member_status'] ?? '';
        $current_tier   = $_GET['member_tier'] ?? '';
        $current_type   = $_GET['member_type'] ?? '';

        // Status filter
        $statuses = [ 'active', 'expired', 'grace', 'deceased', 'inactive' ];
        echo '<div class="alignleft actions">';
        echo '<select name="member_status">';
        echo '<option value="">All Statuses</option>';
        foreach ( $statuses as $s ) {
            printf(
                '<option value="%s" %s>%s</option>',
                esc_attr( $s ),
                selected( $current_status, $s, false ),
                esc_html( ucfirst( $s ) )
            );
        }
        echo '</select>';

        // Tier filter
        $tiers = $wpdb->get_results(
            "SELECT id, name FROM {$wpdb->prefix}sp_membership_tiers WHERE active = 1 ORDER BY sort_order"
        );
        echo '<select name="member_tier">';
        echo '<option value="">All Plans</option>';
        foreach ( $tiers as $t ) {
            printf(
                '<option value="%d" %s>%s</option>',
                $t->id,
                selected( $current_tier, $t->id, false ),
                esc_html( $t->name )
            );
        }
        echo '</select>';

        // Group filter — filter members by group membership
        // WHY: When building blast email lists, Harold needs to see which
        //      members are in a specific group. This dropdown filters the
        //      members list to show only members in the selected group.
        $groups = $wpdb->get_results(
            "SELECT id, name FROM {$wpdb->prefix}sp_groups WHERE status = 'active' ORDER BY sort_order, name"
        );
        $current_group = $_GET['member_group'] ?? '';
        echo '<select name="member_group">';
        echo '<option value="">All Groups</option>';
        foreach ( $groups as $g ) {
            printf(
                '<option value="%d" %s>%s</option>',
                $g->id,
                selected( $current_group, $g->id, false ),
                esc_html( $g->name )
            );
        }
        echo '</select>';

        // Member type checkboxes — Individual and/or Organization
        // WHY: Checkboxes feel more natural than a dropdown for a binary toggle.
        //      Both checked (or both unchecked) = show all. Uncheck one to exclude it.
        $show_individual   = isset( $_GET['show_individual'] );
        $show_organization = isset( $_GET['show_organization'] );
        // If neither is checked (fresh page load), treat as "show all"
        $neither_checked = ! $show_individual && ! $show_organization && empty( $_GET['filter_action'] );

        echo '<label style="margin-left: 8px; cursor: pointer;">';
        printf( '<input type="checkbox" name="show_individual" value="1" %s> Individuals',
            checked( $show_individual || $neither_checked, true, false ) );
        echo '</label>';
        echo '<label style="margin-left: 6px; cursor: pointer;">';
        printf( '<input type="checkbox" name="show_organization" value="1" %s> Organizations',
            checked( $show_organization || $neither_checked, true, false ) );
        echo '</label>';

        submit_button( 'Filter', '', 'filter_action', false );
        echo '</div>';
    }

    /**
     * Fetch member data from the database.
     *
     * Handles searching, filtering, sorting, and pagination — everything
     * Harold needs to find a specific member in a list of hundreds.
     */
    public function prepare_items(): void {
        global $wpdb;

        $sp_settings = get_option( 'societypress_settings', [] );
        $per_page = (int) ( $sp_settings['dir_per_page'] ?? 25 );
        $table    = $wpdb->prefix . 'sp_members';

        // Build the WHERE clause from search and filters
        $where  = [];
        $values = [];

        // Search — checks first name, last name, preferred name, and email
        $search = $_GET['s'] ?? '';
        if ( ! empty( $search ) ) {
            $like     = '%' . $wpdb->esc_like( $search ) . '%';
            $where[]  = "(m.first_name LIKE %s OR m.last_name LIKE %s OR m.preferred_name LIKE %s OR m.organization_name LIKE %s OR u.user_email LIKE %s)";
            $values[] = $like;
            $values[] = $like;
            $values[] = $like;
            $values[] = $like;
            $values[] = $like;
        }

        // Status filter
        $status_filter = $_GET['member_status'] ?? '';
        if ( ! empty( $status_filter ) ) {
            $where[]  = "m.status = %s";
            $values[] = $status_filter;
        }

        // Tier filter
        $tier_filter = $_GET['member_tier'] ?? '';
        if ( ! empty( $tier_filter ) ) {
            $where[]  = "m.tier_id = %d";
            $values[] = (int) $tier_filter;
        }

        // Group filter — only show members in the selected group
        // WHY: Enables filtering by group membership for blast email targeting
        $group_filter = $_GET['member_group'] ?? '';
        if ( ! empty( $group_filter ) ) {
            $where[]  = "m.user_id IN (SELECT user_id FROM {$wpdb->prefix}sp_group_members WHERE group_id = %d)";
            $values[] = (int) $group_filter;
        }

        // Member type filter — checkboxes for individual / organization.
        // WHY: If neither or both are checked, show all (no filter). If only one
        //      is checked, filter to that type. This way unchecking "Organizations"
        //      hides them without needing to remember dropdown values.
        $show_ind = isset( $_GET['show_individual'] );
        $show_org = isset( $_GET['show_organization'] );
        $has_filter = isset( $_GET['filter_action'] );
        if ( $has_filter && $show_ind && ! $show_org ) {
            $where[]  = "m.member_type = %s";
            $values[] = 'individual';
        } elseif ( $has_filter && $show_org && ! $show_ind ) {
            $where[]  = "m.member_type = %s";
            $values[] = 'organization';
        }

        $where_sql = ! empty( $where ) ? 'WHERE ' . implode( ' AND ', $where ) : '';

        // Sorting — default to last_name ASC
        $allowed_orderby = [ 'last_name', 'tier_id', 'status', 'expiration_date' ];
        $orderby = $_GET['orderby'] ?? 'last_name';
        if ( ! in_array( $orderby, $allowed_orderby, true ) ) {
            $orderby = 'last_name';
        }
        $order = ( $_GET['order'] ?? 'asc' ) === 'desc' ? 'DESC' : 'ASC';

        // Count total items (for pagination)
        $count_sql = "SELECT COUNT(*) FROM {$table} m
                      LEFT JOIN {$wpdb->users} u ON m.user_id = u.ID
                      {$where_sql}";
        if ( ! empty( $values ) ) {
            $total_items = (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$values ) );
        } else {
            $total_items = (int) $wpdb->get_var( $count_sql );
        }

        // Pagination
        $current_page = $this->get_pagenum();
        $offset       = ( $current_page - 1 ) * $per_page;

        // Fetch the rows
        $query = "SELECT m.* FROM {$table} m
                  LEFT JOIN {$wpdb->users} u ON m.user_id = u.ID
                  {$where_sql}
                  ORDER BY m.{$orderby} {$order}
                  LIMIT %d OFFSET %d";

        $query_values = array_merge( $values, [ $per_page, $offset ] );
        $this->items  = $wpdb->get_results( $wpdb->prepare( $query, ...$query_values ) );

        // Tell WP_List_Table about columns and pagination
        $this->_column_headers = [
            $this->get_columns(),
            [],                          // hidden columns (none)
            $this->get_sortable_columns(),
        ];

        $this->set_pagination_args( [
            'total_items' => $total_items,
            'per_page'    => $per_page,
            'total_pages' => ceil( $total_items / $per_page ),
        ] );
    }

    /**
     * Message shown when the table has no rows to display.
     *
     * WHY: If there ARE members in the database but the current filters/search
     *      returned zero results, we just say "no matching members" — not
     *      "add your first member," which would be confusing and wrong.
     */
    public function no_items(): void {
        global $wpdb;
        $has_any = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$wpdb->prefix}sp_members"
        );
        if ( $has_any > 0 ) {
            echo 'No members match your current filters.';
        } else {
            echo 'No members found. <a href="' . esc_url( admin_url( 'admin.php?page=sp-member-edit' ) ) . '">Add your first member</a>.';
        }
    }
}


/**
 * Handle ALL member delete actions (single, bulk, delete-all-others) BEFORE
 * any HTML output.
 *
 * WHY: WordPress fires page callbacks (sp_render_members_page) AFTER the admin
 *      header has already been sent. Any wp_redirect() inside the callback
 *      fails with "headers already sent". Moving delete handlers to admin_init
 *      ensures we redirect cleanly before any output. The member save handler
 *      already uses this pattern (see sp_save_member admin_init hook above).
 *
 * We check $_GET['page'] === 'sp-members' to avoid running on unrelated pages.
 */
add_action( 'admin_init', function () {
    // Only run on the Members page
    if ( ! isset( $_GET['page'] ) || $_GET['page'] !== 'sp-members' ) {
        return;
    }

    // ---- SELF-DELETE PROTECTION (belt AND suspenders) ----
    //
    // WHY: If get_current_user_id() ever returns 0 (auth cookie hiccup,
    //      session timeout, edge-case race condition), every comparison
    //      like "$user_id === $current" silently fails — the code thinks
    //      "0 is not 282" and happily deletes the admin's own account.
    //      That happened to Charles on 2026-02-14.
    //
    //      Fix: refuse to run ANY delete operation unless we can positively
    //      confirm who the current user is. And inside every loop, double-
    //      check each user_id against both the current user ID AND the
    //      username (in case IDs change after a reimport).
    // ----------------------------------------------------------------

    $current = get_current_user_id();

    // If WordPress can't identify who's logged in, we refuse to delete
    // anything. Better to show an error than to nuke the admin's account.
    if ( $current === 0 ) {
        wp_redirect( admin_url( 'admin.php?page=sp-members&sp_error=auth_failed' ) );
        exit;
    }

    // Also grab the username — used as a second identity check below.
    $current_user = wp_get_current_user();
    $current_login = $current_user->user_login;


    // ---- Single delete (row action) ----
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete' && isset( $_GET['member'] ) ) {
        $user_id = (int) $_GET['member'];
        check_admin_referer( 'sp_delete_member_' . $user_id );

        // Block self-deletion — you can't remove yourself from the system.
        // WHY: If the admin creates their member record using a different email
        //      than their WP admin account, the member gets a DIFFERENT user_id.
        //      A simple "$user_id === get_current_user_id()" check misses that
        //      case entirely — it sees "639 !== 282" and happily deletes.
        //      So we check three ways: by ID, by username, and by admin role.
        //      An admin should never be able to delete any admin-level user
        //      through the Members interface.
        if ( $user_id === $current ) {
            wp_redirect( admin_url( 'admin.php?page=sp-members&sp_error=self_delete' ) );
            exit;
        }

        // Also check by username or admin role — demote first, then delete.
        $target_user = get_userdata( $user_id );
        if ( $target_user && ( $target_user->user_login === $current_login || user_can( $user_id, 'manage_options' ) ) ) {
            wp_redirect( admin_url( 'admin.php?page=sp-members&sp_error=self_delete' ) );
            exit;
        }

        global $wpdb;
        $prefix = $wpdb->prefix . 'sp_';

        $wpdb->delete( $prefix . 'members', [ 'user_id' => $user_id ] );
        $wpdb->delete( $prefix . 'member_surnames', [ 'user_id' => $user_id ] );
        $wpdb->delete( $prefix . 'member_payments', [ 'user_id' => $user_id ] );
        $wpdb->delete( $prefix . 'member_notes', [ 'user_id' => $user_id ] );

        require_once ABSPATH . 'wp-admin/includes/user.php';
        wp_delete_user( $user_id );

        wp_redirect( admin_url( 'admin.php?page=sp-members&deleted=1' ) );
        exit;
    }

    // ---- Bulk delete (checkbox + dropdown action) ----
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && ! empty( $_POST['member'] ) ) {
        check_admin_referer( 'bulk-members' );

        global $wpdb;
        $prefix  = $wpdb->prefix . 'sp_';
        $deleted = 0;
        $skipped_self = false;

        require_once ABSPATH . 'wp-admin/includes/user.php';

        foreach ( (array) $_POST['member'] as $user_id ) {
            $user_id = (int) $user_id;

            // Belt: skip by ID
            if ( $user_id === $current ) {
                $skipped_self = true;
                continue;
            }

            // Suspenders: skip by username or admin role — demote first, then delete.
            $target_user = get_userdata( $user_id );
            if ( $target_user && ( $target_user->user_login === $current_login || user_can( $user_id, 'manage_options' ) ) ) {
                $skipped_self = true;
                continue;
            }

            $wpdb->delete( $prefix . 'members', [ 'user_id' => $user_id ] );
            $wpdb->delete( $prefix . 'member_surnames', [ 'user_id' => $user_id ] );
            $wpdb->delete( $prefix . 'member_payments', [ 'user_id' => $user_id ] );
            $wpdb->delete( $prefix . 'member_notes', [ 'user_id' => $user_id ] );
            wp_delete_user( $user_id );
            $deleted++;
        }

        $redirect = admin_url( 'admin.php?page=sp-members&deleted=' . $deleted );
        if ( $skipped_self ) {
            $redirect = add_query_arg( 'sp_error', 'self_delete', $redirect );
        }
        wp_redirect( $redirect );
        exit;
    }

    // ---- Bulk Assign to Group ----
    // WHY: Harold needs to batch-add members to groups for blast email targeting.
    //      Select 20 members, pick a group, done — instead of editing each group
    //      one at a time and adding members individually.
    if ( ( ( $_REQUEST['action'] ?? '' ) === 'assign_to_group' || ( $_REQUEST['action2'] ?? '' ) === 'assign_to_group' )
         && ! empty( $_REQUEST['member'] ) && ! empty( $_REQUEST['sp_assign_group_id'] ) ) {

        global $wpdb;
        $prefix   = $wpdb->prefix . 'sp_';
        $group_id = (int) $_REQUEST['sp_assign_group_id'];
        $added    = 0;

        // Verify the group exists
        $group_exists = $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$prefix}groups WHERE id = %d", $group_id
        ) );

        if ( $group_exists ) {
            foreach ( (array) $_REQUEST['member'] as $user_id ) {
                $user_id = (int) $user_id;
                // Only insert if not already in the group (UNIQUE KEY handles
                // this at the DB level too, but checking first avoids errors)
                $already = $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}group_members WHERE group_id = %d AND user_id = %d",
                    $group_id, $user_id
                ) );
                if ( ! $already ) {
                    $wpdb->insert( $prefix . 'group_members', [
                        'group_id'  => $group_id,
                        'user_id'   => $user_id,
                        'joined_at' => current_time( 'mysql' ),
                    ] );
                    $added++;
                }
            }
        }

        wp_redirect( admin_url( 'admin.php?page=sp-members&group_assigned=' . $added ) );
        exit;
    }

    // ---- Delete All Others (nuclear button) ----
    // WHY: During testing or a botched import, the admin needs to wipe the
    //      slate clean without locking themselves out.
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete_all_others' ) {
        check_admin_referer( 'sp_delete_all_others' );

        global $wpdb;
        $prefix  = $wpdb->prefix . 'sp_';

        // Build a list of ALL admin user IDs — never delete any of these.
        // WHY: Admins are protected. Demote first, then delete.
        $admin_ids = array_map( 'intval', get_users( [
            'role'   => 'administrator',
            'fields' => 'ID',
        ] ) );

        // Also get the current admin's display name for fuzzy matching.
        // WHY: If the admin created their member with a different email,
        //      the member's WP user is a subscriber — not caught by admin_ids.
        //      Matching by name is the last line of defense.
        $admin_display = strtolower( trim( $current_user->display_name ) );

        // Get ALL members
        $all_members = $wpdb->get_results(
            "SELECT user_id, first_name, last_name FROM {$prefix}members"
        );

        require_once ABSPATH . 'wp-admin/includes/user.php';

        $deleted = 0;
        foreach ( $all_members as $row ) {
            $uid = (int) $row->user_id;

            // Skip if user_id matches current admin
            if ( $uid === $current ) {
                continue;
            }

            // Skip if user_id belongs to ANY administrator
            if ( in_array( $uid, $admin_ids, true ) ) {
                continue;
            }

            // Skip by username match (catches different-email scenario)
            $target_user = get_userdata( $uid );
            if ( $target_user && $target_user->user_login === $current_login ) {
                continue;
            }

            // Skip if the member's name matches the current admin's display name
            // WHY: Last line of defense — catches the case where the admin's
            //      member record is linked to a subscriber WP user that doesn't
            //      match by ID, role, or username.
            $member_name = strtolower( trim( $row->first_name . ' ' . $row->last_name ) );
            if ( $member_name === $admin_display ) {
                continue;
            }

            $wpdb->delete( $prefix . 'members',         [ 'user_id' => $uid ] );
            $wpdb->delete( $prefix . 'member_surnames',  [ 'user_id' => $uid ] );
            $wpdb->delete( $prefix . 'member_payments',  [ 'user_id' => $uid ] );
            $wpdb->delete( $prefix . 'member_notes',     [ 'user_id' => $uid ] );
            wp_delete_user( $uid );
            $deleted++;
        }

        wp_redirect( admin_url( 'admin.php?page=sp-members&deleted=' . $deleted ) );
        exit;
    }
} );


/**
 * Render the Members list page.
 *
 * WHY: This is where Harold spends most of his time — looking up members,
 *      checking who's expired, searching for someone by name. The page has
 *      an "Add New" button, search box, filter dropdowns, and the sortable
 *      member table.
 */
function sp_render_members_page(): void {
    $table = new SP_Members_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Members</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-member-edit' ) ); ?>" class="page-title-action">
            Add New
        </a>
        <?php
        // Only show the nuclear button if there are other members to delete.
        // WHY: No point showing "Delete All Others" if you're the only one.
        //
        // The count must exclude members that belong to the current admin,
        // even if the member's user_id doesn't match get_current_user_id().
        // This happens when the admin creates their member record with a
        // different email — a new subscriber WP user is created with a
        // different ID.
        global $wpdb;
        $sp_prefix     = $wpdb->prefix . 'sp_';
        $current_uid   = get_current_user_id();
        $current_uobj  = wp_get_current_user();
        $admin_display = strtolower( trim( $current_uobj->display_name ) );

        // Count members that are NOT the current admin:
        // Exclude by user_id match AND by name match (belt + suspenders)
        $others_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$sp_prefix}members
             WHERE user_id != %d
               AND LOWER(TRIM(CONCAT(first_name, ' ', last_name))) != %s",
            $current_uid,
            $admin_display
        ) );
        if ( $others_count > 0 ) :
            $delete_all_url = wp_nonce_url(
                admin_url( 'admin.php?page=sp-members&action=delete_all_others' ),
                'sp_delete_all_others'
            );
        ?>
            <a href="<?php echo esc_url( $delete_all_url ); ?>"
               class="page-title-action"
               style="color: #b32d2e; border-color: #b32d2e;"
               onclick="return confirm('This will permanently delete all <?php echo $others_count; ?> other members and their accounts.\n\nYour own account will NOT be touched.\n\nAre you sure?');">
                Delete All Others
            </a>
        <?php endif; ?>
        <hr class="wp-header-end">

        <?php
        // Show a nudge only if the member list is completely empty.
        // WHY: The old check looked for a user_id match, but manually-added
        //      members don't set user_id. A simple "any rows?" check is
        //      reliable and disappears once the first member is added.
        global $wpdb;
        $has_members = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$wpdb->prefix}sp_members"
        );
        if ( ! $has_members ) {
            echo '<div class="notice notice-info" style="padding: 12px 16px;">'
               . '<p style="margin: 0 0 8px 0; font-size: 14px;"><strong>No members yet!</strong></p>'
               . '<p style="margin: 0;">'
               . '<a href="' . esc_url( admin_url( 'admin.php?page=sp-member-edit&self=1' ) ) . '" class="button button-primary">Add Yourself as Your First Member</a>'
               . '</p></div>';
        }

        // Self-delete warning — shown when someone tries to delete their own record
        if ( isset( $_GET['sp_error'] ) && $_GET['sp_error'] === 'self_delete' ) {
            echo '<div class="notice notice-error is-dismissible">'
               . '<p>You can\'t delete your own member record. '
               . 'Removing yourself would lock you out of the system.</p></div>';
        }

        // Auth failure — get_current_user_id() returned 0, so we refused to
        // run any delete operation rather than risk nuking the admin's account.
        if ( isset( $_GET['sp_error'] ) && $_GET['sp_error'] === 'auth_failed' ) {
            echo '<div class="notice notice-error is-dismissible">'
               . '<p>Delete cancelled — could not verify your identity. '
               . 'Please log out, log back in, and try again.</p></div>';
        }

        // Success notices
        if ( isset( $_GET['deleted'] ) ) {
            $count = (int) $_GET['deleted'];
            if ( $count > 0 ) {
                printf(
                    '<div class="notice notice-success is-dismissible"><p>%s deleted.</p></div>',
                    $count === 1 ? '1 member' : $count . ' members'
                );
            }
        }
        if ( isset( $_GET['saved'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>Member saved.</p></div>';
        }
        if ( isset( $_GET['group_assigned'] ) ) {
            $count = (int) $_GET['group_assigned'];
            printf(
                '<div class="notice notice-success is-dismissible"><p>%s added to group.</p></div>',
                $count === 1 ? '1 member' : $count . ' members'
            );
        }
        ?>

        <?php
        // Group selector for the "Assign to Group" bulk action
        // WHY: The group dropdown needs to appear inline so Harold can pick
        //      a group and submit in one step. JS shows it only when the
        //      "Assign to Group" action is selected.
        $assign_groups = $wpdb->get_results(
            "SELECT id, name FROM {$wpdb->prefix}sp_groups WHERE status = 'active' ORDER BY sort_order, name"
        );
        ?>
        <form method="get">
            <input type="hidden" name="page" value="sp-members">

            <div id="sp-group-assign-wrap" style="display:none; margin: 8px 0; padding: 8px 12px; background: #f0f6fc; border: 1px solid #72aee6; border-radius: 4px;">
                <label for="sp-assign-group-id" style="font-weight: 600; margin-right: 8px;">Assign to:</label>
                <select name="sp_assign_group_id" id="sp-assign-group-id">
                    <option value="">— Select Group —</option>
                    <?php foreach ( $assign_groups as $ag ) : ?>
                        <option value="<?php echo esc_attr( $ag->id ); ?>"><?php echo esc_html( $ag->name ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>

            <?php
            $table->search_box( 'Search Members', 'sp-member-search' );
            $table->display();
            ?>
        </form>

        <script>
        // Show the group selector only when "Assign to Group" is selected
        // WHY: Keeps the UI clean — the dropdown only appears when it's relevant.
        (function() {
            function toggleGroupPicker() {
                var sel = document.querySelector('select[name="action"]');
                var wrap = document.getElementById('sp-group-assign-wrap');
                if (sel && wrap) {
                    wrap.style.display = sel.value === 'assign_to_group' ? '' : 'none';
                }
            }
            var sel = document.querySelector('select[name="action"]');
            if (sel) {
                sel.addEventListener('change', toggleGroupPicker);
                toggleGroupPicker();
            }
        })();
        </script>
    </div>
    <?php
}


// ============================================================================
// MEMBER EDIT PAGE — Add New / Edit Member
// ============================================================================

/**
 * Handle the member save (both new and edit).
 *
 * WHY: This function runs before any HTML output because it may need to
 *      redirect after saving. WordPress requires redirects to happen before
 *      headers are sent, so we hook into admin_init and check if we're on
 *      our page with a POST submission.
 *
 * FLOW:
 *   1. Verify the nonce (prevents CSRF attacks)
 *   2. For NEW members: create a WordPress user, then insert sp_members row
 *   3. For EXISTING members: update WordPress user email, then update sp_members
 *   4. Sync surnames (delete all + re-insert — simpler than tracking changes)
 *   5. Add new note if one was typed
 *   6. Add new payment if one was entered
 *   7. Redirect back to the edit page with ?saved=1
 */
add_action( 'admin_init', function () {
    // Only run on our page, only on POST
    if ( ! isset( $_POST['sp_member_nonce'] ) ) {
        return;
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'Unauthorized.' );
    }
    if ( ! wp_verify_nonce( $_POST['sp_member_nonce'], 'sp_save_member' ) ) {
        wp_die( 'Security check failed.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Collect and sanitize all form fields
    $member_type        = sanitize_text_field( $_POST['member_type'] ?? 'individual' );
    $organization_name  = sanitize_text_field( $_POST['organization_name'] ?? '' );
    $email          = sanitize_email( $_POST['email'] ?? '' );
    $first_name     = sanitize_text_field( $_POST['first_name'] ?? '' );
    $last_name      = sanitize_text_field( $_POST['last_name'] ?? '' );
    $preferred_name = sanitize_text_field( $_POST['preferred_name'] ?? '' );
    $middle_name    = sanitize_text_field( $_POST['middle_name'] ?? '' );
    $maiden_name    = sanitize_text_field( $_POST['maiden_name'] ?? '' );
    $member_prefix  = sanitize_text_field( $_POST['prefix'] ?? '' );
    $suffix         = sanitize_text_field( $_POST['suffix'] ?? '' );
    $member_number  = sanitize_text_field( $_POST['member_number'] ?? '' );
    $date_of_birth  = sanitize_text_field( $_POST['date_of_birth'] ?? '' );
    $status         = sanitize_text_field( $_POST['status'] ?? 'active' );
    $tier_id        = absint( $_POST['tier_id'] ?? 0 );
    $join_date      = sanitize_text_field( $_POST['join_date'] ?? '' );
    $expiration_date = sanitize_text_field( $_POST['expiration_date'] ?? '' );
    $household_id   = absint( $_POST['household_id'] ?? 0 );
    $phone          = sanitize_text_field( $_POST['phone'] ?? '' );
    $cell           = sanitize_text_field( $_POST['cell'] ?? '' );
    $website        = esc_url_raw( $_POST['website'] ?? '' );
    $address_1      = sanitize_text_field( $_POST['address_1'] ?? '' );
    $address_2      = sanitize_text_field( $_POST['address_2'] ?? '' );
    $city           = sanitize_text_field( $_POST['city'] ?? '' );
    $state          = sanitize_text_field( $_POST['state'] ?? '' );
    $postal_code    = sanitize_text_field( $_POST['postal_code'] ?? '' );
    $country        = sanitize_text_field( $_POST['country'] ?? '' );

    // Seasonal address fields
    $seasonal               = isset( $_POST['seasonal'] ) ? 1 : 0;
    $seasonal_from          = sanitize_text_field( $_POST['seasonal_from'] ?? '' );
    $seasonal_to            = sanitize_text_field( $_POST['seasonal_to'] ?? '' );
    $seasonal_address_1     = sanitize_text_field( $_POST['seasonal_address_1'] ?? '' );
    $seasonal_city          = sanitize_text_field( $_POST['seasonal_city'] ?? '' );
    $seasonal_state         = sanitize_text_field( $_POST['seasonal_state'] ?? '' );
    $seasonal_postal_code   = sanitize_text_field( $_POST['seasonal_postal_code'] ?? '' );
    $seasonal_country       = sanitize_text_field( $_POST['seasonal_country'] ?? '' );

    // Preferences — checkboxes: present = 1, absent = 0
    $receive_print          = isset( $_POST['receive_print'] ) ? 1 : 0;
    $pref_email_notices     = isset( $_POST['pref_email_notices'] ) ? 1 : 0;
    $pref_email_events      = isset( $_POST['pref_email_events'] ) ? 1 : 0;
    $pref_email_newsletters = isset( $_POST['pref_email_newsletters'] ) ? 1 : 0;
    $pref_email_surnames    = isset( $_POST['pref_email_surnames'] ) ? 1 : 0;

    // Directory visibility
    $dir_show_name    = isset( $_POST['dir_show_name'] ) ? 1 : 0;
    $dir_show_address = isset( $_POST['dir_show_address'] ) ? 1 : 0;
    $dir_show_phone   = isset( $_POST['dir_show_phone'] ) ? 1 : 0;
    $dir_show_email   = isset( $_POST['dir_show_email'] ) ? 1 : 0;
    $dir_show_website = isset( $_POST['dir_show_website'] ) ? 1 : 0;
    $dir_show_photo   = isset( $_POST['dir_show_photo'] ) ? 1 : 0;

    // Validate required fields — orgs need organization name, individuals need first+last
    if ( $member_type === 'organization' ) {
        if ( empty( $organization_name ) || empty( $email ) ) {
            set_transient( 'sp_member_error', 'Organization name and email are required.', 30 );
            $redirect_url = $_POST['user_id']
                ? admin_url( 'admin.php?page=sp-member-edit&user_id=' . absint( $_POST['user_id'] ) . '&error=1' )
                : admin_url( 'admin.php?page=sp-member-edit&error=1' );
            wp_redirect( $redirect_url );
            exit;
        }
        // WHY: Org members still need first_name and last_name in the DB because
        //      those columns are NOT NULL. We store the organization name there too
        //      so sorts and searches still work on the name columns.
        if ( empty( $first_name ) ) {
            $first_name = $organization_name;
        }
        if ( empty( $last_name ) ) {
            $last_name = $organization_name;
        }
    } elseif ( empty( $first_name ) || empty( $last_name ) || empty( $email ) ) {
        // Store error in transient so we can show it after redirect
        set_transient( 'sp_member_error', 'First name, last name, and email are required.', 30 );
        $redirect_url = $_POST['user_id']
            ? admin_url( 'admin.php?page=sp-member-edit&user_id=' . absint( $_POST['user_id'] ) . '&error=1' )
            : admin_url( 'admin.php?page=sp-member-edit&error=1' );
        wp_redirect( $redirect_url );
        exit;
    }

    // Default join_date to today if not provided
    if ( empty( $join_date ) ) {
        $join_date = current_time( 'Y-m-d' );
    }

    // The member data array — used for both insert and update
    $member_data = [
        'member_type'           => $member_type,
        'organization_name'     => ( $member_type === 'organization' ) ? $organization_name : null,
        'household_id'          => $household_id ?: null,
        'member_number'         => $member_number ?: null,
        'status'                => $status,
        'tier_id'               => $tier_id ?: null,
        'prefix'                => $member_prefix ?: null,
        'first_name'            => $first_name,
        'preferred_name'        => $preferred_name ?: null,
        'middle_name'           => $middle_name ?: null,
        'last_name'             => $last_name,
        'maiden_name'           => $maiden_name ?: null,
        'suffix'                => $suffix ?: null,
        'date_of_birth'         => $date_of_birth ?: null,
        'join_date'             => $join_date,
        'expiration_date'       => $expiration_date ?: null,
        'address_1'             => $address_1 ?: null,
        'address_2'             => $address_2 ?: null,
        'city'                  => $city ?: null,
        'state'                 => $state ?: null,
        'postal_code'           => $postal_code ?: null,
        'country'               => $country ?: null,
        'phone'                 => $phone ?: null,
        'cell'                  => $cell ?: null,
        'website'               => $website ?: null,
        'seasonal'              => $seasonal,
        'seasonal_from'         => $seasonal_from ?: null,
        'seasonal_to'           => $seasonal_to ?: null,
        'seasonal_address_1'    => $seasonal_address_1 ?: null,
        'seasonal_city'         => $seasonal_city ?: null,
        'seasonal_state'        => $seasonal_state ?: null,
        'seasonal_postal_code'  => $seasonal_postal_code ?: null,
        'seasonal_country'      => $seasonal_country ?: null,
        'receive_print'         => $receive_print,
        'pref_email_notices'    => $pref_email_notices,
        'pref_email_events'     => $pref_email_events,
        'pref_email_newsletters'=> $pref_email_newsletters,
        'pref_email_surnames'   => $pref_email_surnames,
        'dir_show_name'         => $dir_show_name,
        'dir_show_address'      => $dir_show_address,
        'dir_show_phone'        => $dir_show_phone,
        'dir_show_email'        => $dir_show_email,
        'dir_show_website'      => $dir_show_website,
        'dir_show_photo'        => $dir_show_photo,
        'blast_email_opt_out'   => isset( $_POST['blast_email_opt_out'] ) ? 1 : 0,
    ];

    $editing_user_id = absint( $_POST['user_id'] ?? 0 );

    if ( $editing_user_id ) {
        // ============================================================
        // UPDATING an existing member
        // ============================================================

        // Update WordPress user email and display name
        // WHY: Orgs use their organization name as display_name instead of
        //      first+last, so they show up properly everywhere WP references them.
        $wp_display = ( $member_type === 'organization' && ! empty( $organization_name ) )
            ? $organization_name
            : trim( $first_name . ' ' . $last_name );
        wp_update_user( [
            'ID'           => $editing_user_id,
            'user_email'   => $email,
            'first_name'   => $first_name,
            'last_name'    => $last_name,
            'display_name' => $wp_display,
        ] );

        // Update WordPress role if provided and not editing yourself.
        // WHY: Admins need to promote/demote members (e.g., new board member
        //      becomes an administrator). But we never let an admin change
        //      their own role — that's how you accidentally lock yourself out.
        $new_role = sanitize_text_field( $_POST['wp_role'] ?? '' );
        if ( $new_role && (int) $editing_user_id !== get_current_user_id() ) {
            $edit_user = new WP_User( $editing_user_id );
            $edit_user->set_role( $new_role );
        }

        // Update sp_members row
        $wpdb->update(
            $prefix . 'members',
            $member_data,
            [ 'user_id' => $editing_user_id ]
        );

        $user_id = $editing_user_id;

    } else {
        // ============================================================
        // CREATING a new member
        // ============================================================

        // "Add Yourself" flow — link to the admin's existing WP user
        // WHY: If the admin uses a different email (e.g. society email vs
        //      personal email), normal flow creates a new subscriber WP user.
        //      The member record then has a user_id that doesn't match the
        //      admin's user_id, breaking every self-delete protection check.
        //      This flag ensures the member links to the admin's real account.
        $link_to_self = isset( $_POST['link_to_self'] ) && $_POST['link_to_self'] === '1';
        if ( $link_to_self ) {
            $self_id = get_current_user_id();
            // Make sure the admin doesn't already have a member record
            $already_member = $wpdb->get_var( $wpdb->prepare(
                "SELECT user_id FROM {$prefix}members WHERE user_id = %d",
                $self_id
            ) );
            if ( $already_member ) {
                set_transient( 'sp_member_error', 'You already have a member record.', 30 );
                wp_redirect( admin_url( 'admin.php?page=sp-member-edit&user_id=' . $self_id . '&error=1' ) );
                exit;
            }
            // Update the admin's WP user profile with whatever name/email
            // they entered in the form (they might want their society email
            // displayed instead of their personal one)
            wp_update_user( [
                'ID'           => $self_id,
                'first_name'   => $first_name,
                'last_name'    => $last_name,
                'display_name' => $first_name . ' ' . $last_name,
            ] );
            $user_id = $self_id;

        // Normal flow — check if a WP user with this email already exists
        } elseif ( $existing_user = get_user_by( 'email', $email ) ) {
            // Check if they're already a member
            $already_member = $wpdb->get_var( $wpdb->prepare(
                "SELECT user_id FROM {$prefix}members WHERE user_id = %d",
                $existing_user->ID
            ) );
            if ( $already_member ) {
                set_transient( 'sp_member_error', 'A member with this email address already exists.', 30 );
                wp_redirect( admin_url( 'admin.php?page=sp-member-edit&error=1' ) );
                exit;
            }
            // User exists but isn't a member yet — link them
            $user_id = $existing_user->ID;
        } else {
            // Create a new WordPress user
            // WHY: We generate a random password and email it to them.
            //      They can change it later. The username is their email
            //      address — simplest thing to remember for non-technical users.
            $random_password = wp_generate_password( 12, true, true );
            $new_display = ( $member_type === 'organization' && ! empty( $organization_name ) )
                ? $organization_name
                : trim( $first_name . ' ' . $last_name );
            $user_id = wp_insert_user( [
                'user_login'   => $email,
                'user_email'   => $email,
                'user_pass'    => $random_password,
                'first_name'   => $first_name,
                'last_name'    => $last_name,
                'display_name' => $new_display,
                'role'         => 'subscriber',
            ] );

            if ( is_wp_error( $user_id ) ) {
                set_transient( 'sp_member_error', $user_id->get_error_message(), 30 );
                wp_redirect( admin_url( 'admin.php?page=sp-member-edit&error=1' ) );
                exit;
            }

            // Send the new user their credentials
            wp_new_user_notification( $user_id, null, 'user' );
        }

        // Insert the sp_members row
        $member_data['user_id'] = $user_id;
        $wpdb->insert( $prefix . 'members', $member_data );
    }

    // ================================================================
    // SURNAMES — Delete all and re-insert from form
    // ================================================================
    // WHY: Tracking individual add/edit/delete for a repeatable field set
    //      is complex and error-prone. Since surnames are lightweight rows
    //      (no auto-increment IDs that matter externally), it's simpler
    //      and safer to wipe and re-insert. The form sends parallel arrays.
    $wpdb->delete( $prefix . 'member_surnames', [ 'user_id' => $user_id ] );

    $surnames = $_POST['surname'] ?? [];
    if ( is_array( $surnames ) ) {
        $counties   = $_POST['surname_county'] ?? [];
        $states     = $_POST['surname_state'] ?? [];
        $countries  = $_POST['surname_country'] ?? [];
        $year_froms = $_POST['surname_year_from'] ?? [];
        $year_tos   = $_POST['surname_year_to'] ?? [];

        foreach ( $surnames as $i => $surname ) {
            $surname = sanitize_text_field( $surname );
            if ( empty( $surname ) ) {
                continue; // Skip blank rows
            }
            $wpdb->insert( $prefix . 'member_surnames', [
                'user_id'   => $user_id,
                'surname'   => $surname,
                'county'    => sanitize_text_field( $counties[ $i ] ?? '' ) ?: null,
                'state'     => sanitize_text_field( $states[ $i ] ?? '' ) ?: null,
                'country'   => sanitize_text_field( $countries[ $i ] ?? '' ) ?: null,
                'year_from' => absint( $year_froms[ $i ] ?? 0 ) ?: null,
                'year_to'   => absint( $year_tos[ $i ] ?? 0 ) ?: null,
            ] );
        }
    }

    // ================================================================
    // NEW NOTE — Only insert if Harold actually typed something
    // ================================================================
    $new_note = sanitize_textarea_field( $_POST['new_note'] ?? '' );
    if ( ! empty( $new_note ) ) {
        $wpdb->insert( $prefix . 'member_notes', [
            'user_id'   => $user_id,
            'content'   => $new_note,
            'author_id' => get_current_user_id(),
        ] );
    }

    // ================================================================
    // NEW PAYMENT — Only insert if an amount was entered
    // ================================================================
    $new_payment_amount = floatval( $_POST['new_payment_amount'] ?? 0 );
    if ( $new_payment_amount > 0 ) {
        $wpdb->insert( $prefix . 'member_payments', [
            'user_id'     => $user_id,
            'amount'      => $new_payment_amount,
            'type'        => sanitize_text_field( $_POST['new_payment_type'] ?? 'dues' ),
            'method'      => sanitize_text_field( $_POST['new_payment_method'] ?? '' ) ?: null,
            'date'        => sanitize_text_field( $_POST['new_payment_date'] ?? '' ) ?: current_time( 'Y-m-d' ),
            'note'        => sanitize_text_field( $_POST['new_payment_note'] ?? '' ) ?: null,
            'recorded_by' => get_current_user_id(),
        ] );
    }

    // Redirect to the edit page with success message
    wp_redirect( admin_url( 'admin.php?page=sp-member-edit&user_id=' . $user_id . '&saved=1' ) );
    exit;
});


/**
 * Render the Add New / Edit Member page.
 *
 * WHY: This is the form Harold uses to enter or update a member's information.
 *      Instead of spreading data across 7 tabs like the old EasyNetSites system,
 *      we use a single scrollable page with clearly labeled sections. Everything
 *      is visible at once — no hidden tabs where data gets lost. Each section
 *      uses WordPress's standard postbox styling so it looks native.
 *
 * SECTIONS:
 *   1. Membership    — status, tier, join date, expiration, member number
 *   2. Personal Info — name fields (prefix, first, preferred, middle, last, maiden, suffix), DOB
 *   3. Contact       — email, phone, cell, website, mailing address
 *   4. Seasonal Address — for snowbirds who have a winter/summer address
 *   5. Research Surnames — the genealogy-specific repeatable field set
 *   6. Preferences   — email opt-ins, print newsletter, directory visibility
 *   7. Admin Notes   — timestamped notes with author attribution
 *   8. Payment History — full payment ledger with add-new form
 */
function sp_render_member_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Are we editing an existing member or adding a new one?
    $user_id = absint( $_GET['user_id'] ?? 0 );
    $is_edit = (bool) $user_id;

    // "Add Yourself as Your First Member" passes &self=1 in the URL.
    // WHY: This tells the save handler to link the member record to the
    //      current admin's WP user (get_current_user_id()) instead of
    //      creating a new subscriber WP user. The form is NOT pre-filled —
    //      the admin enters their society member info fresh, which may use
    //      a completely different email than their WP admin account.
    $link_to_self = ! $is_edit && isset( $_GET['self'] ) && $_GET['self'] === '1';

    // Load existing data if editing
    $member   = null;
    $wp_user  = null;
    $surnames = [];
    $notes    = [];
    $payments = [];

    if ( $is_edit ) {
        $member = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}members WHERE user_id = %d",
            $user_id
        ) );

        if ( ! $member ) {
            echo '<div class="wrap"><h1>Member not found.</h1>'
               . '<p><a href="' . esc_url( admin_url( 'admin.php?page=sp-members' ) ) . '">&larr; Back to Members</a></p></div>';
            return;
        }

        $wp_user = get_userdata( $user_id );

        $surnames = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}member_surnames WHERE user_id = %d ORDER BY surname",
            $user_id
        ) );

        $notes = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}member_notes WHERE user_id = %d ORDER BY created_at DESC",
            $user_id
        ) );

        $payments = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}member_payments WHERE user_id = %d ORDER BY date DESC",
            $user_id
        ) );
    }

    // Load available tiers for the dropdown
    $tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers WHERE active = 1 ORDER BY sort_order"
    );

    // Show error if one was stored
    $error = get_transient( 'sp_member_error' );
    if ( $error ) {
        delete_transient( 'sp_member_error' );
    }

    // WHY: Org members display their organization name in the title instead of
    //      the first+last placeholder values that were stored in those columns.
    if ( $is_edit && ( $member->member_type ?? 'individual' ) === 'organization' && ! empty( $member->organization_name ) ) {
        $page_title = 'Edit Member: ' . esc_html( $member->organization_name );
    } elseif ( $is_edit ) {
        $page_title = 'Edit Member: ' . esc_html( $member->first_name . ' ' . $member->last_name );
    } else {
        $page_title = 'Add New Member';
    }

    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php echo $page_title; ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-members' ) ); ?>" class="page-title-action">
            &larr; Back to Members
        </a>
        <hr class="wp-header-end">

        <?php if ( $error ) : ?>
            <div class="notice notice-error is-dismissible">
                <p><?php echo esc_html( $error ); ?></p>
            </div>
        <?php endif; ?>

        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible">
                <p>Member saved successfully.</p>
            </div>
        <?php endif; ?>

        <form method="post" action="">
            <?php wp_nonce_field( 'sp_save_member', 'sp_member_nonce' ); ?>
            <input type="hidden" name="user_id" value="<?php echo esc_attr( $user_id ); ?>">
            <?php if ( $link_to_self ) : ?>
                <!-- WHY: Tells the save handler to link this member record to the
                     current admin's WP user (get_current_user_id()) instead of
                     creating a new subscriber WP user. -->
                <input type="hidden" name="link_to_self" value="1">
            <?php endif; ?>

            <style>
                /* Clean section styling — each section is a WordPress-style postbox */
                .sp-section {
                    background: #fff;
                    border: 1px solid #c3c4c7;
                    border-radius: 4px;
                    margin-top: 20px;
                    padding: 0;
                }
                .sp-section h2 {
                    margin: 0;
                    padding: 12px 20px;
                    border-bottom: 1px solid #c3c4c7;
                    font-size: 14px;
                    font-weight: 600;
                    background: #f6f7f7;
                }
                .sp-section-body {
                    padding: 20px;
                }
                /* Two-column grid for form fields */
                .sp-fields {
                    display: grid;
                    grid-template-columns: 1fr 1fr;
                    gap: 16px 24px;
                }
                .sp-fields.sp-fields-3col {
                    grid-template-columns: 1fr 1fr 1fr;
                }
                .sp-field {
                    display: flex;
                    flex-direction: column;
                }
                .sp-field label {
                    font-weight: 600;
                    margin-bottom: 4px;
                    font-size: 13px;
                    color: #1d2327;
                }
                .sp-field input,
                .sp-field select,
                .sp-field textarea {
                    width: 100%;
                    max-width: 100%;
                }
                .sp-field .description {
                    font-size: 12px;
                    color: #787c82;
                    margin-top: 4px;
                }
                /* Full-width fields that span all columns */
                .sp-field-full {
                    grid-column: 1 / -1;
                }
                /* Surname repeater rows */
                .sp-surname-row {
                    display: grid;
                    grid-template-columns: 2fr 1.5fr 1fr 1fr 1fr 1fr auto;
                    gap: 8px;
                    align-items: end;
                    margin-bottom: 8px;
                }
                .sp-surname-row input {
                    width: 100%;
                }
                .sp-surname-header {
                    display: grid;
                    grid-template-columns: 2fr 1.5fr 1fr 1fr 1fr 1fr auto;
                    gap: 8px;
                    margin-bottom: 4px;
                    font-weight: 600;
                    font-size: 12px;
                    color: #787c82;
                }
                /* Responsive: stack to single column on smaller screens */
                @media (max-width: 782px) {
                    .sp-fields,
                    .sp-fields.sp-fields-3col {
                        grid-template-columns: 1fr;
                    }
                    .sp-surname-row,
                    .sp-surname-header {
                        grid-template-columns: 1fr;
                    }
                }
                /* Checkbox groups */
                .sp-checkboxes label {
                    display: block;
                    font-weight: normal;
                    margin-bottom: 8px;
                }
                .sp-checkboxes label input {
                    width: auto;
                    margin-right: 6px;
                }
                /* Notes timeline */
                .sp-note {
                    border-left: 3px solid #2271b1;
                    padding: 8px 12px;
                    margin-bottom: 12px;
                    background: #f6f7f7;
                }
                .sp-note-meta {
                    font-size: 12px;
                    color: #787c82;
                    margin-top: 4px;
                }
                /* Payment table */
                .sp-payments-table {
                    width: 100%;
                    border-collapse: collapse;
                }
                .sp-payments-table th,
                .sp-payments-table td {
                    padding: 8px 12px;
                    text-align: left;
                    border-bottom: 1px solid #e0e0e0;
                }
                .sp-payments-table th {
                    font-size: 12px;
                    color: #787c82;
                    font-weight: 600;
                }
            </style>

            <!-- ============================================================ -->
            <!-- SECTION: Membership -->
            <!-- ============================================================ -->
            <div class="sp-section">
                <h2>Membership</h2>
                <div class="sp-section-body">
                    <div class="sp-fields">

                        <div class="sp-field">
                            <label for="sp-status">Status</label>
                            <select name="status" id="sp-status">
                                <?php
                                $statuses = [
                                    'active'   => 'Active',
                                    'expired'  => 'Expired',
                                    'grace'    => 'Grace Period',
                                    'inactive' => 'Inactive',
                                    'deceased' => 'Deceased',
                                ];
                                $current_status = $member->status ?? 'active';
                                foreach ( $statuses as $val => $label ) {
                                    printf(
                                        '<option value="%s" %s>%s</option>',
                                        esc_attr( $val ),
                                        selected( $current_status, $val, false ),
                                        esc_html( $label )
                                    );
                                }
                                ?>
                            </select>
                        </div>

                        <div class="sp-field">
                            <label for="sp-tier">Membership Plan</label>
                            <select name="tier_id" id="sp-tier">
                                <option value="0">— None —</option>
                                <?php foreach ( $tiers as $t ) : ?>
                                    <option value="<?php echo esc_attr( $t->id ); ?>"
                                        <?php selected( $member->tier_id ?? 0, $t->id ); ?>>
                                        <?php echo esc_html( $t->name ); ?>
                                    </option>
                                <?php endforeach; ?>
                            </select>
                            <?php if ( empty( $tiers ) ) : ?>
                                <p class="description">No plans created yet.
                                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-member-tiers' ) ); ?>">Set up membership plans</a> under Members &rarr; Membership Plans.</p>
                            <?php endif; ?>
                        </div>

                        <div class="sp-field">
                            <label for="sp-role">Site Role</label>
                            <?php
                            // WHY: Admins need to be able to promote members (e.g., make
                            //      a board member an administrator) without leaving
                            //      SocietyPress. This dropdown shows all WordPress roles.
                            //      Self-demotion is blocked — you can't accidentally
                            //      remove your own admin access.
                            $current_role = 'subscriber'; // Default for new members
                            if ( $is_edit && ! empty( $member->user_id ) ) {
                                $edit_user = get_userdata( $member->user_id );
                                if ( $edit_user && ! empty( $edit_user->roles ) ) {
                                    $current_role = $edit_user->roles[0];
                                }
                            }
                            $is_self = $is_edit && ! empty( $member->user_id )
                                       && (int) $member->user_id === get_current_user_id();
                            ?>
                            <select name="wp_role" id="sp-role" <?php echo $is_self ? 'disabled' : ''; ?>>
                                <?php
                                // Get all editable roles (WordPress filters out super admin, etc.)
                                $roles = wp_roles()->get_names();
                                foreach ( $roles as $role_slug => $role_name ) :
                                ?>
                                    <option value="<?php echo esc_attr( $role_slug ); ?>"
                                        <?php selected( $current_role, $role_slug ); ?>>
                                        <?php echo esc_html( translate_user_role( $role_name ) ); ?>
                                    </option>
                                <?php endforeach; ?>
                            </select>
                            <?php if ( $is_self ) : ?>
                                <p class="description">You cannot change your own role.</p>
                                <!-- Hidden field so the form still submits the current value -->
                                <input type="hidden" name="wp_role" value="<?php echo esc_attr( $current_role ); ?>">
                            <?php endif; ?>
                        </div>

                        <?php
                        // --- Join Date ---
                        // WHY: For new members, default to today so the volunteer
                        //      doesn't have to type it every time. For existing
                        //      members, show whatever is stored.
                        $join_date_val = $member->join_date ?? '';
                        if ( ! $is_edit && empty( $join_date_val ) ) {
                            $join_date_val = current_time( 'Y-m-d' );
                        }

                        // --- Expiration Date ---
                        // WHY: Pre-calculate the expected expiration based on the
                        //      society's membership settings so the volunteer just
                        //      confirms it rather than doing date math in their head.
                        // Load membership settings — used both for the PHP pre-fill
                        // below and the JavaScript recalculator further down the page.
                        $sp_settings = get_option( 'societypress_settings', [] );

                        $expiration_val = $member->expiration_date ?? '';
                        if ( ! $is_edit && empty( $expiration_val ) ) {
                            $expiration_val = sp_calculate_expiration(
                                $join_date_val,
                                $sp_settings
                            );
                        }
                        ?>
                        <div class="sp-field">
                            <label for="sp-join-date">Join Date</label>
                            <input type="date" name="join_date" id="sp-join-date"
                                   value="<?php echo esc_attr( $join_date_val ); ?>">
                            <p class="description">Defaults to today for new members.</p>
                        </div>

                        <div class="sp-field">
                            <label for="sp-expiration">Expiration Date</label>
                            <input type="date" name="expiration_date" id="sp-expiration"
                                   value="<?php echo esc_attr( $expiration_val ); ?>">
                            <p class="description">Pre-filled based on your membership period settings. Leave blank for lifetime members.</p>
                        </div>

                        <div class="sp-field">
                            <label for="sp-member-number">Member Number</label>
                            <input type="text" name="member_number" id="sp-member-number"
                                   value="<?php echo esc_attr( $member->member_number ?? '' ); ?>"
                                   placeholder="Optional">
                        </div>

                        <div class="sp-field">
                            <label for="sp-household">Household ID</label>
                            <input type="number" name="household_id" id="sp-household"
                                   value="<?php echo esc_attr( $member->household_id ?? '' ); ?>"
                                   min="0" placeholder="0 = none">
