                    <!-- ============================================================ -->
                    <!-- Phone Number Auto-Formatting                                 -->
                    <!-- WHY: Format as (XXX) XXX-XXXX while typing so elderly users  -->
                    <!--      don't have to remember formatting. Numbers starting      -->
                    <!--      with "+" are left alone (international). On form submit  -->
                    <!--      we strip to digits only for clean storage.               -->
                    <!-- ============================================================ -->
                    <script>
                    (function() {
                        /**
                         * Format a phone number as (XXX) XXX-XXXX.
                         * - Numbers starting with "+" are left untouched (international).
                         * - Under 4 digits: just show the digits.
                         * - 4-6 digits:  (XXX) XXX
                         * - 7-10 digits: (XXX) XXX-XXXX
                         * - Over 10: truncate to 10 and format.
                         */
                        function formatPhone(value) {
                            if (!value) return "";
                            if (value.charAt(0) === "+") return value;
                            var digits = value.replace(/\D/g, "");
                            if (digits.length < 4) return digits;
                            if (digits.length <= 6) {
                                return "(" + digits.substring(0, 3) + ") " + digits.substring(3);
                            }
                            if (digits.length > 10) digits = digits.substring(0, 10);
                            return "(" + digits.substring(0, 3) + ") " + digits.substring(3, 6) + "-" + digits.substring(6);
                        }

                        var phoneFields = document.querySelectorAll("#sp-phone, #sp-cell");
                        phoneFields.forEach(function(field) {
                            // Format any existing value on page load (raw digits from DB)
                            if (field.value) field.value = formatPhone(field.value);

                            // Format as the user types
                            field.addEventListener("input", function() {
                                var cursorPos = this.selectionStart;
                                var oldLen = this.value.length;
                                var formatted = formatPhone(this.value);
                                var newLen = formatted.length;
                                this.value = formatted;
                                // Keep cursor in a sensible position after formatting
                                var newCursor = cursorPos + (newLen - oldLen);
                                if (newCursor < 0) newCursor = 0;
                                if (newCursor > newLen) newCursor = newLen;
                                this.setSelectionRange(newCursor, newCursor);
                            });

                            // On submit, strip to digits only so the DB stores clean data
                            var form = field.closest("form");
                            if (form) {
                                form.addEventListener("submit", function() {
                                    if (field.value && field.value.charAt(0) !== "+") {
                                        field.value = field.value.replace(/\D/g, "");
                                    }
                                });
                            }
                        });
                    })();
                    </script>

                    <!-- ============================================================ -->
                    <!-- Country / State-Province Dynamic Fields                       -->
                    <!-- WHY: When Country is US or CA, show a dropdown with states    -->
                    <!--      or provinces. For everything else, show a freetext       -->
                    <!--      input. Labels also adjust — "State" vs "Province" vs     -->
                    <!--      "State / Province", and "ZIP Code" vs "Postal Code".     -->
                    <!-- ============================================================ -->
                    <script>
                    (function() {
                        var US_STATES = {
                            "AL":"Alabama","AK":"Alaska","AZ":"Arizona","AR":"Arkansas",
                            "CA":"California","CO":"Colorado","CT":"Connecticut","DE":"Delaware",
                            "DC":"District of Columbia","FL":"Florida","GA":"Georgia","HI":"Hawaii",
                            "ID":"Idaho","IL":"Illinois","IN":"Indiana","IA":"Iowa",
                            "KS":"Kansas","KY":"Kentucky","LA":"Louisiana","ME":"Maine",
                            "MD":"Maryland","MA":"Massachusetts","MI":"Michigan","MN":"Minnesota",
                            "MS":"Mississippi","MO":"Missouri","MT":"Montana","NE":"Nebraska",
                            "NV":"Nevada","NH":"New Hampshire","NJ":"New Jersey","NM":"New Mexico",
                            "NY":"New York","NC":"North Carolina","ND":"North Dakota","OH":"Ohio",
                            "OK":"Oklahoma","OR":"Oregon","PA":"Pennsylvania","RI":"Rhode Island",
                            "SC":"South Carolina","SD":"South Dakota","TN":"Tennessee","TX":"Texas",
                            "UT":"Utah","VT":"Vermont","VA":"Virginia","WA":"Washington",
                            "WV":"West Virginia","WI":"Wisconsin","WY":"Wyoming"
                        };

                        var CA_PROVINCES = {
                            "AB":"Alberta","BC":"British Columbia","MB":"Manitoba",
                            "NB":"New Brunswick","NL":"Newfoundland and Labrador",
                            "NS":"Nova Scotia","NT":"Northwest Territories","NU":"Nunavut",
                            "ON":"Ontario","PE":"Prince Edward Island","QC":"Quebec",
                            "SK":"Saskatchewan","YT":"Yukon"
                        };

                        var countrySelect = document.getElementById("sp-country");
                        var stateSelect   = document.getElementById("sp-state-select");
                        var stateText     = document.getElementById("sp-state-text");
                        var stateSaved    = document.getElementById("sp-state-saved");
                        var stateLabel    = document.getElementById("sp-state-label");
                        var postalLabel   = document.getElementById("sp-postal-label");

                        if (!countrySelect || !stateSelect) return;

                        function updateStateField() {
                            var country = countrySelect.value;
                            var savedValue = stateSaved ? stateSaved.value : "";
                            var list = null;

                            if (country === "US") list = US_STATES;
                            else if (country === "CA") list = CA_PROVINCES;

                            if (list) {
                                // -- DROPDOWN MODE --
                                stateSelect.innerHTML = '<option value="">— Select —</option>';
                                Object.keys(list).forEach(function(code) {
                                    var opt = document.createElement("option");
                                    opt.value = code;
                                    opt.textContent = list[code];
                                    if (code === savedValue) opt.selected = true;
                                    stateSelect.appendChild(opt);
                                });
                                stateSelect.style.display = "";
                                stateSelect.disabled = false;
                                stateSelect.name = "state";

                                if (stateText) {
                                    stateText.style.display = "none";
                                    stateText.disabled = true;
                                    stateText.removeAttribute("name");
                                }
                            } else {
                                // -- FREETEXT MODE --
                                stateSelect.style.display = "none";
                                stateSelect.disabled = true;
                                stateSelect.removeAttribute("name");

                                if (stateText) {
                                    stateText.style.display = "";
                                    stateText.disabled = false;
                                    stateText.name = "state";
                                    if (savedValue) stateText.value = savedValue;
                                }
                            }

                            // Update labels to match the selected country
                            if (stateLabel) {
                                if (country === "US") stateLabel.textContent = "State";
                                else if (country === "CA") stateLabel.textContent = "Province";
                                else stateLabel.textContent = "State / Province";
                            }
                            if (postalLabel) {
                                postalLabel.textContent = (country === "US") ? "ZIP Code" : "Postal Code";
                            }
                        }

                        // Run once on page load
                        updateStateField();

                        // Re-run when country changes
                        countrySelect.addEventListener("change", function() {
                            if (stateSaved) stateSaved.value = "";
                            if (stateText) stateText.value = "";
                            updateStateField();
                        });
                    })();
                    </script>

                    <!-- ============================================================ -->
                    <!-- Expiration Date Auto-Calculator                               -->
                    <!-- WHY: When the volunteer changes the join date on a NEW        -->
                    <!--      member form, recalculate the expiration date so they     -->
                    <!--      don't have to do fiscal-year math in their head. The     -->
                    <!--      settings (period type, start month, late-join credit)    -->
                    <!--      are baked into the JS at render time via PHP.            -->
                    <!-- ============================================================ -->
                    <?php if ( ! $is_edit ) : ?>
                    <script>
                    (function() {
                        var joinField = document.getElementById("sp-join-date");
                        var expField  = document.getElementById("sp-expiration");
                        if (!joinField || !expField) return;

                        // Settings baked in from PHP at render time
                        var periodType  = <?php echo wp_json_encode( $sp_settings['membership_period_type'] ?? 'annual' ); ?>;
                        var startMonth  = <?php echo (int) ( $sp_settings['membership_start_month'] ?? 7 ); ?>;
                        var creditMonths = <?php echo (int) ( $sp_settings['late_join_months'] ?? 5 ); ?>;

                        /**
                         * Calculate the expiration date from a join date string.
                         * Mirrors the PHP sp_calculate_expiration() function exactly.
                         */
                        function calcExpiration(joinStr) {
                            if (!joinStr) return "";
                            var parts = joinStr.split("-");
                            var joinYear  = parseInt(parts[0], 10);
                            var joinMonth = parseInt(parts[1], 10);
                            var joinDay   = parseInt(parts[2], 10);

                            if (periodType === "rolling") {
                                // Add 12 months
                                var d = new Date(joinYear, joinMonth - 1 + 12, joinDay);
                                return formatDate(d);
                            }

                            // Annual: find the fiscal year end
                            var endMonth = (startMonth === 1) ? 12 : startMonth - 1;
                            var endYear;

                            if (startMonth === 1) {
                                endYear = joinYear;
                            } else {
                                endYear = (joinMonth >= startMonth) ? joinYear + 1 : joinYear;
                            }

                            // Last day of end month (day 0 of next month = last day of this month)
                            var lastDay = new Date(endYear, endMonth, 0).getDate();
                            var endDate = new Date(endYear, endMonth - 1, lastDay);

                            // Check late-join credit window
                            var monthsRemaining = (endYear * 12 + endMonth) - (joinYear * 12 + joinMonth);
                            if (monthsRemaining <= creditMonths) {
                                // Roll forward 12 months
                                var nextEndMonth = endMonth;
                                var nextEndYear  = endYear + 1;
                                var nextLastDay  = new Date(nextEndYear, nextEndMonth, 0).getDate();
                                endDate = new Date(nextEndYear, nextEndMonth - 1, nextLastDay);
                            }

                            return formatDate(endDate);
                        }

                        function formatDate(d) {
                            var y = d.getFullYear();
                            var m = ("0" + (d.getMonth() + 1)).slice(-2);
                            var day = ("0" + d.getDate()).slice(-2);
                            return y + "-" + m + "-" + day;
                        }

                        joinField.addEventListener("change", function() {
                            expField.value = calcExpiration(this.value);
                        });
                    })();
                    </script>
                    <?php endif; ?>

