// ============================================================================
// EXPIRATION DATE CALCULATOR
// ============================================================================

/**
 * Calculate the expected membership expiration date from a join date.
 *
 * WHY: Every society has different bylaws for when memberships expire.
 *      Rather than making the volunteer do date math, we auto-calculate
 *      based on the society's configured settings. The volunteer can
 *      always override the result on the form.
 *
 * LOGIC:
 *   - Rolling: join date + 12 months.
 *   - Annual:  find the end of the membership period (last day of the
 *              month before the start month). If the join date falls
 *              within the "late-join credit" window (N months before the
 *              period ends), roll forward to the NEXT period's end.
 *
 * @param string $join_date  The join date in Y-m-d format.
 * @param array  $settings   The societypress_settings option array.
 * @return string Expiration date in Y-m-d format, or empty string on error.
 */
function sp_calculate_expiration( string $join_date, array $settings ): string {
    if ( empty( $join_date ) ) {
        return '';
    }

    $period_type  = $settings['membership_period_type'] ?? 'annual';
    $start_month  = (int) ( $settings['membership_start_month'] ?? 7 );
    $credit_months = (int) ( $settings['late_join_months'] ?? 5 );

    // --- Rolling: simply add 12 months ---
    if ( $period_type === 'rolling' ) {
        $dt = date_create( $join_date );
        if ( ! $dt ) return '';
        $dt->modify( '+12 months' );
        return $dt->format( 'Y-m-d' );
    }

    // --- Annual: calculate fiscal year end ---
    $dt = date_create( $join_date );
    if ( ! $dt ) return '';

    $join_year  = (int) $dt->format( 'Y' );
    $join_month = (int) $dt->format( 'n' );

    // The period ends on the last day of the month BEFORE the start month.
    // Example: start_month = 7 (July) → period ends June 30.
    // Example: start_month = 1 (Jan)  → period ends December 31.
    $end_month = ( $start_month === 1 ) ? 12 : $start_month - 1;

    // Determine the calendar year of the period end.
    // If the period spans two calendar years (start_month > 1), the end
    // falls in the NEXT calendar year for anyone joining on or after
    // the start month, and the SAME calendar year for earlier joiners.
    if ( $start_month === 1 ) {
        // Calendar year: Jan–Dec, ends in the same year
        $end_year = $join_year;
    } else {
        if ( $join_month >= $start_month ) {
            // Joined after the period started → ends next calendar year
            $end_year = $join_year + 1;
        } else {
            // Joined before the period starts → still in the period
            // that started last year, ends this calendar year
            $end_year = $join_year;
        }
    }

    // Last day of the end month
    $end_date = date_create( sprintf( '%04d-%02d-01', $end_year, $end_month ) );
    $end_date->modify( 'last day of this month' );

    // Check if the join date falls in the late-join credit window.
    // If there are $credit_months or fewer months remaining before the
    // period ends, roll forward to the NEXT period (add 12 months).
    $months_remaining = ( (int) $end_date->format( 'Y' ) * 12 + (int) $end_date->format( 'n' ) )
                      - ( $join_year * 12 + $join_month );

    if ( $months_remaining <= $credit_months ) {
        $end_date->modify( '+12 months' );
        // Recalculate last day in case of month-length differences
        $end_date->modify( 'last day of this month' );
    }

    return $end_date->format( 'Y-m-d' );
}


// ============================================================================
// FIELD RENDERERS
// ============================================================================

/**
 * Render a single-line text input for the Settings page.
 *
 * WHY: Each settings field needs a function that outputs the actual HTML.
 *      We keep these generic so adding new fields later is trivial — just
 *      pass a different 'key' and 'placeholder' in the args array.
 *
 * @param array $args Field arguments from add_settings_field() — contains
 *                    'key' (which setting), 'placeholder', and optional 'type'.
 */
function sp_render_text_field( array $args ): void {
    $settings = get_option( 'societypress_settings', [] );
    $value    = $settings[ $args['key'] ] ?? '';
    $type     = $args['type'] ?? 'text';
    $id_attr  = ! empty( $args['id'] ) ? sprintf( ' id="%s"', esc_attr( $args['id'] ) ) : '';

    printf(
        '<input type="%s" name="societypress_settings[%s]" value="%s" placeholder="%s" class="regular-text"%s>',
        esc_attr( $type ),
        esc_attr( $args['key'] ),
        esc_attr( $value ),
        esc_attr( $args['placeholder'] ?? '' ),
        $id_attr
    );
}

/**
 * Render a multi-line textarea for the Settings page.
 *
 * @param array $args Field arguments — contains 'key' and 'placeholder'.
 */
function sp_render_textarea_field( array $args ): void {
    $settings = get_option( 'societypress_settings', [] );
    $value    = $settings[ $args['key'] ] ?? '';

    printf(
        '<textarea name="societypress_settings[%s]" placeholder="%s" class="large-text" rows="3">%s</textarea>',
        esc_attr( $args['key'] ),
        esc_attr( $args['placeholder'] ?? '' ),
        esc_textarea( $value )
    );
}


// ============================================================================
// SANITIZE CALLBACK
// ============================================================================

/**
 * Clean all SocietyPress-specific settings before they're saved.
 *
 * WHY: Never trust user input, even from admin users. We strip HTML tags
 *      and trim whitespace to prevent XSS and keep data clean.
 *
 *      WordPress core settings (blogname, timezone_string, etc.) have their
 *      own sanitize callbacks registered individually above — they don't
 *      go through this function.
 *
 * @param array $input The raw form values.
 * @return array Sanitized values safe for storage.
 */
function sp_sanitize_settings( array $input ): array {

    // ---- MERGE, don't replace ----
    // WHY: Each settings page now has its own form that only submits the
    //      fields on that page. If we rebuilt the entire array from scratch
    //      (the old approach), saving Organization would wipe out Design,
    //      Events, Directory, etc. — because those keys wouldn't be in
    //      $input at all and would get their defaults.
    //
    //      Instead we start from the existing saved values and only overwrite
    //      keys that are actually present in the submitted form data.
    $existing = get_option( 'societypress_settings', [] );

    // Master sanitization rules — each key maps to its sanitizer.
    // WHY a lookup table: Keeps every field's sanitization visible in one
    // place. When adding a new setting, add one line here and you're done.
    $sanitizers = [
        // Organization
        // Website
        'website_require_login'   => fn() => ! empty( $input['website_require_login'] ) ? 1 : 0,
        'website_show_admin_bar'  => fn() => ! empty( $input['website_show_admin_bar'] ) ? 1 : 0,
        'social_facebook'         => fn() => esc_url_raw( $input['social_facebook'] ?? '' ),
        'social_youtube'          => fn() => esc_url_raw( $input['social_youtube'] ?? '' ),
        'social_instagram'        => fn() => esc_url_raw( $input['social_instagram'] ?? '' ),
        'social_tiktok'           => fn() => esc_url_raw( $input['social_tiktok'] ?? '' ),
        'social_x'                => fn() => esc_url_raw( $input['social_x'] ?? '' ),

        // Organization
        'organization_name'       => fn() => sanitize_text_field( $input['organization_name'] ?? '' ),
        'organization_address'    => fn() => sanitize_textarea_field( $input['organization_address'] ?? '' ),
        'organization_phone'      => fn() => sanitize_text_field( $input['organization_phone'] ?? '' ),
        'organization_email'      => fn() => sanitize_email( $input['organization_email'] ?? '' ),
        'community_forum_url'     => fn() => esc_url_raw( $input['community_forum_url'] ?? '' ),
        'help_requests_notify_all'=> fn() => ! empty( $input['help_requests_notify_all'] ) ? 1 : 0,

        // Membership
        'membership_period_type'  => fn() => in_array( $input['membership_period_type'] ?? '', [ 'annual', 'rolling' ], true )
                                              ? $input['membership_period_type'] : 'annual',
        'membership_start_month'  => fn() => max( 1, min( 12, (int) ( $input['membership_start_month'] ?? 7 ) ) ),
        'late_join_months'        => fn() => max( 0, min( 11, (int) ( $input['late_join_months'] ?? 3 ) ) ),
        'grace_period_months'     => fn() => max( 0, min( 11, (int) ( $input['grace_period_months'] ?? 2 ) ) ),
        'renewal_reminder_30d'    => fn() => ! empty( $input['renewal_reminder_30d'] ) ? 1 : 0,
        'renewal_reminder_15d'    => fn() => ! empty( $input['renewal_reminder_15d'] ) ? 1 : 0,
        'renewal_reminder_7d'     => fn() => ! empty( $input['renewal_reminder_7d'] ) ? 1 : 0,
        'renewal_reminder_subject'=> fn() => sanitize_text_field( $input['renewal_reminder_subject'] ?? 'Your membership expires soon' ),

        // Directory — checkboxes: present = 1, absent = 0
        'dir_show_city_state'     => fn() => ! empty( $input['dir_show_city_state'] ) ? 1 : 0,
        'dir_show_phone'          => fn() => ! empty( $input['dir_show_phone'] ) ? 1 : 0,
        'dir_show_email'          => fn() => ! empty( $input['dir_show_email'] ) ? 1 : 0,
        'dir_show_website'        => fn() => ! empty( $input['dir_show_website'] ) ? 1 : 0,
        'dir_show_tier'           => fn() => ! empty( $input['dir_show_tier'] ) ? 1 : 0,
        'dir_show_join_date'      => fn() => ! empty( $input['dir_show_join_date'] ) ? 1 : 0,
        'dir_show_surnames'       => fn() => ! empty( $input['dir_show_surnames'] ) ? 1 : 0,
        'dir_per_page'            => fn() => in_array( (int) ( $input['dir_per_page'] ?? 25 ), [ 10, 25, 50, 100, 250, 500 ], true )
                                              ? (int) $input['dir_per_page'] : 25,

        // Events
        'events_default_visibility'   => fn() => in_array( $input['events_default_visibility'] ?? '', [ 'public', 'members_only' ], true )
                                                   ? $input['events_default_visibility'] : 'public',
        'events_default_registration' => fn() => ! empty( $input['events_default_registration'] ) ? 1 : 0,
        'events_guest_registration'   => fn() => ! empty( $input['events_guest_registration'] ) ? 1 : 0,
        'events_per_page'             => fn() => in_array( (int) ( $input['events_per_page'] ?? 12 ), [ 6, 12, 24, 48 ], true )
                                                   ? (int) $input['events_per_page'] : 12,
        'events_calendar_start_day'   => fn() => in_array( (int) ( $input['events_calendar_start_day'] ?? 0 ), [ 0, 1 ], true )
                                                   ? (int) $input['events_calendar_start_day'] : 0,
        'events_reminder_1_day'       => fn() => ! empty( $input['events_reminder_1_day'] ) ? 1 : 0,
        'events_reminder_3_days'      => fn() => ! empty( $input['events_reminder_3_days'] ) ? 1 : 0,
        'events_reminder_1_week'      => fn() => ! empty( $input['events_reminder_1_week'] ) ? 1 : 0,
        'events_confirmation_subject' => fn() => sanitize_text_field( $input['events_confirmation_subject'] ?? 'Registration Confirmed: {event_title}' ),
        'events_reminder_subject'     => fn() => sanitize_text_field( $input['events_reminder_subject'] ?? 'Reminder: {event_title} is coming up' ),

        // Stripe payment settings
        'stripe_test_mode'            => fn() => ! empty( $input['stripe_test_mode'] ) ? 1 : 0,
        'stripe_test_publishable_key' => fn() => sanitize_text_field( $input['stripe_test_publishable_key'] ?? '' ),
        'stripe_test_secret_key'      => fn() => sanitize_text_field( $input['stripe_test_secret_key'] ?? '' ),
        'stripe_live_publishable_key' => fn() => sanitize_text_field( $input['stripe_live_publishable_key'] ?? '' ),
        'stripe_live_secret_key'      => fn() => sanitize_text_field( $input['stripe_live_secret_key'] ?? '' ),
        'stripe_currency'             => fn() => in_array( $input['stripe_currency'] ?? '', [ 'usd', 'cad', 'gbp', 'eur', 'aud' ], true )
                                                   ? $input['stripe_currency'] : 'usd',

        // Design — site-wide appearance customization
        // WHY sanitize_hex_color with fallbacks: We must ensure valid hex colors
        // are stored. If someone tampers with the form and sends garbage, we
        // fall back to the original theme defaults so the site never breaks.
        'design_color_primary'        => fn() => sanitize_hex_color( $input['design_color_primary'] ?? '' ) ?: '#1e3a5f',
        'design_color_primary_hover'  => fn() => sanitize_hex_color( $input['design_color_primary_hover'] ?? '' ) ?: '#2c5282',
        'design_color_accent'         => fn() => sanitize_hex_color( $input['design_color_accent'] ?? '' ) ?: '#667eea',
        'design_color_header_bg'      => fn() => sanitize_hex_color( $input['design_color_header_bg'] ?? '' ) ?: '#1e3a5f',
        'design_color_header_text'    => fn() => sanitize_hex_color( $input['design_color_header_text'] ?? '' ) ?: '#ffffff',
        'design_color_footer_bg'      => fn() => sanitize_hex_color( $input['design_color_footer_bg'] ?? '' ) ?: '#1e3a5f',
        'design_color_footer_text'    => fn() => sanitize_hex_color( $input['design_color_footer_text'] ?? '' ) ?: '#ffffff',
        'design_font_body'            => fn() => in_array( $input['design_font_body'] ?? '', [ 'system', 'georgia', 'palatino', 'garamond', 'merriweather', 'lora', 'roboto', 'open-sans', 'source-sans', 'nunito' ], true )
                                                   ? $input['design_font_body'] : 'system',
        'design_font_heading'         => fn() => in_array( $input['design_font_heading'] ?? '', [ 'inherit', 'system', 'georgia', 'palatino', 'garamond', 'merriweather', 'lora', 'roboto', 'open-sans', 'source-sans', 'nunito' ], true )
                                                   ? $input['design_font_heading'] : 'inherit',
        'design_font_size'            => fn() => in_array( $input['design_font_size'] ?? '', [ 'compact', 'comfortable', 'large' ], true )
                                                   ? $input['design_font_size'] : 'comfortable',
        'design_heading_scale'        => fn() => in_array( $input['design_heading_scale'] ?? '', [ 'small', 'normal', 'large' ], true )
                                                   ? $input['design_heading_scale'] : 'normal',
        'design_content_width'        => fn() => in_array( $input['design_content_width'] ?? '', [ 'narrow', 'standard', 'wide', 'custom' ], true )
                                                   ? $input['design_content_width'] : 'standard',

        // Logo — stores the attachment ID from the Media Library.
        // WHY absint: Attachment IDs are always positive integers. Zero = no logo.
        'design_logo_id'              => fn() => absint( $input['design_logo_id'] ?? 0 ),

        // Header title/tagline toggle — 1 = show, 0 = hide.
        // WHY: Some societies have their name baked into their logo and don't
        //      want it repeated as text next to it. Default on (1) so existing
        //      sites aren't affected.
        'design_show_header_title'    => fn() => ! empty( $input['design_show_header_title'] ) ? 1 : 0,

        // Header height in pixels. 0 = auto (no explicit height set).
        // WHY: Some societies want to match a specific header size from a
        //      reference design. Clamped to 50–500px to prevent absurd values.
        'design_header_height'        => fn() => max( 0, min( 500, (int) ( $input['design_header_height'] ?? 0 ) ) ),

        // Content width in exact pixels. Replaces the old preset dropdown.
        // WHY: Harold may need to match a specific design width (e.g., 975px).
        //      Clamped to 600–2000px to prevent unusable layouts.
        'design_content_width_px'     => fn() => max( 600, min( 2000, (int) ( $input['design_content_width_px'] ?? 1100 ) ) ),
    ];

    // Only sanitize + update keys that were actually submitted in the form.
    // Keys not in $input are left untouched from the existing saved values.
    // WHY array_key_exists instead of isset: checkbox fields that are unchecked
    // won't be in $input at all — but we still need to handle them. We detect
    // which PAGE submitted based on which known keys appear in $input, then
    // process all keys that belong to that page (including missing checkboxes).
    //
    // Page detection: look for a "signature" key unique to each page's form.
    // This tells us which group of keys to process (and zero out unchecked
    // checkboxes for), while leaving every other page's data untouched.
    $page_keys = [];

    // Website page — signature: website_require_login hidden field is always present
    if ( array_key_exists( 'website_require_login', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'website_require_login', 'website_show_admin_bar',
            'social_facebook', 'social_youtube', 'social_instagram',
            'social_tiktok', 'social_x',
        ]);
    }

    // Organization page — signature: organization_name is always in the form
    if ( array_key_exists( 'organization_name', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'organization_name', 'organization_address', 'organization_phone',
            'organization_email', 'community_forum_url', 'help_requests_notify_all',
        ]);
    }

    // Membership page — signature: membership_period_type radio is always present
    if ( array_key_exists( 'membership_period_type', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'membership_period_type', 'membership_start_month', 'late_join_months',
            'grace_period_months', 'renewal_reminder_30d', 'renewal_reminder_15d',
            'renewal_reminder_7d', 'renewal_reminder_subject',
        ]);
    }

    // Directory page — signature: dir_per_page select is always present
    if ( array_key_exists( 'dir_per_page', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'dir_show_city_state', 'dir_show_phone', 'dir_show_email',
            'dir_show_website', 'dir_show_tier', 'dir_show_join_date',
            'dir_show_surnames', 'dir_per_page',
        ]);
    }

    // Events page — signature: events_default_visibility select is always present
    if ( array_key_exists( 'events_default_visibility', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'events_default_visibility', 'events_default_registration',
            'events_guest_registration', 'events_per_page',
            'events_calendar_start_day', 'events_reminder_1_day',
            'events_reminder_3_days', 'events_reminder_1_week',
            'events_confirmation_subject', 'events_reminder_subject',
            'stripe_test_mode', 'stripe_test_publishable_key',
            'stripe_test_secret_key', 'stripe_live_publishable_key',
            'stripe_live_secret_key', 'stripe_currency',
        ]);
    }

    // Design page — signature: design_font_body select is always present
    if ( array_key_exists( 'design_font_body', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'design_color_primary', 'design_color_primary_hover',
            'design_color_accent', 'design_color_header_bg',
            'design_color_header_text', 'design_color_footer_bg',
            'design_color_footer_text', 'design_font_body',
            'design_font_heading', 'design_font_size',
            'design_heading_scale', 'design_content_width',
            'design_logo_id', 'design_show_header_title',
            'design_header_height', 'design_content_width_px',
        ]);
    }

    // Apply sanitizers only for the keys that belong to the submitting page
    $result = $existing;
    foreach ( $page_keys as $key ) {
        if ( isset( $sanitizers[ $key ] ) ) {
            $result[ $key ] = $sanitizers[ $key ]();
        }
    }

    // Sync logo to WordPress's custom_logo theme mod.
    // WHY: The theme reads the logo via has_custom_logo() / the_custom_logo(),
    //      which uses get_theme_mod('custom_logo'). We store the attachment ID
    //      in our own settings array (design_logo_id) so it's part of the SP
    //      settings system, but we also write it to the theme mod so the theme
    //      picks it up without any changes to header.php.
    if ( in_array( 'design_logo_id', $page_keys, true ) ) {
        $logo_id = $result['design_logo_id'] ?? 0;
        if ( $logo_id ) {
            set_theme_mod( 'custom_logo', $logo_id );
        } else {
            remove_theme_mod( 'custom_logo' );
        }
    }

    return $result;
}


// ============================================================================
// INSTALLER WIZARD — First-run setup experience
// ============================================================================
//
// WHY: When a society admin installs SocietyPress for the first time, they
//      shouldn't have to hunt through settings tabs to get basic info entered.
//      The wizard walks them through organization details, membership config,
//      and key settings in a friendly step-by-step flow. Once completed, the
//      wizard never shows again (a flag is saved in options).
//
// FLOW:
//   1. Plugin activation sets default settings
//   2. First admin visit triggers redirect to wizard
//   3. Wizard collects: org info → membership → appearance → done
//   4. Wizard saves settings and marks itself complete
//   5. Admin is redirected to the SocietyPress dashboard

/**
 * Register the hidden wizard admin page.
 */
function sp_register_wizard_page(): void {
    add_submenu_page(
        null, // Hidden — no menu link
        'SocietyPress Setup',
        'Setup Wizard',
        'manage_options',
        'sp-setup-wizard',
        'sp_render_setup_wizard'
    );
}
add_action( 'admin_menu', 'sp_register_wizard_page', 1 );

/**
 * On first admin visit after activation, redirect to the setup wizard.
 *
 * WHY: We use a transient set during activation (sp_activation_redirect)
 *      to trigger a one-time redirect. The wizard only shows if it hasn't
 *      been completed yet (checked via sp_wizard_completed option).
 */
function sp_maybe_redirect_to_wizard(): void {
    // Only redirect if: transient exists, wizard not completed, user is admin
    if ( ! get_transient( 'sp_activation_redirect' ) ) {
        return;
    }
    delete_transient( 'sp_activation_redirect' );

    // Don't redirect if wizard already completed
    if ( get_option( 'sp_wizard_completed' ) ) {
        return;
    }

    // Don't redirect during bulk activation or AJAX
    if ( wp_doing_ajax() || isset( $_GET['activate-multi'] ) ) {
        return;
    }

    // Don't redirect if already on the wizard page
    if ( isset( $_GET['page'] ) && $_GET['page'] === 'sp-setup-wizard' ) {
        return;
    }

    wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard' ) );
    exit;
}
add_action( 'admin_init', 'sp_maybe_redirect_to_wizard' );

/**
 * Render the multi-step setup wizard.
 */
function sp_render_setup_wizard(): void {
    $settings = get_option( 'societypress_settings', [] );
    $step     = (int) ( $_GET['step'] ?? 1 );

    // Handle form submission
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_wizard_nonce'] ) ) {
        check_admin_referer( 'sp_setup_wizard', 'sp_wizard_nonce' );
        $step = (int) ( $_POST['wizard_step'] ?? 1 );

        switch ( $step ) {
            case 1: // Organization info
                $settings['organization_name']    = sanitize_text_field( $_POST['organization_name'] ?? '' );
                $settings['organization_email']   = sanitize_email( $_POST['organization_email'] ?? '' );
                $settings['organization_address'] = sanitize_textarea_field( $_POST['organization_address'] ?? '' );
                $settings['organization_phone']   = sanitize_text_field( $_POST['organization_phone'] ?? '' );
                update_option( 'societypress_settings', $settings );
                wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard&step=2' ) );
                exit;

            case 2: // Membership settings
                $settings['membership_period_type'] = sanitize_text_field( $_POST['membership_period_type'] ?? 'annual' );
                $settings['membership_start_month'] = (int) ( $_POST['membership_start_month'] ?? 7 );
                update_option( 'societypress_settings', $settings );
                wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard&step=3' ) );
                exit;

            case 3: // Appearance
                $settings['design_color_primary'] = sanitize_hex_color( $_POST['design_color_primary'] ?? '#1e3a5f' );
                $settings['design_color_accent']  = sanitize_hex_color( $_POST['design_color_accent'] ?? '#667eea' );
                $settings['email_from_name']      = sanitize_text_field( $_POST['email_from_name'] ?? '' );
                $settings['email_from_email']     = sanitize_email( $_POST['email_from_email'] ?? '' );
                update_option( 'societypress_settings', $settings );

                // Mark wizard as complete
                update_option( 'sp_wizard_completed', 1 );

                // Log it
                if ( function_exists( 'sp_audit' ) ) {
                    sp_audit( 'wizard_completed', 'Setup wizard completed.', 'settings' );
                }

                wp_safe_redirect( admin_url( 'admin.php?page=societypress&wizard=done' ) );
                exit;
        }
    }

    // Prevent the default admin UI from wrapping our wizard
    ?>
    <style>
        .sp-wizard-wrap { max-width: 640px; margin: 40px auto; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
        .sp-wizard-header { text-align: center; margin-bottom: 32px; }
        .sp-wizard-header h1 { font-size: 28px; margin: 0 0 8px; }
        .sp-wizard-header p { color: #646970; font-size: 15px; margin: 0; }
        .sp-wizard-steps { display: flex; justify-content: center; gap: 8px; margin-bottom: 32px; }
        .sp-wizard-step { width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; font-weight: 600; }
        .sp-wizard-step.active { background: #2271b1; color: #fff; }
        .sp-wizard-step.done { background: #00a32a; color: #fff; }
        .sp-wizard-step.pending { background: #dcdcde; color: #646970; }
        .sp-wizard-step-line { width: 40px; height: 2px; background: #dcdcde; align-self: center; }
        .sp-wizard-card { background: #fff; border: 1px solid #c3c4c7; border-radius: 8px; padding: 32px; }
        .sp-wizard-card h2 { margin: 0 0 8px; font-size: 20px; }
        .sp-wizard-card .desc { color: #646970; margin-bottom: 24px; }
        .sp-wizard-field { margin-bottom: 20px; }
        .sp-wizard-field label { display: block; font-weight: 600; margin-bottom: 4px; font-size: 14px; }
        .sp-wizard-field .hint { font-size: 12px; color: #646970; margin-top: 2px; }
        .sp-wizard-field input[type="text"],
        .sp-wizard-field input[type="email"],
        .sp-wizard-field input[type="tel"],
        .sp-wizard-field input[type="color"],
        .sp-wizard-field textarea,
        .sp-wizard-field select { width: 100%; padding: 8px 12px; border: 1px solid #8c8f94; border-radius: 4px; font-size: 14px; }
        .sp-wizard-field input[type="color"] { width: 60px; height: 36px; padding: 2px; cursor: pointer; }
        .sp-wizard-field textarea { resize: vertical; }
        .sp-wizard-actions { display: flex; justify-content: space-between; margin-top: 24px; }
        .sp-wizard-actions .button { padding: 8px 24px; font-size: 14px; }
