// ============================================================================
// MEMBER RELATIONSHIPS — Family/household connections
// ============================================================================

/**
 * Get all relationships for a member.
 *
 * @param int $user_id The member's user ID.
 * @return array Array of relationship objects with related_user_id, relationship, note,
 *               and the related user's display_name and email.
 */
function sp_get_member_relationships( int $user_id ): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_member_relationships';

    // Query both directions — user can be in either column
    return $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*,
                CASE WHEN r.user_id_a = %d THEN r.user_id_b ELSE r.user_id_a END AS related_user_id,
                CASE WHEN r.user_id_a = %d THEN ub.display_name ELSE ua.display_name END AS related_name,
                CASE WHEN r.user_id_a = %d THEN ub.user_email ELSE ua.user_email END AS related_email
         FROM {$table} r
         LEFT JOIN {$wpdb->users} ua ON r.user_id_a = ua.ID
         LEFT JOIN {$wpdb->users} ub ON r.user_id_b = ub.ID
         WHERE r.user_id_a = %d OR r.user_id_b = %d
         ORDER BY r.relationship ASC",
        $user_id, $user_id, $user_id, $user_id, $user_id
    ) );
}

/**
 * Add a relationship between two members.
 *
 * WHY: We always store the lower user_id as user_id_a to prevent
 *      duplicate entries (A→B and B→A would be the same relationship).
 *
 * @param int    $user_a       First member's user ID.
 * @param int    $user_b       Second member's user ID.
 * @param string $relationship Relationship type (spouse, parent, child, sibling, household).
 * @param string $note         Optional note.
 * @return int|false The relationship ID, or false on failure.
 */
function sp_add_member_relationship( int $user_a, int $user_b, string $relationship = 'spouse', string $note = '' ) {
    if ( $user_a === $user_b ) return false;

    global $wpdb;
    $table = $wpdb->prefix . 'sp_member_relationships';

    // Always store lower ID first for consistent uniqueness
    $a = min( $user_a, $user_b );
    $b = max( $user_a, $user_b );

    // Check if relationship already exists
    $exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE user_id_a = %d AND user_id_b = %d",
        $a, $b
    ) );
    if ( $exists ) return (int) $exists;

    $wpdb->insert( $table, [
        'user_id_a'    => $a,
        'user_id_b'    => $b,
        'relationship' => $relationship,
        'note'         => $note ?: null,
        'created_by'   => get_current_user_id() ?: null,
        'created_at'   => current_time( 'mysql' ),
    ] );

    return $wpdb->insert_id ? (int) $wpdb->insert_id : false;
}

/**
 * Remove a relationship by ID.
 */
function sp_remove_member_relationship( int $rel_id ): bool {
    global $wpdb;
    return (bool) $wpdb->delete(
        $wpdb->prefix . 'sp_member_relationships',
        [ 'id' => $rel_id ]
    );
}

/**
 * Get the spouse/partner of a member (if any).
 *
 * WHY: Quick lookup for the most common relationship type. Useful for
 *      displaying "Joint membership with [name]" on the member card.
 *
 * @param int $user_id The member's user ID.
 * @return object|null The related user object, or null if no spouse found.
 */
function sp_get_member_spouse( int $user_id ): ?object {
    $rels = sp_get_member_relationships( $user_id );
    foreach ( $rels as $r ) {
        if ( $r->relationship === 'spouse' ) {
            return $r;
        }
    }
    return null;
}

/**
 * AJAX handler: add a relationship from the member edit page.
 */
function sp_ajax_add_relationship(): void {
    check_ajax_referer( 'sp_relationship_nonce', 'nonce' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Permission denied.' ] );
    }

    $user_a = (int) ( $_POST['user_a'] ?? 0 );
    $user_b = (int) ( $_POST['user_b'] ?? 0 );
    $type   = sanitize_text_field( $_POST['relationship'] ?? 'spouse' );
    $note   = sanitize_text_field( $_POST['note'] ?? '' );

    if ( ! $user_a || ! $user_b ) {
        wp_send_json_error( [ 'message' => 'Both members are required.' ] );
    }
    if ( $user_a === $user_b ) {
        wp_send_json_error( [ 'message' => 'Cannot create a relationship with the same person.' ] );
    }

    $id = sp_add_member_relationship( $user_a, $user_b, $type, $note );
    if ( $id ) {
        wp_send_json_success( [ 'id' => $id, 'message' => 'Relationship added.' ] );
    } else {
        wp_send_json_error( [ 'message' => 'Failed to add relationship.' ] );
    }
}
add_action( 'wp_ajax_sp_add_relationship', 'sp_ajax_add_relationship' );

/**
 * AJAX handler: remove a relationship.
 */
function sp_ajax_remove_relationship(): void {
    check_ajax_referer( 'sp_relationship_nonce', 'nonce' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Permission denied.' ] );
    }

    $rel_id = (int) ( $_POST['rel_id'] ?? 0 );
    if ( sp_remove_member_relationship( $rel_id ) ) {
        wp_send_json_success( [ 'message' => 'Relationship removed.' ] );
    } else {
        wp_send_json_error( [ 'message' => 'Failed to remove relationship.' ] );
    }
}
add_action( 'wp_ajax_sp_remove_relationship', 'sp_ajax_remove_relationship' );

// ============================================================================
// AUDIT LOG — Activity tracking for admin actions
// ============================================================================

/**
 * Record an action in the audit log.
 *
 * WHY: This is the single entry point for all audit logging. Any part of
 *      the plugin that wants to record an action calls sp_audit(). The
 *      function is intentionally lightweight — it should never block or
 *      slow down the action it's logging.
 *
 * @param string      $action       Short action identifier (e.g., 'member_created', 'event_updated').
 * @param string|null $description  Human-readable description of what happened.
 * @param string|null $object_type  Type of object affected (e.g., 'member', 'event', 'settings').
 * @param int|null    $object_id    ID of the affected object (e.g., user_id, event_id).
 */
function sp_audit( string $action, ?string $description = null, ?string $object_type = null, ?int $object_id = null ): void {
    global $wpdb;

    $wpdb->insert( $wpdb->prefix . 'sp_audit_log', [
        'user_id'     => get_current_user_id() ?: null,
        'action'      => $action,
        'object_type' => $object_type,
        'object_id'   => $object_id,
        'description' => $description,
        'ip_address'  => $_SERVER['REMOTE_ADDR'] ?? null,
        'created_at'  => current_time( 'mysql' ),
    ] );
}

/**
 * Prune old audit log entries (older than 1 year).
 *
 * WHY: The audit log grows continuously. Entries older than a year are
 *      rarely useful and just take up space. We prune on a daily cron
 *      to keep the table lean.
 */
function sp_prune_audit_log(): void {
    global $wpdb;
    $wpdb->query(
        "DELETE FROM {$wpdb->prefix}sp_audit_log
         WHERE created_at < DATE_SUB(NOW(), INTERVAL 1 YEAR)"
    );
}
add_action( 'sp_daily_maintenance', 'sp_prune_audit_log' );

// Schedule the daily maintenance cron if not already scheduled
if ( ! wp_next_scheduled( 'sp_daily_maintenance' ) ) {
    wp_schedule_event( time(), 'daily', 'sp_daily_maintenance' );
}

