} );

// ============================================================================
// BREADCRUMBS NAVIGATION
// ============================================================================
//
// WHY: Breadcrumbs help visitors understand where they are in the site
//      hierarchy. For a society website with events, member pages, library,
//      etc., clear navigation context is essential. The theme calls
//      sp_breadcrumbs() to render them, or they auto-render if the
//      'breadcrumbs_enabled' setting is on.

/**
 * Generate and return breadcrumb HTML.
 *
 * WHY: We build breadcrumbs from the current page context rather than
 *      relying on URL structure. This handles WordPress pages (with
 *      parent hierarchy), posts (with categories), custom SP pages
 *      (events, member portal, etc.), and archive pages correctly.
 *
 * @param bool $echo Whether to echo (true) or return (false) the HTML.
 * @return string The breadcrumb HTML.
 */
function sp_breadcrumbs( bool $echo = true ): string {
    // Don't show breadcrumbs on the front page — it IS home
    if ( is_front_page() ) {
        return '';
    }

    $settings  = get_option( 'societypress_settings', [] );
    $home_label = $settings['breadcrumb_home_label'] ?? 'Home';
    $separator  = $settings['breadcrumb_separator'] ?? '&rsaquo;';

    $crumbs = [];

    // Always start with Home
    $crumbs[] = [
        'label' => $home_label,
        'url'   => home_url( '/' ),
    ];

    if ( is_page() ) {
        // For pages, walk up the parent hierarchy
        global $post;
        $ancestors = get_post_ancestors( $post );
        $ancestors = array_reverse( $ancestors );
        foreach ( $ancestors as $anc_id ) {
            $crumbs[] = [
                'label' => get_the_title( $anc_id ),
                'url'   => get_permalink( $anc_id ),
            ];
        }
        // Current page (no link)
        $crumbs[] = [
            'label' => get_the_title(),
            'url'   => '',
        ];

    } elseif ( is_single() ) {
        // For posts, show the primary category, then the post title
        $cats = get_the_category();
        if ( ! empty( $cats ) ) {
            $cat = $cats[0];
            // If category has a parent, show parent first
            if ( $cat->parent ) {
                $parent_cat = get_category( $cat->parent );
                if ( $parent_cat ) {
                    $crumbs[] = [
                        'label' => $parent_cat->name,
                        'url'   => get_category_link( $parent_cat->term_id ),
                    ];
                }
            }
            $crumbs[] = [
                'label' => $cat->name,
                'url'   => get_category_link( $cat->term_id ),
            ];
        }
        $crumbs[] = [
            'label' => get_the_title(),
            'url'   => '',
        ];

    } elseif ( is_category() ) {
        $cat = get_queried_object();
        if ( $cat->parent ) {
            $parent_cat = get_category( $cat->parent );
            if ( $parent_cat ) {
                $crumbs[] = [
                    'label' => $parent_cat->name,
                    'url'   => get_category_link( $parent_cat->term_id ),
                ];
            }
        }
        $crumbs[] = [
            'label' => $cat->name,
            'url'   => '',
        ];

    } elseif ( is_tag() ) {
        $crumbs[] = [
            'label' => 'Tag: ' . single_tag_title( '', false ),
            'url'   => '',
        ];

    } elseif ( is_search() ) {
        $crumbs[] = [
            'label' => 'Search Results',
            'url'   => '',
        ];

    } elseif ( is_404() ) {
        $crumbs[] = [
            'label' => 'Page Not Found',
            'url'   => '',
        ];

    } elseif ( is_archive() ) {
        $crumbs[] = [
            'label' => get_the_archive_title(),
            'url'   => '',
        ];

    } elseif ( is_home() ) {
        // Blog/news page
        $crumbs[] = [
            'label' => 'News',
            'url'   => '',
        ];
    }

    // Build HTML
    $html = '<nav class="sp-breadcrumbs" aria-label="Breadcrumb">';
    $html .= '<ol class="sp-breadcrumb-list">';

    $last = count( $crumbs ) - 1;
    foreach ( $crumbs as $i => $crumb ) {
        $html .= '<li class="sp-breadcrumb-item">';
        if ( $crumb['url'] && $i < $last ) {
            $html .= '<a href="' . esc_url( $crumb['url'] ) . '">' . esc_html( $crumb['label'] ) . '</a>';
        } else {
            $html .= '<span aria-current="page">' . esc_html( $crumb['label'] ) . '</span>';
        }
        if ( $i < $last ) {
            $html .= ' <span class="sp-breadcrumb-sep" aria-hidden="true">' . $separator . '</span> ';
        }
        $html .= '</li>';
    }

    $html .= '</ol>';
    $html .= '</nav>';

    // Inline styles — minimal, theme can override with CSS
    $html .= '<style>'
            . '.sp-breadcrumbs { padding: 8px 0; font-size: 13px; color: var(--sp-color-text-secondary, #646970); }'
            . '.sp-breadcrumb-list { list-style: none; margin: 0; padding: 0; display: flex; flex-wrap: wrap; gap: 0; }'
            . '.sp-breadcrumb-item { display: inline; }'
            . '.sp-breadcrumb-item a { color: var(--sp-color-primary, #2271b1); text-decoration: none; }'
            . '.sp-breadcrumb-item a:hover { text-decoration: underline; }'
            . '.sp-breadcrumb-sep { margin: 0 6px; color: var(--sp-color-text-secondary, #999); }'
            . '.sp-breadcrumb-item [aria-current] { color: var(--sp-color-text, #1d2327); }'
            . '</style>';

    if ( $echo ) {
        echo $html;
    }

    return $html;
}

/**
 * Auto-render breadcrumbs if the setting is enabled.
 *
 * WHY: Some themes don't call sp_breadcrumbs() themselves. This hook
 *      lets the admin enable auto-rendering without touching theme files.
 *      Uses the 'wp' action (after the query is set up) to inject
 *      breadcrumbs via the_content filter on pages and posts.
 */
function sp_maybe_auto_breadcrumbs(): void {
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['breadcrumbs_enabled'] ) ) {
        return;
    }
    // Prepend breadcrumbs to the_content on single pages and posts
    add_filter( 'the_content', function( $content ) {
        if ( ! is_main_query() || ! in_the_loop() || is_front_page() ) {
            return $content;
        }
        static $done = false;
        if ( $done ) return $content;
        $done = true;
        return sp_breadcrumbs( false ) . $content;
    }, 5 );
}
add_action( 'wp', 'sp_maybe_auto_breadcrumbs' );

// ============================================================================
// GROUPS — INTEREST GROUPS / SIGs (Admin + Frontend)
// ============================================================================

/**
 * Render the Groups admin list page.
 */
function sp_render_groups_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete' && isset( $_GET['group_id'] ) ) {
        check_admin_referer( 'sp_delete_group_' . $_GET['group_id'] );
        $gid = (int) $_GET['group_id'];
        $wpdb->delete( $prefix . 'group_members', [ 'group_id' => $gid ] );
        $wpdb->delete( $prefix . 'groups', [ 'id' => $gid ] );
        wp_redirect( admin_url( 'admin.php?page=sp-groups&deleted=1' ) );
        exit;
    }

    $groups = $wpdb->get_results(
        "SELECT g.*,
                u.display_name AS leader_name,
                (SELECT COUNT(*) FROM {$prefix}group_members gm WHERE gm.group_id = g.id) AS member_count
         FROM {$prefix}groups g
         LEFT JOIN {$wpdb->users} u ON g.leader_id = u.ID
         ORDER BY g.sort_order ASC, g.name ASC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline">Groups</h1>
        <a href="<?php echo admin_url( 'admin.php?page=sp-group-edit' ); ?>" class="page-title-action">Add New</a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p>Group deleted.</p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p>Group saved.</p></div>
        <?php endif; ?>

        <table class="widefat striped" style="margin-top: 16px;">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Members</th>
                    <th>Leader</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $groups ) ) : ?>
                    <tr><td colspan="5" style="text-align: center; padding: 20px;">No groups yet. <a href="<?php echo admin_url( 'admin.php?page=sp-group-edit' ); ?>">Create one</a>.</td></tr>
                <?php else : ?>
                    <?php foreach ( $groups as $g ) : ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo admin_url( 'admin.php?page=sp-group-edit&group_id=' . $g->id ); ?>"><?php echo esc_html( $g->name ); ?></a></strong>
                                <?php if ( $g->description ) : ?>
                                    <br><span style="color: #646970; font-size: 12px;"><?php echo esc_html( wp_trim_words( $g->description, 15 ) ); ?></span>
                                <?php endif; ?>
                            </td>
                            <td><?php echo (int) $g->member_count; ?></td>
                            <td><?php echo $g->leader_name ? esc_html( $g->leader_name ) : '&#8212;'; ?></td>
                            <td>
                                <?php if ( $g->status === 'active' ) : ?>
                                    <span style="color: #00a32a;">Active</span>
                                <?php else : ?>
                                    <span style="color: #787c82;">Inactive</span>
                                <?php endif; ?>
                            </td>
                            <td>
                                <a href="<?php echo admin_url( 'admin.php?page=sp-group-edit&group_id=' . $g->id ); ?>">Edit</a>
                                |
                                <a href="<?php echo wp_nonce_url( admin_url( 'admin.php?page=sp-groups&action=delete&group_id=' . $g->id ), 'sp_delete_group_' . $g->id ); ?>"
                                   onclick="return confirm('Delete this group and remove all members from it?');"
                                   style="color: #b32d2e;">Delete</a>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Render the Group edit/add page.
 */
function sp_render_group_edit_page(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_GET['group_id'] ?? 0 );
    $group    = null;
    $members  = [];

    if ( $group_id ) {
        $group = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}groups WHERE id = %d", $group_id
        ) );
        if ( ! $group ) {
            echo '<div class="wrap"><h1>Group Not Found</h1><p><a href="' . admin_url( 'admin.php?page=sp-groups' ) . '">&larr; Back</a></p></div>';
            return;
        }
        $members = $wpdb->get_results( $wpdb->prepare(
            "SELECT gm.*, u.display_name, u.user_email
             FROM {$prefix}group_members gm
             JOIN {$wpdb->users} u ON gm.user_id = u.ID
             WHERE gm.group_id = %d
             ORDER BY u.display_name ASC",
            $group_id
        ) );
    }

    // Handle save
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_group_nonce'] ) ) {
        check_admin_referer( 'sp_save_group', 'sp_group_nonce' );

        $name = sanitize_text_field( $_POST['name'] ?? '' );
        if ( ! $name ) {
            echo '<div class="notice notice-error"><p>Group name is required.</p></div>';
        } else {
            $slug = sanitize_title( $name );
            $data = [
                'name'         => $name,
                'slug'         => $slug,
                'description'  => sanitize_textarea_field( $_POST['description'] ?? '' ) ?: null,
                'leader_id'    => (int) ( $_POST['leader_id'] ?? 0 ) ?: null,
                'meeting_info' => sanitize_text_field( $_POST['meeting_info'] ?? '' ) ?: null,
                'status'       => sanitize_text_field( $_POST['status'] ?? 'active' ),
                'sort_order'   => (int) ( $_POST['sort_order'] ?? 0 ),
            ];

            if ( $group_id ) {
                $wpdb->update( $prefix . 'groups', $data, [ 'id' => $group_id ] );
            } else {
                $wpdb->insert( $prefix . 'groups', $data );
                $group_id = (int) $wpdb->insert_id;
            }

            // Handle member removal
            if ( ! empty( $_POST['remove_members'] ) && is_array( $_POST['remove_members'] ) ) {
                foreach ( $_POST['remove_members'] as $uid ) {
                    $wpdb->delete( $prefix . 'group_members', [
                        'group_id' => $group_id,
                        'user_id'  => (int) $uid,
                    ] );
                }
            }

            // Handle adding a member
            $add_user = (int) ( $_POST['add_member_id'] ?? 0 );
            if ( $add_user ) {
                $exists = $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}group_members WHERE group_id = %d AND user_id = %d",
                    $group_id, $add_user
                ) );
                if ( ! $exists ) {
                    $wpdb->insert( $prefix . 'group_members', [
                        'group_id'  => $group_id,
                        'user_id'   => $add_user,
                        'joined_at' => current_time( 'mysql' ),
                    ] );
                }
            }

            wp_redirect( admin_url( 'admin.php?page=sp-groups&saved=1' ) );
            exit;
        }
    }

    // All SP members for dropdowns
    $all_members = $wpdb->get_results(
        "SELECT m.user_id, u.display_name, u.user_email
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON m.user_id = u.ID
         ORDER BY u.display_name ASC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php echo $group_id ? 'Edit Group' : 'Add New Group'; ?></h1>
        <p><a href="<?php echo admin_url( 'admin.php?page=sp-groups' ); ?>">&larr; Back to Groups</a></p>

        <form method="post" style="max-width: 600px;">
            <?php wp_nonce_field( 'sp_save_group', 'sp_group_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-g-name">Group Name <span style="color: #d63638;">*</span></label></th>
                    <td><input type="text" name="name" id="sp-g-name" value="<?php echo esc_attr( $group->name ?? '' ); ?>" required style="width: 100%;"></td>
                </tr>
                <tr>
                    <th><label for="sp-g-desc">Description</label></th>
                    <td><textarea name="description" id="sp-g-desc" rows="4" style="width: 100%;"><?php echo esc_textarea( $group->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="sp-g-leader">Group Leader</label></th>
                    <td>
                        <select name="leader_id" id="sp-g-leader" style="width: 100%;">
                            <option value="">&#8212; None &#8212;</option>
                            <?php foreach ( $all_members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>" <?php selected( (int) ( $group->leader_id ?? 0 ), (int) $m->user_id ); ?>>
                                    <?php echo esc_html( $m->display_name ); ?> (<?php echo esc_html( $m->user_email ); ?>)
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-g-meeting">Meeting Info</label></th>
                    <td><input type="text" name="meeting_info" id="sp-g-meeting" value="<?php echo esc_attr( $group->meeting_info ?? '' ); ?>" style="width: 100%;" placeholder="e.g., 2nd Tuesday at 2 PM"></td>
                </tr>
                <tr>
                    <th><label for="sp-g-status">Status</label></th>
                    <td>
                        <select name="status" id="sp-g-status">
                            <option value="active" <?php selected( $group->status ?? 'active', 'active' ); ?>>Active</option>
                            <option value="inactive" <?php selected( $group->status ?? '', 'inactive' ); ?>>Inactive</option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-g-order">Sort Order</label></th>
                    <td><input type="number" name="sort_order" id="sp-g-order" value="<?php echo (int) ( $group->sort_order ?? 0 ); ?>" style="width: 80px;"></td>
                </tr>
            </table>

            <?php if ( $group_id && ! empty( $members ) ) : ?>
                <h2>Current Members (<?php echo count( $members ); ?>)</h2>
                <table class="widefat striped" style="max-width: 600px;">
                    <thead><tr><th>Name</th><th>Email</th><th>Joined</th><th>Remove</th></tr></thead>
                    <tbody>
                        <?php foreach ( $members as $gm ) : ?>
                            <tr>
                                <td><?php echo esc_html( $gm->display_name ); ?></td>
                                <td><?php echo esc_html( $gm->user_email ); ?></td>
                                <td><?php echo esc_html( date( 'M j, Y', strtotime( $gm->joined_at ) ) ); ?></td>
                                <td><label><input type="checkbox" name="remove_members[]" value="<?php echo esc_attr( $gm->user_id ); ?>"> Remove</label></td>
                            </tr>
                        <?php endforeach; ?>
                    </tbody>
                </table>
            <?php endif; ?>

            <?php if ( $group_id ) : ?>
                <h2>Add Member</h2>
                <select name="add_member_id" style="width: 300px;">
                    <option value="">&#8212; Select Member &#8212;</option>
                    <?php
                    $current_ids = array_map( function( $m ) { return (int) $m->user_id; }, $members );
                    foreach ( $all_members as $m ) :
                        if ( in_array( (int) $m->user_id, $current_ids, true ) ) continue;
                    ?>
                        <option value="<?php echo esc_attr( $m->user_id ); ?>">
                            <?php echo esc_html( $m->display_name ); ?> (<?php echo esc_html( $m->user_email ); ?>)
                        </option>
                    <?php endforeach; ?>
                </select>
            <?php endif; ?>

            <p class="submit">
                <button type="submit" class="button button-primary"><?php echo $group_id ? 'Save Changes' : 'Create Group'; ?></button>
                <a href="<?php echo admin_url( 'admin.php?page=sp-groups' ); ?>" class="button">Cancel</a>
            </p>
        </form>
    </div>
    <?php
}

/**
 * AJAX handler: member joins a group from the frontend.
 */
function sp_ajax_join_group(): void {
    check_ajax_referer( 'sp_groups_nonce', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => 'You must be logged in.' ] );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_POST['group_id'] ?? 0 );
    $user_id  = get_current_user_id();

    if ( ! $group_id ) {
        wp_send_json_error( [ 'message' => 'Invalid group.' ] );
    }

    $group = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}groups WHERE id = %d AND status = 'active'", $group_id
    ) );
    if ( ! $group ) {
        wp_send_json_error( [ 'message' => 'Group not found or inactive.' ] );
    }

    $exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}group_members WHERE group_id = %d AND user_id = %d",
        $group_id, $user_id
    ) );
    if ( $exists ) {
        wp_send_json_error( [ 'message' => 'You are already in this group.' ] );
    }

    $wpdb->insert( $prefix . 'group_members', [
        'group_id'  => $group_id,
        'user_id'   => $user_id,
        'joined_at' => current_time( 'mysql' ),
    ] );

    wp_send_json_success( [ 'message' => 'You have joined ' . $group->name . '!' ] );
}
add_action( 'wp_ajax_sp_join_group', 'sp_ajax_join_group' );

/**
 * AJAX handler: member leaves a group from the frontend.
 */
function sp_ajax_leave_group(): void {
    check_ajax_referer( 'sp_groups_nonce', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => 'You must be logged in.' ] );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_POST['group_id'] ?? 0 );
    $user_id  = get_current_user_id();

    $wpdb->delete( $prefix . 'group_members', [
        'group_id' => $group_id,
        'user_id'  => $user_id,
    ] );

    wp_send_json_success( [ 'message' => 'You have left the group.' ] );
}
add_action( 'wp_ajax_sp_leave_group', 'sp_ajax_leave_group' );

// =========================================================================
// PAGES MANAGEMENT
// =========================================================================
//
// WHY: WordPress's native Pages screen (edit.php?post_type=page) drops
//      Harold into the WP admin he's not supposed to see. This section
//      builds an SP-native Pages interface that wraps wp_posts (type=page)
//      with our own list table, add/edit form, and save/delete handlers.
//
//      No new database tables — we query and write to WP's pages table
//      directly using wp_insert_post(), wp_update_post(), wp_delete_post(),
//      and get_page_template_slug().
// =========================================================================

/**
 * SP_Pages_List_Table
 *
 * Extends WP_List_Table to display WordPress pages in the SP admin UI.
 * Same pattern as SP_Members_List_Table and other SP list tables.
 */
class SP_Pages_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'page',
            'plural'   => 'pages',
            'ajax'     => false,
        ] );
    }

    /**
     * Define the columns Harold sees in the pages list.
     *
     * WHY each column:
     *   Title     — primary identifier, links to edit
     *   Page Type — which SP template is assigned (Events, Directory, etc.)
     *   Status    — Published or Draft so Harold knows what's live
     *   Date      — when the page was created/modified
     */
    public function get_columns(): array {
        return [
            'cb'        => '<input type="checkbox" />',
            'title'     => 'Title',
            'page_type' => 'Page Type',
            'status'    => 'Status',
            'date'      => 'Date',
        ];
    }

    /**
     * Which columns can be clicked to sort the list.
     */
    public function get_sortable_columns(): array {
        return [
            'title' => [ 'post_title', true ],   // Default sort: title A→Z
            'date'  => [ 'post_date', false ],
        ];
    }

    /**
     * Bulk actions dropdown — appears above the table.
     */
    protected function get_bulk_actions(): array {
        return [
            'delete' => 'Delete',
        ];
    }

    /**
     * Checkbox column for bulk actions.
     */
    protected function column_cb( $item ): string {
        return sprintf(
            '<input type="checkbox" name="page_id[]" value="%d" />',
            $item->ID
        );
    }

    /**
     * Title column — the primary column with row actions.
     *
     * Links to the SP page editor, not the WP editor.
     */
    protected function column_title( $item ): string {
        $title = ! empty( $item->post_title ) ? $item->post_title : '(no title)';
        $name  = '<strong>' . esc_html( $title ) . '</strong>';

        $edit_url = admin_url( 'admin.php?page=sp-page-edit&post_id=' . $item->ID );

        $actions = [
            'edit' => sprintf( '<a href="%s">Edit</a>', esc_url( $edit_url ) ),
            'quick_edit' => sprintf(
                '<a href="#" class="sp-quick-edit-trigger" data-id="%d" data-title="%s" data-status="%s" data-template="%s">Quick Edit</a>',
                $item->ID,
                esc_attr( $item->post_title ),
                esc_attr( $item->post_status ),
                esc_attr( get_page_template_slug( $item->ID ) )
            ),
        ];

        // View link — only for published pages
        if ( $item->post_status === 'publish' ) {
            $actions['view'] = sprintf(
                '<a href="%s" target="_blank">View</a>',
                esc_url( get_permalink( $item->ID ) )
            );
        }

        // Delete link with confirmation
        $delete_url = wp_nonce_url(
            admin_url( 'admin.php?page=sp-pages&action=delete&post_id=' . $item->ID ),
            'sp_delete_page_' . $item->ID
        );
        $actions['delete'] = sprintf(
            '<a href="%s" onclick="return confirm(\'Are you sure you want to delete this page?\');">Delete</a>',
            esc_url( $delete_url )
        );

        return $name . $this->row_actions( $actions );
    }

    /**
     * Page Type column — shows the friendly template label.
     *
     * WHY: Harold doesn't know what "sp-events" means. He sees "Events".
     *      If no template is set, it's just a "Standard Page" — a plain
     *      content page Harold typed up.
     */
    protected function column_page_type( $item ): string {
        $template = get_page_template_slug( $item->ID );
        $labels   = sp_get_page_type_labels();

        if ( ! empty( $template ) && isset( $labels[ $template ] ) ) {
            return '<span style="color: #0073aa; font-weight: 500;">'
                 . esc_html( $labels[ $template ] )
                 . '</span>';
        }

        return 'Standard Page';
    }

    /**
     * Status column — color-coded so Harold can see at a glance.
     */
    protected function column_status( $item ): string {
        if ( $item->post_status === 'publish' ) {
            return '<span style="color: #00a32a; font-weight: 600;">Published</span>';
        }
        return '<span style="color: #787c82; font-weight: 600;">Draft</span>';
    }

    /**
     * Date column — when the page was last modified.
     */
    protected function column_date( $item ): string {
        return esc_html( date_i18n(
            get_option( 'date_format', 'F j, Y' ),
            strtotime( $item->post_modified )
        ) );
    }

    /**
     * Fetch page data from wp_posts.
     *
     * Handles searching, sorting, and pagination.
     */
    public function prepare_items(): void {
        // WHY: Most societies have a small number of pages (under 50). Showing
        //      all on one screen is often more useful than paginating. The
        //      ?show_all=1 parameter toggles between paginated and full list.
        $show_all = ! empty( $_GET['show_all'] );
        $per_page = $show_all ? 999 : 100;

        // Build query args
        $args = [
            'post_type'      => 'page',
            'post_status'    => [ 'publish', 'draft' ],
            'posts_per_page' => $per_page,
            'paged'          => $show_all ? 1 : $this->get_pagenum(),
        ];

        // Search by title
        $search = $_GET['s'] ?? '';
        if ( ! empty( $search ) ) {
            $args['s'] = sanitize_text_field( $search );
        }

        // Sorting — default to menu_order so pages appear in the same
        // order Harold arranged them in Appearance → Menus / Pages.
        // WHY menu_order: WordPress stores a numeric order on each page.
        // When Harold drags pages around in the WP page list or sets parent
        // pages, menu_order reflects that hierarchy. Showing pages in this
        // order matches what he sees on the actual site nav.
        $orderby = $_GET['orderby'] ?? 'menu_order';
        $order   = $_GET['order'] ?? 'ASC';

        $allowed_orderby = [ 'post_title', 'post_date', 'menu_order' ];
        if ( in_array( $orderby, $allowed_orderby, true ) ) {
            $args['orderby'] = $orderby;
            $args['order']   = strtoupper( $order ) === 'DESC' ? 'DESC' : 'ASC';
        } else {
            $args['orderby'] = 'menu_order';
            $args['order']   = 'ASC';
        }

        $query = new WP_Query( $args );

        $this->items = $query->posts;

        $this->set_pagination_args( [
            'total_items' => $query->found_posts,
            'per_page'    => $per_page,
            'total_pages' => $query->max_num_pages,
        ] );

        $this->_column_headers = [
            $this->get_columns(),
            [],  // hidden columns
            $this->get_sortable_columns(),
        ];
    }

    /**
     * Message shown when no pages exist yet.
     */
    public function no_items(): void {
        echo 'No pages found. <a href="'
           . esc_url( admin_url( 'admin.php?page=sp-page-edit' ) )
           . '">Create your first page</a>.';
    }
}


/**
 * Returns the map of SP template slugs → friendly labels.
 *
 * WHY: This is the single source of truth for page type labels used in
 *      the list table, the add/edit dropdown, and anywhere else we need
 *      to translate a template slug into something Harold understands.
 *      Add new SP page templates here as they're built.
 */
function sp_get_page_type_labels(): array {
    return [
        'sp-events'          => 'Events',
        'sp-directory'       => 'Membership Directory',
        'sp-library-catalog' => 'Library Catalog',
        'sp-groups'          => 'Interest Groups',
        'sp-help-requests'   => 'Research Help Requests',
        'sp-resources'       => 'Resource Links Directory',
        'sp-builder'         => 'Page Builder',
        'sp-newsletter-archive' => 'Newsletter Archive',
        'sp-search'          => 'Site Search',
        'sp-calendar'        => 'Calendar',
    ];
}


/**
 * Render the Pages list page.
 *
 * Shows the SP-native pages list with search, bulk actions, and pagination.
 * Pattern matches sp_render_members_page().
 */
function sp_render_pages_page(): void {

    // Handle single delete action (row action — has post_id as scalar, not array)
    if ( ( $_GET['action'] ?? '' ) === 'delete'
         && isset( $_GET['post_id'] ) && ! is_array( $_GET['post_id'] ) ) {
        $post_id = (int) $_GET['post_id'];
        check_admin_referer( 'sp_delete_page_' . $post_id );
        wp_delete_post( $post_id, true ); // true = bypass trash, permanent delete
        wp_redirect( admin_url( 'admin.php?page=sp-pages&deleted=1' ) );
        exit;
    }

    // Handle bulk delete action
    // WHY: WP_List_Table submits bulk actions via action (top dropdown) or
    //      action2 (bottom dropdown). We check both so either works.
    if ( ( ( $_GET['action'] ?? '' ) === 'delete' || ( $_GET['action2'] ?? '' ) === 'delete' )
         && ! empty( $_GET['page_id'] ) && is_array( $_GET['page_id'] ) ) {
        check_admin_referer( 'bulk-pages' );
        $count = 0;
        foreach ( $_GET['page_id'] as $pid ) {
            wp_delete_post( (int) $pid, true );
            $count++;
        }
        wp_redirect( admin_url( 'admin.php?page=sp-pages&deleted=' . $count ) );
        exit;
    }

    $table = new SP_Pages_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Pages</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-page-edit' ) ); ?>" class="page-title-action">
            Add New
        </a>
        <hr class="wp-header-end">

        <?php
        // Success notices
        if ( isset( $_GET['deleted'] ) ) {
            $count = (int) $_GET['deleted'];
            if ( $count > 0 ) {
                printf(
                    '<div class="notice notice-success is-dismissible"><p>%s deleted.</p></div>',
                    $count === 1 ? '1 page' : $count . ' pages'
                );
            }
        }
        if ( isset( $_GET['saved'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>Page saved.</p></div>';
        }
        ?>

        <?php
        // Show All / Show Paginated toggle
        $showing_all = ! empty( $_GET['show_all'] );
        if ( $showing_all ) {
            echo '<p><a href="' . esc_url( admin_url( 'admin.php?page=sp-pages' ) ) . '">Show paginated</a></p>';
        } else {
            echo '<p><a href="' . esc_url( admin_url( 'admin.php?page=sp-pages&show_all=1' ) ) . '">Show all pages</a></p>';
        }
        ?>

        <form method="get">
            <input type="hidden" name="page" value="sp-pages">
            <?php if ( $showing_all ) : ?>
                <input type="hidden" name="show_all" value="1">
            <?php endif; ?>
            <?php
            $table->search_box( 'Search Pages', 'sp-page-search' );
            $table->display();
            ?>
        </form>

        <!-- Quick Edit inline form — hidden by default, JS clones it into the row -->
        <div id="sp-quick-edit-template" style="display:none;">
            <div class="sp-quick-edit-form" style="background:#f6f7f7; padding:12px 16px; border:1px solid #c3c4c7; margin:4px 0;">
                <div style="display:flex; gap:16px; align-items:flex-end; flex-wrap:wrap;">
                    <label style="flex:1; min-width:200px;">
                        <span style="display:block; font-weight:600; margin-bottom:4px;">Title</span>
                        <input type="text" class="sp-qe-title" style="width:100%;">
                    </label>
                    <label>
                        <span style="display:block; font-weight:600; margin-bottom:4px;">Page Type</span>
                        <select class="sp-qe-template">
                            <option value="">Standard Page</option>
                            <?php foreach ( sp_get_page_type_labels() as $slug => $label ) : ?>
                                <option value="<?php echo esc_attr( $slug ); ?>"><?php echo esc_html( $label ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </label>
                    <label>
                        <span style="display:block; font-weight:600; margin-bottom:4px;">Status</span>
                        <select class="sp-qe-status">
                            <option value="publish">Published</option>
                            <option value="draft">Draft</option>
                        </select>
                    </label>
                    <div style="display:flex; gap:8px;">
                        <button type="button" class="button button-primary sp-qe-save">Update</button>
                        <button type="button" class="button sp-qe-cancel">Cancel</button>
                    </div>
                </div>
                <input type="hidden" class="sp-qe-id">
            </div>
        </div>

        <script>
        /**
         * SP Pages Quick Edit
         *
         * WHY: Lets Harold change title, page type, and status without leaving
         * the list or loading the full edit form. Clicking "Quick Edit" opens
         * an inline form right below the row. Save fires an AJAX request so
         * the page doesn't reload.
         */
        (function() {
            var template = document.getElementById('sp-quick-edit-template');
            if (!template) return;

            var activeRow = null;
            var activeForm = null;

            document.addEventListener('click', function(e) {
                var trigger = e.target.closest('.sp-quick-edit-trigger');
                if (!trigger) return;
                e.preventDefault();

                // Close any existing quick edit form
                if (activeForm) {
                    activeForm.remove();
                    activeForm = null;
                }

                var row = trigger.closest('tr');
                activeRow = row;

                // Clone the template form
                var form = template.firstElementChild.cloneNode(true);
                form.style.display = '';

                // Populate fields from data attributes
                form.querySelector('.sp-qe-id').value = trigger.dataset.id;
                form.querySelector('.sp-qe-title').value = trigger.dataset.title;
                form.querySelector('.sp-qe-status').value = trigger.dataset.status;
                form.querySelector('.sp-qe-template').value = trigger.dataset.template || '';

                // Insert form after the row — create a full-width row to hold it
                var formRow = document.createElement('tr');
                formRow.className = 'sp-quick-edit-row';
                var formCell = document.createElement('td');
                formCell.colSpan = row.cells.length;
                formCell.appendChild(form);
                formRow.appendChild(formCell);
                row.parentNode.insertBefore(formRow, row.nextSibling);
                activeForm = formRow;

                // Focus the title field
                form.querySelector('.sp-qe-title').focus();

                // Cancel button
                form.querySelector('.sp-qe-cancel').addEventListener('click', function() {
                    formRow.remove();
                    activeForm = null;
                });

                // Save button — AJAX POST
                form.querySelector('.sp-qe-save').addEventListener('click', function() {
                    var btn = this;
                    btn.disabled = true;
                    btn.textContent = 'Saving...';

                    var data = new FormData();
                    data.append('action', 'sp_quick_edit_page');
                    data.append('post_id', form.querySelector('.sp-qe-id').value);
                    data.append('title', form.querySelector('.sp-qe-title').value);
                    data.append('status', form.querySelector('.sp-qe-status').value);
                    data.append('template', form.querySelector('.sp-qe-template').value);
                    data.append('_ajax_nonce', '<?php echo wp_create_nonce( "sp_quick_edit_page" ); ?>');

                    fetch(ajaxurl, { method: 'POST', body: data })
                        .then(function(r) { return r.json(); })
                        .then(function(resp) {
                            if (resp.success) {
                                // Update the row in place
                                location.reload();
                            } else {
                                alert(resp.data || 'Error saving.');
                                btn.disabled = false;
                                btn.textContent = 'Update';
                            }
                        })
                        .catch(function() {
                            alert('Network error.');
                            btn.disabled = false;
                            btn.textContent = 'Update';
                        });
                });
            });
        })();
        </script>
    </div>
    <?php
}


/**
 * AJAX handler for Quick Edit on the SP Pages list.
 *
 * WHY: Saves title, status, and page type changes without a full page reload.
 *      Validates nonce, sanitizes input, updates the post and template meta.
 */
function sp_handle_quick_edit_page(): void {
    check_ajax_referer( 'sp_quick_edit_page' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Permission denied.' );
    }

    $post_id  = (int) ( $_POST['post_id'] ?? 0 );
    $title    = sanitize_text_field( $_POST['title'] ?? '' );
    $status   = in_array( $_POST['status'] ?? '', [ 'publish', 'draft' ], true )
                ? $_POST['status'] : 'draft';
    $template = sanitize_text_field( $_POST['template'] ?? '' );

    if ( ! $post_id || ! get_post( $post_id ) ) {
        wp_send_json_error( 'Page not found.' );
    }

    if ( empty( $title ) ) {
        wp_send_json_error( 'Title cannot be empty.' );
    }

    // Validate template slug
    $valid_templates = array_keys( sp_get_page_type_labels() );
    if ( ! empty( $template ) && ! in_array( $template, $valid_templates, true ) ) {
        $template = '';
    }

    wp_update_post( [
        'ID'          => $post_id,
        'post_title'  => $title,
        'post_status' => $status,
    ] );

    // Set or clear the page template
    if ( ! empty( $template ) ) {
        update_post_meta( $post_id, '_wp_page_template', $template );
    } else {
        delete_post_meta( $post_id, '_wp_page_template' );
    }

    wp_send_json_success();
}
add_action( 'wp_ajax_sp_quick_edit_page', 'sp_handle_quick_edit_page' );


/**
 * Render the Page add/edit form.
 *
 * WHY: This gives Harold a clean, SP-native form to create and edit pages
 *      without ever seeing the WordPress editor. The Page Type dropdown
 *      assigns an SP template (Events, Directory, etc.) so the right
 *      frontend rendering kicks in automatically.
 */
function sp_render_page_edit(): void {

    // Handle save on POST
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_page_nonce'] ) ) {
        sp_handle_page_save();
        return; // sp_handle_page_save() redirects, but just in case
    }

    // Load existing page data if editing
    $post_id  = (int) ( $_GET['post_id'] ?? 0 );
    $post     = $post_id ? get_post( $post_id ) : null;
    $is_edit  = (bool) $post;

    $title    = $is_edit ? $post->post_title : '';
    $content  = $is_edit ? $post->post_content : '';
    $status   = $is_edit ? $post->post_status : 'publish';
    $template = $is_edit ? get_page_template_slug( $post_id ) : '';

    $page_types = sp_get_page_type_labels();

    // WHY: wp_enqueue_media() and wp_enqueue_editor() must be called so the
    // Page Builder's Image widget, Hero Slider "Choose Image" buttons, and
    // Rich Text widget all work. Calling them here (in the page callback)
    // is safe because WordPress prints footer scripts AFTER the callback
    // runs. The admin_enqueue_scripts hook should also load these, but
    // calling them directly guarantees they're available regardless of
    // hook-suffix matching quirks on hidden submenu pages.
    wp_enqueue_media();
    wp_enqueue_editor();

    ?>
    <div class="wrap">
        <h1><?php echo $is_edit ? 'Edit Page' : 'Add New Page'; ?></h1>

        <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-page-edit' ) ); ?>">
            <?php wp_nonce_field( 'sp_save_page', 'sp_page_nonce' ); ?>
            <?php if ( $is_edit ) : ?>
                <input type="hidden" name="post_id" value="<?php echo esc_attr( $post_id ); ?>">
            <?php endif; ?>

            <table class="form-table" role="presentation">

                <!-- Title -->
                <tr>
                    <th scope="row"><label for="page_title">Title</label></th>
                    <td>
                        <input type="text"
                               id="page_title"
                               name="page_title"
                               value="<?php echo esc_attr( $title ); ?>"
                               class="regular-text"
                               style="width: 100%; max-width: 600px;"
                               required>
                    </td>
                </tr>

                <!-- Page Type -->
                <tr>
                    <th scope="row"><label for="page_type">Page Type</label></th>
                    <td>
                        <select id="page_type" name="page_type" style="min-width: 250px;">
                            <option value="" <?php selected( $template, '' ); ?>>Standard Page</option>
                            <?php foreach ( $page_types as $slug => $label ) : ?>
                                <option value="<?php echo esc_attr( $slug ); ?>"
                                    <?php selected( $template, $slug ); ?>>
                                    <?php echo esc_html( $label ); ?>
                                </option>
                            <?php endforeach; ?>
                        </select>
                        <p class="description">
                            Standard Pages use the content editor below.
                            Other page types display their own specialized content.
                        </p>
                    </td>
                </tr>

                <!-- Page Builder widgets — shown only when Page Type is "Page Builder" -->
                <?php
                // WHY: The builder UI needs to live inside the custom page editor form
                // so Harold can add/configure widgets without ever seeing WordPress'
                // native post.php screen. Hidden by default; JS below toggles visibility
                // based on the Page Type dropdown value.
                $builder_display = ( 'sp-builder' === $template ) ? '' : 'display:none;';
                ?>
                <tr id="sp-builder-row" style="<?php echo $builder_display; ?>">
                    <th scope="row">Page Builder</th>
                    <td>
                        <?php
                        // WHY: The builder nonce is separate from the page nonce because
                        // save_post_page (native WP) and sp_handle_page_save (custom editor)
                        // both need to verify it independently.
                        wp_nonce_field( 'sp_page_builder_save', 'sp_page_builder_nonce' );

                        if ( $is_edit && $post ) {
                            // Existing page — render the full builder UI with saved widgets
                            sp_render_builder_ui( $post );
                        } else {
                            // New page — can't render widgets until the page exists.
                            // Harold picks the type, creates the page, then edits it
                            // to add widgets. This avoids orphaned widget data.
                            echo '<p class="description">Save this page first, then edit it to add widgets.</p>';
                        }
                        ?>
                    </td>
                </tr>

                <!-- Content Editor -->
                <tr>
                    <th scope="row"><label for="page_content">Content</label></th>
                    <td>
                        <?php
                        // WHY: wp_editor() gives Harold a WYSIWYG editor for page
                        // content. For Standard Pages this is the main content. For
                        // template pages (Events, Directory, etc.) this content appears
                        // above the template output — useful for intro text.
                        wp_editor(
                            $content,
                            'page_content',
                            [
                                'textarea_name' => 'page_content',
                                'textarea_rows' => 15,
                                'media_buttons' => true,
                                'teeny'         => false,
                                'quicktags'     => true,
                            ]
                        );
                        ?>
                    </td>
                </tr>

                <!-- Status -->
                <tr>
                    <th scope="row"><label for="page_status">Status</label></th>
                    <td>
                        <select id="page_status" name="page_status">
                            <option value="publish" <?php selected( $status, 'publish' ); ?>>Published</option>
                            <option value="draft" <?php selected( $status, 'draft' ); ?>>Draft</option>
                        </select>
                    </td>
                </tr>

            </table>

            <p class="submit">
                <input type="submit"
                       name="sp_save_page"
                       class="button button-primary"
                       value="<?php echo $is_edit ? 'Update Page' : 'Create Page'; ?>">

                <?php if ( $is_edit ) : ?>
                    <?php
                    $delete_url = wp_nonce_url(
                        admin_url( 'admin.php?page=sp-pages&action=delete&post_id=' . $post_id ),
                        'sp_delete_page_' . $post_id
                    );
                    ?>
                    <a href="<?php echo esc_url( $delete_url ); ?>"
                       class="button"
                       style="color: #b32d2e; border-color: #b32d2e; margin-left: 8px;"
                       onclick="return confirm('Are you sure you want to delete this page?');">
                        Delete Page
                    </a>
                <?php endif; ?>

                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-pages' ) ); ?>"
                   class="button"
                   style="margin-left: 8px;">
                    Cancel
                </a>
            </p>
        </form>
    </div>

    <?php
    // WHY: Toggle the builder row visibility when Harold changes the Page Type
    // dropdown. If it's "sp-builder", show the builder; otherwise hide it.
    // This runs on both page load (in case we're editing an existing builder
    // page) and on change events.
    ?>
    <script>
    (function() {
        var sel = document.getElementById('page_type');
        var row = document.getElementById('sp-builder-row');
        if (!sel || !row) return;

        function toggleBuilder() {
            row.style.display = (sel.value === 'sp-builder') ? '' : 'none';
        }

        sel.addEventListener('change', toggleBuilder);
        // Initial state is already set via PHP $builder_display, but run once
        // in case browser auto-fills a cached form value on back-navigation.
        toggleBuilder();
    })();
    </script>
    <?php
}


/**
 * Handle saving a page (both create and update).
 *
 * WHY: Validates the nonce, sanitizes input, uses wp_insert_post() for new
 *      pages and wp_update_post() for existing ones. Sets the SP template
 *      via _wp_page_template post meta — the same mechanism WordPress uses
 *      natively, so template_include filters work seamlessly.
 */
function sp_handle_page_save(): void {
    // Verify nonce
    if ( ! wp_verify_nonce( $_POST['sp_page_nonce'] ?? '', 'sp_save_page' ) ) {
        wp_die( 'Security check failed.' );
    }

    // Only admins can manage pages
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'You do not have permission to manage pages.' );
    }

    $post_id  = (int) ( $_POST['post_id'] ?? 0 );
    $title    = sanitize_text_field( $_POST['page_title'] ?? '' );
    $content  = wp_kses_post( $_POST['page_content'] ?? '' );
    $status   = in_array( $_POST['page_status'] ?? '', [ 'publish', 'draft' ], true )
                ? $_POST['page_status']
                : 'draft';
    $template = sanitize_text_field( $_POST['page_type'] ?? '' );

    // Validate template slug — must be empty (Standard Page) or a known SP template
    $valid_templates = array_keys( sp_get_page_type_labels() );
    if ( ! empty( $template ) && ! in_array( $template, $valid_templates, true ) ) {
        $template = '';
    }

    if ( empty( $title ) ) {
        // Redirect back with error — page title is required
        $redirect = admin_url( 'admin.php?page=sp-page-edit' );
        if ( $post_id ) {
            $redirect .= '&post_id=' . $post_id;
        }
        $redirect .= '&sp_error=no_title';
        wp_redirect( $redirect );
        exit;
    }

    $post_data = [
        'post_title'   => $title,
        'post_content' => $content,
        'post_status'  => $status,
        'post_type'    => 'page',
    ];

    if ( $post_id ) {
        // Update existing page
        $post_data['ID'] = $post_id;
        $result = wp_update_post( $post_data, true );
    } else {
        // Create new page
        // WHY: post_author is the current user so the page is "owned" by the
        //      admin who created it, even though Harold doesn't see WP's
        //      author system.
        $post_data['post_author'] = get_current_user_id();
        $result = wp_insert_post( $post_data, true );
    }

    if ( is_wp_error( $result ) ) {
        wp_die( 'Error saving page: ' . $result->get_error_message() );
    }

    $saved_id = $post_id ?: $result;

    // Set or clear the page template
    // WHY: WordPress stores the page template as _wp_page_template post meta.
    //      An empty string or 'default' means "use the theme's page.php".
    //      Our SP template slugs (sp-events, sp-directory, etc.) are picked up
    //      by the theme_page_templates + template_include filters registered
    //      elsewhere in this plugin.
    if ( ! empty( $template ) ) {
        update_post_meta( $saved_id, '_wp_page_template', $template );
    } else {
        delete_post_meta( $saved_id, '_wp_page_template' );
    }

    // --- Save Page Builder widgets (if applicable) ---
    // WHY: When the page type is "Page Builder" and the builder nonce is present,
    // save the widget data to post meta. This mirrors the save_post_page hook
    // used by the native WP meta box, but works within our custom editor flow.
    // If the page type is NOT "Page Builder", clean up any orphaned widget data
    // so switching away from builder doesn't leave stale widgets behind.
    if ( 'sp-builder' === $template
         && isset( $_POST['sp_page_builder_nonce'] )
         && wp_verify_nonce( $_POST['sp_page_builder_nonce'], 'sp_page_builder_save' )
    ) {
        $registry    = sp_get_widget_registry();
        $raw_widgets = $_POST['sp_widgets'] ?? [];
        $clean       = [];

        foreach ( $raw_widgets as $w ) {
            $type = sanitize_key( $w['type'] ?? '' );
            if ( ! isset( $registry[ $type ] ) ) continue;

            $s       = $w['settings'] ?? [];
            $clean[] = [
                'type'     => $type,
                'settings' => sp_sanitize_builder_widget( $type, $s ),
            ];
        }

        update_post_meta( $saved_id, '_sp_page_widgets', $clean );
    } elseif ( 'sp-builder' !== $template ) {
        // Not a builder page — remove widget meta if it exists
        delete_post_meta( $saved_id, '_sp_page_widgets' );
    }

    wp_redirect( admin_url( 'admin.php?page=sp-pages&saved=1' ) );
    exit;
}


/**
 * Register "Interest Groups" as a page template.
 */
function sp_register_groups_template( $templates ) {
    $templates['sp-groups'] = 'Interest Groups';
    return $templates;
}
add_filter( 'theme_page_templates', 'sp_register_groups_template' );

function sp_load_groups_template( $template ) {
    if ( is_page() ) {
        $page_template = get_page_template_slug();
        if ( $page_template === 'sp-groups' ) {
            add_filter( 'the_content', 'sp_render_groups_frontend', 20 );
        }
    }
    return $template;
}
add_filter( 'template_include', 'sp_load_groups_template' );

/**
 * Render the groups frontend content (card grid with join/leave buttons).
 */
function sp_render_groups_frontend( $content ): string {
    if ( ! is_main_query() || ! in_the_loop() ) {
        return $content;
    }
    remove_filter( 'the_content', 'sp_render_groups_frontend', 20 );

    if ( ! is_user_logged_in() ) {
        return '<p>Please log in to view and join interest groups.</p>';
    }

    global $wpdb;
    $prefix  = $wpdb->prefix . 'sp_';
    $user_id = get_current_user_id();

    $groups = $wpdb->get_results(
        "SELECT g.*,
                u.display_name AS leader_name,
                (SELECT COUNT(*) FROM {$prefix}group_members gm WHERE gm.group_id = g.id) AS member_count
         FROM {$prefix}groups g
         LEFT JOIN {$wpdb->users} u ON g.leader_id = u.ID
         WHERE g.status = 'active'
         ORDER BY g.sort_order ASC, g.name ASC"
    );

    $my_groups = $wpdb->get_col( $wpdb->prepare(
        "SELECT group_id FROM {$prefix}group_members WHERE user_id = %d", $user_id
    ) );
    $my_groups = array_map( 'intval', $my_groups );

    $nonce = wp_create_nonce( 'sp_groups_nonce' );

    ob_start();
    ?>
    <style>
        .sp-groups-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 20px; margin: 20px 0; }
        .sp-group-card { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 20px; }
        .sp-group-card.sp-in-group { border-color: #00a32a; border-width: 2px; }
        .sp-group-card h3 { margin: 0 0 8px; font-size: 18px; }
        .sp-group-card .sp-group-meta { font-size: 13px; color: #646970; margin-bottom: 12px; }
        .sp-group-card .sp-group-desc { margin-bottom: 16px; }
        .sp-group-card .sp-group-badge { display: inline-block; background: #00a32a; color: #fff; font-size: 11px; padding: 2px 8px; border-radius: 10px; margin-left: 8px; }
        .sp-group-btn { display: inline-block; padding: 8px 16px; border: none; border-radius: 4px; cursor: pointer; font-size: 14px; }
        .sp-group-btn.join { background: #2271b1; color: #fff; }
        .sp-group-btn.join:hover { background: #135e96; }
        .sp-group-btn.leave { background: #dcdcde; color: #50575e; }
        .sp-group-btn.leave:hover { background: #c3c4c7; }
    </style>

    <?php if ( empty( $groups ) ) : ?>
        <p>No interest groups are available yet.</p>
    <?php else : ?>
        <div class="sp-groups-grid">
            <?php foreach ( $groups as $g ) :
                $is_member = in_array( (int) $g->id, $my_groups, true );
            ?>
                <div class="sp-group-card <?php echo $is_member ? 'sp-in-group' : ''; ?>" data-group-id="<?php echo esc_attr( $g->id ); ?>">
                    <h3>
                        <?php echo esc_html( $g->name ); ?>
                        <?php if ( $is_member ) : ?>
                            <span class="sp-group-badge">Joined</span>
                        <?php endif; ?>
                    </h3>
                    <div class="sp-group-meta">
                        <?php if ( $g->leader_name ) : ?>
                            <span>Leader: <?php echo esc_html( $g->leader_name ); ?></span> &middot;
                        <?php endif; ?>
                        <span><?php echo (int) $g->member_count; ?> member(s)</span>
                        <?php if ( $g->meeting_info ) : ?>
                            &middot; <span><?php echo esc_html( $g->meeting_info ); ?></span>
                        <?php endif; ?>
                    </div>
                    <?php if ( $g->description ) : ?>
                        <div class="sp-group-desc"><?php echo esc_html( $g->description ); ?></div>
                    <?php endif; ?>
                    <?php if ( $is_member ) : ?>
                        <button type="button" class="sp-group-btn leave" data-action="leave" data-group-id="<?php echo esc_attr( $g->id ); ?>">Leave Group</button>
                    <?php else : ?>
                        <button type="button" class="sp-group-btn join" data-action="join" data-group-id="<?php echo esc_attr( $g->id ); ?>">Join Group</button>
                    <?php endif; ?>
                </div>
            <?php endforeach; ?>
        </div>
    <?php endif; ?>

    <script>
    (function() {
        var ajaxUrl = '<?php echo esc_url( admin_url( "admin-ajax.php" ) ); ?>';
        var nonce   = '<?php echo esc_js( $nonce ); ?>';

        document.querySelectorAll('.sp-group-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var action  = this.getAttribute('data-action');
                var groupId = this.getAttribute('data-group-id');
                var self    = this;

                self.disabled = true;
                self.textContent = action === 'join' ? 'Joining...' : 'Leaving...';

                var fd = new FormData();
                fd.append('action', action === 'join' ? 'sp_join_group' : 'sp_leave_group');
                fd.append('group_id', groupId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            alert(data.data.message || 'Something went wrong.');
                            self.disabled = false;
                            self.textContent = action === 'join' ? 'Join Group' : 'Leave Group';
                        }
                    })
                    .catch(function() {
                        alert('Network error. Please try again.');
                        self.disabled = false;
                        self.textContent = action === 'join' ? 'Join Group' : 'Leave Group';
                    });
            });
        });
    })();
    </script>
    <?php

    return ob_get_clean();
}

