/**
 * Render the main Finances page — shows all payment transactions across
 * all members, with summary stats, filtering, and search.
 *
 * WHY: The treasurer needs a single view of all financial activity. Previously,
 *      payments were only visible per-member in the member edit form. This page
 *      aggregates everything and adds filtering by type, method, and date range.
 */
function sp_render_finances_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete action
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete' && isset( $_GET['payment_id'] ) ) {
        check_admin_referer( 'sp_delete_payment_' . $_GET['payment_id'] );
        $wpdb->delete( $prefix . 'member_payments', [ 'id' => (int) $_GET['payment_id'] ] );
        wp_redirect( admin_url( 'admin.php?page=sp-finances&deleted=1' ) );
        exit;
    }

    // Filters
    $filter_type   = sanitize_text_field( $_GET['type'] ?? '' );
    $filter_method = sanitize_text_field( $_GET['method'] ?? '' );
    $filter_from   = sanitize_text_field( $_GET['from'] ?? '' );
    $filter_to     = sanitize_text_field( $_GET['to'] ?? '' );
    $search        = sanitize_text_field( $_GET['s'] ?? '' );
    $per_page      = 50;
    $paged         = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
    $offset        = ( $paged - 1 ) * $per_page;

    // Build WHERE clause
    $where = [ '1=1' ];
    $args  = [];

    if ( $filter_type ) {
        $where[] = 'p.type = %s';
        $args[]  = $filter_type;
    }
    if ( $filter_method ) {
        $where[] = 'p.method = %s';
        $args[]  = $filter_method;
    }
    if ( $filter_from ) {
        $where[] = 'p.date >= %s';
        $args[]  = $filter_from;
    }
    if ( $filter_to ) {
        $where[] = 'p.date <= %s';
        $args[]  = $filter_to;
    }
    if ( $search ) {
        $like    = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = '(u.display_name LIKE %s OR p.note LIKE %s)';
        $args[]  = $like;
        $args[]  = $like;
    }

    $where_sql = implode( ' AND ', $where );

    // Summary stats (for the filtered set)
    $stats_sql = "SELECT
        COUNT(*) AS total_count,
        COALESCE(SUM(p.amount), 0) AS total_amount,
        COALESCE(SUM(CASE WHEN p.type = 'dues' THEN p.amount ELSE 0 END), 0) AS dues_total,
        COALESCE(SUM(CASE WHEN p.type = 'donation' THEN p.amount ELSE 0 END), 0) AS donation_total
        FROM {$prefix}member_payments p
        LEFT JOIN {$wpdb->users} u ON p.user_id = u.ID
        WHERE {$where_sql}";

    if ( $args ) {
        $stats = $wpdb->get_row( $wpdb->prepare( $stats_sql, ...$args ) );
    } else {
        $stats = $wpdb->get_row( $stats_sql );
    }

    // Paginated results
    $order_by  = sanitize_sql_orderby( $_GET['orderby'] ?? 'p.date' ) ?: 'p.date';
    $order_dir = ( strtoupper( $_GET['order'] ?? 'DESC' ) === 'ASC' ) ? 'ASC' : 'DESC';

    $rows_sql = "SELECT p.*, u.display_name AS member_name, u.user_email AS member_email,
                        r.display_name AS recorded_by_name
                 FROM {$prefix}member_payments p
                 LEFT JOIN {$wpdb->users} u ON p.user_id = u.ID
                 LEFT JOIN {$wpdb->users} r ON p.recorded_by = r.ID
                 WHERE {$where_sql}
                 ORDER BY {$order_by} {$order_dir}
                 LIMIT %d OFFSET %d";

    $query_args = array_merge( $args, [ $per_page, $offset ] );
    $rows = $wpdb->get_results( $wpdb->prepare( $rows_sql, ...$query_args ) );

    $total_rows = (int) ( $stats->total_count ?? 0 );
    $total_pages = ceil( $total_rows / $per_page );

    // Get distinct types and methods for filter dropdowns
    $types   = $wpdb->get_col( "SELECT DISTINCT type FROM {$prefix}member_payments ORDER BY type" );
    $methods = $wpdb->get_col( "SELECT DISTINCT method FROM {$prefix}member_payments WHERE method IS NOT NULL AND method != '' ORDER BY method" );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline">Finances</h1>
        <a href="<?php echo admin_url( 'admin.php?page=sp-record-payment' ); ?>" class="page-title-action">Record Payment</a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p>Payment deleted.</p></div>
        <?php endif; ?>

        <style>
            .sp-finance-stats { display: flex; gap: 16px; margin: 16px 0; flex-wrap: wrap; }
            .sp-finance-stat { background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; padding: 12px 20px; min-width: 140px; }
            .sp-finance-stat .stat-label { font-size: 12px; color: #646970; text-transform: uppercase; letter-spacing: 0.5px; }
            .sp-finance-stat .stat-value { font-size: 24px; font-weight: 600; margin-top: 4px; }
            .sp-finance-stat .stat-value.money { color: #00a32a; }
            .sp-finance-filters { background: #fff; border: 1px solid #c3c4c7; padding: 12px; margin-bottom: 12px; display: flex; gap: 8px; align-items: end; flex-wrap: wrap; }
            .sp-finance-filters label { font-size: 12px; display: block; margin-bottom: 2px; color: #646970; }
            .sp-finance-filters select,
            .sp-finance-filters input { padding: 4px 8px; }
        </style>

        <!-- Summary Stats -->
        <div class="sp-finance-stats">
            <div class="sp-finance-stat">
                <div class="stat-label">Transactions</div>
                <div class="stat-value"><?php echo number_format( $total_rows ); ?></div>
            </div>
            <div class="sp-finance-stat">
                <div class="stat-label">Total Amount</div>
                <div class="stat-value money">$<?php echo number_format( (float) $stats->total_amount, 2 ); ?></div>
            </div>
            <div class="sp-finance-stat">
                <div class="stat-label">Dues</div>
                <div class="stat-value money">$<?php echo number_format( (float) $stats->dues_total, 2 ); ?></div>
            </div>
            <div class="sp-finance-stat">
                <div class="stat-label">Donations</div>
                <div class="stat-value money">$<?php echo number_format( (float) $stats->donation_total, 2 ); ?></div>
            </div>
        </div>

        <!-- Filters -->
        <form method="get" class="sp-finance-filters">
            <input type="hidden" name="page" value="sp-finances">
            <div>
                <label for="sp-f-type">Type</label>
                <select name="type" id="sp-f-type">
                    <option value="">All Types</option>
                    <?php foreach ( $types as $t ) : ?>
                        <option value="<?php echo esc_attr( $t ); ?>" <?php selected( $filter_type, $t ); ?>><?php echo esc_html( ucfirst( $t ) ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label for="sp-f-method">Method</label>
                <select name="method" id="sp-f-method">
                    <option value="">All Methods</option>
                    <?php foreach ( $methods as $m ) : ?>
                        <option value="<?php echo esc_attr( $m ); ?>" <?php selected( $filter_method, $m ); ?>><?php echo esc_html( ucfirst( $m ) ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label for="sp-f-from">From</label>
                <input type="date" name="from" id="sp-f-from" value="<?php echo esc_attr( $filter_from ); ?>">
            </div>
            <div>
                <label for="sp-f-to">To</label>
                <input type="date" name="to" id="sp-f-to" value="<?php echo esc_attr( $filter_to ); ?>">
            </div>
            <div>
                <label for="sp-f-search">Search</label>
                <input type="search" name="s" id="sp-f-search" value="<?php echo esc_attr( $search ); ?>" placeholder="Name or note...">
            </div>
            <div>
                <button type="submit" class="button">Filter</button>
                <?php if ( $filter_type || $filter_method || $filter_from || $filter_to || $search ) : ?>
                    <a href="<?php echo admin_url( 'admin.php?page=sp-finances' ); ?>" class="button">Clear</a>
                <?php endif; ?>
            </div>
        </form>

        <!-- Transactions Table -->
        <table class="widefat striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Member</th>
                    <th>Amount</th>
                    <th>Type</th>
                    <th>Method</th>
                    <th>Note</th>
                    <th>Recorded By</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $rows ) ) : ?>
                    <tr><td colspan="8" style="text-align: center; padding: 20px;">No transactions found.</td></tr>
                <?php else : ?>
                    <?php foreach ( $rows as $row ) : ?>
                        <tr>
                            <td><?php echo esc_html( $row->date ); ?></td>
                            <td>
                                <?php if ( $row->member_name ) : ?>
                                    <a href="<?php echo admin_url( 'admin.php?page=sp-member-edit&user_id=' . $row->user_id ); ?>">
                                        <?php echo esc_html( $row->member_name ); ?>
                                    </a>
                                <?php else : ?>
                                    <span style="color: #787c82;">Unknown (ID <?php echo esc_html( $row->user_id ); ?>)</span>
                                <?php endif; ?>
                            </td>
                            <td style="font-weight: 600; color: #00a32a;">$<?php echo esc_html( number_format( (float) $row->amount, 2 ) ); ?></td>
                            <td><?php echo esc_html( ucfirst( $row->type ) ); ?></td>
                            <td><?php echo $row->method ? esc_html( ucfirst( $row->method ) ) : '<span style="color:#787c82;">—</span>'; ?></td>
                            <td><?php echo $row->note ? esc_html( wp_trim_words( $row->note, 10 ) ) : ''; ?></td>
                            <td><?php echo $row->recorded_by_name ? esc_html( $row->recorded_by_name ) : ''; ?></td>
                            <td>
                                <a href="<?php echo wp_nonce_url( admin_url( 'admin.php?page=sp-finances&action=delete&payment_id=' . $row->id ), 'sp_delete_payment_' . $row->id ); ?>"
                                   onclick="return confirm('Delete this payment record?');"
                                   style="color: #b32d2e;">Delete</a>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <?php if ( $total_pages > 1 ) : ?>
            <div class="tablenav bottom">
                <div class="tablenav-pages">
                    <span class="displaying-num"><?php echo number_format( $total_rows ); ?> item(s)</span>
                    <?php
                    echo paginate_links( [
                        'base'    => add_query_arg( 'paged', '%#%' ),
                        'format'  => '',
                        'current' => $paged,
                        'total'   => $total_pages,
                        'prev_text' => '&laquo;',
                        'next_text' => '&raquo;',
                    ] );
                    ?>
                </div>
            </div>
        <?php endif; ?>
    </div>
    <?php
}

/**
 * Render the Record Payment page — a standalone form to add a payment
 * for any member.
 *
 * WHY: The member edit page lets you add payments for one member at a time,
 *      but sometimes the treasurer has a stack of checks to enter and wants
 *      to do them quickly without navigating to each member's edit page.
 *      This page lets them pick a member and record payment in one step.
 */
function sp_render_record_payment_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle form submission
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_record_payment_nonce'] ) ) {
        check_admin_referer( 'sp_record_payment', 'sp_record_payment_nonce' );

        $user_id = (int) ( $_POST['user_id'] ?? 0 );
        $amount  = floatval( $_POST['amount'] ?? 0 );

        if ( ! $user_id || $amount <= 0 ) {
            echo '<div class="notice notice-error"><p>Please select a member and enter a valid amount.</p></div>';
        } else {
            $wpdb->insert( $prefix . 'member_payments', [
                'user_id'     => $user_id,
                'amount'      => $amount,
                'type'        => sanitize_text_field( $_POST['type'] ?? 'dues' ),
                'method'      => sanitize_text_field( $_POST['method'] ?? '' ) ?: null,
                'date'        => sanitize_text_field( $_POST['date'] ?? '' ) ?: current_time( 'Y-m-d' ),
                'note'        => sanitize_text_field( $_POST['note'] ?? '' ) ?: null,
                'recorded_by' => get_current_user_id(),
                'created_at'  => current_time( 'mysql' ),
            ] );

            wp_redirect( admin_url( 'admin.php?page=sp-finances&recorded=1' ) );
            exit;
        }
    }

    // Get all members for the dropdown
    $members = $wpdb->get_results(
        "SELECT m.user_id, u.display_name, u.user_email
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON m.user_id = u.ID
         ORDER BY u.display_name ASC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1>Record Payment</h1>
        <p><a href="<?php echo admin_url( 'admin.php?page=sp-finances' ); ?>">&larr; Back to Finances</a></p>

        <form method="post" style="max-width: 500px;">
            <?php wp_nonce_field( 'sp_record_payment', 'sp_record_payment_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-pay-member">Member <span style="color: #d63638;">*</span></label></th>
                    <td>
                        <select name="user_id" id="sp-pay-member" required style="width: 100%;">
                            <option value="">— Select Member —</option>
                            <?php foreach ( $members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>">
                                    <?php echo esc_html( $m->display_name ); ?> (<?php echo esc_html( $m->user_email ); ?>)
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-pay-amount">Amount <span style="color: #d63638;">*</span></label></th>
                    <td><input type="number" name="amount" id="sp-pay-amount" step="0.01" min="0.01" required style="width: 120px;"> USD</td>
                </tr>
                <tr>
                    <th><label for="sp-pay-type">Type</label></th>
                    <td>
                        <select name="type" id="sp-pay-type">
                            <option value="dues">Dues</option>
                            <option value="donation">Donation</option>
                            <option value="event">Event Fee</option>
                            <option value="other">Other</option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-pay-method">Method</label></th>
                    <td>
                        <select name="method" id="sp-pay-method">
                            <option value="">— None —</option>
                            <option value="check">Check</option>
                            <option value="cash">Cash</option>
                            <option value="card">Credit/Debit Card</option>
                            <option value="stripe">Stripe</option>
                            <option value="paypal">PayPal</option>
                            <option value="transfer">Bank Transfer</option>
                            <option value="other">Other</option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-pay-date">Date</label></th>
                    <td><input type="date" name="date" id="sp-pay-date" value="<?php echo esc_attr( current_time( 'Y-m-d' ) ); ?>"></td>
                </tr>
                <tr>
                    <th><label for="sp-pay-note">Note</label></th>
                    <td><textarea name="note" id="sp-pay-note" rows="3" style="width: 100%;"></textarea></td>
                </tr>
            </table>

            <p class="submit">
                <button type="submit" class="button button-primary">Record Payment</button>
                <a href="<?php echo admin_url( 'admin.php?page=sp-finances' ); ?>" class="button">Cancel</a>
            </p>
        </form>
    </div>
    <?php
}

