    <!-- ================================================================== -->
    <!-- DESIGN PAGE — COLOR PICKER INIT + LIVE PREVIEW ENGINE              -->
    <!-- ================================================================== -->
    <!-- WHY all of this is inline instead of a separate .js file:           -->
    <!-- Single-file plugin architecture. This script only loads on the      -->
    <!-- Design page (it's inside sp_render_settings_design_page), so        -->
    <!-- there's zero overhead on other admin pages or the frontend.         -->
    <script>
    (function() {
        // ---- Logo uploader ----
        // WHY deferred to window load: wp_enqueue_media() outputs its scripts
        // in the footer (wp_footer hook), which runs AFTER our inline <script>
        // in the page body. If we check for wp.media right now, it doesn't
        // exist yet and the handler silently never attaches. Deferring to
        // window 'load' guarantees all footer scripts have executed.
        window.addEventListener('load', function() {
            var logoBtn    = document.getElementById('sp-logo-upload-btn');
            var logoRemove = document.getElementById('sp-logo-remove-btn');
            var logoInput  = document.getElementById('sp-design-logo-id');
            var logoPreview = document.getElementById('sp-logo-preview');

            if (logoBtn && typeof wp !== 'undefined' && wp.media) {
                var logoFrame;

                logoBtn.addEventListener('click', function(e) {
                    e.preventDefault();

                    if (logoFrame) {
                        logoFrame.open();
                        return;
                    }

                    logoFrame = wp.media({
                        title:    'Select Logo',
                        button:   { text: 'Use as Logo' },
                        multiple: false
                    });

                    logoFrame.on('select', function() {
                        var attachment = logoFrame.state().get('selection').first().toJSON();
                        logoInput.value = attachment.id;
                        // Use medium size if available, otherwise full URL (SVGs only have full)
                        var url = (attachment.sizes && attachment.sizes.medium)
                                ? attachment.sizes.medium.url
                                : attachment.url;
                        logoPreview.innerHTML = '<img src="' + url + '" style="max-height: 80px; width: auto; background: #f0f0f0; padding: 8px; border-radius: 4px;">';
                        logoBtn.textContent = 'Change Logo';
                        if (logoRemove) logoRemove.style.display = '';
                    });

                    logoFrame.open();
                });

                if (logoRemove) {
                    logoRemove.addEventListener('click', function(e) {
                        e.preventDefault();
                        logoInput.value = '0';
                        logoPreview.innerHTML = '';
                        logoBtn.textContent = 'Upload Logo';
                        logoRemove.style.display = 'none';
                    });
                }
            }
        });

        // ---- Initialize WordPress color pickers ----
        // WHY: WordPress ships wp-color-picker (based on Iris) but we need
        // to initialize it ourselves. The 'change' and 'clear' callbacks
        // trigger preview updates whenever a color changes.
        if (typeof jQuery !== 'undefined' && jQuery.fn.wpColorPicker) {
            jQuery('.sp-color-picker').wpColorPicker({
                change: function() {
                    // Small delay because wpColorPicker fires 'change' before
                    // updating the input value. 50ms is enough for it to sync.
                    setTimeout(updatePreview, 50);
                },
                clear: function() {
                    setTimeout(updatePreview, 50);
                }
            });
        }

        // ---- Font family mapping (mirrors the PHP mapping in functions.php) ----
        // WHY duplicated here: The preview runs client-side and needs to know
        // what CSS font stack each key maps to. Keeping it in sync with the
        // PHP version is critical — if you add a font, add it in both places.
        var fontMap = {
            'system':       "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif",
            'georgia':      "Georgia, 'Times New Roman', serif",
            'palatino':     "'Palatino Linotype', 'Book Antiqua', Palatino, serif",
            'garamond':     "'EB Garamond', Georgia, serif",
            'merriweather': "Merriweather, Georgia, serif",
            'lora':         "Lora, Georgia, serif",
            'roboto':       "Roboto, -apple-system, BlinkMacSystemFont, sans-serif",
            'open-sans':    "'Open Sans', -apple-system, BlinkMacSystemFont, sans-serif",
            'source-sans':  "'Source Sans 3', -apple-system, BlinkMacSystemFont, sans-serif",
            'nunito':       "Nunito, -apple-system, BlinkMacSystemFont, sans-serif"
        };

        // Google Fonts that need loading via <link> tag (web-safe fonts don't)
        var googleFonts = {
            'garamond':     'EB+Garamond:wght@400;500;600;700',
            'merriweather': 'Merriweather:wght@400;700',
            'lora':         'Lora:wght@400;500;600;700',
            'roboto':       'Roboto:wght@400;500;700',
            'open-sans':    'Open+Sans:wght@400;500;600;700',
            'source-sans':  'Source+Sans+3:wght@400;500;600;700',
            'nunito':       'Nunito:wght@400;500;600;700'
        };

        // Size/scale/width mappings (mirrors PHP)
        var sizeMap  = { 'compact': '16px', 'comfortable': '18px', 'large': '20px' };
        var scaleMap = { 'small': '0.85', 'normal': '1', 'large': '1.15' };
        var widthMap = { 'narrow': '900px', 'standard': '1100px', 'wide': '1400px' };

        var iframe = document.getElementById('sp-design-preview');

        /**
         * Read all current design form values and inject a <style> block
         * into the preview iframe's <head> that overrides :root variables.
         *
         * WHY we override :root in the iframe: The iframe loads the real
         * homepage which already has the :root block from functions.php.
         * By injecting a second :root block with higher specificity (later
         * in the cascade), we override the saved values with the unsaved
         * form values. This gives Harold an instant preview without saving.
         */
        function updatePreview() {
            if (!iframe || !iframe.contentDocument) return;

            try {
                var doc = iframe.contentDocument;
                var head = doc.head || doc.getElementsByTagName('head')[0];
                if (!head) return;

                // Get color values — wpColorPicker stores the value in the
                // original input, which may be hidden. jQuery can read it.
                var primary      = getColorValue('sp-design-primary', '#1e3a5f');
                var primaryHover = getColorValue('sp-design-primary-hover', '#2c5282');
                var accent       = getColorValue('sp-design-accent', '#667eea');
                var headerBg     = getColorValue('sp-design-header-bg', '#1e3a5f');
                var headerText   = getColorValue('sp-design-header-text', '#ffffff');
                var footerBg     = getColorValue('sp-design-footer-bg', '#1e3a5f');
                var footerText   = getColorValue('sp-design-footer-text', '#ffffff');

                // Get select values
                var bodyFont     = document.getElementById('sp-design-font-body').value;
                var headingFont  = document.getElementById('sp-design-font-heading').value;
                var fontSize     = document.getElementById('sp-design-font-size').value;
                var headingScale = document.getElementById('sp-design-heading-scale').value;
                var contentWidth = document.getElementById('sp-design-content-width').value;

                // Resolve font family strings
                var bodyFontCSS    = fontMap[bodyFont] || fontMap['system'];
                var headingFontCSS = (headingFont === 'inherit') ? 'inherit' : (fontMap[headingFont] || 'inherit');

                // Build the override CSS
                var css = ':root {\n'
                    + '  --sp-color-primary: ' + primary + ';\n'
                    + '  --sp-color-primary-hover: ' + primaryHover + ';\n'
                    + '  --sp-color-accent: ' + accent + ';\n'
                    + '  --sp-color-header-bg: ' + headerBg + ';\n'
                    + '  --sp-color-header-text: ' + headerText + ';\n'
                    + '  --sp-color-footer-bg: ' + footerBg + ';\n'
                    + '  --sp-color-footer-text: ' + footerText + ';\n'
                    + '  --sp-font-body: ' + bodyFontCSS + ';\n'
                    + '  --sp-font-heading: ' + headingFontCSS + ';\n'
                    + '  --sp-font-size-base: ' + (sizeMap[fontSize] || '18px') + ';\n'
                    + '  --sp-font-scale: ' + (scaleMap[headingScale] || '1') + ';\n'
                    + '  --sp-content-width: ' + (contentWidth === 'custom'
                        ? (document.getElementById('sp-design-content-width-px').value || '1100') + 'px'
                        : (widthMap[contentWidth] || '1100px')) + ';\n'
                    + '}\n';

                // Remove any existing preview override style
                var existing = doc.getElementById('sp-design-preview-override');
                if (existing) existing.remove();

                // Inject the new override style
                var style = doc.createElement('style');
                style.id = 'sp-design-preview-override';
                style.textContent = css;
                head.appendChild(style);

                // Load Google Fonts in the iframe if needed
                loadGoogleFontsInIframe(doc, head, bodyFont, headingFont);

            } catch (e) {
                // Cross-origin errors are expected if the iframe hasn't loaded
                // yet or if the site is on a different domain. Silently ignore.
            }
        }

        /**
         * Get the current color value from a wpColorPicker input.
         * WHY: wpColorPicker hides the original input and creates its own
         * UI elements. We need to read the actual input value, which jQuery's
         * wpColorPicker keeps in sync.
         */
        function getColorValue(inputId, fallback) {
            var el = document.getElementById(inputId);
            if (!el) return fallback;
            return el.value || fallback;
        }

        /**
         * Load Google Fonts inside the preview iframe when a Google Font
         * is selected. We track which fonts are already loaded to avoid
         * duplicate <link> tags.
         */
        function loadGoogleFontsInIframe(doc, head, bodyKey, headingKey) {
            var families = [];
            if (googleFonts[bodyKey]) families.push(googleFonts[bodyKey]);
            if (headingKey !== 'inherit' && headingKey !== bodyKey && googleFonts[headingKey]) {
                families.push(googleFonts[headingKey]);
            }

            // Remove old Google Fonts link if any
            var oldLink = doc.getElementById('sp-preview-google-fonts');
            if (oldLink) oldLink.remove();

            if (families.length === 0) return;

            var link = doc.createElement('link');
            link.id = 'sp-preview-google-fonts';
            link.rel = 'stylesheet';
            link.href = 'https://fonts.googleapis.com/css2?family=' + families.join('&family=') + '&display=swap';
            head.appendChild(link);
        }

        // ---- Bind change/input events on all design controls ----
        // WHY both 'change' and 'input': 'change' fires when a select changes
        // or when the color picker closes. 'input' fires continuously as the
        // user drags the color picker slider, giving true real-time feedback.
        var controls = document.querySelectorAll('.sp-design-control');
        controls.forEach(function(ctrl) {
            ctrl.addEventListener('change', updatePreview);
            ctrl.addEventListener('input', updatePreview);
        });

        // ---- Device width toggle ----
        // WHY: Harold wants to see how the site looks on different screen sizes.
        // Instead of making him resize his browser, we resize the iframe container.
        var deviceBtns = document.querySelectorAll('.sp-preview-device');
        var previewContainer = document.getElementById('sp-preview-container');
        deviceBtns.forEach(function(btn) {
            btn.addEventListener('click', function() {
                deviceBtns.forEach(function(b) { b.classList.remove('sp-preview-device-active'); });
                this.classList.add('sp-preview-device-active');
                var width = this.getAttribute('data-width');
                if (previewContainer) {
                    previewContainer.style.maxWidth = width;
                    // Center the container when it's narrower than full width
                    previewContainer.style.margin = (width === '100%') ? '0' : '0 auto';
                }
            });
        });

        // ---- Active device button styling ----
        var styleTag = document.createElement('style');
        styleTag.textContent = '.sp-preview-device-active { background: #2271b1 !important; color: #fff !important; border-color: #2271b1 !important; }';
        document.head.appendChild(styleTag);

        // ---- Custom width row toggle ----
        // WHY: The Custom Width field should only show when "Custom" is selected
        // in the Content Width dropdown. No point confusing Harold with an extra
        // field when he's using a preset.
        var widthSelect  = document.getElementById('sp-design-content-width');
        var customRow    = document.getElementById('sp-custom-width-row');
        if (widthSelect && customRow) {
            widthSelect.addEventListener('change', function() {
                customRow.style.display = (this.value === 'custom') ? '' : 'none';
            });
        }

        // ---- Initial preview update after iframe loads ----
        if (iframe) {
            iframe.addEventListener('load', function() {
                updatePreview();
            });
        }
    })();
    </script>
    <?php
}


// ============================================================================
// DESIGN TAB — ENQUEUE COLOR PICKER ON SETTINGS PAGE
// ============================================================================

/**
 * Load WordPress's built-in color picker (wp-color-picker) on our Settings page.
 *
 * WHY: The Design tab uses color picker inputs for all 7 color settings.
 * WordPress ships a jQuery-based color picker (Iris) that we just need to
 * enqueue. We only load it on our Settings page to avoid adding overhead
 * to every admin page.
 *
 * WHY we check the screen: Loading color picker CSS+JS on every admin page
 * would slow down pages that don't need it. We target only the SocietyPress
 * settings page by checking the hook suffix.
 */
add_action( 'admin_enqueue_scripts', function ( $hook ) {
    // Our Design page is registered as a submenu under our custom menu.
    // The hook suffix varies by menu structure, so we check for our page slug.
    // WHY sp-settings-design specifically: Only the Design page uses color
    // pickers — no need to load these assets on the other six settings pages.
    if ( strpos( $hook, 'sp-settings-design' ) === false ) {
        return;
    }

    // wp-color-picker is the WordPress wrapper around the Iris color picker.
    // It provides a nice UI with a color swatch, hex input, and visual picker.
    wp_enqueue_style( 'wp-color-picker' );
    wp_enqueue_script( 'wp-color-picker' );

    // WHY: The Logo uploader uses wp.media — WordPress's built-in media modal.
    // Must be enqueued before the page renders or wp.media will be undefined.
    wp_enqueue_media();
});


// ============================================================================
// MEMBERSHIP DIRECTORY — PAGE TEMPLATE
// ============================================================================
//
// WHY: The society needs a public-facing page where members (and optionally
//      visitors) can browse and search the membership. Rather than making
//      the admin fiddle with shortcodes, we register a page template called
//      "Membership Directory" that they simply select from the Template
//      dropdown when editing a page. WordPress handles the rest.
//
// ============================================================================
// NAV MENU — HIDE MEMBERS-ONLY PAGES FROM LOGGED-OUT VISITORS
// ============================================================================
// WHY: The membership directory (and any future members-only pages) already
// show a "Members Only" gate when visited by non-members, but there's no
// reason to advertise the link in the nav if they can't use it. This filter
// removes nav menu items that point to pages using members-only templates
// (sp-directory) when the visitor isn't logged in.
// ----------------------------------------------------------------------------

add_filter( 'wp_nav_menu_objects', 'sp_hide_members_only_nav_items', 10, 2 );

function sp_hide_members_only_nav_items( $items, $args ) {
    // Don't filter if logged in — members see everything
    if ( is_user_logged_in() ) return $items;

    // Templates that require login — add more here as needed
    $members_only_templates = [ 'sp-directory' ];

    // Build a list of menu item IDs to remove (including their children)
    $remove_ids = [];
    foreach ( $items as $item ) {
        // Only check page-type menu items
        if ( $item->type !== 'post_type' || $item->object !== 'page' ) continue;
        $template = get_page_template_slug( $item->object_id );
        if ( in_array( $template, $members_only_templates, true ) ) {
            $remove_ids[] = $item->ID;
        }
    }

    if ( empty( $remove_ids ) ) return $items;

    // Also remove any child items whose parent is being removed
    // WHY: If "Directory" has sub-items, they'd be orphaned in the nav
    $all_remove = $remove_ids;
    foreach ( $items as $item ) {
        if ( in_array( (int) $item->menu_item_parent, $remove_ids, true ) ) {
            $all_remove[] = $item->ID;
        }
    }

    return array_filter( $items, function( $item ) use ( $all_remove ) {
        return ! in_array( $item->ID, $all_remove, true );
    } );
}

// HOW IT WORKS:
//      1. theme_page_templates filter — adds "Membership Directory" to the
//         template dropdown in the Page editor
//      2. template_include filter — when WordPress loads that page, we
//         intercept and render our own output (with the active theme's
//         header and footer so it looks native)
//
// PRIVACY MODEL (three layers):
//      Layer 0 — Login required (always enforced, not a setting):
//        Only logged-in members can see the directory. Period. Non-members
//        have no business browsing member contact info.
//
//      Layer 1 — Society level (Settings → Directory tab):
//        The admin decides which columns appear at all. If they turn off
//        "Phone," no one sees any phone numbers, period.
//
//      Layer 2 — Individual member (member profile → Directory Visibility):
//        Each member has dir_show_name, dir_show_email, dir_show_phone,
//        dir_show_address, dir_show_website checkboxes. Even if the admin
//        enables "Email" at the society level, a member who unchecked
//        "Show email" on their profile will have their email hidden.
//
//      All layers must agree for data to appear.
// ============================================================================


/**
 * Register the "Membership Directory" page template so it shows up
 * in the Template dropdown on the Edit Page screen.
 *
 * WHY: This is a plugin-provided template (not a theme file). We use
 *      the theme_page_templates filter to inject it into the list
 *      WordPress shows. The key ('sp-directory') is an arbitrary slug —
 *      it doesn't need to correspond to a file on disk because we
 *      intercept it in template_include below.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-directory'] = 'Membership Directory';
    return $templates;
});


/**
 * When WordPress is about to load the template for a page that uses our
 * "Membership Directory" template, hijack it and render the directory.
 *
 * WHY: Since our template isn't a physical file in the theme folder,
 *      WordPress would 404 trying to find "sp-directory.php." We catch
 *      it here and output the directory ourselves, using the active
 *      theme's header/footer so it blends in naturally.
 */
add_filter( 'template_include', function ( $template ) {

    // Only act on pages assigned to our custom template
    if ( is_page() && get_page_template_slug() === 'sp-directory' ) {

        $settings = get_option( 'societypress_settings', [] );

        // Enqueue our directory styles
        // WHY: We add the CSS via wp_head so it loads in the <head> where
        //      stylesheets belong, not inline in the body.
        add_action( 'wp_head', 'sp_directory_styles' );
        add_action( 'wp_head', 'sp_directory_detail_styles' );
        add_action( 'wp_footer', 'sp_directory_detail_script' );

        // Start output with the theme's header
        get_header();

        echo '<div class="sp-directory-wrap">';

        // WHY: The membership directory is always members-only. Non-members
        //      have no business browsing member contact info, phone numbers,
        //      and email addresses. This isn't a setting — it's a principle.
        if ( ! is_user_logged_in() ) {
            echo '<div class="sp-directory-login-required">';
            echo '<h2>Members Only</h2>';
            echo '<p>The membership directory is available to logged-in members. '
               . 'Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> '
               . 'to view the directory.</p>';
            echo '</div>';
        } else {
            sp_render_directory( $settings );
        }

        echo '</div>';

        get_footer();

        // Return an empty string to prevent WordPress from loading another template.
        // WHY: We already output everything via get_header/get_footer. If we return
        //      the original $template, WordPress would load it on top of our output,
        //      causing duplicate headers/footers. An empty include file means "done."
        //
        // We use a trick: return a path to a file that outputs nothing. The simplest
        // approach is to return the path to a tiny temp file. But an even simpler
        // approach is to just exit — except that breaks wp_footer scripts. So we
        // use PHP's __DIR__ trick to find a file we know is empty-ish.
        //
        // Actually the cleanest pattern: have template_include return a custom file
        // that just does nothing. Since we can't create files from a monolithic
        // plugin, we'll use a PHP wrapper.
        return SOCIETYPRESS_PLUGIN_DIR . 'sp-blank-template.php';
    }

    return $template;
});


/**
 * Create the blank template file if it doesn't exist.
 *
 * WHY: template_include needs to return a path to a real file. This file
 *      does absolutely nothing — it exists solely so WordPress has
 *      something to include after we've already output the full page
 *      via get_header() + our content + get_footer().
 */
add_action( 'init', function () {
    $blank = SOCIETYPRESS_PLUGIN_DIR . 'sp-blank-template.php';
    if ( ! file_exists( $blank ) ) {
        file_put_contents( $blank, "<?php\n// Intentionally blank — used by the directory page template.\n" );
    }
});
/**
 * Render the membership directory — the main content between header and footer.
 *
 * WHY: This function builds the complete directory UI: search bar, filter
 *      dropdowns, letter filter, results table, and pagination. It queries
 *      the database respecting both society-level column toggles (settings)
 *      and individual member privacy preferences (dir_show_* fields).
 *
 * FILTERS: Text search + status + group + tier + surname all combine with
 *          AND logic. This lets members drill down precisely — e.g., find
 *          all active members in the "Cemetery Research" group who are
 *          researching the surname "Smith."
 *
 * @param array $settings The societypress_settings option array.
 */
function sp_render_directory( array $settings ): void {
    global $wpdb;

    $prefix   = $wpdb->prefix . 'sp_';
    $per_page = (int) ( $settings['dir_per_page'] ?? 25 );

    // ---- Collect filter/search parameters from the URL ----

    // Search query — sanitize and trim
    $search = isset( $_GET['sp_search'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_search'] ) ) : '';

    // Letter filter — single uppercase letter or empty for "all"
    $letter = isset( $_GET['sp_letter'] ) ? strtoupper( sanitize_text_field( $_GET['sp_letter'] ) ) : '';
    if ( $letter && ! preg_match( '/^[A-Z]$/', $letter ) ) {
        $letter = ''; // Invalid letter — show all
    }

    // Status filter — default to "active" so the directory shows current members
    $status_filter = isset( $_GET['sp_status'] ) ? sanitize_text_field( $_GET['sp_status'] ) : 'active';
    $allowed_statuses = [ 'active', 'inactive', 'all' ];
    if ( ! in_array( $status_filter, $allowed_statuses, true ) ) {
        $status_filter = 'active';
    }

    // Group/committee filter — numeric group ID or empty for "all"
    $group_filter = isset( $_GET['sp_group'] ) ? (int) $_GET['sp_group'] : 0;

    // Membership tier filter — numeric tier ID or empty for "all"
    $tier_filter = isset( $_GET['sp_tier'] ) ? (int) $_GET['sp_tier'] : 0;

    // Dedicated surname search — separate from the main text search so members
    // can filter specifically by surname being researched without mixing it
    // into the general name/email search.
    $surname_search = isset( $_GET['sp_surname'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_surname'] ) ) : '';

    // Sort column and direction
    $allowed_sorts = [ 'last_name', 'first_name', 'city', 'state', 'join_date', 'tier_name', 'phone', 'user_email', 'website' ];
    $sort_by       = isset( $_GET['sp_sort'] ) && in_array( $_GET['sp_sort'], $allowed_sorts, true )
                     ? $_GET['sp_sort'] : 'last_name';
    $sort_dir      = isset( $_GET['sp_dir'] ) && strtolower( $_GET['sp_dir'] ) === 'desc' ? 'DESC' : 'ASC';

    // Pagination
    $current_page = max( 1, (int) ( $_GET['sp_page'] ?? 1 ) );
    $offset       = ( $current_page - 1 ) * $per_page;


    // ---- Load filter options from the database ----
    // WHY: We need these for the dropdown menus. One query each — cheap,
    //      and we cache-bust naturally since these change rarely.

    $groups = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}groups WHERE status = 'active' ORDER BY name"
    );

    $tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers ORDER BY sort_order, name"
    );


    // ---- Build the WHERE clause ----

    $where  = [];
    $params = [];

    // Status filter — "all" shows everyone, otherwise filter by status
    if ( $status_filter !== 'all' ) {
        $where[]  = "m.status = %s";
        $params[] = $status_filter;
    }

    // Text search — look in name, city, email, member number, interests, skills, and surnames
    if ( $search !== '' ) {
        $like     = '%' . $wpdb->esc_like( $search ) . '%';
        $where[]  = "(
            m.first_name LIKE %s
            OR m.last_name LIKE %s
            OR m.preferred_name LIKE %s
            OR m.organization_name LIKE %s
            OR m.city LIKE %s
            OR m.member_number LIKE %s
            OR m.interests LIKE %s
            OR m.skills LIKE %s
            OR u.user_email LIKE %s
            OR EXISTS (
                SELECT 1 FROM {$prefix}member_surnames s
                WHERE s.user_id = m.user_id AND s.surname LIKE %s
            )
        )";
        $params[] = $like; // first_name
        $params[] = $like; // last_name
        $params[] = $like; // preferred_name
        $params[] = $like; // organization_name
        $params[] = $like; // city
        $params[] = $like; // member_number
        $params[] = $like; // interests
        $params[] = $like; // skills
        $params[] = $like; // user_email
        $params[] = $like; // surname
    }

    // Dedicated surname filter — matches against the surnames table specifically.
    // WHY: Surnames are THE killer feature for genealogical societies. Members
    //      want to find others researching the same family lines without wading
    //      through general search results. A dedicated surname filter makes
    //      this dead simple.
    if ( $surname_search !== '' ) {
        $surname_like = '%' . $wpdb->esc_like( $surname_search ) . '%';
        $where[]  = "EXISTS (
            SELECT 1 FROM {$prefix}member_surnames s
            WHERE s.user_id = m.user_id AND s.surname LIKE %s
        )";
        $params[] = $surname_like;
    }

    // Group/committee filter — find members who belong to the selected group
    if ( $group_filter > 0 ) {
        $where[]  = "m.user_id IN (
            SELECT gm.user_id FROM {$prefix}group_members gm
            WHERE gm.group_id = %d
        )";
        $params[] = $group_filter;
    }

    // Tier filter — match against the membership tier
    if ( $tier_filter > 0 ) {
        $where[]  = "m.tier_id = %d";
        $params[] = $tier_filter;
    }

    // Letter filter — match first character of last name (or org name for orgs)
    if ( $letter !== '' ) {
        $where[]  = "(m.last_name LIKE %s OR m.organization_name LIKE %s)";
        $params[] = $letter . '%';
        $params[] = $letter . '%';
    }

    // Default: if no filters at all, show all records (no WHERE restriction beyond joins)
    $where_sql = ! empty( $where ) ? implode( ' AND ', $where ) : '1=1';


    // ---- Count total matching members (for pagination) ----

    $count_sql = "SELECT COUNT(*)
        FROM {$prefix}members m
        JOIN {$wpdb->users} u ON u.ID = m.user_id
        WHERE {$where_sql}";

    if ( ! empty( $params ) ) {
        $count_sql = $wpdb->prepare( $count_sql, ...$params );
    }

    $total_members = (int) $wpdb->get_var( $count_sql );
    $total_pages   = max( 1, (int) ceil( $total_members / $per_page ) );

    // Clamp current page to valid range
    if ( $current_page > $total_pages ) {
        $current_page = $total_pages;
        $offset       = ( $current_page - 1 ) * $per_page;
    }


    // ---- Handle sort column that comes from a joined table ----

    // Map sort keys to actual SQL column references.
    // WHY: Some sortable columns live on joined tables, not on sp_members.
    $sort_col_map = [
        'tier_name'  => 't.name',
        'user_email' => 'u.user_email',
    ];
    $order_col = $sort_col_map[ $sort_by ] ?? $sort_by;


    // ---- Fetch the members for this page ----

    $query = "SELECT m.*, u.user_email, t.name AS tier_name
        FROM {$prefix}members m
        JOIN {$wpdb->users} u ON u.ID = m.user_id
        LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
        WHERE {$where_sql}
        ORDER BY {$order_col} {$sort_dir}
        LIMIT %d OFFSET %d";

    // Build params: search/letter params + limit + offset
    $query_params = array_merge( $params, [ $per_page, $offset ] );
    $members      = $wpdb->get_results( $wpdb->prepare( $query, ...$query_params ) );


    // ---- Load surnames for all members on this page (one query, not N) ----

    $surnames_map = [];
    if ( ! empty( $settings['dir_show_surnames'] ) && ! empty( $members ) ) {
        $user_ids    = array_map( fn( $m ) => (int) $m->user_id, $members );
        $placeholders = implode( ', ', array_fill( 0, count( $user_ids ), '%d' ) );
        $surname_rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT user_id, surname, county, state, country, year_from, year_to
                 FROM {$prefix}member_surnames
                 WHERE user_id IN ({$placeholders})
                 ORDER BY surname",
                ...$user_ids
            )
        );
        foreach ( $surname_rows as $row ) {
            $surnames_map[ $row->user_id ][] = $row;
        }
    }


    // ---- Load group memberships for all members on this page ----
    // WHY: We show which groups each member belongs to in the results,
    //      so members can see at a glance who's in what committee.

    $groups_map = [];
    if ( ! empty( $members ) ) {
        $user_ids     = array_map( fn( $m ) => (int) $m->user_id, $members );
        $placeholders = implode( ', ', array_fill( 0, count( $user_ids ), '%d' ) );
        $group_rows   = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT gm.user_id, g.name
                 FROM {$prefix}group_members gm
                 JOIN {$prefix}groups g ON g.id = gm.group_id
                 WHERE gm.user_id IN ({$placeholders}) AND g.status = 'active'
                 ORDER BY g.name",
                ...$user_ids
            )
        );
        foreach ( $group_rows as $row ) {
            $groups_map[ $row->user_id ][] = $row->name;
        }
    }


    // ---- Determine which columns to show (society-level settings) ----

    $show_city_state = ! empty( $settings['dir_show_city_state'] );
    $show_phone      = ! empty( $settings['dir_show_phone'] );
    $show_email      = ! empty( $settings['dir_show_email'] );
    $show_website    = ! empty( $settings['dir_show_website'] );
    $show_tier       = ! empty( $settings['dir_show_tier'] );
    $show_join_date  = ! empty( $settings['dir_show_join_date'] );
    $show_surnames   = ! empty( $settings['dir_show_surnames'] );

    // Count columns for the "no results" colspan
    $col_count = 1; // Name is always shown
    if ( $show_city_state ) $col_count++;
    if ( $show_phone )      $col_count++;
    if ( $show_email )      $col_count++;
    if ( $show_website )    $col_count++;
    if ( $show_tier )       $col_count++;
    if ( $show_join_date )  $col_count++;


    // ---- Build the current page URL for filters/sorting/pagination ----

    $base_url = get_permalink();


    // ---- Helper: collect all active filter args for URL building ----
    // WHY: Every link on the page (sort headers, letter filter, pagination)
    //      needs to preserve the current filter state. This array holds all
    //      non-empty filter values so we can merge them into URLs.

    $filter_args = array_filter( [
        'sp_search'  => $search ?: null,
        'sp_status'  => $status_filter !== 'active' ? $status_filter : null,
        'sp_group'   => $group_filter > 0 ? $group_filter : null,
        'sp_tier'    => $tier_filter > 0 ? $tier_filter : null,
        'sp_surname' => $surname_search ?: null,
    ] );


    // ---- Helper: build a sort URL for a column header ----

    $sort_url = function ( $col ) use ( $base_url, $filter_args, $letter, $sort_by, $sort_dir ) {
        $new_dir = ( $sort_by === $col && $sort_dir === 'ASC' ) ? 'desc' : 'asc';
        $args    = array_merge( $filter_args, [ 'sp_sort' => $col, 'sp_dir' => $new_dir ] );
        if ( $letter !== '' ) $args['sp_letter'] = $letter;
        return esc_url( add_query_arg( $args, $base_url ) );
    };

    // ---- Helper: sort indicator arrow ----

    $sort_arrow = function ( $col ) use ( $sort_by, $sort_dir ) {
        if ( $sort_by !== $col ) return '';
        return $sort_dir === 'ASC' ? ' &#9650;' : ' &#9660;';
    };


    // ---- Check if any filters are active (for the "Clear All" button) ----
    $has_filters = $search !== '' || $status_filter !== 'active' || $group_filter > 0
                   || $tier_filter > 0 || $surname_search !== '' || $letter !== '';


    // ================================================================
    // OUTPUT: Search bar + filter dropdowns
    // ================================================================

    ?>
    <div class="sp-directory-search">
        <form method="get" action="<?php echo esc_url( $base_url ); ?>">

            <!-- Text search row -->
            <div class="sp-search-row">
                <input type="text"
                       name="sp_search"
                       value="<?php echo esc_attr( $search ); ?>"
                       placeholder="<?php echo esc_attr__( 'Search by name, city, email, or surname…', 'societypress' ); ?>"
                       class="sp-search-input"
                       aria-label="<?php echo esc_attr__( 'Search the membership directory', 'societypress' ); ?>">
                <button type="submit" class="sp-search-button"><?php echo esc_html__( 'Search', 'societypress' ); ?></button>
                <?php if ( $has_filters ) : ?>
                    <a href="<?php echo esc_url( $base_url ); ?>" class="sp-search-clear"><?php echo esc_html__( 'Clear All', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>

            <!-- Filter dropdowns row -->
            <div class="sp-filter-row">

                <!-- Status filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-status" class="sp-filter-label"><?php echo esc_html__( 'Status', 'societypress' ); ?></label>
                    <select name="sp_status" id="sp-filter-status" class="sp-filter-select">
                        <option value="active" <?php selected( $status_filter, 'active' ); ?>><?php echo esc_html__( 'Active', 'societypress' ); ?></option>
                        <option value="inactive" <?php selected( $status_filter, 'inactive' ); ?>><?php echo esc_html__( 'Inactive', 'societypress' ); ?></option>
                        <option value="all" <?php selected( $status_filter, 'all' ); ?>><?php echo esc_html__( 'All Members', 'societypress' ); ?></option>
                    </select>
                </div>

                <?php if ( ! empty( $groups ) ) : ?>
                <!-- Group/committee filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-group" class="sp-filter-label"><?php echo esc_html__( 'Group', 'societypress' ); ?></label>
                    <select name="sp_group" id="sp-filter-group" class="sp-filter-select">
                        <option value="0"><?php echo esc_html__( 'All Groups', 'societypress' ); ?></option>
                        <?php foreach ( $groups as $g ) : ?>
                            <option value="<?php echo (int) $g->id; ?>" <?php selected( $group_filter, (int) $g->id ); ?>>
                                <?php echo esc_html( $g->name ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <?php endif; ?>

                <?php if ( ! empty( $tiers ) ) : ?>
                <!-- Membership tier filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-tier" class="sp-filter-label"><?php echo esc_html__( 'Membership', 'societypress' ); ?></label>
                    <select name="sp_tier" id="sp-filter-tier" class="sp-filter-select">
                        <option value="0"><?php echo esc_html__( 'All Types', 'societypress' ); ?></option>
                        <?php foreach ( $tiers as $t ) : ?>
                            <option value="<?php echo (int) $t->id; ?>" <?php selected( $tier_filter, (int) $t->id ); ?>>
                                <?php echo esc_html( $t->name ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <?php endif; ?>

                <!-- Dedicated surname search -->
                <div class="sp-filter-group">
                    <label for="sp-filter-surname" class="sp-filter-label"><?php echo esc_html__( 'Surname Being Researched', 'societypress' ); ?></label>
                    <input type="text"
                           name="sp_surname"
                           id="sp-filter-surname"
                           value="<?php echo esc_attr( $surname_search ); ?>"
                           placeholder="<?php echo esc_attr__( 'e.g. Smith', 'societypress' ); ?>"
                           class="sp-filter-input">
                </div>

            </div>

            <!-- Preserve sort state across filter changes -->
            <?php if ( $sort_by !== 'last_name' ) : ?>
                <input type="hidden" name="sp_sort" value="<?php echo esc_attr( $sort_by ); ?>">
            <?php endif; ?>
            <?php if ( $sort_dir !== 'ASC' ) : ?>
                <input type="hidden" name="sp_dir" value="<?php echo esc_attr( strtolower( $sort_dir ) ); ?>">
            <?php endif; ?>
            <?php if ( $letter !== '' ) : ?>
                <input type="hidden" name="sp_letter" value="<?php echo esc_attr( $letter ); ?>">
            <?php endif; ?>

        </form>
    </div>
    <?php


    // ================================================================
    // OUTPUT: Alphabetical letter filter
    // ================================================================

    ?>
    <div class="sp-directory-letters">
        <a href="<?php echo esc_url( add_query_arg( $filter_args, $base_url ) ); ?>"
           class="sp-letter <?php echo $letter === '' ? 'sp-letter-active' : ''; ?>"><?php echo esc_html__( 'All', 'societypress' ); ?></a>
        <?php
        foreach ( range( 'A', 'Z' ) as $l ) :
            $l_args = array_merge( $filter_args, [ 'sp_letter' => $l ] );
        ?>
            <a href="<?php echo esc_url( add_query_arg( $l_args, $base_url ) ); ?>"
               class="sp-letter <?php echo $letter === $l ? 'sp-letter-active' : ''; ?>"><?php echo $l; ?></a>
        <?php endforeach; ?>
    </div>
    <?php


    // ================================================================
    // OUTPUT: Results count + active filter summary
    // ================================================================

    ?>
    <div class="sp-directory-count">
        <?php
        if ( $total_members === 0 ) {
            echo '<p>' . esc_html__( 'No members found.', 'societypress' ) . '</p>';
        } elseif ( $total_members === 1 ) {
            echo '<p>' . esc_html__( '1 member', 'societypress' ) . '</p>';
        } else {
            printf( '<p>%s ' . esc_html__( 'members', 'societypress' ) . '</p>', number_format_i18n( $total_members ) );
        }
        ?>
    </div>
    <?php


    // ================================================================
    // OUTPUT: Results table
    // ================================================================

    if ( ! empty( $members ) ) :
    ?>
    <div class="sp-directory-table-wrap">
        <table class="sp-directory-table">
            <thead>
                <tr>
                    <th class="sp-col-name">
                        <a href="<?php echo $sort_url( 'last_name' ); ?>"><?php echo esc_html__( 'Name', 'societypress' ); ?><?php echo $sort_arrow( 'last_name' ); ?></a>
                    </th>
                    <?php if ( $show_city_state ) : ?>
                        <th class="sp-col-location">
                            <a href="<?php echo $sort_url( 'city' ); ?>"><?php echo esc_html__( 'Location', 'societypress' ); ?><?php echo $sort_arrow( 'city' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_phone ) : ?>
                        <th class="sp-col-phone">
                            <a href="<?php echo $sort_url( 'phone' ); ?>"><?php echo esc_html__( 'Phone', 'societypress' ); ?><?php echo $sort_arrow( 'phone' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_email ) : ?>
                        <th class="sp-col-email">
                            <a href="<?php echo $sort_url( 'user_email' ); ?>"><?php echo esc_html__( 'Email', 'societypress' ); ?><?php echo $sort_arrow( 'user_email' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_website ) : ?>
                        <th class="sp-col-website">
                            <a href="<?php echo $sort_url( 'website' ); ?>"><?php echo esc_html__( 'Website', 'societypress' ); ?><?php echo $sort_arrow( 'website' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_tier ) : ?>
                        <th class="sp-col-tier">
                            <a href="<?php echo $sort_url( 'tier_name' ); ?>"><?php echo esc_html__( 'Type', 'societypress' ); ?><?php echo $sort_arrow( 'tier_name' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_join_date ) : ?>
                        <th class="sp-col-date">
                            <a href="<?php echo $sort_url( 'join_date' ); ?>"><?php echo esc_html__( 'Member Since', 'societypress' ); ?><?php echo $sort_arrow( 'join_date' ); ?></a>
                        </th>
                    <?php endif; ?>
                </tr>
            </thead>
            <tbody>
            <?php foreach ( $members as $m ) :

                // ---- Individual member privacy checks (Layer 2) ----
                // If the member has opted out of showing their name entirely,
                // skip them from the directory. (Rare, but respected.)
                if ( empty( $m->dir_show_name ) ) {
                    continue;
                }

                // Build the display name — orgs show their org name, individuals
                // show preferred (or first) + last name as before.
                if ( ( $m->member_type ?? 'individual' ) === 'organization' && ! empty( $m->organization_name ) ) {
                    $display_name = esc_html( $m->organization_name );
                } else {
                    $display_name = esc_html( trim(
                        ( $m->preferred_name ?: $m->first_name ) . ' ' . $m->last_name
                    ) );
                    if ( $m->suffix ) {
                        $display_name .= ', ' . esc_html( $m->suffix );
                    }
                }
            ?>
                <tr>
                    <td class="sp-col-name" data-label="<?php echo esc_attr__( 'Name', 'societypress' ); ?>"><a href="#" class="sp-member-name-link" data-user-id="<?php echo (int) $m->user_id; ?>"><?php echo $display_name; ?></a></td>

                    <?php if ( $show_city_state ) : ?>
                        <td class="sp-col-location" data-label="<?php echo esc_attr__( 'Location', 'societypress' ); ?>">
                            <?php
                            // Respect the member's address privacy preference
                            if ( ! empty( $m->dir_show_address ) ) {
                                $parts = array_filter( [ $m->city, $m->state ] );
                                echo esc_html( implode( ', ', $parts ) );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_phone ) : ?>
                        <td class="sp-col-phone" data-label="<?php echo esc_attr__( 'Phone', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_phone ) && $m->phone ) {
                                // Link the phone number for mobile users
                                printf(
                                    '<a href="tel:%s">%s</a>',
                                    esc_attr( preg_replace( '/[^+0-9]/', '', $m->phone ) ),
                                    esc_html( $m->phone )
                                );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_email ) : ?>
                        <td class="sp-col-email" data-label="<?php echo esc_attr__( 'Email', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_email ) && $m->user_email ) {
                                // JS-based obfuscation: email is split and base64-encoded
                                // in data attributes, assembled into a real mailto: link
                                // by the spAssembleEmails() script in the footer. Bots
                                // that don't execute JS get nothing.
                                echo sp_obfuscate_email( $m->user_email );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_website ) : ?>
                        <td class="sp-col-website" data-label="<?php echo esc_attr__( 'Website', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_website ) && $m->website ) {
                                // Strip protocol for display but keep it for the href
                                $display_url = preg_replace( '#^https?://#', '', rtrim( $m->website, '/' ) );
                                $full_url    = $m->website;
                                if ( ! preg_match( '#^https?://#', $full_url ) ) {
                                    $full_url = 'https://' . $full_url;
                                }
                                printf(
                                    '<a href="%s" target="_blank" rel="noopener">%s</a>',
                                    esc_url( $full_url ),
                                    esc_html( $display_url )
                                );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_tier ) : ?>
                        <td class="sp-col-tier" data-label="<?php echo esc_attr__( 'Type', 'societypress' ); ?>">
                            <?php echo esc_html( $m->tier_name ?? '' ); ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_join_date ) : ?>
                        <td class="sp-col-date" data-label="<?php echo esc_attr__( 'Member Since', 'societypress' ); ?>">
                            <?php
                            if ( $m->join_date && $m->join_date !== '0000-00-00' ) {
                                echo esc_html( wp_date( get_option( 'date_format', 'F j, Y' ), strtotime( $m->join_date ) ) );
                            }
                            ?>
                        </td>
                    <?php endif; ?>
                </tr>

                <?php
                // ---- Surnames row (spans full width below the member) ----
                // WHY: Surnames are the killer feature for genealogical societies.
                //      Showing them inline in a column would be too cramped — they
                //      can have location/date ranges. So we show them in an
                //      expandable row below the member's main row.
                if ( $show_surnames && ! empty( $surnames_map[ $m->user_id ] ) ) :
                ?>
                    <tr class="sp-surname-row">
                        <td colspan="<?php echo $col_count; ?>">
                            <div class="sp-surnames">
                                <span class="sp-surnames-label"><?php echo esc_html__( 'Researching:', 'societypress' ); ?></span>
                                <?php
                                $parts = [];
                                foreach ( $surnames_map[ $m->user_id ] as $s ) {
                                    $text = '<strong>' . esc_html( $s->surname ) . '</strong>';

                                    // Add location context if available
                                    $loc = array_filter( [ $s->county, $s->state, $s->country ] );
                                    if ( $loc ) {
                                        $text .= ' <span class="sp-surname-detail">(' . esc_html( implode( ', ', $loc ) );
                                        // Add year range if available
                                        if ( $s->year_from || $s->year_to ) {
                                            $text .= ', ' . esc_html( ( $s->year_from ?: '?' ) . '–' . ( $s->year_to ?: 'present' ) );
                                        }
                                        $text .= ')</span>';
                                    } elseif ( $s->year_from || $s->year_to ) {
                                        $text .= ' <span class="sp-surname-detail">(' . esc_html( ( $s->year_from ?: '?' ) . '–' . ( $s->year_to ?: 'present' ) ) . ')</span>';
                                    }

                                    $parts[] = $text;
                                }
                                echo implode( ' &middot; ', $parts );
                                ?>
                            </div>
                        </td>
                    </tr>
                <?php endif; ?>

                <?php
                // ---- Groups row (spans full width below the member/surnames) ----
                // WHY: Showing group membership helps members find others in the
                //      same committee or interest group. Displayed as tags.
                if ( ! empty( $groups_map[ $m->user_id ] ) ) :
                ?>
                    <tr class="sp-groups-row">
                        <td colspan="<?php echo $col_count; ?>">
                            <div class="sp-member-groups">
                                <span class="sp-groups-label"><?php echo esc_html__( 'Groups:', 'societypress' ); ?></span>
                                <?php
                                $group_tags = [];
                                foreach ( $groups_map[ $m->user_id ] as $gname ) {
                                    $group_tags[] = '<span class="sp-group-tag">' . esc_html( $gname ) . '</span>';
                                }
                                echo implode( ' ', $group_tags );
                                ?>
                            </div>
                        </td>
                    </tr>
                <?php endif; ?>

            <?php endforeach; ?>
            </tbody>
        </table>
    </div>
    <?php endif; // ! empty( $members ) ?>


    <?php
    // ================================================================
    // OUTPUT: Pagination
    // ================================================================

    if ( $total_pages > 1 ) :
        // Build base args that persist across page links — includes all filters
        $page_args = $filter_args;
        if ( $letter !== '' ) $page_args['sp_letter'] = $letter;
        if ( $sort_by !== 'last_name' ) $page_args['sp_sort'] = $sort_by;
        if ( $sort_dir !== 'ASC' ) $page_args['sp_dir'] = strtolower( $sort_dir );
    ?>
    <nav class="sp-directory-pagination" aria-label="<?php echo esc_attr__( 'Directory pagination', 'societypress' ); ?>">
        <?php if ( $current_page > 1 ) : ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page - 1 ] ), $base_url ) ); ?>"
               class="sp-page-link sp-page-prev">&laquo; <?php echo esc_html__( 'Previous', 'societypress' ); ?></a>
        <?php endif; ?>

        <?php
        // Show page numbers with ellipsis for large sets
        // WHY: If there are 50 pages, we don't want to show all 50 links.
        //      Show: 1 ... [current-1] [current] [current+1] ... [last]
        $range = 2; // How many pages to show on each side of current
        $start = max( 1, $current_page - $range );
        $end   = min( $total_pages, $current_page + $range );

        if ( $start > 1 ) :
        ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => 1 ] ), $base_url ) ); ?>"
               class="sp-page-link">1</a>
            <?php if ( $start > 2 ) : ?>
                <span class="sp-page-ellipsis">&hellip;</span>
            <?php endif; ?>
        <?php endif; ?>

        <?php for ( $p = $start; $p <= $end; $p++ ) : ?>
            <?php if ( $p === $current_page ) : ?>
                <span class="sp-page-link sp-page-current"><?php echo $p; ?></span>
            <?php else : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $p ] ), $base_url ) ); ?>"
                   class="sp-page-link"><?php echo $p; ?></a>
            <?php endif; ?>
        <?php endfor; ?>

        <?php if ( $end < $total_pages ) : ?>
            <?php if ( $end < $total_pages - 1 ) : ?>
                <span class="sp-page-ellipsis">&hellip;</span>
            <?php endif; ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $total_pages ] ), $base_url ) ); ?>"
               class="sp-page-link"><?php echo $total_pages; ?></a>
        <?php endif; ?>

        <?php if ( $current_page < $total_pages ) : ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page + 1 ] ), $base_url ) ); ?>"
               class="sp-page-link sp-page-next"><?php echo esc_html__( 'Next', 'societypress' ); ?> &raquo;</a>
        <?php endif; ?>
    </nav>
    <?php endif; // $total_pages > 1 ?>

    <?php
}



