/**
 * Render admin settings fields for the Upcoming Events widget.
 *
 * WHY: Lets the page builder admin choose how many events to show, which
 * category to filter by, and which detail fields to include on each card.
 */
function sp_builder_fields_upcoming_events( $index, array $settings ): void {
    global $wpdb;
    $count         = $settings['count'] ?? 5;
    $category_id   = $settings['category_id'] ?? '';
    $show_date     = $settings['show_date'] ?? 1;
    $show_time     = $settings['show_time'] ?? 1;
    $show_location = $settings['show_location'] ?? 1;

    // Fetch active categories for the dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order, name"
    );
    ?>
    <div class="sp-builder-field">
        <p class="description">Displays a compact list of upcoming events pulled from your Events system.</p>

        <label style="display:block; font-weight:600; margin-bottom:4px;">Number of events to show</label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][count]">
            <?php foreach ( [ 3, 5, 10, 15, 20 ] as $opt ) : ?>
                <option value="<?php echo $opt; ?>" <?php selected( $count, $opt ); ?>><?php echo $opt; ?></option>
            <?php endforeach; ?>
        </select>

        <label style="display:block; font-weight:600; margin:12px 0 4px;">Filter by category</label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][category_id]">
            <option value="">All Categories</option>
            <?php foreach ( $categories as $cat ) : ?>
                <option value="<?php echo esc_attr( $cat->id ); ?>" <?php selected( $category_id, $cat->id ); ?>>
                    <?php echo esc_html( $cat->name ); ?>
                </option>
            <?php endforeach; ?>
        </select>

        <fieldset style="margin-top:12px; border:none; padding:0;">
            <legend style="font-weight:600; margin-bottom:4px;">Show on each card</legend>
            <label style="display:block; margin-bottom:4px;">
                <input type="hidden" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_date]" value="0">
                <input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_date]" value="1" <?php checked( $show_date ); ?>>
                Date
            </label>
            <label style="display:block; margin-bottom:4px;">
                <input type="hidden" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_time]" value="0">
                <input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_time]" value="1" <?php checked( $show_time ); ?>>
                Time
            </label>
            <label style="display:block; margin-bottom:4px;">
                <input type="hidden" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_location]" value="0">
                <input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_location]" value="1" <?php checked( $show_location ); ?>>
                Location
            </label>
        </fieldset>
    </div>
    <?php
}


/**
 * Events Calendar widget settings.
 *
 * WHY: Lets the admin drop a full monthly calendar grid into any Page Builder
 *      page. The only setting is an optional category filter — everything else
 *      (start day, colors, mobile behavior) comes from the global settings
 *      and the events data itself. Keeping it simple because the calendar
 *      already handles its own month navigation via query params.
 */
function sp_builder_fields_event_calendar( $index, array $settings ): void {
    global $wpdb;
    $category_id = $settings['category_id'] ?? '';
    $heading     = $settings['heading'] ?? '';

    // Fetch active event categories for the dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order, name"
    );
    ?>
    <div class="sp-builder-field">
        <p class="description"><?php echo esc_html__( 'Displays a monthly calendar grid with color-coded event pills, month navigation, and mobile day-tap.', 'societypress' ); ?></p>

        <label style="display:block; font-weight:600; margin-bottom:4px;"><?php echo esc_html__( 'Heading (optional)', 'societypress' ); ?></label>
        <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][heading]"
               value="<?php echo esc_attr( $heading ); ?>"
               placeholder="<?php echo esc_attr__( 'Events Calendar', 'societypress' ); ?>"
               style="width:100%;">

        <label style="display:block; font-weight:600; margin:12px 0 4px;"><?php echo esc_html__( 'Filter by category', 'societypress' ); ?></label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][category_id]">
            <option value=""><?php echo esc_html__( 'All Categories', 'societypress' ); ?></option>
            <?php foreach ( $categories as $cat ) : ?>
                <option value="<?php echo esc_attr( $cat->id ); ?>" <?php selected( $category_id, $cat->id ); ?>>
                    <?php echo esc_html( $cat->name ); ?>
                </option>
            <?php endforeach; ?>
        </select>
    </div>
    <?php
}


