/**
 * Render the Events admin page — list table with filters, search, and actions.
 *
 * WHY: Same pattern as sp_render_members_page(). The WP_List_Table class does
 *      the heavy lifting — we just wrap it with a page title, Add New button,
 *      and success/error notices.
 */
function sp_render_events_page(): void {
    $table = new SP_Events_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Events</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-event-edit' ) ); ?>" class="page-title-action">
            Add New
        </a>
        <hr class="wp-header-end">

        <?php
        // Success notices
        if ( isset( $_GET['deleted'] ) ) {
            $count = (int) $_GET['deleted'];
            if ( $count > 0 ) {
                printf(
                    '<div class="notice notice-success is-dismissible"><p>%s deleted.</p></div>',
                    $count === 1 ? '1 event' : $count . ' events'
                );
            }
        }
        if ( isset( $_GET['cancelled'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>Event cancelled.</p></div>';
        }
        if ( isset( $_GET['saved'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>Event saved.</p></div>';
        }
        ?>

        <form method="get">
            <input type="hidden" name="page" value="sp-events">
            <?php
            $table->search_box( 'Search Events', 'sp-event-search' );
            $table->display();
            ?>
        </form>
    </div>
    <?php
}


// ============================================================================
// EVENTS — SAVE HANDLER (runs on admin_init before any output)
// ============================================================================
//
// WHY: Same pattern as the member save handler — we process the form submission
//      on admin_init so we can redirect cleanly after saving. If we tried to
//      save inside the page callback, headers would already be sent.
// ============================================================================

add_action( 'admin_init', function () {
    if ( ! isset( $_POST['sp_event_nonce'] ) ) {
        return;
    }
    if ( ! wp_verify_nonce( $_POST['sp_event_nonce'], 'sp_save_event' ) ) {
        wp_die( 'Security check failed.' );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'Unauthorized.' );
    }

    global $wpdb;
    $events_table = $wpdb->prefix . 'sp_events';
    $event_id     = (int) ( $_POST['event_id'] ?? 0 );

    // Generate a URL-safe slug from the title
    // WHY: Slugs are used in frontend event URLs (?sp_event=slug). We create
    //      them from the title automatically so Harold doesn't have to think
    //      about URL formatting. sanitize_title() handles the heavy lifting.
    $title = sanitize_text_field( $_POST['event_title'] ?? '' );
    $slug  = sanitize_title( $title );

    // Ensure slug uniqueness — append a number if the slug already exists
    // for a different event.
    $existing_slug = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$events_table} WHERE slug = %s AND id != %d",
        $slug, $event_id
    ) );
    if ( $existing_slug ) {
        $slug .= '-' . time();
    }

    // Build the data array for insert/update
    $data = [
        'title'                => $title,
        'slug'                 => $slug,
        'description'          => wp_kses_post( $_POST['event_description'] ?? '' ),
        'category_id'          => ! empty( $_POST['event_category_id'] ) ? (int) $_POST['event_category_id'] : null,
        'status'               => in_array( $_POST['event_status'] ?? '', [ 'scheduled', 'cancelled', 'postponed', 'completed' ], true )
                                  ? $_POST['event_status'] : 'scheduled',
        'event_date'           => sanitize_text_field( $_POST['event_date'] ?? '' ),
        'start_time'           => ! empty( $_POST['event_start_time'] ) ? sanitize_text_field( $_POST['event_start_time'] ) : null,
        'end_time'             => ! empty( $_POST['event_end_time'] ) ? sanitize_text_field( $_POST['event_end_time'] ) : null,
        'location_name'        => sanitize_text_field( $_POST['event_location_name'] ?? '' ),
        'location_address'     => sanitize_textarea_field( $_POST['event_location_address'] ?? '' ),
        'is_virtual'           => ! empty( $_POST['event_is_virtual'] ) ? 1 : 0,
        'virtual_url'          => esc_url_raw( $_POST['event_virtual_url'] ?? '' ),
        'image_id'             => ! empty( $_POST['event_image_id'] ) ? (int) $_POST['event_image_id'] : null,
        'visibility'           => in_array( $_POST['event_visibility'] ?? '', [ 'public', 'members_only' ], true )
                                  ? $_POST['event_visibility'] : 'public',
        'registration_enabled' => ! empty( $_POST['event_registration_enabled'] ) ? 1 : 0,
        'registration_limit'   => ! empty( $_POST['event_registration_limit'] ) ? (int) $_POST['event_registration_limit'] : null,
        'guest_registration'   => ! empty( $_POST['event_guest_registration'] ) ? 1 : 0,
        'member_price'         => ! empty( $_POST['event_member_price'] ) ? number_format( (float) $_POST['event_member_price'], 2, '.', '' ) : '0.00',
        'nonmember_price'      => ! empty( $_POST['event_nonmember_price'] ) ? number_format( (float) $_POST['event_nonmember_price'], 2, '.', '' ) : '0.00',
        'payment_mode'         => in_array( $_POST['event_payment_mode'] ?? '', [ 'none', 'at_door', 'online', 'either' ], true )
                                  ? $_POST['event_payment_mode'] : 'none',
        'price_description'    => sanitize_text_field( $_POST['event_price_description'] ?? '' ),
        'contact_name'         => sanitize_text_field( $_POST['event_contact_name'] ?? '' ),
        'contact_email'        => sanitize_email( $_POST['event_contact_email'] ?? '' ),
        'contact_phone'        => sanitize_text_field( $_POST['event_contact_phone'] ?? '' ),
    ];

    if ( $event_id > 0 ) {
        // Capture old event data BEFORE updating — we need to compare fields
        // to decide whether to send update/cancellation emails to registrants.
        $old_event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$events_table} WHERE id = %d", $event_id
        ) );

        // Update existing event
        $wpdb->update( $events_table, $data, [ 'id' => $event_id ] );

        // Check if we need to notify registrants about changes
        if ( $old_event && $old_event->registration_enabled ) {
            // Event cancelled — notify all confirmed/waitlisted registrants
            if ( $old_event->status === 'scheduled' && $data['status'] === 'cancelled' ) {
                sp_send_event_cancellation_emails( $event_id, $old_event->title );
            }
            // Key details changed (date, time, location) — notify registrants
            elseif ( $data['status'] === 'scheduled' ) {
                $changed_fields = [];
                if ( $old_event->event_date !== $data['event_date'] ) {
                    $changed_fields[] = 'date';
                }
                if ( $old_event->start_time !== $data['start_time'] || $old_event->end_time !== $data['end_time'] ) {
                    $changed_fields[] = 'time';
                }
                if ( $old_event->location_name !== $data['location_name'] || $old_event->location_address !== $data['location_address'] ) {
                    $changed_fields[] = 'location';
                }
                if ( ! empty( $changed_fields ) ) {
                    $new_event = $wpdb->get_row( $wpdb->prepare(
                        "SELECT * FROM {$events_table} WHERE id = %d", $event_id
                    ) );
                    sp_send_event_update_emails( $new_event, $changed_fields );
                }
            }
        }
    } else {
        // Insert new event
        $data['created_by'] = get_current_user_id();
        $wpdb->insert( $events_table, $data );
        $event_id = $wpdb->insert_id;
    }

    // ---- Save speaker assignments ----
    // WHY: Speaker assignments are a many-to-many relationship. We delete all
    //      existing assignments for this event and re-insert from the form data.
    //      This is simpler than tracking individual adds/removes and handles
    //      reordering naturally.
    $assign_table = $wpdb->prefix . 'sp_event_speaker_assignments';
    $wpdb->delete( $assign_table, [ 'event_id' => $event_id ], [ '%d' ] );

    if ( ! empty( $_POST['event_speakers'] ) && is_array( $_POST['event_speakers'] ) ) {
        $sort = 0;
        foreach ( $_POST['event_speakers'] as $speaker_data ) {
            $speaker_id = (int) ( $speaker_data['id'] ?? 0 );
            if ( $speaker_id > 0 ) {
                $role = in_array( $speaker_data['role'] ?? '', [ 'speaker', 'instructor', 'moderator', 'panelist' ], true )
                    ? $speaker_data['role'] : 'speaker';
                $wpdb->insert( $assign_table, [
                    'event_id'   => $event_id,
                    'speaker_id' => $speaker_id,
                    'role'       => $role,
                    'sort_order' => $sort++,
                ] );
            }
        }
    }

    // ---- Save time slots ----
    // WHY: The repeatable slot rows in the form are processed here. We pass
    //      the entire array to sp_slots_save_event() which handles creates,
    //      updates, and soft-deletes for removed rows.
    if ( ! empty( $_POST['event_slots'] ) && is_array( $_POST['event_slots'] ) ) {
        sp_slots_save_event( $event_id, $_POST['event_slots'] );
    } else {
        // No slots submitted — if event had slots before, soft-delete them all
        // (only if this is an existing event, not a new one)
        if ( $event_id > 0 ) {
            $existing_slot_count = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$wpdb->prefix}sp_event_slots WHERE event_id = %d AND is_active = 1",
                $event_id
            ) );
            if ( (int) $existing_slot_count > 0 ) {
                sp_slots_delete_by_event( $event_id, true );
            }
        }
    }

    // ---- Save recurrence rule ----
    // WHY: If this is a new event or an existing parent event, save the
    //      recurrence rule and end date so "Generate Occurrences" can work.
    $recurrence_type = sanitize_text_field( $_POST['event_recurrence_type'] ?? '' );
    if ( $recurrence_type && ! empty( $data['event_date'] ) ) {
        $event_date_ts = strtotime( $data['event_date'] );
        $rule = '';

        if ( $recurrence_type === 'weekly' ) {
            // weekly:N where N = day of week (0=Sun, 6=Sat)
            $rule = 'weekly:' . date( 'w', $event_date_ts );
        } elseif ( $recurrence_type === 'monthly-nth' ) {
            // monthly-nth:W-D where W = week number (1-5), D = day of week
            $day_of_week = (int) date( 'w', $event_date_ts );
            $day_of_month = (int) date( 'j', $event_date_ts );
            $week_num = (int) ceil( $day_of_month / 7 );
            $rule = 'monthly-nth:' . $week_num . '-' . $day_of_week;
        } elseif ( $recurrence_type === 'monthly-date' ) {
            // monthly-date:D where D = day of month
            $rule = 'monthly-date:' . date( 'j', $event_date_ts );
        }

        if ( $rule ) {
            $end_date = ! empty( $_POST['event_recurrence_end'] )
                ? sanitize_text_field( $_POST['event_recurrence_end'] )
                : date( 'Y-m-d', strtotime( '+12 months', $event_date_ts ) );

            $wpdb->update( $events_table, [
                'recurrence_rule'     => $rule,
                'recurrence_end_date' => $end_date,
            ], [ 'id' => $event_id ] );
        }
    } elseif ( empty( $recurrence_type ) ) {
        // Recurrence was removed — clear the rule but keep existing children
        $wpdb->update( $events_table, [
            'recurrence_rule'     => null,
            'recurrence_end_date' => null,
        ], [ 'id' => $event_id ] );
    }

    wp_redirect( admin_url( 'admin.php?page=sp-events&saved=1' ) );
    exit;
});


// ============================================================================
// EVENTS — ADD/EDIT PAGE RENDERER
// ============================================================================
//
// WHY: One form handles both "Add New Event" and "Edit Event." If an event_id
//      is in the URL, we load that event's data and pre-fill the form. If not,
//      we show empty fields with sensible defaults from Settings.
//
// SECTIONS:
//   1. Basic Info     — Title, Category, Status, Description, Featured Image
//   2. Date & Time    — Date, Start Time, End Time
//   3. Location       — Name, Address, Virtual checkbox + URL
//   4. Registration   — Enable toggle, Limit, Guest reg, Visibility, Pricing
//   5. Contact        — Name, Email, Phone
// ============================================================================

// WHY: wp_enqueue_media() must run during admin_enqueue_scripts — NOT inside
//      the page callback. If called during render, the media modal scripts
//      arrive after wp_head() and wp.media is undefined, so the "Select Image"
//      button silently does nothing.
add_action( 'admin_enqueue_scripts', function ( $hook ) {
    if ( strpos( $hook, 'sp-event-edit' ) === false ) {
        return;
    }
    wp_enqueue_media();
});

function sp_render_event_edit_page(): void {
    global $wpdb;

    $event_id = (int) ( $_GET['event_id'] ?? 0 );
    $event    = null;
    $settings = get_option( 'societypress_settings', [] );

    // Load existing event data if editing
    if ( $event_id > 0 ) {
        $event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d",
            $event_id
        ) );
        if ( ! $event ) {
            echo '<div class="wrap"><h1>Event Not Found</h1><p>The requested event does not exist.</p></div>';
            return;
        }
    }

    // Helper to get field value: from event if editing, or default
    $val = function ( string $field, $default = '' ) use ( $event ) {
        if ( $event && isset( $event->$field ) ) {
            return $event->$field;
        }
        return $default;
    };

    // Fetch categories for the dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order"
    );

    $page_title = $event ? 'Edit Event' : 'Add New Event';

    // Default values from settings for new events
    $default_visibility   = $settings['events_default_visibility'] ?? 'public';
    $default_registration = $settings['events_default_registration'] ?? 0;
    $default_guest_reg    = $settings['events_guest_registration'] ?? 0;

    ?>
    <div class="wrap">
        <h1><?php echo esc_html( $page_title ); ?></h1>

        <?php if ( isset( $_GET['duplicated'] ) ) : ?>
            <div class="notice notice-info is-dismissible">
                <p>Event duplicated. Update the details below and save.</p>
            </div>
        <?php endif; ?>

        <form method="post">
            <?php wp_nonce_field( 'sp_save_event', 'sp_event_nonce' ); ?>
            <input type="hidden" name="event_id" value="<?php echo esc_attr( $event_id ); ?>">

            <table class="form-table" role="presentation">

                <!-- ============================================================ -->
                <!-- SECTION 1: Basic Info                                         -->
                <!-- ============================================================ -->

                <tr>
                    <td colspan="2" style="padding: 0;">
                        <h2 style="margin: 20px 0 0 0; padding-bottom: 8px; border-bottom: 1px solid #c3c4c7;">Basic Info</h2>
                    </td>
                </tr>

                <tr>
                    <th scope="row"><label for="event_title">Title <span style="color: #d63638;">*</span></label></th>
                    <td>
                        <input type="text" id="event_title" name="event_title"
                               value="<?php echo esc_attr( $val( 'title' ) ); ?>"
                               class="large-text" required>
                    </td>
                </tr>

                <tr>
                    <th scope="row"><label for="event_category_id">Category</label></th>
