                        <?php endforeach; ?>
                    <?php endif; ?>
                </tbody>
            </table>
        </div>
    </div>

    <script>
    /**
     * Event Categories AJAX management.
     *
     * WHY: Inline editing with AJAX saves is much faster than full-page reloads
     *      for a simple CRUD table like this. Harold can rename a category, change
     *      its color, and save — all without leaving the page.
     */
    (function() {
        'use strict';

        var ajaxUrl = '<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>';
        var nonce   = document.getElementById('sp_cat_nonce').value;

        // ---- Color picker: update hex display as user picks ----
        var colorInput = document.getElementById('sp-cat-color');
        var colorHex   = document.getElementById('sp-cat-color-hex');
        if (colorInput && colorHex) {
            colorInput.addEventListener('input', function() {
                colorHex.textContent = this.value;
            });
        }

        // ---- Add New Category ----
        var addForm   = document.getElementById('sp-add-category-form');
        var addStatus = document.getElementById('sp-cat-add-status');

        addForm.addEventListener('submit', function(e) {
            e.preventDefault();

            var name  = document.getElementById('sp-cat-name').value.trim();
            var color = document.getElementById('sp-cat-color').value;
            var sort  = document.getElementById('sp-cat-sort').value;

            if (!name) return;

            addStatus.textContent = 'Saving...';
            addStatus.style.color = '#787c82';

            var data = new FormData();
            data.append('action', 'sp_save_event_category');
            data.append('nonce', nonce);
            data.append('name', name);
            data.append('color', color);
            data.append('sort_order', sort);

            fetch(ajaxUrl, { method: 'POST', body: data })
                .then(function(r) { return r.json(); })
                .then(function(r) {
                    if (r.success) {
                        addStatus.textContent = 'Saved!';
                        addStatus.style.color = '#00a32a';
                        // Reload to show the new row (simpler than DOM manipulation)
                        setTimeout(function() { location.reload(); }, 500);
                    } else {
                        addStatus.textContent = r.data.message || 'Error saving.';
                        addStatus.style.color = '#d63638';
                    }
                })
                .catch(function() {
                    addStatus.textContent = 'Network error.';
                    addStatus.style.color = '#d63638';
                });
        });

        // ---- Inline Edit / Save / Cancel / Delete ----
        var table = document.getElementById('sp-categories-table');
        if (!table) return;

        table.addEventListener('click', function(e) {
            var btn = e.target;
            var row = btn.closest('tr');
            if (!row) return;

            var catId = row.getAttribute('data-cat-id');

            // EDIT: Show input fields, hide display text
            if (btn.classList.contains('sp-cat-edit-btn')) {
                row.querySelectorAll('[class*="sp-cat-display"]').forEach(function(el) { el.style.display = 'none'; });
                row.querySelectorAll('[class*="sp-cat-edit-"]').forEach(function(el) {
                    if (!el.classList.contains('sp-cat-edit-btn')) el.style.display = '';
                });
                btn.style.display = 'none';
                row.querySelector('.sp-cat-save-btn').style.display = '';
                row.querySelector('.sp-cat-cancel-btn').style.display = '';
                var delBtn = row.querySelector('.sp-cat-delete-btn');
                if (delBtn) delBtn.style.display = 'none';
            }

            // CANCEL: Revert to display mode
            if (btn.classList.contains('sp-cat-cancel-btn')) {
                row.querySelectorAll('[class*="sp-cat-display"]').forEach(function(el) { el.style.display = ''; });
                row.querySelectorAll('.sp-cat-edit-name, .sp-cat-edit-color, .sp-cat-edit-sort').forEach(function(el) { el.style.display = 'none'; });
                row.querySelector('.sp-cat-edit-active').style.display = 'none';
                row.querySelector('.sp-cat-edit-btn').style.display = '';
                btn.style.display = 'none';
                row.querySelector('.sp-cat-save-btn').style.display = 'none';
                var delBtn = row.querySelector('.sp-cat-delete-btn');
                if (delBtn) delBtn.style.display = '';
            }

            // SAVE: Send updated values via AJAX
            if (btn.classList.contains('sp-cat-save-btn')) {
                var name   = row.querySelector('.sp-cat-edit-name').value.trim();
                var color  = row.querySelector('.sp-cat-edit-color').value;
                var sort   = row.querySelector('.sp-cat-edit-sort').value;
                var active = row.querySelector('.sp-cat-edit-active-cb').checked ? 1 : 0;

                if (!name) { alert('Category name is required.'); return; }

                btn.textContent = 'Saving...';
                btn.disabled = true;

                var data = new FormData();
                data.append('action', 'sp_save_event_category');
                data.append('nonce', nonce);
                data.append('category_id', catId);
                data.append('name', name);
                data.append('color', color);
                data.append('sort_order', sort);
                data.append('active', active);

                fetch(ajaxUrl, { method: 'POST', body: data })
                    .then(function(r) { return r.json(); })
                    .then(function(r) {
                        if (r.success) {
                            // Update display values
                            row.querySelector('.sp-cat-display-name').textContent = name;
                            row.querySelector('.sp-cat-display-color').style.background = color;
                            row.querySelector('.sp-cat-display-sort').textContent = sort;
                            row.querySelector('.sp-cat-display-active').textContent = active ? '✓' : '—';

                            // Switch back to display mode
                            row.querySelectorAll('[class*="sp-cat-display"]').forEach(function(el) { el.style.display = ''; });
                            row.querySelectorAll('.sp-cat-edit-name, .sp-cat-edit-color, .sp-cat-edit-sort').forEach(function(el) { el.style.display = 'none'; });
                            row.querySelector('.sp-cat-edit-active').style.display = 'none';
                            row.querySelector('.sp-cat-edit-btn').style.display = '';
                            row.querySelector('.sp-cat-save-btn').style.display = 'none';
                            row.querySelector('.sp-cat-cancel-btn').style.display = 'none';
                            var delBtn = row.querySelector('.sp-cat-delete-btn');
                            if (delBtn) delBtn.style.display = '';
                        } else {
                            alert(r.data.message || 'Error saving category.');
                        }
                        btn.textContent = 'Save';
                        btn.disabled = false;
                    })
                    .catch(function() {
                        alert('Network error. Please try again.');
                        btn.textContent = 'Save';
                        btn.disabled = false;
                    });
            }

            // DELETE: Remove category via AJAX
            if (btn.classList.contains('sp-cat-delete-btn')) {
                if (!confirm('Delete this category? This cannot be undone.')) return;

                btn.textContent = 'Deleting...';
                btn.disabled = true;

                var data = new FormData();
                data.append('action', 'sp_delete_event_category');
                data.append('nonce', nonce);
                data.append('category_id', catId);

                fetch(ajaxUrl, { method: 'POST', body: data })
                    .then(function(r) { return r.json(); })
                    .then(function(r) {
                        if (r.success) {
                            row.remove();
                            // Show empty message if no rows left
                            var tbody = table.querySelector('tbody');
                            if (!tbody.querySelector('tr[data-cat-id]')) {
                                var emptyRow = document.createElement('tr');
                                emptyRow.id = 'sp-no-categories-row';
                                emptyRow.innerHTML = '<td colspan="6" style="text-align: center; color: #787c82; padding: 20px;">No categories yet. Add one above.</td>';
                                tbody.appendChild(emptyRow);
                            }
                        } else {
                            alert(r.data.message || 'Error deleting category.');
                            btn.textContent = 'Delete';
                            btn.disabled = false;
                        }
                    })
                    .catch(function() {
                        alert('Network error. Please try again.');
                        btn.textContent = 'Delete';
                        btn.disabled = false;
                    });
            }
        });
    })();
    </script>
    <?php
}


// ============================================================================
// EVENT CATEGORIES — AJAX HANDLERS
// ============================================================================
//
// WHY: The categories page uses AJAX for add/edit/delete operations so Harold
//      doesn't have to wait for full page reloads. These handlers process the
//      AJAX requests and return JSON responses.
// ============================================================================

/**
 * AJAX: Save (create or update) an event category.
 *
 * WHY: Handles both "Add New" (no category_id) and inline edit (with category_id).
 *      We generate the slug automatically from the name so Harold never has to
 *      think about URL formatting.
 */
add_action( 'wp_ajax_sp_save_event_category', function () {
    // Security checks
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_event_category_nonce' ) ) {
        wp_send_json_error( [ 'message' => 'Security check failed.' ] );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Unauthorized.' ] );
    }

    global $wpdb;
    $table = $wpdb->prefix . 'sp_event_categories';

    $category_id = (int) ( $_POST['category_id'] ?? 0 );
    $name        = sanitize_text_field( $_POST['name'] ?? '' );
    $color       = sanitize_hex_color( $_POST['color'] ?? '#2271b1' ) ?: '#2271b1';
    $sort_order  = (int) ( $_POST['sort_order'] ?? 0 );
    $active      = isset( $_POST['active'] ) ? (int) $_POST['active'] : 1;

    if ( empty( $name ) ) {
        wp_send_json_error( [ 'message' => 'Category name is required.' ] );
    }

    // Generate slug from name
    $slug = sanitize_title( $name );

    // Ensure slug uniqueness
    $existing = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE slug = %s AND id != %d",
        $slug, $category_id
    ) );
    if ( $existing ) {
        $slug .= '-' . time();
    }

    $data = [
        'name'       => $name,
        'slug'       => $slug,
        'color'      => $color,
        'sort_order' => $sort_order,
        'active'     => $active,
    ];

    if ( $category_id > 0 ) {
        // Update existing
        $wpdb->update( $table, $data, [ 'id' => $category_id ] );
    } else {
        // Insert new
        $wpdb->insert( $table, $data );
        $category_id = $wpdb->insert_id;
    }

    wp_send_json_success( [ 'id' => $category_id, 'slug' => $slug ] );
});

/**
 * AJAX: Delete an event category.
 *
 * WHY: Categories with events assigned can't be deleted — that would leave
 *      orphaned category_id references. The admin must reassign or remove
 *      the category from those events first.
 */
add_action( 'wp_ajax_sp_delete_event_category', function () {
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_event_category_nonce' ) ) {
        wp_send_json_error( [ 'message' => 'Security check failed.' ] );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Unauthorized.' ] );
    }

    global $wpdb;

    $category_id = (int) ( $_POST['category_id'] ?? 0 );
    if ( $category_id <= 0 ) {
        wp_send_json_error( [ 'message' => 'Invalid category.' ] );
    }

    // Check if any events use this category
    $event_count = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$wpdb->prefix}sp_events WHERE category_id = %d",
        $category_id
    ) );

    if ( $event_count > 0 ) {
        wp_send_json_error( [
            'message' => "Can't delete — {$event_count} event(s) use this category. Remove the category from those events first."
        ] );
    }

    $wpdb->delete( $wpdb->prefix . 'sp_event_categories', [ 'id' => $category_id ], [ '%d' ] );

    wp_send_json_success();
});


