    <script>
    /**
     * Membership Plans AJAX management.
     *
     * WHY: Inline editing with AJAX saves is much faster than full-page reloads
     *      for a simple CRUD table like this. Harold can rename a plan, change
     *      its price, and save — all without leaving the page.
     *
     *      This mirrors the Event Categories JS pattern exactly so the codebase
     *      stays consistent and predictable.
     */
    (function() {
        'use strict';

        var ajaxUrl = '<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>';
        var nonce   = document.getElementById('sp_tier_nonce').value;

        // ---- Lifetime checkbox: disable/enable duration field in Add form ----
        var lifetimeCb    = document.getElementById('sp-tier-lifetime');
        var durationInput = document.getElementById('sp-tier-duration');
        if (lifetimeCb && durationInput) {
            lifetimeCb.addEventListener('change', function() {
                durationInput.disabled = this.checked;
                if (this.checked) durationInput.value = '';
            });
        }

        // ---- Add New Plan ----
        var addForm   = document.getElementById('sp-add-tier-form');
        var addStatus = document.getElementById('sp-tier-add-status');

        addForm.addEventListener('submit', function(e) {
            e.preventDefault();

            var name     = document.getElementById('sp-tier-name').value.trim();
            var price    = document.getElementById('sp-tier-price').value;
            var duration = lifetimeCb.checked ? '' : document.getElementById('sp-tier-duration').value;
            var sort     = document.getElementById('sp-tier-sort').value;
            var lifetime = lifetimeCb.checked ? '1' : '0';

            if (!name) return;

            addStatus.textContent = 'Saving...';
            addStatus.style.color = '#787c82';

            var data = new FormData();
            data.append('action', 'sp_save_membership_tier');
            data.append('nonce', nonce);
            data.append('name', name);
            data.append('price', price);
            data.append('duration_months', duration);
            data.append('lifetime', lifetime);
            data.append('sort_order', sort);

            fetch(ajaxUrl, { method: 'POST', body: data })
                .then(function(r) { return r.json(); })
                .then(function(r) {
                    if (r.success) {
                        addStatus.textContent = 'Saved!';
                        addStatus.style.color = '#00a32a';
                        // Reload to show the new row (simpler than DOM manipulation)
                        setTimeout(function() { location.reload(); }, 500);
                    } else {
                        addStatus.textContent = r.data.message || 'Error saving.';
                        addStatus.style.color = '#d63638';
                    }
                })
                .catch(function() {
                    addStatus.textContent = 'Network error.';
                    addStatus.style.color = '#d63638';
                });
        });

        // ---- Inline Edit / Save / Cancel / Delete ----
        var table = document.getElementById('sp-tiers-table');
        if (!table) return;

        table.addEventListener('click', function(e) {
            var btn = e.target;
            var row = btn.closest('tr');
            if (!row) return;

            var tierId = row.getAttribute('data-tier-id');

            // EDIT: Show input fields, hide display text
            if (btn.classList.contains('sp-tier-edit-btn')) {
                row.querySelectorAll('[class*="sp-tier-display"]').forEach(function(el) { el.style.display = 'none'; });
                row.querySelectorAll('[class*="sp-tier-edit-"]').forEach(function(el) {
                    if (!el.classList.contains('sp-tier-edit-btn')) el.style.display = '';
                });
                btn.style.display = 'none';
                row.querySelector('.sp-tier-save-btn').style.display = '';
                row.querySelector('.sp-tier-cancel-btn').style.display = '';
                var delBtn = row.querySelector('.sp-tier-delete-btn');
                if (delBtn) delBtn.style.display = 'none';

                // Wire up inline lifetime checkbox to disable/enable duration
                var inlineLtCb = row.querySelector('.sp-tier-edit-lifetime-cb');
                var inlineDur  = row.querySelector('.sp-tier-edit-duration');
                if (inlineLtCb && inlineDur) {
                    inlineLtCb.onchange = function() {
                        inlineDur.disabled = this.checked;
                        if (this.checked) inlineDur.value = '';
                    };
                }
            }

            // CANCEL: Revert to display mode
            if (btn.classList.contains('sp-tier-cancel-btn')) {
                row.querySelectorAll('[class*="sp-tier-display"]').forEach(function(el) { el.style.display = ''; });
                row.querySelectorAll('.sp-tier-edit-name, .sp-tier-edit-price, .sp-tier-edit-sort').forEach(function(el) { el.style.display = 'none'; });
                row.querySelector('.sp-tier-edit-duration-wrap').style.display = 'none';
                row.querySelector('.sp-tier-edit-active').style.display = 'none';
                row.querySelector('.sp-tier-edit-btn').style.display = '';
                btn.style.display = 'none';
                row.querySelector('.sp-tier-save-btn').style.display = 'none';
                var delBtn = row.querySelector('.sp-tier-delete-btn');
                if (delBtn) delBtn.style.display = '';
            }

            // SAVE: Send updated values via AJAX
            if (btn.classList.contains('sp-tier-save-btn')) {
                var name     = row.querySelector('.sp-tier-edit-name').value.trim();
                var price    = row.querySelector('.sp-tier-edit-price').value;
                var sort     = row.querySelector('.sp-tier-edit-sort').value;
                var active   = row.querySelector('.sp-tier-edit-active-cb').checked ? 1 : 0;
                var ltCb     = row.querySelector('.sp-tier-edit-lifetime-cb');
                var lifetime = ltCb.checked ? '1' : '0';
                var duration = ltCb.checked ? '' : row.querySelector('.sp-tier-edit-duration').value;

                if (!name) { alert('Plan name is required.'); return; }

                btn.textContent = 'Saving...';
                btn.disabled = true;

                var data = new FormData();
                data.append('action', 'sp_save_membership_tier');
                data.append('nonce', nonce);
                data.append('tier_id', tierId);
                data.append('name', name);
                data.append('price', price);
                data.append('duration_months', duration);
                data.append('lifetime', lifetime);
                data.append('sort_order', sort);
                data.append('active', active);

                fetch(ajaxUrl, { method: 'POST', body: data })
                    .then(function(r) { return r.json(); })
                    .then(function(r) {
                        if (r.success) {
                            // Update display values
                            row.querySelector('.sp-tier-display-name').textContent = name;
                            row.querySelector('.sp-tier-display-price').textContent = '$' + parseFloat(price).toFixed(2);
                            row.querySelector('.sp-tier-display-sort').textContent = sort;
                            row.querySelector('.sp-tier-display-active').innerHTML = active ? '&#10003;' : '&mdash;';

                            // Duration display
                            if (lifetime === '1') {
                                row.querySelector('.sp-tier-display-duration').textContent = 'Lifetime';
                            } else {
                                var m = parseInt(duration, 10);
                                row.querySelector('.sp-tier-display-duration').textContent = m + ' month' + (m !== 1 ? 's' : '');
                            }

                            // Switch back to display mode
                            row.querySelectorAll('[class*="sp-tier-display"]').forEach(function(el) { el.style.display = ''; });
                            row.querySelectorAll('.sp-tier-edit-name, .sp-tier-edit-price, .sp-tier-edit-sort').forEach(function(el) { el.style.display = 'none'; });
                            row.querySelector('.sp-tier-edit-duration-wrap').style.display = 'none';
                            row.querySelector('.sp-tier-edit-active').style.display = 'none';
                            row.querySelector('.sp-tier-edit-btn').style.display = '';
                            row.querySelector('.sp-tier-save-btn').style.display = 'none';
                            row.querySelector('.sp-tier-cancel-btn').style.display = 'none';
                            var delBtn = row.querySelector('.sp-tier-delete-btn');
                            if (delBtn) delBtn.style.display = '';
                        } else {
                            alert(r.data.message || 'Error saving plan.');
                        }
                        btn.textContent = 'Save';
                        btn.disabled = false;
                    })
                    .catch(function() {
                        alert('Network error. Please try again.');
                        btn.textContent = 'Save';
                        btn.disabled = false;
                    });
            }

            // DELETE: Remove tier via AJAX (only possible when 0 members assigned)
            if (btn.classList.contains('sp-tier-delete-btn')) {
                if (!confirm('Delete this membership plan? This cannot be undone.')) return;

                btn.textContent = 'Deleting...';
                btn.disabled = true;

                var data = new FormData();
                data.append('action', 'sp_delete_membership_tier');
                data.append('nonce', nonce);
                data.append('tier_id', tierId);

                fetch(ajaxUrl, { method: 'POST', body: data })
                    .then(function(r) { return r.json(); })
                    .then(function(r) {
                        if (r.success) {
                            row.remove();
                            // Show empty message if no rows left
                            var tbody = table.querySelector('tbody');
                            if (!tbody.querySelector('tr[data-tier-id]')) {
                                var emptyRow = document.createElement('tr');
                                emptyRow.id = 'sp-no-tiers-row';
                                emptyRow.innerHTML = '<td colspan="7" style="text-align: center; color: #787c82; padding: 20px;">No membership plans yet. Add one above.</td>';
                                tbody.appendChild(emptyRow);
                            }
                        } else {
                            alert(r.data.message || 'Error deleting plan.');
                            btn.textContent = 'Delete';
                            btn.disabled = false;
                        }
                    })
                    .catch(function() {
                        alert('Network error. Please try again.');
                        btn.textContent = 'Delete';
                        btn.disabled = false;
                    });
            }
        });
    })();
    </script>
    <?php
}


// ============================================================================
// MEMBERSHIP PLANS — AJAX HANDLERS
// ============================================================================
//
// WHY: The Membership Plans page uses AJAX for add/edit/delete operations so
//      Harold doesn't have to wait for full page reloads. These handlers
//      process the AJAX requests and return JSON responses.
// ============================================================================

/**
 * AJAX: Save (create or update) a membership tier.
 *
 * WHY: Handles both "Add New Plan" (no tier_id) and inline edit (with tier_id).
 *      The lifetime checkbox sets duration_months to NULL, which means the
 *      membership never expires — perfect for Lifetime and Honorary tiers.
 */
add_action( 'wp_ajax_sp_save_membership_tier', function () {
    // Security checks
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_membership_tier_nonce' ) ) {
        wp_send_json_error( [ 'message' => 'Security check failed.' ] );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Unauthorized.' ] );
    }

    global $wpdb;
    $table = $wpdb->prefix . 'sp_membership_tiers';

    $tier_id         = (int) ( $_POST['tier_id'] ?? 0 );
    $name            = sanitize_text_field( $_POST['name'] ?? '' );
    $price           = floatval( $_POST['price'] ?? 0 );
    $lifetime        = ( $_POST['lifetime'] ?? '0' ) === '1';
    $duration_months = $lifetime ? null : max( 1, (int) ( $_POST['duration_months'] ?? 12 ) );
    $sort_order      = (int) ( $_POST['sort_order'] ?? 0 );
    $active          = isset( $_POST['active'] ) ? (int) $_POST['active'] : 1;

    if ( empty( $name ) ) {
        wp_send_json_error( [ 'message' => 'Plan name is required.' ] );
    }

    // Check for duplicate name (different row)
    $existing = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE name = %s AND id != %d",
        $name, $tier_id
    ) );
    if ( $existing ) {
        wp_send_json_error( [ 'message' => 'A plan with that name already exists.' ] );
    }

    $data = [
        'name'            => $name,
        'price'           => $price,
        'duration_months' => $duration_months,
        'sort_order'      => $sort_order,
        'active'          => $active,
    ];

    // Format strings for wpdb — NULL needs special handling for duration_months
    $formats = [ '%s', '%f', $lifetime ? null : '%d', '%d', '%d' ];

    if ( $tier_id > 0 ) {
        // Update existing tier
        // WHY: We can't use $wpdb->update() directly because it doesn't handle
        //      NULL values well for duration_months. We build the query manually
        //      when lifetime is selected so we get a proper SQL NULL.
        if ( $lifetime ) {
            $wpdb->query( $wpdb->prepare(
                "UPDATE {$table} SET name = %s, price = %f, duration_months = NULL, sort_order = %d, active = %d WHERE id = %d",
                $name, $price, $sort_order, $active, $tier_id
            ) );
        } else {
            $wpdb->update( $table, $data, [ 'id' => $tier_id ], [ '%s', '%f', '%d', '%d', '%d' ], [ '%d' ] );
        }
    } else {
        // Insert new tier
        if ( $lifetime ) {
            $wpdb->query( $wpdb->prepare(
                "INSERT INTO {$table} (name, price, duration_months, sort_order, active) VALUES (%s, %f, NULL, %d, %d)",
                $name, $price, $sort_order, $active
            ) );
            $tier_id = $wpdb->insert_id;
        } else {
            $wpdb->insert( $table, $data, [ '%s', '%f', '%d', '%d', '%d' ] );
            $tier_id = $wpdb->insert_id;
        }
    }

    wp_send_json_success( [ 'id' => $tier_id ] );
});

/**
 * AJAX: Delete a membership tier.
 *
 * WHY: Tiers with members assigned can't be deleted — that would leave orphaned
 *      tier_id references on those member records. The admin must reassign
 *      members to a different tier first. The Delete button is only shown in
 *      the UI when the member count is 0, but we double-check server-side.
 */
add_action( 'wp_ajax_sp_delete_membership_tier', function () {
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_membership_tier_nonce' ) ) {
        wp_send_json_error( [ 'message' => 'Security check failed.' ] );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => 'Unauthorized.' ] );
    }

    global $wpdb;

    $tier_id = (int) ( $_POST['tier_id'] ?? 0 );
    if ( $tier_id <= 0 ) {
        wp_send_json_error( [ 'message' => 'Invalid plan.' ] );
    }

    // Check if any members use this tier
    $member_count = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$wpdb->prefix}sp_members WHERE tier_id = %d",
        $tier_id
    ) );

    if ( $member_count > 0 ) {
        wp_send_json_error( [
            'message' => "Can't delete — {$member_count} member(s) are on this plan. Reassign them to a different plan first."
        ] );
    }

    $wpdb->delete( $wpdb->prefix . 'sp_membership_tiers', [ 'id' => $tier_id ], [ '%d' ] );

    wp_send_json_success();
});


