    // WHY: Harold just pasted two cryptic strings. A "Test Connection" button
    //      that immediately tells him "it works!" (or "it doesn't") is the
    //      difference between confidence and calling his grandson. We fire
    //      an AJAX request that creates a tiny test PaymentIntent on Stripe's
    //      side — if it succeeds, the keys are valid.
    add_settings_field(
        'stripe_test_connection',
        'Verify Setup',
        function () {
            ?>
            <button type="button" class="button button-secondary" id="sp-stripe-test-btn">
                <span class="dashicons dashicons-superhero-alt" style="margin-top: 4px; margin-right: 2px;"></span>
                Test Connection
            </button>
            <span id="sp-stripe-test-result" style="margin-left: 12px; font-weight: 500;"></span>
            <p class="description">Checks that your API keys are valid. Save your settings first, then click this button.</p>
            <script>
            (function() {
                var btn = document.getElementById('sp-stripe-test-btn');
                var result = document.getElementById('sp-stripe-test-result');
                if (!btn) return;

                btn.addEventListener('click', function() {
                    btn.disabled = true;
                    btn.textContent = 'Testing\u2026';
                    result.textContent = '';
                    result.style.color = '';

                    var formData = new FormData();
                    formData.append('action', 'sp_test_stripe_connection');
                    formData.append('nonce', '<?php echo wp_create_nonce( "sp_stripe_test" ); ?>');

                    fetch('<?php echo admin_url( "admin-ajax.php" ); ?>', {
                        method: 'POST',
                        body: formData,
                        credentials: 'same-origin'
                    })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            result.textContent = '\u2705 Connected! Your Stripe keys are working.';
                            result.style.color = '#00a32a';
                        } else {
                            result.textContent = '\u274C ' + (data.data || 'Connection failed. Check your keys and try again.');
                            result.style.color = '#d63638';
                        }
                        btn.disabled = false;
                        btn.innerHTML = '<span class="dashicons dashicons-superhero-alt" style="margin-top:4px;margin-right:2px;"></span> Test Connection';
                    })
                    .catch(function() {
                        result.textContent = '\u274C Could not reach the server. Please try again.';
                        result.style.color = '#d63638';
                        btn.disabled = false;
                        btn.innerHTML = '<span class="dashicons dashicons-superhero-alt" style="margin-top:4px;margin-right:2px;"></span> Test Connection';
                    });
                });
            })();
            </script>
            <?php
        },
        'sp-settings-events',
        'sp_stripe_section'
    );
});


// ============================================================================
// IMPORT EVENTS — File Upload, Preview, and Import
// ============================================================================
//
// WHY: Harold gets event lists from committee chairs in spreadsheets —
//      "here are next year's meeting dates" or a program schedule exported
//      from the old system. Manually entering 20+ events one at a time is
//      tedious and error-prone. An import lets him upload once and go.
//
// FORMATS: CSV (comma-delimited), TSV/TXT (tab-delimited), XLSX (Excel).
//   Delimiter is auto-detected for text files. XLSX is parsed natively
//   using ZipArchive + SimpleXML — no external libraries needed.
//
// FLOW (two-step, same as member import):
//   Step 1: Upload file → show preview table + column mapping dropdowns
//   Step 2: Confirm → import events into sp_events table
// ============================================================================

/**
 * Parse an import file (CSV, TSV, or XLSX) into a normalized array.
 *
 * WHY: Societies export event data from all kinds of tools — Excel, Google
 *      Sheets, LibreOffice, legacy databases. Instead of forcing everyone
 *      to "Save as CSV" (which many non-technical users struggle with),
 *      we accept the most common formats and normalize them internally.
 *
 * @param string $file_path  Absolute path to the uploaded file.
 * @return array|false  ['headers' => [...], 'rows' => [[...], ...]] or false on failure.
 */
function sp_parse_import_file( string $file_path ) {
    if ( ! file_exists( $file_path ) || ! is_readable( $file_path ) ) {
        return false;
    }

    $extension = strtolower( pathinfo( $file_path, PATHINFO_EXTENSION ) );

    // -----------------------------------------------------------------
    // XLSX — Excel Open XML format
    // -----------------------------------------------------------------
    // WHY: XLSX files are ZIP archives containing XML. PHP's ZipArchive
    //      and SimpleXML can parse them without any external library.
    //      We read the shared string table (where Excel stores text) and
    //      then walk through sheet1's cell data to reconstruct rows.
    // -----------------------------------------------------------------
    if ( $extension === 'xlsx' ) {
        return sp_parse_xlsx_file( $file_path );
    }

    // -----------------------------------------------------------------
    // CSV / TSV / TXT — auto-detect delimiter
    // -----------------------------------------------------------------
    // WHY: Tab-delimited exports are common from older systems and some
    //      spreadsheet "Save As" options. Rather than making Harold guess
    //      which format he has, we peek at the first line and pick
    //      whichever delimiter (comma or tab) appears more often.
    // -----------------------------------------------------------------
    $handle = fopen( $file_path, 'r' );
    if ( ! $handle ) {
        return false;
    }

    // Read first line to detect delimiter
    $first_line = fgets( $handle );
    if ( $first_line === false ) {
        fclose( $handle );
        return false;
    }
    rewind( $handle );

    $tab_count   = substr_count( $first_line, "\t" );
    $comma_count = substr_count( $first_line, ',' );
    $delimiter   = ( $tab_count > $comma_count ) ? "\t" : ',';

    // Read header row
    $headers = fgetcsv( $handle, 0, $delimiter );
    if ( ! $headers ) {
        fclose( $handle );
        return false;
    }

    // Strip BOM and whitespace from headers
    $headers = array_map( function( $h ) {
        return trim( $h, "\xEF\xBB\xBF \t\n\r" );
    }, $headers );

    // Read all data rows
    $rows = [];
    while ( ( $row = fgetcsv( $handle, 0, $delimiter ) ) !== false ) {
        $rows[] = $row;
    }

    fclose( $handle );

    return [
        'headers' => $headers,
        'rows'    => $rows,
    ];
}

/**
 * Parse an XLSX (Excel) file into headers + rows.
 *
 * WHY: XLSX is a ZIP containing XML files. The key pieces are:
 *   - xl/sharedStrings.xml: lookup table of all text strings in the workbook
 *   - xl/worksheets/sheet1.xml: the actual cell data for the first sheet
 *
 * Each cell has a reference like "A1", "B2", etc. and a type attribute:
 *   - type="s" means the value is an index into the shared strings table
 *   - type="inlineStr" means the string is stored directly in the cell
 *   - no type or type="n" means the value is a literal number
 *
 * We convert column letters (A, B, ..., Z, AA, AB...) to 0-based indexes
 * and reconstruct a dense row array so it looks just like fgetcsv() output.
 *
 * @param string $file_path  Path to the .xlsx file.
 * @return array|false  ['headers' => [...], 'rows' => [[...], ...]] or false.
 */
function sp_parse_xlsx_file( string $file_path ) {
    if ( ! class_exists( 'ZipArchive' ) ) {
        return false;
    }

    $zip = new ZipArchive();
    if ( $zip->open( $file_path ) !== true ) {
        return false;
    }

    // ---- Shared strings table ----
    // WHY: Excel stores repeated strings once in a lookup table and
    //      references them by index in each cell. This keeps file size
    //      small when the same category name appears in 200 rows.
    $shared_strings = [];
    $ss_xml = $zip->getFromName( 'xl/sharedStrings.xml' );
    if ( $ss_xml !== false ) {
        $ss = simplexml_load_string( $ss_xml );
        if ( $ss ) {
            foreach ( $ss->si as $si ) {
                // Some shared strings use <t> directly, others use <r> runs
                // (rich text with formatting). We concatenate all <t> elements.
                $text = '';
                if ( isset( $si->t ) ) {
                    $text = (string) $si->t;
                } elseif ( isset( $si->r ) ) {
                    foreach ( $si->r as $run ) {
                        $text .= (string) $run->t;
                    }
                }
                $shared_strings[] = $text;
            }
        }
    }

    // ---- Worksheet data (sheet1) ----
    $sheet_xml = $zip->getFromName( 'xl/worksheets/sheet1.xml' );
    if ( $sheet_xml === false ) {
        $zip->close();
        return false;
    }

    $sheet = simplexml_load_string( $sheet_xml );
    if ( ! $sheet ) {
        $zip->close();
        return false;
    }

    $zip->close();

    // Parse all rows from the sheet
    $all_rows = [];
    $max_col  = 0;

    if ( isset( $sheet->sheetData->row ) ) {
        foreach ( $sheet->sheetData->row as $row ) {
            $row_data = [];

            if ( isset( $row->c ) ) {
                foreach ( $row->c as $cell ) {
                    // Extract column index from cell reference (e.g., "C5" → column 2)
                    $ref    = (string) $cell['r'];
                    $col_letters = preg_replace( '/[0-9]/', '', $ref );
                    $col_idx     = sp_xlsx_col_to_index( $col_letters );

                    if ( $col_idx > $max_col ) {
                        $max_col = $col_idx;
                    }

                    // Determine cell value based on type attribute
                    $type  = (string) ( $cell['t'] ?? '' );
                    $value = '';

                    if ( $type === 's' ) {
                        // Shared string reference
                        $string_idx = (int) (string) $cell->v;
                        $value = $shared_strings[ $string_idx ] ?? '';
                    } elseif ( $type === 'inlineStr' ) {
                        // Inline string — value is in <is><t>
                        $value = (string) ( $cell->is->t ?? '' );
                    } elseif ( isset( $cell->v ) ) {
                        // Numeric or other literal value
                        $value = (string) $cell->v;
                    }

                    $row_data[ $col_idx ] = $value;
                }
            }

            $all_rows[] = $row_data;
        }
    }

    if ( empty( $all_rows ) ) {
        return false;
    }

    // Convert sparse row arrays into dense arrays (fill gaps with empty strings)
    // WHY: Cells with no data in XLSX don't appear in the XML at all, so we
    //      might have [0 => 'Title', 2 => 'Date'] with column 1 missing.
    //      We need dense arrays like fgetcsv() returns.
    $dense_rows = [];
    foreach ( $all_rows as $sparse ) {
        $dense = [];
        for ( $i = 0; $i <= $max_col; $i++ ) {
            $dense[] = $sparse[ $i ] ?? '';
        }
        $dense_rows[] = $dense;
    }

    // First row is headers, rest is data
    $headers = array_shift( $dense_rows );

    // Strip BOM and whitespace from headers (shouldn't be in XLSX but just in case)
    $headers = array_map( function( $h ) {
        return trim( $h, "\xEF\xBB\xBF \t\n\r" );
    }, $headers );

    return [
        'headers' => $headers,
        'rows'    => $dense_rows,
    ];
}

/**
 * Convert an Excel column letter string to a 0-based index.
 *
 * WHY: Excel uses letters for columns — A=0, B=1, ..., Z=25, AA=26, AB=27, etc.
 *      We need numeric indexes to build our dense row arrays.
 *
 * @param string $letters  Column letters (e.g., "A", "AA", "BZ").
 * @return int  0-based column index.
 */
function sp_xlsx_col_to_index( string $letters ): int {
    $letters = strtoupper( $letters );
    $index   = 0;
    $len     = strlen( $letters );
    for ( $i = 0; $i < $len; $i++ ) {
        $index = $index * 26 + ( ord( $letters[ $i ] ) - ord( 'A' ) + 1 );
    }
    return $index - 1; // Convert to 0-based
}

/**
 * Process the event import (CSV, TSV, or XLSX).
 *
 * WHY: Takes a file path and column mapping, creates event rows in the
 *      database. Categories are matched by name (case-insensitive) — if a
 *      category name in the file doesn't exist yet, we create it automatically
 *      so Harold doesn't have to set them up first.
 *
 * @param string $file_path  Path to the temp file (CSV, TSV, or XLSX).
 * @param array  $field_map  Column mapping: column_header => target_field.
 * @return array Results summary with imported/skipped/errors counts.
 */
function sp_process_event_import( string $file_path, array $field_map ): array {
    global $wpdb;

    $events_table     = $wpdb->prefix . 'sp_events';
    $categories_table = $wpdb->prefix . 'sp_event_categories';

    $results = [
        'imported'           => 0,
        'skipped'            => 0,
        'errors'             => [],
        'categories_created' => [],
    ];

    // Parse file using the multi-format helper (handles CSV, TSV, XLSX)
    $parsed = sp_parse_import_file( $file_path );
    if ( ! $parsed ) {
        $results['errors'][] = 'Could not open or parse the uploaded file.';
        return $results;
    }

    $headers = $parsed['headers'];
    $rows    = $parsed['rows'];

    if ( empty( $headers ) ) {
        $results['errors'][] = 'File is empty or has no header row.';
        return $results;
    }

    // Build a reverse lookup: which column index maps to which target field
    // WHY: The admin chose which column maps to which event field via the
    //      dropdowns on the preview page. We need to know "column 3 = title"
    //      so we can pull the right value from each row.
    $col_to_field = [];
    foreach ( $headers as $idx => $header ) {
        $target = $field_map[ $header ] ?? '__skip';
        if ( $target !== '__skip' ) {
            $col_to_field[ $idx ] = $target;
        }
    }

    // Cache existing categories for fast lookup (name → id)
    $existing_cats = [];
    $cat_rows = $wpdb->get_results( "SELECT id, name FROM {$categories_table}" );
    foreach ( $cat_rows as $c ) {
        $existing_cats[ strtolower( trim( $c->name ) ) ] = $c->id;
    }

    // Next sort order for new categories
    $max_sort = (int) $wpdb->get_var( "SELECT MAX(sort_order) FROM {$categories_table}" );

    $row_num = 1; // 1-based (header was row 0)

    foreach ( $rows as $row ) {
        $row_num++;

        // Build an associative array of target_field => value for this row
        $data = [];
        foreach ( $col_to_field as $idx => $field ) {
            $data[ $field ] = isset( $row[ $idx ] ) ? trim( $row[ $idx ] ) : '';
        }

        // Title is required — skip rows without one
        $title = $data['title'] ?? '';
        if ( empty( $title ) ) {
            $results['skipped']++;
            $results['errors'][] = "Row {$row_num}: Skipped — no title.";
            continue;
        }

        // Date is required — skip rows without one
        $event_date = $data['event_date'] ?? '';
        if ( empty( $event_date ) ) {
            $results['skipped']++;
            $results['errors'][] = "Row {$row_num}: Skipped — no date for \"{$title}\".";
            continue;
        }

        // Normalize the date format — accept various common formats
        // WHY: Spreadsheets export dates in all sorts of formats: "3/14/2026",
        //      "2026-03-14", "March 14, 2026", "14-Mar-2026". PHP's strtotime()
        //      handles most of them gracefully.
        $parsed_date = strtotime( $event_date );
        if ( $parsed_date === false ) {
            $results['skipped']++;
            $results['errors'][] = "Row {$row_num}: Skipped — could not parse date \"{$event_date}\" for \"{$title}\".";
            continue;
        }
        $event_date = date( 'Y-m-d', $parsed_date );

        // Generate slug from title
        $slug = sanitize_title( $title );
        // Ensure uniqueness by appending date
        $existing_slug = $wpdb->get_var( $wpdb->prepare(
            "SELECT id FROM {$events_table} WHERE slug = %s", $slug
        ) );
        if ( $existing_slug ) {
            $slug .= '-' . $event_date;
        }
        // If still not unique, add a timestamp
        $existing_slug = $wpdb->get_var( $wpdb->prepare(
            "SELECT id FROM {$events_table} WHERE slug = %s", $slug
        ) );
        if ( $existing_slug ) {
            $slug .= '-' . time() . '-' . $row_num;
        }

        // Resolve category name to ID (create if new)
        $category_id = null;
        $cat_name    = $data['category'] ?? '';
        if ( ! empty( $cat_name ) ) {
            $cat_key = strtolower( trim( $cat_name ) );
            if ( isset( $existing_cats[ $cat_key ] ) ) {
                $category_id = $existing_cats[ $cat_key ];
            } else {
                // Create the category on the fly
                $max_sort++;
                $cat_slug = sanitize_title( $cat_name );
                $wpdb->insert( $categories_table, [
                    'name'       => $cat_name,
                    'slug'       => $cat_slug,
                    'color'      => '#2271b1',
                    'sort_order' => $max_sort,
                    'active'     => 1,
                ] );
                $category_id = $wpdb->insert_id;
                $existing_cats[ $cat_key ] = $category_id;
                $results['categories_created'][] = $cat_name;
            }
        }

        // Normalize time values — accept "10:00", "10:00 AM", "1:30pm", etc.
        $start_time = null;
        if ( ! empty( $data['start_time'] ) ) {
            $pt = strtotime( $data['start_time'] );
            if ( $pt !== false ) {
                $start_time = date( 'H:i:s', $pt );
            }
        }

        $end_time = null;
        if ( ! empty( $data['end_time'] ) ) {
            $pt = strtotime( $data['end_time'] );
            if ( $pt !== false ) {
                $end_time = date( 'H:i:s', $pt );
            }
        }

        // Parse boolean-ish fields (1, 0, yes, no, true, false)
        $parse_bool = function( $val, $default = 0 ) {
            if ( $val === '' || $val === null ) return $default;
            $v = strtolower( trim( $val ) );
            return in_array( $v, [ '1', 'yes', 'true', 'on' ], true ) ? 1 : 0;
        };

        // Parse visibility — accept "public", "members_only", "members only", etc.
        $visibility = 'public';
        if ( ! empty( $data['visibility'] ) ) {
            $v = strtolower( trim( $data['visibility'] ) );
            if ( in_array( $v, [ 'members_only', 'members only', 'members-only', 'private' ], true ) ) {
                $visibility = 'members_only';
            }
        }

        // Build the insert array
        $insert = [
            'title'                => sanitize_text_field( $title ),
            'slug'                 => $slug,
            'description'          => wp_kses_post( $data['description'] ?? '' ),
            'category_id'          => $category_id,
            'status'               => 'scheduled',
            'event_date'           => $event_date,
            'start_time'           => $start_time,
            'end_time'             => $end_time,
            'location_name'        => sanitize_text_field( $data['location_name'] ?? '' ),
            'location_address'     => sanitize_text_field( $data['location_address'] ?? '' ),
            'is_virtual'           => $parse_bool( $data['is_virtual'] ?? '' ),
            'virtual_url'          => esc_url_raw( $data['virtual_url'] ?? '' ),
            'visibility'           => $visibility,
            'registration_enabled' => $parse_bool( $data['registration_enabled'] ?? '' ),
            'registration_limit'   => ! empty( $data['registration_limit'] ) ? (int) $data['registration_limit'] : null,
            'guest_registration'   => $parse_bool( $data['guest_registration'] ?? '' ),
            'member_price'         => ! empty( $data['member_price'] ) ? number_format( (float) $data['member_price'], 2, '.', '' ) : '0.00',
            'nonmember_price'      => ! empty( $data['nonmember_price'] ) ? number_format( (float) $data['nonmember_price'], 2, '.', '' ) : '0.00',
            'payment_mode'         => in_array( $data['payment_mode'] ?? '', [ 'none', 'at_door', 'online', 'either' ], true )
                                      ? $data['payment_mode'] : 'none',
            'price_description'    => sanitize_text_field( $data['price_description'] ?? '' ),
            'contact_name'         => sanitize_text_field( $data['contact_name'] ?? '' ),
            'contact_email'        => sanitize_email( $data['contact_email'] ?? '' ),
            'contact_phone'        => sanitize_text_field( $data['contact_phone'] ?? '' ),
            'created_by'           => get_current_user_id(),
        ];

        $inserted = $wpdb->insert( $events_table, $insert );

        if ( $inserted ) {
            $results['imported']++;
        } else {
            $results['skipped']++;
            $results['errors'][] = "Row {$row_num}: Database error inserting \"{$title}\".";
        }
    }

    return $results;
}


/**
 * Render the Import Events admin page.
 *
 * WHY: Two-step flow (same as member import) — upload first, preview the
 *      data and adjust column mappings, then confirm the import. This prevents
 *      surprises like importing "Date" into "Location" because the columns
 *      were in a different order than expected.
 */
function sp_render_import_events_page(): void {
    $results = null;
    $preview = null;

    // ------------------------------------------------------------------
    // STEP 2: Run the actual import from the temp file
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_event_import_action'] ) && $_POST['sp_event_import_action'] === 'run_import' ) {
        check_admin_referer( 'sp_import_events' );

        $temp_file = sanitize_text_field( $_POST['sp_import_temp_file'] ?? '' );

        // Parse the field mapping from the preview form
        $raw_map = isset( $_POST['sp_field_map'] ) && is_array( $_POST['sp_field_map'] )
                 ? $_POST['sp_field_map']
                 : [];
        $import_field_map = [];
        foreach ( $raw_map as $csv_col => $target ) {
            $import_field_map[ sanitize_text_field( $csv_col ) ] = sanitize_text_field( $target );
        }

        if ( ! empty( $temp_file ) && file_exists( $temp_file ) ) {
            $results = sp_process_event_import( $temp_file, $import_field_map );
            @unlink( $temp_file );
        } else {
            $results = [
                'imported'           => 0,
                'skipped'            => 0,
                'errors'             => [ 'The uploaded file has expired. Please upload again.' ],
                'categories_created' => [],
            ];
        }
    }

    // ------------------------------------------------------------------
    // STEP 1: Upload CSV and show preview / field mapping
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_event_import_action'] ) && $_POST['sp_event_import_action'] === 'preview' ) {
        check_admin_referer( 'sp_import_events' );

        if ( ! empty( $_FILES['import_file']['tmp_name'] ) ) {
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }

            // Preserve the original extension so the parser can detect format
            // WHY: XLSX detection relies on the file extension. If we always
            //      save as .csv, the parser would try to fgetcsv() an XLSX
            //      file and get garbage.
            $orig_name = $_FILES['import_file']['name'] ?? 'import.csv';
            $orig_ext  = strtolower( pathinfo( $orig_name, PATHINFO_EXTENSION ) );
            $safe_ext  = in_array( $orig_ext, [ 'csv', 'tsv', 'txt', 'xlsx' ], true ) ? $orig_ext : 'csv';
            $temp_file = $temp_dir . '/event-import-' . wp_generate_password( 12, false ) . '.' . $safe_ext;
            move_uploaded_file( $_FILES['import_file']['tmp_name'], $temp_file );

            // Use the multi-format parser (handles CSV, TSV, XLSX)
            $parsed = sp_parse_import_file( $temp_file );

            if ( $parsed && ! empty( $parsed['headers'] ) ) {
                $preview = [
                    'headers'     => $parsed['headers'],
                    'sample_rows' => array_slice( $parsed['rows'], 0, 5 ),
                    'row_count'   => count( $parsed['rows'] ),
                    'temp_file'   => $temp_file,
                ];
            } else {
                @unlink( $temp_file );
            }
        }
    }

    // ------------------------------------------------------------------
    // Target fields — the event columns we can import into.
    // The keys are what gets stored in the mapping; the values are
    // human-friendly labels shown in the dropdown.
    // ------------------------------------------------------------------
    $target_fields = [
        'title'                => 'Title',
        'event_date'           => 'Date',
        'start_time'           => 'Start Time',
        'end_time'             => 'End Time',
        'category'             => 'Category',
        'description'          => 'Description',
        'location_name'        => 'Venue / Location Name',
        'location_address'     => 'Address',
        'is_virtual'           => 'Virtual Event (yes/no)',
        'virtual_url'          => 'Virtual Meeting URL',
        'visibility'           => 'Visibility (public/members_only)',
        'registration_enabled' => 'Registration Enabled (yes/no)',
        'registration_limit'   => 'Registration Limit',
        'guest_registration'   => 'Guest Registration (yes/no)',
        'member_price'         => 'Member Price',
        'nonmember_price'      => 'Non-Member Price',
        'payment_mode'         => 'Payment Mode',
        'price_description'    => 'Price Description',
        'contact_name'         => 'Contact Name',
        'contact_email'        => 'Contact Email',
        'contact_phone'        => 'Contact Phone',
    ];

    // Auto-mapping: try to match CSV column names to target fields.
    // WHY: If the CSV headers are "title", "date", "start_time" etc.,
    //      we shouldn't make Harold manually select every dropdown.
    //      We match by exact key, or by the human label, case-insensitive.
    $auto_map = [];
    if ( $preview ) {
        foreach ( $preview['headers'] as $header ) {
            $h_lower = strtolower( trim( $header ) );
            // Try exact match on target field key
            if ( isset( $target_fields[ $h_lower ] ) ) {
                $auto_map[ $header ] = $h_lower;
                continue;
            }
            // Try match on target field label
            foreach ( $target_fields as $key => $label ) {
                if ( strtolower( $label ) === $h_lower ) {
                    $auto_map[ $header ] = $key;
                    break;
                }
            }
            // Try common aliases
            $aliases = [
                'date'     => 'event_date',
                'time'     => 'start_time',
                'location' => 'location_name',
                'venue'    => 'location_name',
                'address'  => 'location_address',
                'virtual'  => 'is_virtual',
                'zoom'     => 'virtual_url',
                'zoom_url' => 'virtual_url',
                'zoom url' => 'virtual_url',
                'price'    => 'member_price',
                'cost'     => 'member_price',
                'limit'    => 'registration_limit',
                'capacity' => 'registration_limit',
                'contact'  => 'contact_name',
                'email'    => 'contact_email',
                'phone'    => 'contact_phone',
                'name'     => 'contact_name',
                'type'     => 'category',
                'event type' => 'category',
            ];
            if ( ! isset( $auto_map[ $header ] ) && isset( $aliases[ $h_lower ] ) ) {
                $auto_map[ $header ] = $aliases[ $h_lower ];
            }
        }
    }

    ?>
    <div class="wrap">
        <h1>Import Events</h1>

        <?php // ============================================================ ?>
        <?php // RESULTS — shown after Step 2 completes                        ?>
        <?php // ============================================================ ?>
        <?php if ( $results ) : ?>
            <?php if ( $results['imported'] > 0 ) : ?>
                <div class="notice notice-success is-dismissible">
                    <p><strong><?php echo (int) $results['imported']; ?> events imported successfully.</strong></p>
                </div>
            <?php endif; ?>

            <?php if ( ! empty( $results['categories_created'] ) ) : ?>
                <div class="notice notice-info is-dismissible">
                    <p>Created new categories: <strong><?php echo esc_html( implode( ', ', array_unique( $results['categories_created'] ) ) ); ?></strong></p>
                    <p>You can customize their colors on the
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-event-categories' ) ); ?>">Event Categories</a> page.</p>
                </div>
            <?php endif; ?>

            <?php if ( $results['skipped'] > 0 ) : ?>
                <div class="notice notice-warning is-dismissible">
                    <p><?php echo (int) $results['skipped']; ?> rows skipped.</p>
                </div>
            <?php endif; ?>

            <?php if ( ! empty( $results['errors'] ) ) : ?>
                <div class="notice notice-error">
                    <p><strong>Details:</strong></p>
                    <ul style="margin: 0 0 10px 20px; list-style: disc;">
                        <?php foreach ( array_slice( $results['errors'], 0, 50 ) as $err ) : ?>
                            <li><?php echo esc_html( $err ); ?></li>
                        <?php endforeach; ?>
                        <?php if ( count( $results['errors'] ) > 50 ) : ?>
                            <li>...and <?php echo count( $results['errors'] ) - 50; ?> more.</li>
                        <?php endif; ?>
                    </ul>
                </div>
            <?php endif; ?>

            <p>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-events' ) ); ?>" class="button button-primary">View Events</a>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-events' ) ); ?>" class="button" style="margin-left: 8px;">Import More</a>
            </p>
        <?php endif; ?>

        <?php // ============================================================ ?>
        <?php // PREVIEW — shown after Step 1, before confirming import        ?>
        <?php // ============================================================ ?>
        <?php if ( $preview && ! $results ) : ?>
            <div class="card" style="max-width: 100%; padding: 20px; margin-top: 10px;">
                <h2 style="margin-top: 0;">Preview &amp; Column Mapping</h2>
                <p>
                    Found <strong><?php echo (int) $preview['row_count']; ?> events</strong> in the file.
                    Review the column mapping below, then click <strong>Import Events</strong>.
                </p>

                <form method="post">
                    <?php wp_nonce_field( 'sp_import_events' ); ?>
                    <input type="hidden" name="sp_event_import_action" value="run_import">
                    <input type="hidden" name="sp_import_temp_file"
                           value="<?php echo esc_attr( $preview['temp_file'] ); ?>">

                    <!-- Column mapping table -->
                    <table class="widefat" style="margin-bottom: 20px;">
                        <thead>
                            <tr>
                                <th style="width: 25%;">File Column</th>
                                <th style="width: 25%;">Maps To</th>
                                <th>Sample Values</th>
                            </tr>
                        </thead>
                        <tbody>
                            <?php foreach ( $preview['headers'] as $idx => $header ) : ?>
                                <tr>
                                    <td><strong><?php echo esc_html( $header ); ?></strong></td>
                                    <td>
                                        <select name="sp_field_map[<?php echo esc_attr( $header ); ?>]"
                                                style="width: 100%;">
                                            <option value="__skip">— Skip this column —</option>
                                            <?php foreach ( $target_fields as $key => $label ) : ?>
                                                <option value="<?php echo esc_attr( $key ); ?>"
                                                    <?php selected( $auto_map[ $header ] ?? '', $key ); ?>>
                                                    <?php echo esc_html( $label ); ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </td>
                                    <td style="color: #787c82; font-size: 12px;">
                                        <?php
                                        // Show up to 3 sample values for this column
                                        $samples = [];
                                        foreach ( $preview['sample_rows'] as $srow ) {
                                            if ( isset( $srow[ $idx ] ) && $srow[ $idx ] !== '' ) {
                                                $val = $srow[ $idx ];
                                                // Truncate long descriptions
                                                if ( strlen( $val ) > 80 ) {
                                                    $val = substr( $val, 0, 80 ) . '...';
                                                }
                                                $samples[] = $val;
                                            }
                                        }
                                        echo esc_html( implode( ' | ', array_slice( $samples, 0, 3 ) ) );
                                        ?>
                                    </td>
                                </tr>
                            <?php endforeach; ?>
                        </tbody>
                    </table>

                    <p>
                        <?php submit_button( 'Import ' . (int) $preview['row_count'] . ' Events', 'primary', 'submit', false ); ?>
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-events' ) ); ?>"
                           class="button" style="margin-left: 8px;">Cancel</a>
                    </p>
                </form>
            </div>
        <?php endif; ?>

        <?php // ============================================================ ?>
        <?php // UPLOAD FORM — Step 1 (shown when no preview and no results)   ?>
        <?php // ============================================================ ?>
        <?php if ( ! $preview && ! $results ) : ?>
            <div class="card" style="max-width: 700px; padding: 20px; margin-top: 10px;">
                <h2 style="margin-top: 0;">Upload Events</h2>
                <p>Upload a file containing your events. CSV, tab-delimited (TSV/TXT), and
                   Excel (.xlsx) files are all supported. The file should have a header row
                   with column names.</p>

                <form method="post" enctype="multipart/form-data">
                    <?php wp_nonce_field( 'sp_import_events' ); ?>
                    <input type="hidden" name="sp_event_import_action" value="preview">

                    <table class="form-table" role="presentation">
                        <tr>
                            <th scope="row"><label for="import_file">Import File</label></th>
                            <td>
                                <input type="file" id="import_file" name="import_file"
                                       accept=".csv,.tsv,.txt,.xlsx" required>
                                <p class="description">
                                    Accepted formats: CSV, TSV, TXT, Excel (.xlsx).
                                    Maximum file size: <?php echo esc_html( ini_get( 'upload_max_filesize' ) ); ?>
                                </p>
                            </td>
                        </tr>
                    </table>

                    <?php submit_button( 'Upload &amp; Preview', 'primary', 'submit', true ); ?>
                </form>

                <hr style="margin: 24px 0;">

                <h3 style="margin-top: 0;">Expected Format</h3>
                <p>Your file should include at minimum a <strong>title</strong> and <strong>date</strong> column.
                   All other columns are optional. The importer will try to auto-detect column mappings,
                   and you can adjust them on the next screen.</p>

                <table class="widefat" style="font-size: 12px;">
                    <thead>
                        <tr>
                            <th>Column</th>
                            <th>Required</th>
                            <th>Example</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr><td><code>title</code></td><td>Yes</td><td>March General Meeting: FamilySearch</td></tr>
                        <tr><td><code>date</code></td><td>Yes</td><td>2026-03-14 <em>or</em> 3/14/2026</td></tr>
                        <tr><td><code>start_time</code></td><td>No</td><td>10:00 <em>or</em> 10:00 AM</td></tr>
                        <tr><td><code>end_time</code></td><td>No</td><td>12:00</td></tr>
                        <tr><td><code>category</code></td><td>No</td><td>Workshop (created if new)</td></tr>
                        <tr><td><code>location_name</code></td><td>No</td><td>Dwyer Memorial Center</td></tr>
                        <tr><td><code>location_address</code></td><td>No</td><td>19100 Goldenwest St, HB, CA</td></tr>
                        <tr><td><code>description</code></td><td>No</td><td>Full event description...</td></tr>
                        <tr><td><code>contact_name</code></td><td>No</td><td>Martha Colvin</td></tr>
                        <tr><td><code>contact_email</code></td><td>No</td><td>programs@kndgs.org</td></tr>
                        <tr><td><code>registration_enabled</code></td><td>No</td><td>1 <em>or</em> yes</td></tr>
                        <tr><td><code>registration_limit</code></td><td>No</td><td>25 (blank = unlimited)</td></tr>
                        <tr><td><code>member_price</code></td><td>No</td><td>5.00 (0 = free)</td></tr>
                        <tr><td><code>nonmember_price</code></td><td>No</td><td>10.00</td></tr>
                        <tr><td><code>visibility</code></td><td>No</td><td>public <em>or</em> members_only</td></tr>
                        <tr><td><code>is_virtual</code></td><td>No</td><td>0 <em>or</em> 1</td></tr>
                        <tr><td><code>virtual_url</code></td><td>No</td><td>https://zoom.us/j/...</td></tr>
                    </tbody>
                </table>
            </div>
        <?php endif; ?>

    </div>
    <?php
}


// ============================================================================
// EVENTS — FRONTEND PAGE TEMPLATE REGISTRATION
// ============================================================================
//
// WHY: Same pattern as the Membership Directory. We register an "Events"
//      page template that Harold selects from the Template dropdown when
//      editing a page. WordPress handles showing it in the dropdown; we
//      handle rendering when it's loaded on the frontend.
//
// TWO VIEWS on one page:
//   - List View (default): Event cards with search, filters, pagination
//   - Calendar View (toggle): Month grid with color-coded event dots
//
// DETAIL PAGE:
//   Uses a query var (?sp_event=slug) on the same page to show a single
//   event's full details. This avoids creating a custom post type or
//   rewrite rules — keeps everything in one place.
// ============================================================================

/**
 * Register the "Events" page template.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-events'] = 'Events';
    return $templates;
});

/**
 * Register the sp_event query var so WordPress doesn't strip it.
 *
 * WHY: WordPress ignores query vars it doesn't know about. We need
 *      ?sp_event=slug to work on the events page for detail views.
 */
add_filter( 'query_vars', function ( $vars ) {
    $vars[] = 'sp_event';
    return $vars;
});

/**
 * Intercept the template load for the Events page and render our content.
 */
add_filter( 'template_include', function ( $template ) {

    if ( is_page() && get_page_template_slug() === 'sp-events' ) {

        $settings = get_option( 'societypress_settings', [] );

        // Enqueue our events styles and scripts
        add_action( 'wp_head', 'sp_events_frontend_styles' );
        add_action( 'wp_footer', 'sp_events_frontend_scripts' );

        get_header();

        echo '<div class="sp-events-wrap">';

        // Check if we're viewing a single event detail page
        $event_slug = get_query_var( 'sp_event', '' );

        if ( ! empty( $event_slug ) ) {
            sp_render_event_detail( $event_slug, $settings );
        } else {
            sp_render_events_listing( $settings );
        }

        echo '</div>';

        get_footer();

        return SOCIETYPRESS_PLUGIN_DIR . 'sp-blank-template.php';
    }

    return $template;
});


// ============================================================================
// EVENTS — STANDALONE CALENDAR PAGE TEMPLATE
// ============================================================================

/**
 * Register the "Calendar" page template.
 *
 * WHY: Harold might want a dedicated calendar page separate from the events
 *      listing — no list view, no search/filter bar, just a clean monthly
 *      calendar grid. This shows up in the Template dropdown in the page editor.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-calendar'] = __( 'Calendar', 'societypress' );
    return $templates;
});

/**
 * Register sp_cal_cat query var for the calendar category filter.
 *
 * WHY: The standalone calendar template has a category filter dropdown that
 *      uses ?sp_cal_cat=ID in the URL. WordPress strips unknown query vars,
 *      so we need to register it.
 */
add_filter( 'query_vars', function ( $vars ) {
    $vars[] = 'sp_cal_cat';
    return $vars;
});

/**
 * Intercept the template load for the Calendar page and render the grid.
 *
 * WHY: Since sp-calendar isn't a physical theme file, WordPress would 404.
 *      We catch it here, render the calendar with the theme's header/footer,
 *      and return a blank template so WordPress doesn't try to load anything.
 */
add_filter( 'template_include', function ( $template ) {

    if ( ! is_page() || get_page_template_slug() !== 'sp-calendar' ) {
        return $template;
    }

    // Output calendar CSS and queue JS for footer
    add_action( 'wp_head', 'sp_events_calendar_styles' );
    add_action( 'wp_footer', 'sp_events_calendar_scripts', 50 );

    get_header();

    global $wpdb;
    $base_url = get_permalink();
    $page_title = get_the_title();

    // Category filter from query param
    $cat_filter = absint( get_query_var( 'sp_cal_cat', 0 ) );

    // Fetch active event categories for the filter dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order, name"
    );

    echo '<div class="site-content"><div class="content-area-full" style="max-width:var(--sp-content-width,1100px); margin:0 auto; padding:40px 20px;">';

    // Page heading
    echo '<h1 style="margin:0 0 24px; font-size:28px; font-weight:700; color:#1d2327;">'
         . esc_html( $page_title ) . '</h1>';

    // Category filter bar — only show if there are categories to filter by
    if ( ! empty( $categories ) ) {
        echo '<form method="get" action="' . esc_url( $base_url ) . '" style="margin-bottom:20px; display:flex; gap:8px; align-items:center; flex-wrap:wrap;">';

        // Preserve the current month if set
        $current_cal_month = isset( $_GET['sp_cal_month'] ) ? sanitize_text_field( $_GET['sp_cal_month'] ) : '';
        if ( $current_cal_month && preg_match( '/^\d{4}-\d{2}$/', $current_cal_month ) ) {
            echo '<input type="hidden" name="sp_cal_month" value="' . esc_attr( $current_cal_month ) . '">';
        }

        echo '<select name="sp_cal_cat" style="padding:8px 12px; border:1px solid #ddd; border-radius:6px; font-size:14px;">';
        echo '<option value="0">' . esc_html__( 'All Categories', 'societypress' ) . '</option>';
        foreach ( $categories as $cat ) {
            echo '<option value="' . esc_attr( $cat->id ) . '"' . selected( $cat_filter, (int) $cat->id, false ) . '>'
                 . esc_html( $cat->name ) . '</option>';
        }
        echo '</select>';
        echo '<button type="submit" style="padding:8px 16px; background:var(--sp-color-primary,#1e3a5f); color:#fff; border:none; border-radius:6px; font-size:14px; cursor:pointer;">'
             . esc_html__( 'Filter', 'societypress' ) . '</button>';

        if ( $cat_filter > 0 ) {
            echo '<a href="' . esc_url( $base_url ) . '" style="font-size:14px; color:#666; text-decoration:none;">'
                 . esc_html__( 'Clear', 'societypress' ) . '</a>';
        }
        echo '</form>';
    }

    // Extra args to preserve in calendar nav links
    $extra_args = [];
    if ( $cat_filter > 0 ) {
        $extra_args['sp_cal_cat'] = $cat_filter;
    }

    // Render the shared calendar grid
    sp_render_calendar_grid( $cat_filter, $base_url, $extra_args );

    echo '</div></div>';

    get_footer();

    return SOCIETYPRESS_PLUGIN_DIR . 'sp-blank-template.php';
});


// ============================================================================
// EVENTS — SHARED CALENDAR GRID RENDERER
// ============================================================================

/**
 * Render a monthly calendar grid with event pills, mobile dots, and nav.
 *
 * WHY: The calendar grid is used in three places — the events listing page
 *      (calendar view toggle), the Page Builder "Events Calendar" widget,
 *      and the standalone "Calendar" page template. Centralizing the
 *      rendering here keeps one source of truth: same HTML structure, same
 *      mobile behavior, same category-colored pills everywhere.
 *
 * @param int    $category_id  Optional category filter (0 = all).
 * @param string $base_url     The page URL for nav links and event detail links.
 * @param array  $extra_args   Extra query args to preserve in nav links (e.g., sp_view, sp_cat).
 */
function sp_render_calendar_grid( int $category_id = 0, string $base_url = '', array $extra_args = [] ): void {
    global $wpdb;

    $settings    = get_option( 'societypress_settings', [] );
    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';

    if ( empty( $base_url ) ) {
        $base_url = get_permalink();
    }

    // ---- Determine which month to display ----
    // WHY: The sp_cal_month query param lets users navigate months via
    //      prev/next links. Default to current month if not set or invalid.
    $cal_month = isset( $_GET['sp_cal_month'] ) ? sanitize_text_field( $_GET['sp_cal_month'] ) : date( 'Y-m' );
    if ( ! preg_match( '/^\d{4}-\d{2}$/', $cal_month ) ) {
        $cal_month = date( 'Y-m' );
    }

    $cal_year    = (int) substr( $cal_month, 0, 4 );
    $cal_mon     = (int) substr( $cal_month, 5, 2 );
    $days_in     = (int) date( 't', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) );
    $first_dow   = (int) date( 'w', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) ); // 0=Sun
    $month_label = date( 'F Y', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) );

    // ---- Start day of week (Sunday or Monday) ----
    $start_day  = (int) ( $settings['events_calendar_start_day'] ?? 0 );
    $day_names  = $start_day === 1
                ? [ 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun' ]
                : [ 'Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat' ];

    // Adjust first day of week offset for Monday start
    if ( $start_day === 1 ) {
        $first_offset = ( $first_dow === 0 ) ? 6 : $first_dow - 1;
    } else {
        $first_offset = $first_dow;
    }

    // ---- Fetch events for this month ----
    $month_start = sprintf( '%04d-%02d-01', $cal_year, $cal_mon );
    $month_end   = sprintf( '%04d-%02d-%02d', $cal_year, $cal_mon, $days_in );

    $cal_where  = [ "e.status != 'cancelled'", "e.event_date >= %s", "e.event_date <= %s" ];
    $cal_params = [ $month_start, $month_end ];

    if ( $category_id > 0 ) {
        $cal_where[]  = 'e.category_id = %d';
        $cal_params[] = $category_id;
    }

    if ( ! is_user_logged_in() ) {
        $cal_where[] = "e.visibility = 'public'";
    }

    $cal_sql = "SELECT e.id, e.title, e.slug, e.event_date, e.start_time,
                       c.name AS category_name, c.color AS category_color
                FROM {$events_table} e
                LEFT JOIN {$cats_table} c ON e.category_id = c.id
                WHERE " . implode( ' AND ', $cal_where ) . "
                ORDER BY e.event_date ASC, e.start_time ASC";
    $cal_events = $wpdb->get_results( $wpdb->prepare( $cal_sql, ...$cal_params ) );

    // ---- Build day → events lookup ----
    $events_by_day = [];
    foreach ( $cal_events as $ce ) {
        $day = (int) substr( $ce->event_date, 8, 2 );
        $events_by_day[ $day ][] = $ce;
    }

    $today_str = current_time( 'Y-m-d' );

    // ---- Find the events listing page for detail links ----
    // WHY: Event pills link to the event detail page (?sp_event=slug) on
    //      whichever page uses the sp-events template. If no events page
    //      exists, pills still show but without links.
    $events_page_url = '';
    $events_pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $events_pages ) ) {
        $events_page_url = get_permalink( $events_pages[0]->ID );
    }

    // ---- Prev/Next month links ----
    $prev_month = date( 'Y-m', mktime( 0, 0, 0, $cal_mon - 1, 1, $cal_year ) );
    $next_month = date( 'Y-m', mktime( 0, 0, 0, $cal_mon + 1, 1, $cal_year ) );
    $cal_nav_args = $extra_args;
    $cal_nav_args['sp_cal_month'] = $prev_month;
    $prev_url = add_query_arg( $cal_nav_args, $base_url );
    $cal_nav_args['sp_cal_month'] = $next_month;
    $next_url = add_query_arg( $cal_nav_args, $base_url );

    ?>
    <div class="sp-calendar-wrap">
        <!-- Calendar Navigation -->
        <div class="sp-calendar-nav">
            <a href="<?php echo esc_url( $prev_url ); ?>"
               class="sp-cal-nav-btn">&laquo; <?php echo esc_html__( 'Prev', 'societypress' ); ?></a>
            <h2 class="sp-cal-month-label"><?php echo esc_html( $month_label ); ?></h2>
            <a href="<?php echo esc_url( $next_url ); ?>"
               class="sp-cal-nav-btn"><?php echo esc_html__( 'Next', 'societypress' ); ?> &raquo;</a>
        </div>

        <!-- Calendar Grid -->
        <div class="sp-calendar-grid">
            <!-- Day headers -->
            <?php foreach ( $day_names as $dn ) : ?>
                <div class="sp-cal-header"><?php echo esc_html( $dn ); ?></div>
            <?php endforeach; ?>

            <!-- Empty cells before first day -->
            <?php for ( $i = 0; $i < $first_offset; $i++ ) : ?>
                <div class="sp-cal-day sp-cal-empty"></div>
            <?php endfor; ?>

            <!-- Day cells -->
            <?php for ( $d = 1; $d <= $days_in; $d++ ) :
                $date_str  = sprintf( '%04d-%02d-%02d', $cal_year, $cal_mon, $d );
                $is_today  = ( $date_str === $today_str );
                $has_events = isset( $events_by_day[ $d ] );
                $day_class = 'sp-cal-day';
                if ( $is_today ) $day_class .= ' sp-cal-today';
                if ( $has_events ) $day_class .= ' sp-cal-has-events';
            ?>
                <div class="<?php echo $day_class; ?>">
                    <div class="sp-cal-day-num"><?php echo $d; ?></div>
                    <?php if ( $has_events ) : ?>
                        <div class="sp-cal-events">
                            <?php foreach ( $events_by_day[ $d ] as $ce ) :
                                $detail_url = $events_page_url ? add_query_arg( 'sp_event', $ce->slug, $events_page_url ) : '';
                                $color = $ce->category_color ?: '#2271b1';
                            ?>
                                <?php if ( $detail_url ) : ?>
                                <a href="<?php echo esc_url( $detail_url ); ?>"
                                   class="sp-cal-event"
                                   style="background: <?php echo esc_attr( $color ); ?>;"
                                   title="<?php echo esc_attr( $ce->title ); ?>">
                                    <span class="sp-cal-event-title"><?php echo esc_html( $ce->title ); ?></span>
                                    <?php if ( $ce->start_time ) : ?>
                                        <span class="sp-cal-event-time"><?php echo esc_html( date( 'g:iA', strtotime( $ce->start_time ) ) ); ?></span>
                                    <?php endif; ?>
                                </a>
                                <?php else : ?>
                                <span class="sp-cal-event"
                                      style="background: <?php echo esc_attr( $color ); ?>;"
                                      title="<?php echo esc_attr( $ce->title ); ?>">
                                    <span class="sp-cal-event-title"><?php echo esc_html( $ce->title ); ?></span>
                                    <?php if ( $ce->start_time ) : ?>
                                        <span class="sp-cal-event-time"><?php echo esc_html( date( 'g:iA', strtotime( $ce->start_time ) ) ); ?></span>
                                    <?php endif; ?>
                                </span>
                                <?php endif; ?>
                            <?php endforeach; ?>
                        </div>
                        <!-- Mobile: dots instead of full titles -->
                        <div class="sp-cal-dots">
                            <?php foreach ( $events_by_day[ $d ] as $ce ) :
                                $color = $ce->category_color ?: '#2271b1';
                            ?>
                                <span class="sp-cal-dot" style="background: <?php echo esc_attr( $color ); ?>;"></span>
                            <?php endforeach; ?>
                        </div>
                    <?php endif; ?>
                </div>
            <?php endfor; ?>

            <!-- Empty cells after last day to fill the row -->
            <?php
            $total_cells = $first_offset + $days_in;
            $remainder   = $total_cells % 7;
            if ( $remainder > 0 ) :
                for ( $i = 0; $i < ( 7 - $remainder ); $i++ ) :
            ?>
                <div class="sp-cal-day sp-cal-empty"></div>
            <?php endfor; endif; ?>
        </div>

        <!-- Mobile: expanded day panel (populated by JS on tap) -->
        <div class="sp-cal-mobile-panel" id="sp-cal-mobile-panel" style="display: none;">
            <div class="sp-cal-mobile-panel-header">
                <span id="sp-cal-mobile-date"></span>
                <button type="button" class="sp-cal-mobile-close" id="sp-cal-mobile-close">&times;</button>
            </div>
            <div id="sp-cal-mobile-events"></div>
        </div>
    </div>
    <?php
}


// ============================================================================
// EVENTS — FRONTEND LISTING (List View + Calendar View)
// ============================================================================

/**
 * Render the events listing page — filters, search, list/calendar toggle,
 * event cards, and pagination.
 *
 * WHY: This is the public-facing events page that members and visitors see.
 *      It needs to be clean, scannable, and easy for octogenarians to use.
 *      Event cards show the most important info at a glance: date, title,
 *      time, location, and category. Clicking an event goes to the detail page.
 *
 * @param array $settings The societypress_settings option array.
 */
function sp_render_events_listing( array $settings ): void {
    global $wpdb;

    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';
    $per_page     = (int) ( $settings['events_per_page'] ?? 12 );
    $base_url     = get_permalink();

    // ---- Collect filter parameters from the URL ----
    $search     = isset( $_GET['sp_search'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_search'] ) ) : '';
    $cat_filter = isset( $_GET['sp_cat'] ) ? (int) $_GET['sp_cat'] : 0;
    $timeframe  = isset( $_GET['sp_time'] ) ? sanitize_text_field( $_GET['sp_time'] ) : '12months';
    $view       = isset( $_GET['sp_view'] ) ? sanitize_text_field( $_GET['sp_view'] ) : 'list';

    // ---- Build the WHERE clause ----
    $where  = [ "e.status != 'cancelled'" ];
    $params = [];

    // Visibility filter — hide members_only events from non-logged-in visitors
    if ( ! is_user_logged_in() ) {
        $where[] = "e.visibility = 'public'";
    }

    // Search
    if ( $search !== '' ) {
        $like     = '%' . $wpdb->esc_like( $search ) . '%';
        $where[]  = "(e.title LIKE %s OR e.description LIKE %s OR e.location_name LIKE %s)";
        $params[] = $like;
        $params[] = $like;
        $params[] = $like;
    }

    // Category filter
    if ( $cat_filter > 0 ) {
        $where[]  = "e.category_id = %d";
        $params[] = $cat_filter;
    }

    // Timeframe filter
    $today = current_time( 'Y-m-d' );
    switch ( $timeframe ) {
        case '30days':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+30 days' ) );
            break;
        case '3months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+3 months' ) );
            break;
        case '6months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+6 months' ) );
            break;
        case '12months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+12 months' ) );
            break;
        case 'all':
            $where[]  = "e.event_date >= %s";
            $params[] = $today;
            break;
        case 'past':
            $where[]  = "e.event_date < %s";
            $params[] = $today;
            break;
    }

    $where_sql = 'WHERE ' . implode( ' AND ', $where );

    // ---- Count total for pagination ----
    $count_sql = "SELECT COUNT(*) FROM {$events_table} e {$where_sql}";
    if ( ! empty( $params ) ) {
        $total = (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$params ) );
    } else {
        $total = (int) $wpdb->get_var( $count_sql );
    }

    $total_pages  = max( 1, (int) ceil( $total / $per_page ) );
    $current_page = max( 1, (int) ( $_GET['sp_page'] ?? 1 ) );
    $offset       = ( $current_page - 1 ) * $per_page;

    // ---- Fetch events ----
    $order = ( $timeframe === 'past' ) ? 'DESC' : 'ASC';
    $query = "SELECT e.*, c.name AS category_name, c.color AS category_color
              FROM {$events_table} e
              LEFT JOIN {$cats_table} c ON e.category_id = c.id
              {$where_sql}
              ORDER BY e.event_date {$order}, e.start_time ASC
              LIMIT %d OFFSET %d";
    $query_params = array_merge( $params, [ $per_page, $offset ] );
    $events = $wpdb->get_results( $wpdb->prepare( $query, ...$query_params ) );

    // ---- Fetch all categories for the filter dropdown ----
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$cats_table} WHERE active = 1 ORDER BY sort_order"
    );

    // Calendar events are now fetched inside sp_render_calendar_grid() — no
    // need to pre-fetch here. The shared function handles its own data query
    // scoped to the displayed month, which is more efficient than the old
    // approach of fetching 13 months of events up front.

    // ---- Build persistent query args for pagination links ----
    $page_args = [];
    if ( $search !== '' ) $page_args['sp_search'] = $search;
    if ( $cat_filter > 0 ) $page_args['sp_cat'] = $cat_filter;
    if ( $timeframe !== '12months' ) $page_args['sp_time'] = $timeframe;
    if ( $view !== 'list' ) $page_args['sp_view'] = $view;

    ?>

    <!-- ================================================================ -->
    <!-- FILTER BAR: Search, Category, Timeframe, View Toggle             -->
    <!-- ================================================================ -->
    <div class="sp-events-filters">
        <form method="get" action="<?php echo esc_url( $base_url ); ?>" class="sp-events-filter-form">

            <div class="sp-events-filter-row">
                <!-- Search -->
                <div class="sp-events-search-wrap">
                    <input type="text" name="sp_search" value="<?php echo esc_attr( $search ); ?>"
                           placeholder="Search events..." class="sp-events-search-input">
                </div>

                <!-- Category -->
                <select name="sp_cat" class="sp-events-filter-select">
                    <option value="0">All Categories</option>
                    <?php foreach ( $categories as $cat ) : ?>
                        <option value="<?php echo esc_attr( $cat->id ); ?>"
                            <?php selected( $cat_filter, $cat->id ); ?>>
                            <?php echo esc_html( $cat->name ); ?>
                        </option>
                    <?php endforeach; ?>
                </select>

                <!-- Timeframe -->
                <select name="sp_time" class="sp-events-filter-select">
                    <?php
                    $timeframes = [
                        '30days'   => 'Next 30 Days',
                        '3months'  => 'Next 3 Months',
                        '6months'  => 'Next 6 Months',
                        '12months' => 'Next 12 Months',
                        'all'      => 'All Upcoming',
                        'past'     => 'Past Events',
                    ];
                    foreach ( $timeframes as $tval => $tlabel ) :
                    ?>
                        <option value="<?php echo esc_attr( $tval ); ?>"
                            <?php selected( $timeframe, $tval ); ?>>
                            <?php echo esc_html( $tlabel ); ?>
                        </option>
                    <?php endforeach; ?>
                </select>

                <button type="submit" class="sp-events-filter-btn">Filter</button>

                <?php if ( $search !== '' || $cat_filter > 0 || $timeframe !== '12months' ) : ?>
                    <a href="<?php echo esc_url( $base_url ); ?>" class="sp-events-clear-link">Clear</a>
                <?php endif; ?>
            </div>

            <!-- View Toggle: List / Calendar -->
            <div class="sp-events-view-toggle">
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_view' => 'list' ] ), $base_url ) ); ?>"
                   class="sp-view-btn <?php echo $view === 'list' ? 'sp-view-active' : ''; ?>">
                    <span class="sp-view-icon">&#9776;</span> List
                </a>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_view' => 'calendar' ] ), $base_url ) ); ?>"
                   class="sp-view-btn <?php echo $view === 'calendar' ? 'sp-view-active' : ''; ?>">
                    <span class="sp-view-icon">&#9638;</span> Calendar
                </a>
            </div>
        </form>
    </div>

    <?php if ( $view === 'calendar' ) : ?>

    <!-- ================================================================ -->
    <!-- CALENDAR VIEW (rendered by shared sp_render_calendar_grid)        -->
    <!-- ================================================================ -->
    <?php
    // WHY: Calendar rendering is now a shared function so the same grid
    //      can be used by the Page Builder widget and standalone template.
    //      We pass the category filter and extra args so the nav links
    //      preserve the current filter state and view toggle.
    $cal_extra_args = $page_args;
    $cal_extra_args['sp_view'] = 'calendar';
    sp_render_calendar_grid( $cat_filter, $base_url, $cal_extra_args );
    ?>

    <?php else : ?>

    <!-- ================================================================ -->
    <!-- LIST VIEW: Event Cards                                            -->
    <!-- ================================================================ -->

    <?php if ( empty( $events ) ) : ?>
        <div class="sp-events-empty">
            <p>No events found<?php echo $search !== '' ? ' matching "' . esc_html( $search ) . '"' : ''; ?>.</p>
            <?php if ( $search !== '' || $cat_filter > 0 ) : ?>
                <p><a href="<?php echo esc_url( $base_url ); ?>">View all upcoming events</a></p>
            <?php endif; ?>
        </div>
    <?php else : ?>

        <div class="sp-events-count">
            <?php
            if ( $total === 1 ) {
                echo '<p>1 event</p>';
            } else {
                printf( '<p>%s events</p>', number_format_i18n( $total ) );
            }
            ?>
        </div>

        <div class="sp-events-list">
            <?php foreach ( $events as $ev ) :
                $detail_url = add_query_arg( 'sp_event', $ev->slug, $base_url );
                $date_ts    = strtotime( $ev->event_date );
                $day_num    = date( 'j', $date_ts );
                $day_name   = date( 'D', $date_ts );
                $month_name = date( 'M', $date_ts );

                // Build time string
                $time_str = '';
                if ( ! empty( $ev->start_time ) ) {
                    $time_str = date( 'g:i A', strtotime( $ev->start_time ) );
                    if ( ! empty( $ev->end_time ) ) {
                        $time_str .= ' – ' . date( 'g:i A', strtotime( $ev->end_time ) );
                    }
                }

                // Location string
                $location = '';
                if ( ! empty( $ev->location_name ) ) {
                    $location = $ev->location_name;
                }
                if ( $ev->is_virtual && empty( $location ) ) {
                    $location = 'Virtual Event';
                } elseif ( $ev->is_virtual ) {
                    $location .= ' + Virtual';
                }

                // Registration info
                $reg_info = '';
                if ( $ev->registration_enabled ) {
                    $reg_count = (int) $wpdb->get_var( $wpdb->prepare(
                        "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
                         WHERE event_id = %d AND status = 'confirmed'",
                        $ev->id
                    ) );
                    if ( $ev->registration_limit ) {
                        $spots_left = max( 0, $ev->registration_limit - $reg_count );
                        if ( $spots_left === 0 ) {
                            $reg_info = 'Full — Waitlist Available';
                        } else {
                            $reg_info = $spots_left . ' spot' . ( $spots_left !== 1 ? 's' : '' ) . ' remaining';
                        }
                    }
                }
            ?>
                <article class="sp-event-card">
                    <a href="<?php echo esc_url( $detail_url ); ?>" class="sp-event-card-link">

                        <!-- Date block -->
                        <div class="sp-event-date-block">
                            <span class="sp-event-month"><?php echo esc_html( $month_name ); ?></span>
                            <span class="sp-event-day"><?php echo esc_html( $day_num ); ?></span>
                            <span class="sp-event-dow"><?php echo esc_html( $day_name ); ?></span>
                        </div>

                        <!-- Event details -->
                        <div class="sp-event-details">
                            <h3 class="sp-event-title"><?php echo esc_html( $ev->title ); ?></h3>

                            <div class="sp-event-meta">
                                <?php if ( $time_str ) : ?>
                                    <span class="sp-event-meta-item sp-event-time">
                                        &#128339; <?php echo esc_html( $time_str ); ?>
                                    </span>
                                <?php endif; ?>

                                <?php if ( $location ) : ?>
                                    <span class="sp-event-meta-item sp-event-location">
                                        &#128205; <?php echo esc_html( $location ); ?>
                                    </span>
                                <?php endif; ?>
                            </div>

                            <div class="sp-event-badges">
                                <?php if ( ! empty( $ev->category_name ) ) : ?>
                                    <span class="sp-event-badge" style="background: <?php echo esc_attr( $ev->category_color ?: '#2271b1' ); ?>;">
                                        <?php echo esc_html( $ev->category_name ); ?>
                                    </span>
                                <?php endif; ?>

                                <?php if ( $ev->status === 'postponed' ) : ?>
                                    <span class="sp-event-badge sp-badge-postponed">Postponed</span>
                                <?php endif; ?>

                                <?php
                                // WHY show both prices: Members and non-members see
                                // different fees. Showing both up front sets expectations
                                // and highlights the membership value — "Members $5 /
                                // Non-Members $10" makes the benefit obvious.
                                $m_price  = (float) $ev->member_price;
                                $nm_price = (float) $ev->nonmember_price;

                                if ( $m_price > 0 && $nm_price > 0 ) : ?>
                                    <span class="sp-event-price">
                                        <?php echo esc_html__( 'Members', 'societypress' ) . ' $' . esc_html( number_format( $m_price, 2 ) ); ?>
                                        / <?php echo esc_html__( 'Non-Members', 'societypress' ) . ' $' . esc_html( number_format( $nm_price, 2 ) ); ?>
                                    </span>
                                <?php elseif ( $m_price > 0 ) : ?>
                                    <span class="sp-event-price">$<?php echo esc_html( number_format( $m_price, 2 ) ); ?></span>
                                <?php elseif ( $nm_price > 0 ) : ?>
                                    <span class="sp-event-price">
                                        <?php echo esc_html__( 'Free for Members', 'societypress' ); ?>
                                        / <?php echo esc_html__( 'Non-Members', 'societypress' ) . ' $' . esc_html( number_format( $nm_price, 2 ) ); ?>
                                    </span>
                                <?php elseif ( $ev->registration_enabled ) : ?>
                                    <span class="sp-event-price sp-event-free"><?php esc_html_e( 'Free', 'societypress' ); ?></span>
                                <?php endif; ?>

                                <?php if ( $reg_info ) : ?>
                                    <span class="sp-event-reg-info"><?php echo esc_html( $reg_info ); ?></span>
                                <?php endif; ?>

                                <?php if ( $ev->visibility === 'members_only' ) : ?>
                                    <span class="sp-event-badge sp-badge-members">Members Only</span>
                                <?php endif; ?>
                            </div>
                        </div>

                    </a>
                </article>
            <?php endforeach; ?>
        </div>

        <!-- Pagination -->
        <?php if ( $total_pages > 1 ) : ?>
        <nav class="sp-events-pagination" aria-label="Events pagination">
            <?php if ( $current_page > 1 ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page - 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link sp-page-prev">&laquo; Previous</a>
            <?php endif; ?>

            <?php
            $range = 2;
            $start = max( 1, $current_page - $range );
            $end   = min( $total_pages, $current_page + $range );

            if ( $start > 1 ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link">1</a>
                <?php if ( $start > 2 ) : ?>
                    <span class="sp-page-ellipsis">&hellip;</span>
                <?php endif; ?>
            <?php endif; ?>

            <?php for ( $p = $start; $p <= $end; $p++ ) : ?>
                <?php if ( $p === $current_page ) : ?>
                    <span class="sp-page-link sp-page-current"><?php echo $p; ?></span>
                <?php else : ?>
                    <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $p ] ), $base_url ) ); ?>"
                       class="sp-page-link"><?php echo $p; ?></a>
                <?php endif; ?>
            <?php endfor; ?>

            <?php if ( $end < $total_pages ) : ?>
                <?php if ( $end < $total_pages - 1 ) : ?>
                    <span class="sp-page-ellipsis">&hellip;</span>
                <?php endif; ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $total_pages ] ), $base_url ) ); ?>"
                   class="sp-page-link"><?php echo $total_pages; ?></a>
            <?php endif; ?>

            <?php if ( $current_page < $total_pages ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page + 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link sp-page-next">Next &raquo;</a>
            <?php endif; ?>
        </nav>
        <?php endif; ?>

    <?php endif; // empty( $events ) ?>

    <?php endif; // view === calendar ?>

    <?php
}


// ============================================================================
// EVENTS — FRONTEND DETAIL PAGE
// ============================================================================

/**
 * Render a single event's detail page.
 *
 * WHY: Members click an event from the listing or calendar to see full details —
 *      the description, speaker info, location, registration status, and contact.
 *      This is the "event flyer" equivalent for the web.
 *
 * @param string $slug     The event slug from the URL query var.
 * @param array  $settings The societypress_settings option array.
 */
function sp_render_event_detail( string $slug, array $settings ): void {
    global $wpdb;

    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';

    // Fetch the event
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT e.*, c.name AS category_name, c.color AS category_color
         FROM {$events_table} e
         LEFT JOIN {$cats_table} c ON e.category_id = c.id
         WHERE e.slug = %s",
        $slug
    ) );

    if ( ! $event ) {
        echo '<div class="sp-event-not-found">';
        echo '<h2>Event Not Found</h2>';
        echo '<p>The event you\'re looking for doesn\'t exist or has been removed.</p>';
        echo '<p><a href="' . esc_url( get_permalink() ) . '">&larr; Back to Events</a></p>';
        echo '</div>';
        return;
    }

    // Visibility check — members_only events require login
    if ( $event->visibility === 'members_only' && ! is_user_logged_in() ) {
        echo '<div class="sp-event-login-required">';
        echo '<h2>Members Only</h2>';
        echo '<p>This event is only visible to logged-in members. ';
        echo 'Please <a href="' . esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ) . '">log in</a> to view details.</p>';
        echo '</div>';
        return;
    }

    // Registration count
    $reg_count = 0;
    if ( $event->registration_enabled ) {
        $reg_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
             WHERE event_id = %d AND status = 'confirmed'",
            $event->id
        ) );
    }

    // Check if current user is already registered
    // WHY: For events with slots, a user can be registered for some slots
    //      but not others. We need to know WHICH slots they're in, not just
    //      whether they have ANY registration. $user_registered controls
    //      whether to show the "You're registered!" block or the form.
    //      For slotted events, we always show the form (so they can pick
    //      additional slots) plus a summary of their existing registrations.
    $user_registered = false;
    $user_slot_registrations = [];
    if ( is_user_logged_in() && $event->registration_enabled ) {
        $user_regs = $wpdb->get_results( $wpdb->prepare(
            "SELECT r.id, r.slot_id, r.status, r.party_size,
                    s.start_time AS slot_start, s.end_time AS slot_end, s.description AS slot_desc
             FROM {$reg_table} r
             LEFT JOIN {$wpdb->prefix}sp_event_slots s ON r.slot_id = s.id
             WHERE r.event_id = %d AND r.user_id = %d AND r.status IN ('confirmed', 'waitlisted')
             ORDER BY s.start_time ASC",
            $event->id, get_current_user_id()
        ) );
        if ( $user_regs ) {
            foreach ( $user_regs as $ur ) {
                $user_slot_registrations[] = $ur;
            }
        }
        // For events WITHOUT slots, use the old behavior (single registration)
        // For events WITH slots, always show the form so they can add more slots
        $user_registered = ! empty( $user_slot_registrations ) && empty( sp_slots_get_by_event( (int) $event->id, true ) );
    }

    // Load event time slots for display
    // WHY: If this event has time slots, we need them both for the detail display
    //      (showing available sessions) and the registration form (slot picker).
    $event_slots = sp_slots_get_by_event( (int) $event->id, true );

    // Featured image
    $image_url = '';
    if ( $event->image_id ) {
        $image_url = wp_get_attachment_image_url( $event->image_id, 'large' );
    }

    // Format date
    $date_ts      = strtotime( $event->event_date );
    $date_display = date_i18n( 'l, F j, Y', $date_ts ); // e.g., "Saturday, March 14, 2026"

    // Format time
    $time_display = '';
    if ( ! empty( $event->start_time ) ) {
        $time_display = date( 'g:i A', strtotime( $event->start_time ) );
        if ( ! empty( $event->end_time ) ) {
            $time_display .= ' – ' . date( 'g:i A', strtotime( $event->end_time ) );
        }
    }

    // Build slot display data for the detail page
    // WHY: When an event has slots, we show them instead of (or alongside) the
    //      main start/end time. Each slot shows its time range, capacity status,
    //      and a description if one was provided.
    $slot_display_data = [];
    if ( ! empty( $event_slots ) ) {
        foreach ( $event_slots as $es ) {
            $slot_reg_count = sp_slot_get_registration_count( (int) $es->id );
            $slot_remaining = sp_slot_get_remaining_capacity( (int) $es->id );
            $slot_display_data[] = (object) [
                'id'          => (int) $es->id,
                'time_range'  => sp_slot_format_time_range( $es ),
                'description' => $es->description ?? '',
                'capacity'    => $es->capacity !== null ? (int) $es->capacity : null,
                'registered'  => $slot_reg_count,
                'remaining'   => $slot_remaining,
                'is_full'     => $slot_remaining !== null && $slot_remaining <= 0,
            ];
        }
    }

    $events_page_url = get_permalink();

    ?>

    <!-- Back link -->
    <div class="sp-event-back">
        <a href="<?php echo esc_url( $events_page_url ); ?>">&larr; Back to Events</a>
    </div>

    <article class="sp-event-detail">

        <!-- Header: Title + Badges -->
        <header class="sp-event-header">
            <?php if ( $event->status === 'cancelled' ) : ?>
                <div class="sp-event-cancelled-banner">This event has been cancelled.</div>
            <?php elseif ( $event->status === 'postponed' ) : ?>
                <div class="sp-event-postponed-banner">This event has been postponed. Check back for updated details.</div>
            <?php endif; ?>

            <h1 class="sp-event-detail-title"><?php echo esc_html( $event->title ); ?></h1>

            <div class="sp-event-detail-badges">
                <?php if ( ! empty( $event->category_name ) ) : ?>
                    <span class="sp-event-badge" style="background: <?php echo esc_attr( $event->category_color ?: '#2271b1' ); ?>;">
                        <?php echo esc_html( $event->category_name ); ?>
                    </span>
                <?php endif; ?>

                <?php if ( $event->visibility === 'members_only' ) : ?>
                    <span class="sp-event-badge sp-badge-members">Members Only</span>
                <?php endif; ?>
            </div>
        </header>

        <!-- Featured Image -->
        <?php if ( $image_url ) : ?>
            <div class="sp-event-image">
                <img src="<?php echo esc_url( $image_url ); ?>" alt="<?php echo esc_attr( $event->title ); ?>">
            </div>
        <?php endif; ?>

        <!-- Key Details: Date, Time, Location -->
        <div class="sp-event-key-details">
            <div class="sp-event-detail-item">
                <span class="sp-detail-icon">&#128197;</span>
                <div>
                    <strong><?php echo esc_html( $date_display ); ?></strong>
                    <?php if ( $time_display ) : ?>
                        <br><span class="sp-detail-secondary"><?php echo esc_html( $time_display ); ?></span>
                    <?php endif; ?>
                </div>
            </div>

            <?php if ( ! empty( $event->location_name ) || $event->is_virtual ) : ?>
            <div class="sp-event-detail-item">
                <span class="sp-detail-icon">&#128205;</span>
                <div>
                    <?php if ( ! empty( $event->location_name ) ) : ?>
                        <strong><?php echo esc_html( $event->location_name ); ?></strong>
                        <?php if ( ! empty( $event->location_address ) ) : ?>
                            <br><span class="sp-detail-secondary"><?php echo esc_html( $event->location_address ); ?></span>
                        <?php endif; ?>
                    <?php endif; ?>

                    <?php if ( $event->is_virtual ) : ?>
                        <?php if ( ! empty( $event->location_name ) ) : ?>
                            <br>
                        <?php endif; ?>
                        <span class="sp-detail-virtual">&#128187; Virtual / Online</span>
                        <?php if ( ! empty( $event->virtual_url ) && is_user_logged_in() ) : ?>
                            <br><a href="<?php echo esc_url( $event->virtual_url ); ?>" target="_blank" rel="noopener"
                                   class="sp-virtual-link">Join Online Meeting &rarr;</a>
                        <?php endif; ?>
                    <?php endif; ?>
                </div>
            </div>
            <?php endif; ?>
        </div>

        <!-- Time Slots (if event has multiple sessions) -->
        <?php if ( ! empty( $slot_display_data ) ) : ?>
            <div class="sp-event-slots-section">
                <h2>Available Sessions</h2>
                <div class="sp-event-slots-grid">
                    <?php foreach ( $slot_display_data as $sd ) : ?>
                        <div class="sp-event-slot-card <?php echo $sd->is_full ? 'sp-slot-full' : ''; ?>">
                            <div class="sp-slot-time"><?php echo esc_html( $sd->time_range ); ?></div>
                            <?php if ( $sd->description ) : ?>
                                <div class="sp-slot-desc"><?php echo esc_html( $sd->description ); ?></div>
                            <?php endif; ?>
                            <?php if ( $sd->capacity !== null ) : ?>
                                <div class="sp-slot-capacity">
                                    <?php if ( $sd->is_full ) : ?>
                                        <span class="sp-slot-full-label">Full</span>
                                    <?php else : ?>
                                        <?php echo $sd->remaining; ?> of <?php echo $sd->capacity; ?> spots left
                                    <?php endif; ?>
                                </div>
                            <?php endif; ?>
                        </div>
                    <?php endforeach; ?>
                </div>
            </div>
        <?php endif; ?>

        <!-- Description -->
        <?php if ( ! empty( $event->description ) ) : ?>
            <div class="sp-event-description">
                <?php echo wp_kses_post( wpautop( $event->description ) ); ?>
            </div>
        <?php endif; ?>

        <!-- Speakers Section -->
        <?php
        // Fetch speakers assigned to this event
        $speakers = $wpdb->get_results( $wpdb->prepare(
            "SELECT s.*, sa.role
             FROM {$wpdb->prefix}sp_event_speaker_assignments sa
             JOIN {$wpdb->prefix}sp_event_speakers s ON sa.speaker_id = s.id
             WHERE sa.event_id = %d
             ORDER BY sa.sort_order",
            $event->id
        ) );

        if ( ! empty( $speakers ) ) :
        ?>
            <div class="sp-event-speakers">
                <h2><?php echo count( $speakers ) === 1 ? 'Speaker' : 'Speakers'; ?></h2>
                <?php foreach ( $speakers as $speaker ) :
                    $photo_url = '';
                    if ( $speaker->photo_id ) {
                        $photo_url = wp_get_attachment_image_url( $speaker->photo_id, 'thumbnail' );
                    }
                    $role_labels = [
                        'speaker'    => 'Speaker',
                        'instructor' => 'Instructor',
                        'moderator'  => 'Moderator',
                        'panelist'   => 'Panelist',
                    ];
                    $role_label = $role_labels[ $speaker->role ] ?? 'Speaker';
                ?>
                    <div class="sp-speaker-card">
                        <?php if ( $photo_url ) : ?>
                            <img src="<?php echo esc_url( $photo_url ); ?>" alt="<?php echo esc_attr( $speaker->name ); ?>"
                                 class="sp-speaker-photo">
                        <?php endif; ?>
                        <div class="sp-speaker-info">
                            <p class="sp-speaker-name"><?php echo esc_html( $speaker->name ); ?></p>
                            <?php if ( ! empty( $speaker->title ) ) : ?>
                                <p class="sp-speaker-title"><?php echo esc_html( $speaker->title ); ?></p>
                            <?php endif; ?>
                            <?php if ( count( $speakers ) > 1 || $speaker->role !== 'speaker' ) : ?>
                                <span class="sp-speaker-role"><?php echo esc_html( $role_label ); ?></span>
                            <?php endif; ?>
                            <?php if ( ! empty( $speaker->bio ) ) : ?>
                                <p class="sp-speaker-bio"><?php echo esc_html( $speaker->bio ); ?></p>
                            <?php endif; ?>
                            <?php if ( ! empty( $speaker->website ) ) : ?>
                                <p><a href="<?php echo esc_url( $speaker->website ); ?>" target="_blank" rel="noopener"
                                       class="sp-speaker-website">Website &rarr;</a></p>
                            <?php endif; ?>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>

        <!-- Registration Section -->
        <?php if ( $event->registration_enabled && $event->status === 'scheduled' ) : ?>
            <div class="sp-event-registration">
                <h2>Registration</h2>

                <!-- Pricing info -->
                <?php if ( (float) $event->member_price > 0 || (float) $event->nonmember_price > 0 ) : ?>
                    <div class="sp-event-pricing">
                        <?php if ( (float) $event->member_price > 0 ) : ?>
                            <div class="sp-price-item">
                                <span class="sp-price-label">Members:</span>
                                <span class="sp-price-amount">$<?php echo esc_html( number_format( (float) $event->member_price, 2 ) ); ?></span>
                            </div>
                        <?php else : ?>
                            <div class="sp-price-item">
                                <span class="sp-price-label">Members:</span>
                                <span class="sp-price-amount sp-price-free">Free</span>
                            </div>
                        <?php endif; ?>

                        <?php if ( $event->guest_registration ) : ?>
                            <?php if ( (float) $event->nonmember_price > 0 ) : ?>
                                <div class="sp-price-item">
                                    <span class="sp-price-label">Non-Members:</span>
                                    <span class="sp-price-amount">$<?php echo esc_html( number_format( (float) $event->nonmember_price, 2 ) ); ?></span>
                                </div>
                            <?php else : ?>
                                <div class="sp-price-item">
                                    <span class="sp-price-label">Non-Members:</span>
                                    <span class="sp-price-amount sp-price-free">Free</span>
                                </div>
                            <?php endif; ?>
                        <?php endif; ?>

                        <?php if ( ! empty( $event->price_description ) ) : ?>
                            <p class="sp-price-note"><?php echo esc_html( $event->price_description ); ?></p>
                        <?php endif; ?>
                    </div>
                <?php endif; ?>

                <!-- Spots remaining -->
                <?php if ( $event->registration_limit ) : ?>
                    <?php
                    $spots_left = max( 0, $event->registration_limit - $reg_count );
                    $pct = ( $reg_count / $event->registration_limit ) * 100;
                    ?>
                    <div class="sp-event-capacity">
                        <div class="sp-capacity-bar">
                            <div class="sp-capacity-fill" style="width: <?php echo min( 100, $pct ); ?>%;
                                background: <?php echo $pct >= 90 ? '#d63638' : ( $pct >= 70 ? '#dba617' : '#00a32a' ); ?>;"></div>
                        </div>
                        <p class="sp-capacity-text">
                            <?php if ( $spots_left === 0 ) : ?>
                                <strong>Event is full.</strong> You can join the waitlist.
                            <?php else : ?>
                                <?php echo $spots_left; ?> of <?php echo $event->registration_limit; ?> spots remaining
                            <?php endif; ?>
                        </p>
                    </div>
                <?php endif; ?>

                <!-- Registration status / button -->
                <?php if ( $user_registered ) : ?>
                    <?php
                    // Fetch the user's actual registration record for status + cancel
                    $user_reg = $wpdb->get_row( $wpdb->prepare(
                        "SELECT id, status, party_size FROM {$reg_table}
                         WHERE event_id = %d AND user_id = %d AND status IN ('confirmed', 'waitlisted')",
                        $event->id, get_current_user_id()
                    ) );
                    ?>
                    <div class="sp-reg-confirmed" id="sp-reg-status-area">
                        <?php if ( $user_reg && $user_reg->status === 'waitlisted' ) : ?>
                            <p>&#128203; <strong>You're on the waitlist.</strong></p>
                            <p class="sp-reg-note">We'll notify you if a spot opens up.</p>
                        <?php else : ?>
                            <p>&#9989; <strong>You're registered!</strong></p>
                            <p class="sp-reg-note">You'll receive a reminder email before the event.</p>
                        <?php endif; ?>
                        <button type="button" class="sp-reg-cancel-btn" id="sp-cancel-reg-btn"
                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                data-reg-id="<?php echo esc_attr( $user_reg->id ?? 0 ); ?>">
                            Cancel My Registration
                        </button>
                    </div>
                <?php else : ?>
                    <div class="sp-reg-action" id="sp-reg-form-area">
                        <?php if ( is_user_logged_in() ) : ?>
                            <!-- Logged-in member registration form -->
                            <div class="sp-reg-form" id="sp-member-reg-form">
                                <?php if ( ! empty( $user_slot_registrations ) ) : ?>
                                    <div class="sp-user-slot-regs" style="margin-bottom: 16px; padding: 12px; background: #f0f6fc; border: 1px solid #c3d4e8; border-radius: 6px;">
                                        <p style="margin: 0 0 8px; font-weight: 600;">Your Registrations:</p>
                                        <?php foreach ( $user_slot_registrations as $usr ) : ?>
                                            <div class="sp-user-slot-reg-row" style="display: flex; align-items: center; gap: 8px; margin-bottom: 6px;">
                                                <span style="flex: 1;">
                                                    <?php if ( $usr->slot_start ) : ?>
                                                        <?php echo esc_html( date( 'g:i A', strtotime( $usr->slot_start ) ) . ' – ' . date( 'g:i A', strtotime( $usr->slot_end ) ) ); ?>
                                                        <?php if ( $usr->slot_desc ) : ?>
                                                            <span style="color: #6b7280;"> — <?php echo esc_html( $usr->slot_desc ); ?></span>
                                                        <?php endif; ?>
                                                    <?php else : ?>
                                                        General Registration
                                                    <?php endif; ?>
                                                    <?php if ( $usr->status === 'waitlisted' ) : ?>
                                                        <span style="color: #dba617; font-size: 12px;">(waitlisted)</span>
                                                    <?php else : ?>
                                                        <span style="color: #00a32a; font-size: 12px;">(confirmed)</span>
                                                    <?php endif; ?>
                                                </span>
                                                <button type="button" class="sp-reg-cancel-btn sp-slot-cancel-btn"
                                                        data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                        data-reg-id="<?php echo esc_attr( $usr->id ); ?>"
                                                        style="font-size: 12px; padding: 2px 8px;">
                                                    Cancel
                                                </button>
                                            </div>
                                        <?php endforeach; ?>
                                    </div>
                                <?php endif; ?>
                                <?php if ( ! empty( $slot_display_data ) ) : ?>
                                    <?php
                                    // Filter out slots the user is already registered for
                                    $user_slot_ids = array_map( function( $r ) { return (int) $r->slot_id; }, $user_slot_registrations );
                                    $available_slots = array_filter( $slot_display_data, function( $sd ) use ( $user_slot_ids ) {
                                        return ! in_array( $sd->id, $user_slot_ids, true );
                                    } );
                                    ?>
                                    <?php if ( ! empty( $available_slots ) ) : ?>
                                    <div class="sp-reg-form-row">
                                        <label for="sp-reg-slot">Select a Session <span class="sp-required">*</span></label>
                                        <select id="sp-reg-slot" required>
                                            <option value="">— Choose a time slot —</option>
                                            <?php foreach ( $slot_display_data as $sd ) : ?>
                                                <option value="<?php echo esc_attr( $sd->id ); ?>"
                                                    <?php echo $sd->is_full ? 'data-full="1"' : ''; ?>>
                                                    <?php echo esc_html( $sd->time_range ); ?>
                                                    <?php if ( $sd->description ) echo ' — ' . esc_html( $sd->description ); ?>
                                                    <?php if ( $sd->is_full ) echo ' (FULL — waitlist)'; ?>
                                                    <?php if ( $sd->capacity !== null && ! $sd->is_full ) echo ' (' . $sd->remaining . ' spots)'; ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </div>
                                    <?php endif; ?>
                                <?php endif; ?>
                                <div class="sp-reg-form-row">
                                    <label for="sp-reg-party-size">How many attending?</label>
                                    <select id="sp-reg-party-size">
                                        <?php for ( $i = 1; $i <= 10; $i++ ) : ?>
                                            <option value="<?php echo $i; ?>"><?php echo $i; ?><?php echo $i === 1 ? ' (just me)' : ' people'; ?></option>
                                        <?php endfor; ?>
                                    </select>
                                </div>
                                <?php
                                // Show fee info if this event costs money
                                // WHY: People need to know what they're going to pay BEFORE
                                //      they click the button. The fee summary updates dynamically
                                //      via JS when party size changes.
                                $member_fee = (float) $event->member_price;
                                if ( $member_fee > 0 ) : ?>
                                    <div class="sp-reg-fee-summary" id="sp-fee-summary">
                                        <span class="sp-fee-label">Fee:</span>
                                        <span class="sp-fee-amount" id="sp-fee-display">
                                            $<?php echo number_format( $member_fee, 2 ); ?>
                                        </span>
                                        <span class="sp-fee-per-person" id="sp-fee-per-person">
                                            ($<?php echo number_format( $member_fee, 2 ); ?>/person)
                                        </span>
                                        <?php if ( ! empty( $event->price_description ) ) : ?>
                                            <span class="sp-fee-note"><?php echo esc_html( $event->price_description ); ?></span>
                                        <?php endif; ?>
                                    </div>
                                <?php endif; ?>
                                <?php
                                // Determine button text based on capacity and payment mode
                                $is_full = $event->registration_limit && $reg_count >= $event->registration_limit;
                                ?>
                                <?php if ( $is_full ) : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="none">
                                        Join Waitlist
                                    </button>
                                <?php elseif ( $show_pay_btn && $show_door_btn ) : ?>
                                    <!-- "Either" mode — two buttons so the registrant can choose -->
                                    <div class="sp-reg-pay-options">
                                        <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-register-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="online">
                                            Pay Now with Card
                                        </button>
                                        <button type="button" class="sp-reg-submit-btn sp-pay-door-btn" id="sp-register-door-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="at_door">
                                            Register — Pay at Door
                                        </button>
                                    </div>
                                <?php elseif ( $show_pay_btn ) : ?>
                                    <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="online">
                                        Pay &amp; Register
                                    </button>
                                <?php else : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="<?php echo $member_fee > 0 ? 'at_door' : 'none'; ?>">
                                        Register Now
                                    </button>
                                <?php endif; ?>
                                <div class="sp-reg-message" id="sp-reg-message" style="display: none;"></div>
                            </div>
                        <?php elseif ( $event->guest_registration ) : ?>
                            <!-- Guest registration form (not logged in, guest allowed) -->
                            <div class="sp-reg-form" id="sp-guest-reg-form">
                                <p class="sp-reg-form-intro">Register as a guest, or <a href="<?php echo esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ); ?>">log in</a> if you're a member.</p>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-name">Full Name <span class="sp-required">*</span></label>
                                    <input type="text" id="sp-guest-name" required placeholder="Your full name">
                                </div>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-email">Email <span class="sp-required">*</span></label>
                                    <input type="email" id="sp-guest-email" required placeholder="your@email.com">
                                </div>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-phone">Phone <span class="sp-reg-optional">(optional)</span></label>
                                    <input type="tel" id="sp-guest-phone" placeholder="(555) 555-1234">
                                </div>
                                <?php if ( ! empty( $slot_display_data ) ) : ?>
                                    <div class="sp-reg-form-row">
                                        <label for="sp-guest-slot">Select a Session <span class="sp-required">*</span></label>
                                        <select id="sp-guest-slot" required>
                                            <option value="">— Choose a time slot —</option>
                                            <?php foreach ( $slot_display_data as $sd ) : ?>
                                                <option value="<?php echo esc_attr( $sd->id ); ?>"
                                                    <?php echo $sd->is_full ? 'data-full="1"' : ''; ?>>
                                                    <?php echo esc_html( $sd->time_range ); ?>
                                                    <?php if ( $sd->description ) echo ' — ' . esc_html( $sd->description ); ?>
                                                    <?php if ( $sd->is_full ) echo ' (FULL — waitlist)'; ?>
                                                    <?php if ( $sd->capacity !== null && ! $sd->is_full ) echo ' (' . $sd->remaining . ' spots)'; ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </div>
                                <?php endif; ?>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-party-size">How many attending?</label>
                                    <select id="sp-guest-party-size">
                                        <?php for ( $i = 1; $i <= 10; $i++ ) : ?>
                                            <option value="<?php echo $i; ?>"><?php echo $i; ?><?php echo $i === 1 ? ' (just me)' : ' people'; ?></option>
                                        <?php endfor; ?>
                                    </select>
                                </div>
                                <?php
                                // Show fee info for guests (non-member pricing)
                                $guest_fee = (float) $event->nonmember_price;
                                if ( $guest_fee > 0 ) : ?>
                                    <div class="sp-reg-fee-summary" id="sp-guest-fee-summary">
                                        <span class="sp-fee-label">Fee:</span>
                                        <span class="sp-fee-amount" id="sp-guest-fee-display">
                                            $<?php echo number_format( $guest_fee, 2 ); ?>
                                        </span>
                                        <span class="sp-fee-per-person" id="sp-guest-fee-per-person">
                                            ($<?php echo number_format( $guest_fee, 2 ); ?>/person)
                                        </span>
                                        <?php if ( ! empty( $event->price_description ) ) : ?>
                                            <span class="sp-fee-note"><?php echo esc_html( $event->price_description ); ?></span>
                                        <?php endif; ?>
                                    </div>
                                <?php endif; ?>
                                <?php
                                $is_full = $event->registration_limit && $reg_count >= $event->registration_limit;
                                ?>
                                <?php if ( $is_full ) : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="none">
                                        Join Waitlist
                                    </button>
                                <?php elseif ( $show_pay_btn && $show_door_btn ) : ?>
                                    <div class="sp-reg-pay-options">
                                        <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-guest-register-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="online">
                                            Pay Now with Card
                                        </button>
                                        <button type="button" class="sp-reg-submit-btn sp-pay-door-btn" id="sp-guest-register-door-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="at_door">
                                            Register — Pay at Door
                                        </button>
                                    </div>
                                <?php elseif ( $show_pay_btn ) : ?>
                                    <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="online">
                                        Pay &amp; Register
                                    </button>
                                <?php else : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="<?php echo $guest_fee > 0 ? 'at_door' : 'none'; ?>">
                                        Register Now
                                    </button>
                                <?php endif; ?>
                                <div class="sp-reg-message" id="sp-reg-message" style="display: none;"></div>
                            </div>
                        <?php else : ?>
                            <!-- Not logged in, no guest registration -->
                            <p class="sp-reg-login-prompt">
                                Please <a href="<?php echo esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ); ?>">log in</a> to register for this event.
                            </p>
                        <?php endif; ?>
                    </div>
                <?php endif; ?>
            </div>
        <?php endif; ?>

        <!-- Contact Section -->
        <?php if ( ! empty( $event->contact_name ) || ! empty( $event->contact_email ) || ! empty( $event->contact_phone ) ) : ?>
            <div class="sp-event-contact">
                <h2>Contact</h2>
                <?php if ( ! empty( $event->contact_name ) ) : ?>
                    <p class="sp-contact-name"><?php echo esc_html( $event->contact_name ); ?></p>
                <?php endif; ?>
                <?php if ( ! empty( $event->contact_email ) ) : ?>
                    <p><?php echo sp_obfuscate_email( $event->contact_email ); ?></p>
                <?php endif; ?>
                <?php if ( ! empty( $event->contact_phone ) ) : ?>
                    <?php
                    $phone_digits = preg_replace( '/\D/', '', $event->contact_phone );
                    $phone_display = $event->contact_phone;
                    if ( strlen( $phone_digits ) === 10 ) {
                        $phone_display = '(' . substr( $phone_digits, 0, 3 ) . ') ' . substr( $phone_digits, 3, 3 ) . '-' . substr( $phone_digits, 6 );
                    }
                    ?>
                    <p><a href="tel:<?php echo esc_attr( $phone_digits ); ?>"><?php echo esc_html( $phone_display ); ?></a></p>
                <?php endif; ?>
            </div>
        <?php endif; ?>

    </article>

    <?php if ( $event->registration_enabled && $event->status === 'scheduled' ) : ?>
        <!-- Registration data for AJAX calls -->
        <?php
        // Determine if Stripe is available for this event
        // WHY: The frontend JS needs to know whether to offer online payment
        //      vs. just a plain registration. We check both the event's payment
        //      mode AND whether Stripe keys are actually configured — no point
        //      showing a "Pay Now" button if the society hasn't set up Stripe.
        $sp_settings    = get_option( 'societypress_settings', [] );
        $stripe_ready   = sp_stripe_is_configured( $sp_settings );
        $payment_mode   = $event->payment_mode ?? 'none';
        $has_fee        = ( (float) $event->member_price > 0 || (float) $event->nonmember_price > 0 );
        $show_pay_btn   = $has_fee && $stripe_ready && in_array( $payment_mode, [ 'online', 'either' ], true );
        $show_door_btn  = $has_fee && in_array( $payment_mode, [ 'at_door', 'either' ], true );
        $pay_only       = $has_fee && $payment_mode === 'online' && $stripe_ready;
        ?>
        <script>
        var spRegData = {
            ajaxUrl:      '<?php echo admin_url( "admin-ajax.php" ); ?>',
            nonce:        '<?php echo wp_create_nonce( "sp_event_register" ); ?>',
            showPayBtn:   <?php echo $show_pay_btn ? 'true' : 'false'; ?>,
            showDoorBtn:  <?php echo $show_door_btn ? 'true' : 'false'; ?>,
            payOnly:      <?php echo $pay_only ? 'true' : 'false'; ?>,
            memberPrice:  <?php echo (float) $event->member_price; ?>,
            nonmemberPrice: <?php echo (float) $event->nonmember_price; ?>,
            currency:     '<?php echo strtoupper( $sp_settings['stripe_currency'] ?? 'USD' ); ?>'
        };
        </script>
    <?php endif; ?>
    <?php
}


// ============================================================================
// EVENTS — FRONTEND CSS
// ============================================================================

/**
 * Output event page styles in <head>.
 *
 * WHY: Only loaded on pages using the events template. Clean, responsive
 *      design that works with any WordPress theme. Mobile breakpoint at
 *      768px converts cards to stacked layout and calendar to dot view.
 */
function sp_events_frontend_styles(): void {
    ?>
    <style id="sp-events-frontend-css">
        /* ---- Wrapper ---- */
        .sp-events-wrap {
            margin: 40px auto;
            padding: 0 20px;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, sans-serif;
        }

        /* ================================================================ */
        /* FILTER BAR                                                        */
        /* ================================================================ */
        .sp-events-filters {
            margin-bottom: 24px;
            padding-bottom: 16px;
            border-bottom: 1px solid #eee;
        }
        .sp-events-filter-form {
            display: flex;
            flex-direction: column;
            gap: 12px;
        }
        .sp-events-filter-row {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
            align-items: center;
        }
        .sp-events-search-wrap {
            flex: 1;
            min-width: 200px;
        }
        .sp-events-search-input {
            width: 100%;
            padding: 10px 14px;
            font-size: 16px;
            border: 2px solid #ddd;
            border-radius: 6px;
            outline: none;
            transition: border-color 0.2s;
            box-sizing: border-box;
        }
        .sp-events-search-input:focus {
            border-color: var(--sp-color-primary);
        }
        .sp-events-filter-select {
            padding: 10px 12px;
            font-size: 15px;
            border: 2px solid #ddd;
            border-radius: 6px;
            background: #fff;
            cursor: pointer;
        }
        .sp-events-filter-btn {
            padding: 10px 24px;
            font-size: 15px;
            font-weight: 600;
            color: #fff;
            background: var(--sp-color-primary);
            border: none;
            border-radius: 6px;
            cursor: pointer;
        }
        .sp-events-filter-btn:hover { background: var(--sp-color-primary-hover); }
        .sp-events-clear-link {
            font-size: 14px;
            color: #666;
            text-decoration: none;
            padding: 10px 8px;
        }
        .sp-events-clear-link:hover { color: #d63638; }

        /* View toggle */
        .sp-events-view-toggle {
            display: flex;
            gap: 4px;
        }
        .sp-view-btn {
            padding: 8px 16px;
            font-size: 14px;
            font-weight: 500;
            color: #555;
            text-decoration: none;
            border: 2px solid #ddd;
            border-radius: 6px;
            transition: all 0.15s;
        }
        .sp-view-btn:hover { border-color: var(--sp-color-primary); color: var(--sp-color-primary); }
        .sp-view-active {
            background: var(--sp-color-primary);
            color: #fff !important;
            border-color: var(--sp-color-primary);
        }
        .sp-view-icon { margin-right: 4px; }

        /* ================================================================ */
        /* EVENT CARDS (List View)                                           */
        /* ================================================================ */
        .sp-events-count {
            margin-bottom: 8px;
            color: #787c82;
            font-size: 14px;
        }
        .sp-events-list {
            display: flex;
            flex-direction: column;
            gap: 12px;
        }
        .sp-event-card {
            border: 1px solid #e8e8e8;
            border-radius: 8px;
            background: #fff;
            transition: box-shadow 0.2s, border-color 0.2s;
        }
        .sp-event-card:hover {
            box-shadow: 0 2px 8px rgba(0,0,0,0.08);
            border-color: #ccc;
        }
        .sp-event-card-link {
            display: flex;
            align-items: stretch;
            text-decoration: none;
            color: inherit;
        }
        .sp-event-date-block {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-width: 80px;
            padding: 16px 12px;
            background: #f7f7f7;
            border-radius: 8px 0 0 8px;
            border-right: 1px solid #e8e8e8;
        }
        .sp-event-month {
            font-size: 12px;
            font-weight: 600;
            text-transform: uppercase;
            color: #d63638;
            letter-spacing: 0.5px;
        }
        .sp-event-day {
            font-size: 28px;
            font-weight: 700;
            line-height: 1.1;
            color: #1d2327;
        }
        .sp-event-dow {
            font-size: 12px;
            color: #787c82;
            text-transform: uppercase;
        }
        .sp-event-details {
            flex: 1;
            padding: 16px 20px;
            min-width: 0;
        }
        .sp-event-title {
            margin: 0 0 6px 0;
            font-size: 17px;
            font-weight: 600;
            color: #1d2327;
            line-height: 1.3;
        }
        .sp-event-meta {
            display: flex;
            flex-wrap: wrap;
            gap: 12px;
            margin-bottom: 8px;
        }
        .sp-event-meta-item {
            font-size: 14px;
            color: #555;
        }
        .sp-event-badges {
            display: flex;
            flex-wrap: wrap;
            gap: 6px;
            align-items: center;
        }
        .sp-event-badge {
            display: inline-block;
            padding: 3px 10px;
            font-size: 12px;
            font-weight: 600;
            color: #fff;
            border-radius: 4px;
            white-space: nowrap;
        }
        .sp-badge-postponed { background: #dba617; }
        .sp-badge-members { background: #787c82; }
        .sp-event-price {
            font-size: 13px;
            font-weight: 600;
            color: #1d2327;
        }
        .sp-event-free { color: #00a32a; }
