// ============================================================================
// USER MANAGER — WordPress User Account Management for Members
// ============================================================================
//
// WHY: Every member needs a WordPress user account to log in, access the
//      portal, view the directory, register for events, etc. The sp_members
//      table uses user_id as its primary key, so member = WP user, always.
//
//      We create a custom "sp_member" role with limited capabilities —
//      members can view content and access the portal, but they can't
//      edit posts, upload files, or access wp-admin. This keeps the site
//      secure even if a member's password is compromised.
//
//      The user creation functions handle the full lifecycle: generate a
//      safe username from their email, create the WP user, assign the
//      sp_member role, and create the sp_members row in one call.
// ============================================================================

/**
 * Register the sp_member WordPress role.
 *
 * WHY: WordPress's built-in roles (subscriber, editor, etc.) are either
 *      too permissive or don't have our custom capabilities. sp_member
 *      gives us fine-grained control over what members can do:
 *        - read: View published content (required for portal/directory)
 *        - sp_access_member_portal: Custom cap for portal access checks
 *      Everything else is denied by default.
 *
 * SAFETY: Only adds the role if it doesn't exist yet. Safe to call repeatedly.
 */
add_action( 'init', function () {
    if ( ! get_role( 'sp_member' ) ) {
        add_role( 'sp_member', 'Society Member', [
            'read'                    => true,
            'edit_posts'              => false,
            'delete_posts'            => false,
            'upload_files'            => false,
            'sp_access_member_portal' => true,
        ] );
    }
} );

/**
 * Create or link a WordPress user account for a member.
 *
 * WHY: When adding a new member (from admin, import, or join form), we need
 *      a WP user account for them. If someone with that email already exists
 *      in WordPress (maybe they registered independently), we link to that
 *      existing account. Otherwise we create a fresh one.
 *
 * FLOW:
 *   1. Check if a WP user with this email already exists
 *   2. If yes: assign sp_member role, return their user_id
 *   3. If no: generate username, create WP user, assign role, return user_id
 *
 * @param string $email      Member's email address.
 * @param string $first_name Member's first name.
 * @param string $last_name  Member's last name.
 * @return int|WP_Error User ID on success, WP_Error on failure.
 */
function sp_create_or_link_user( string $email, string $first_name, string $last_name ) {
    // Validate email
    if ( ! is_email( $email ) ) {
        return new WP_Error( 'invalid_email', 'A valid email address is required to create a member account.' );
    }

    // Check if WP user already exists with this email
    $existing = get_user_by( 'email', $email );

    if ( $existing ) {
        // Add sp_member role if they don't have it (keeps existing roles too)
        if ( ! in_array( 'sp_member', $existing->roles, true ) ) {
            $existing->add_role( 'sp_member' );
        }
        return $existing->ID;
    }

    // Generate a unique username from the email
    $username = sp_generate_username( $email );

    // Create the WP user with a secure random password
    $user_id = wp_insert_user( [
        'user_login'           => $username,
        'user_email'           => $email,
        'user_pass'            => wp_generate_password( 16, true, true ),
        'first_name'           => $first_name,
        'last_name'            => $last_name,
        'display_name'         => trim( $first_name . ' ' . $last_name ),
        'role'                 => 'sp_member',
        'show_admin_bar_front' => 'false',
    ] );

    if ( is_wp_error( $user_id ) ) {
        return $user_id;
    }

    return $user_id;
}

/**
 * Generate a unique WordPress username from an email address.
 *
 * WHY: We need usernames for WP user creation, but members don't pick their
 *      own — we auto-generate from their email. If jane@example.com is taken,
 *      we try jane@example.com2, jane@example.com3, etc. Sanitize_user strips
 *      characters that WordPress doesn't allow in usernames.
 *
 * @param string $email Email address to derive username from.
 * @return string Unique, sanitized username.
 */
function sp_generate_username( string $email ): string {
    $username = sanitize_user( $email, true );

    if ( ! username_exists( $username ) ) {
        return $username;
    }

    // Append incrementing number until we find a unique one
    $i = 2;
    while ( username_exists( $username . $i ) ) {
        $i++;
    }

    return $username . $i;
}

/**
 * Get the sp_members row for a WordPress user ID.
 *
 * WHY: When a logged-in user hits the portal or directory, we know their
 *      WP user_id but need their member record. Since user_id is the PK
 *      of sp_members, this is a direct primary key lookup — fast.
 *
 * @param int $user_id WordPress user ID.
 * @return object|null Member row or null if not a member.
 */
function sp_get_member_by_user_id( int $user_id ): ?object {
    global $wpdb;

    return $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_members WHERE user_id = %d",
        $user_id
    ) );
}

/**
 * Check if a WordPress user is a society member.
 *
 * WHY: Quick boolean check for template conditionals and access control.
 *      "Is this logged-in person actually a member?" is a question every
 *      member-only page needs to answer.
 *
 * @param int $user_id WordPress user ID. Defaults to current user.
 * @return bool True if the user has a member record.
 */
function sp_is_member( int $user_id = 0 ): bool {
    if ( ! $user_id ) {
        $user_id = get_current_user_id();
    }
    if ( ! $user_id ) {
        return false;
    }

    return sp_get_member_by_user_id( $user_id ) !== null;
}

/**
 * Bulk convert existing subscriber users to the sp_member role.
 *
 * WHY: Members imported before the sp_member role existed are all subscribers.
 *      This one-time utility converts them so portal access control works
 *      correctly. Only converts users who have a row in sp_members — random
 *      subscribers who aren't members are left alone.
 *
 * @return array [ 'converted' => int, 'skipped' => int, 'errors' => int ]
 */
function sp_bulk_convert_to_member_role(): array {
    global $wpdb;

    $results = [ 'converted' => 0, 'skipped' => 0, 'errors' => 0 ];

    // Get all member user_ids
    $member_user_ids = $wpdb->get_col(
        "SELECT user_id FROM {$wpdb->prefix}sp_members WHERE user_id IS NOT NULL"
    );

    foreach ( $member_user_ids as $uid ) {
        $user = get_userdata( (int) $uid );
        if ( ! $user ) {
            $results['errors']++;
            continue;
        }

        // Skip if already has sp_member role
        if ( in_array( 'sp_member', $user->roles, true ) ) {
            $results['skipped']++;
            continue;
        }

        // Remove subscriber, add sp_member
        $user->remove_role( 'subscriber' );
        $user->add_role( 'sp_member' );
        $results['converted']++;
    }

    return $results;
}

/**
 * Hide the WordPress admin bar for sp_member users on the frontend.
 *
 * WHY: Members don't need (and shouldn't see) the WordPress admin toolbar
 *      when browsing the site. It's confusing and exposes WP internals.
 */
add_filter( 'show_admin_bar', function ( $show ) {
    if ( is_user_logged_in() ) {
        $user = wp_get_current_user();
        if ( in_array( 'sp_member', $user->roles, true ) && ! current_user_can( 'manage_options' ) ) {
            return false;
        }
    }
    return $show;
} );

/**
 * Redirect sp_member users away from wp-admin to the frontend.
 *
 * WHY: If a member somehow navigates to /wp-admin/, they should be bounced
 *      to the homepage (or eventually the portal). They have no business
 *      in the WordPress backend. Admins are exempted.
 */
add_action( 'admin_init', function () {
    if ( ! current_user_can( 'manage_options' ) && ! wp_doing_ajax() ) {
        $user = wp_get_current_user();
        if ( in_array( 'sp_member', $user->roles, true ) ) {
            wp_safe_redirect( home_url() );
            exit;
        }
    }
} );


// ============================================================================
// EMAIL LOGGING SYSTEM
// ============================================================================
//
// WHY: Genealogical societies need visibility into member communications.
//      Admins can verify emails are correct before enabling production
//      sending, troubleshoot delivery issues, and maintain records.
//
//      In dev mode (WP_DEBUG + non-production URL), emails are intercepted
//      and logged but NOT sent, so you can preview everything safely.
//
//      All emails pass through pre_wp_mail, which logs them first, then
//      decides whether to actually send. After send, wp_mail_succeeded or
//      wp_mail_failed updates the log entry status.
// ============================================================================

/**
 * Log an email to the sp_email_log table.
 *
 * WHY: Central logging function called by the pre_wp_mail interceptor.
 *      Records the email before it's sent so we have a record even if
 *      the send fails silently.
 *
 * @param string      $recipient   Email recipient(s).
 * @param string      $subject     Email subject line.
 * @param string      $body        Email body content.
 * @param string      $headers     Email headers (may be array, gets serialized).
 * @param string      $status      Initial status: pending, blocked, sent, failed.
 * @param string|null $error       Error message if known at log time.
 * @param int|null    $member_id   Associated member ID if known.
 * @param string|null $email_type  Type: welcome, reminder, registration, etc.
 * @return int|false  The log entry ID or false on failure.
 */
function sp_email_log_insert(
    string $recipient,
    string $subject,
    string $body,
    string $headers = '',
    string $status = 'pending',
    ?string $error = null,
    ?int $member_id = null,
    ?string $email_type = null
) {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    // Headers might come in as an array from wp_mail
    if ( is_array( $headers ) ) {
        $headers = implode( "\n", $headers );
    }

    $data = [
        'recipient'     => $recipient,
        'subject'       => $subject,
        'body'          => $body,
        'headers'       => $headers,
        'status'        => $status,
        'error_message' => $error,
        'member_id'     => $member_id,
        'email_type'    => $email_type,
        'created_at'    => current_time( 'mysql' ),
    ];

    if ( $status === 'sent' ) {
        $data['sent_at'] = current_time( 'mysql' );
    }

    $result = $wpdb->insert( $table, $data );

    return $result !== false ? (int) $wpdb->insert_id : false;
}

/**
 * Update an email log entry's status after send attempt.
 *
 * WHY: After pre_wp_mail logs the email as "pending," we need to update
 *      it to "sent" or "failed" once we know the outcome. This keeps
 *      the log accurate.
 *
 * @param int         $log_id  The log entry ID.
 * @param string      $status  New status: sent, failed, blocked.
 * @param string|null $error   Error message if failed.
 * @return bool True on success.
 */
function sp_email_log_update_status( int $log_id, string $status, ?string $error = null ): bool {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    $data    = [ 'status' => $status ];
    $formats = [ '%s' ];

    if ( $status === 'sent' ) {
        $data['sent_at'] = current_time( 'mysql' );
        $formats[]       = '%s';
    }

    if ( $error !== null ) {
        $data['error_message'] = $error;
        $formats[]             = '%s';
    }

    $result = $wpdb->update( $table, $data, [ 'id' => $log_id ], $formats, [ '%d' ] );
    return $result !== false;
}

/**
 * Get a single email log entry by ID.
 *
 * @param int $log_id The log entry ID.
 * @return object|null Log row or null.
 */
function sp_email_log_get( int $log_id ): ?object {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    return $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$table} WHERE id = %d", $log_id
    ) );
}

/**
 * Get paginated email log entries with filtering.
 *
 * WHY: The admin page needs paginated results with status/type/search
 *      filtering. Returns both the result set and total count for
 *      pagination controls.
 *
 * @param array $args Query arguments: status, email_type, search, per_page, page, orderby, order.
 * @return array [ 'items' => array, 'total' => int ]
 */
function sp_email_log_get_list( array $args = [] ): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    $defaults = [
        'status'     => '',
        'email_type' => '',
        'search'     => '',
        'per_page'   => 20,
        'page'       => 1,
        'orderby'    => 'created_at',
        'order'      => 'DESC',
    ];
    $args = wp_parse_args( $args, $defaults );

    // Build WHERE clause
    $where  = [ '1=1' ];
    $values = [];

    if ( ! empty( $args['status'] ) ) {
        $where[]  = 'status = %s';
        $values[] = $args['status'];
    }

    if ( ! empty( $args['email_type'] ) ) {
        $where[]  = 'email_type = %s';
        $values[] = $args['email_type'];
    }

    if ( ! empty( $args['search'] ) ) {
        $where[]  = '(recipient LIKE %s OR subject LIKE %s)';
        $like     = '%' . $wpdb->esc_like( $args['search'] ) . '%';
        $values[] = $like;
        $values[] = $like;
    }

    $where_sql = implode( ' AND ', $where );

    // Sanitize orderby to prevent injection
    $allowed_orderby = [ 'id', 'recipient', 'subject', 'status', 'email_type', 'created_at', 'sent_at' ];
    $orderby = in_array( $args['orderby'], $allowed_orderby, true ) ? $args['orderby'] : 'created_at';
    $order   = strtoupper( $args['order'] ) === 'ASC' ? 'ASC' : 'DESC';

    // Total count for pagination
    $count_sql = "SELECT COUNT(*) FROM {$table} WHERE {$where_sql}";
    if ( ! empty( $values ) ) {
        $count_sql = $wpdb->prepare( $count_sql, ...$values );
    }
    $total = (int) $wpdb->get_var( $count_sql );

    // Fetch page of results
    $offset   = ( $args['page'] - 1 ) * $args['per_page'];
    $values[] = (int) $args['per_page'];
    $values[] = (int) $offset;

    $items = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$table} WHERE {$where_sql} ORDER BY {$orderby} {$order} LIMIT %d OFFSET %d",
        ...$values
    ) );

    return [
        'items' => $items ?: [],
        'total' => $total,
    ];
}

/**
 * Get email log statistics for the dashboard.
 *
 * WHY: Admins need a quick overview — how many emails sent, blocked,
 *      or failed in the last N days. Useful for spotting delivery
 *      problems before members start complaining.
 *
 * @param int $days Number of days to look back. Default 30.
 * @return array [ 'sent' => int, 'blocked' => int, 'failed' => int, 'pending' => int, 'total' => int ]
 */
function sp_email_log_get_stats( int $days = 30 ): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';
    $since = gmdate( 'Y-m-d H:i:s', strtotime( "-{$days} days" ) );

    $stats = $wpdb->get_results( $wpdb->prepare(
        "SELECT status, COUNT(*) as cnt FROM {$table} WHERE created_at >= %s GROUP BY status",
        $since
    ) );

    $result = [ 'sent' => 0, 'blocked' => 0, 'failed' => 0, 'pending' => 0, 'total' => 0 ];
    foreach ( $stats as $row ) {
        if ( isset( $result[ $row->status ] ) ) {
            $result[ $row->status ] = (int) $row->cnt;
        }
        $result['total'] += (int) $row->cnt;
    }

    return $result;
}

/**
 * Get distinct email types for the admin filter dropdown.
 *
 * @return array List of email type strings.
 */
function sp_email_log_get_types(): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    return $wpdb->get_col(
        "SELECT DISTINCT email_type FROM {$table}
         WHERE email_type IS NOT NULL AND email_type != ''
         ORDER BY email_type ASC"
    ) ?: [];
}

/**
 * Delete email log entries older than a given number of days.
 *
 * WHY: Without cleanup, the log table grows indefinitely. 90 days is
 *      enough for troubleshooting and auditing. Older entries are noise.
 *      Called automatically by the daily cron event.
 *
 * @param int $days Delete entries older than this. Default 90.
 * @return int Number of rows deleted.
 */
function sp_email_log_cleanup( int $days = 90 ): int {
    global $wpdb;
    $table  = $wpdb->prefix . 'sp_email_log';
    $cutoff = gmdate( 'Y-m-d H:i:s', strtotime( "-{$days} days" ) );

    $result = $wpdb->query( $wpdb->prepare(
        "DELETE FROM {$table} WHERE created_at < %s", $cutoff
    ) );

    return $result !== false ? (int) $result : 0;
}

/**
 * Determine whether emails should be blocked (dev mode).
 *
 * WHY: On development/staging sites we want to log emails without actually
 *      sending them — prevents embarrassing test emails going to real members.
 *      Checks WP_DEBUG + ensures we're not on a production domain. The
 *      SOCIETYPRESS_ALLOW_EMAILS constant provides an override for testing
 *      email delivery even in dev mode.
 *
 * @return bool True if emails should be blocked.
 */
function sp_email_should_block(): bool {
    // Explicit override — always allow emails
    if ( defined( 'SOCIETYPRESS_ALLOW_EMAILS' ) && SOCIETYPRESS_ALLOW_EMAILS ) {
        return false;
    }

    // Block if WP_DEBUG is on AND we're on localhost or a known dev domain
    if ( defined( 'WP_DEBUG' ) && WP_DEBUG ) {
        $host = wp_parse_url( home_url(), PHP_URL_HOST );
        $dev_indicators = [ 'localhost', '127.0.0.1', '.local', '.test', '.dev', 'staging.' ];
        foreach ( $dev_indicators as $indicator ) {
            if ( stripos( $host, $indicator ) !== false ) {
                return true;
            }
        }
    }

    return false;
}

/**
 * Intercept all outgoing emails via pre_wp_mail.
 *
 * WHY: This is the single hook point for the entire email logging system.
 *      Every email WordPress sends — whether from SocietyPress, a plugin,
 *      or core — passes through here. We log it, then either allow it
 *      through or block it (dev mode). The log_id is stashed in a global
 *      so wp_mail_succeeded and wp_mail_failed can update the right row.
 *
 * FLOW:
 *   1. pre_wp_mail fires → we log the email as "pending" (or "blocked")
 *   2. If blocked, we return false to prevent sending
 *   3. If allowed, wp_mail sends it, then:
 *      - wp_mail_succeeded fires → we update status to "sent"
 *      - wp_mail_failed fires → we update status to "failed" with error
 */
add_filter( 'pre_wp_mail', function ( $null, $atts ) {
    // Extract email details from the atts array
    $to      = is_array( $atts['to'] ) ? implode( ', ', $atts['to'] ) : $atts['to'];
    $subject = $atts['subject'] ?? '';
    $message = $atts['message'] ?? '';
    $headers = $atts['headers'] ?? '';

    if ( is_array( $headers ) ) {
        $headers = implode( "\n", $headers );
    }

    // Check if we should block (dev mode)
    $blocked = sp_email_should_block();
    $status  = $blocked ? 'blocked' : 'pending';

    // Log the email
    $log_id = sp_email_log_insert( $to, $subject, $message, $headers, $status );

    // Stash the log_id so the success/failure hooks can find it
    if ( $log_id ) {
        $GLOBALS['sp_current_email_log_id'] = $log_id;
    }

    // If blocked, return false to prevent wp_mail from sending
    if ( $blocked ) {
        return false;
    }

    // Return null to let wp_mail proceed normally
    return null;
}, 10, 2 );

/**
 * Update log entry to "sent" when wp_mail succeeds.
 */
add_action( 'wp_mail_succeeded', function ( $mail_data ) {
    if ( ! empty( $GLOBALS['sp_current_email_log_id'] ) ) {
        sp_email_log_update_status( (int) $GLOBALS['sp_current_email_log_id'], 'sent' );
        unset( $GLOBALS['sp_current_email_log_id'] );
    }
} );

/**
 * Update log entry to "failed" when wp_mail fails.
 */
add_action( 'wp_mail_failed', function ( $wp_error ) {
    if ( ! empty( $GLOBALS['sp_current_email_log_id'] ) ) {
        $error_msg = $wp_error instanceof WP_Error ? $wp_error->get_error_message() : 'Unknown error';
        sp_email_log_update_status( (int) $GLOBALS['sp_current_email_log_id'], 'failed', $error_msg );
        unset( $GLOBALS['sp_current_email_log_id'] );
    }
} );

/**
 * Schedule daily email log cleanup on plugin activation.
 *
 * WHY: We don't want to check "should we clean up?" on every page load.
 *      A daily cron event is lightweight and keeps the table tidy.
 */
add_action( 'init', function () {
    if ( ! wp_next_scheduled( 'sp_email_log_cleanup_cron' ) ) {
        wp_schedule_event( time(), 'daily', 'sp_email_log_cleanup_cron' );
    }
} );

add_action( 'sp_email_log_cleanup_cron', function () {
    sp_email_log_cleanup( 90 );
} );


// ============================================================================
// EVENTS — EMAIL SYSTEM
// ============================================================================
//
// WHY: Email is the primary way SAGHS communicates with members about events.
//      When someone registers, they expect a confirmation. When their waitlist
//      spot opens up, they need to know. When an event is cancelled or moved,
//      registrants need to be told. And reminders reduce no-shows.
//
//      All emails use a shared HTML template for consistent branding. The
//      society name comes from WordPress settings (blogname), not hardcoded.
// ============================================================================

/**
 * Build an HTML email body with consistent styling.
 *
 * WHY: Every email from SocietyPress should look professional and be readable
 *      on mobile. This shared template gives us a clean layout with the
 *      society's name, a styled content area, and a footer. We keep it simple
 *      (inline CSS, table layout) because email clients are stuck in 2005.
 *
 * @param string $heading   The email heading (e.g., "Registration Confirmed").
 * @param string $body_html The main content HTML.
 * @return string Complete HTML email body.
 */
function sp_build_email_html( string $heading, string $body_html ): string {
    $site_name = get_bloginfo( 'name' );
    $site_url  = home_url();

    return '<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>
<body style="margin: 0; padding: 0; background: #f4f4f4; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background: #f4f4f4; padding: 24px 0;">
<tr><td align="center">
<table width="600" cellpadding="0" cellspacing="0" style="background: #ffffff; border-radius: 8px; overflow: hidden; max-width: 100%;">
    <!-- Header -->
    <tr><td style="background: #2271b1; padding: 20px 32px;">
        <h1 style="margin: 0; color: #ffffff; font-size: 20px; font-weight: 600;">
            ' . esc_html( $site_name ) . '
        </h1>
    </td></tr>
    <!-- Heading -->
    <tr><td style="padding: 24px 32px 8px;">
        <h2 style="margin: 0; font-size: 22px; color: #1d2327;">' . esc_html( $heading ) . '</h2>
    </td></tr>
    <!-- Body -->
    <tr><td style="padding: 16px 32px 24px; font-size: 15px; line-height: 1.6; color: #3c434a;">
        ' . $body_html . '
    </td></tr>
    <!-- Footer -->
    <tr><td style="padding: 16px 32px; background: #f6f7f7; border-top: 1px solid #e0e0e0; font-size: 13px; color: #787c82;">
        <a href="' . esc_url( $site_url ) . '" style="color: #2271b1; text-decoration: none;">' . esc_html( $site_name ) . '</a>
        &mdash; This is an automated message. Please do not reply directly to this email.
    </td></tr>
</table>
</td></tr></table>
</body></html>';
}


/**
 * Format event details block for emails.
 *
 * WHY: Multiple email types need to show the same event info (date, time,
 *      location). This helper builds a styled gray box with those details
 *      so we don't duplicate the formatting logic everywhere.
 *
 * @param object $event The event database row.
 * @return string HTML for the event details block.
 */
function sp_email_event_details_block( object $event ): string {
    $date_str = date( 'l, F j, Y', strtotime( $event->event_date ) );

    $time_str = '';
    if ( $event->start_time ) {
        $time_str = date( 'g:i A', strtotime( $event->start_time ) );
        if ( $event->end_time ) {
            $time_str .= ' – ' . date( 'g:i A', strtotime( $event->end_time ) );
        }
    }

    $html = '<div style="background: #f6f7f7; border: 1px solid #e0e0e0; border-radius: 6px; padding: 16px; margin: 16px 0;">';
    $html .= '<p style="margin: 0 0 6px; font-size: 16px; font-weight: 600; color: #1d2327;">' . esc_html( $event->title ) . '</p>';
    $html .= '<p style="margin: 0 0 4px; color: #3c434a;">' . esc_html( $date_str );
    if ( $time_str ) {
        $html .= '<br>' . esc_html( $time_str );
    }
    $html .= '</p>';

    if ( ! empty( $event->location_name ) ) {
        $html .= '<p style="margin: 4px 0 0; color: #3c434a;">' . esc_html( $event->location_name );
        if ( ! empty( $event->location_address ) ) {
            $html .= '<br><span style="color: #787c82;">' . esc_html( $event->location_address ) . '</span>';
        }
        $html .= '</p>';
    }

    if ( $event->is_virtual && ! empty( $event->virtual_url ) ) {
        $html .= '<p style="margin: 8px 0 0;"><a href="' . esc_url( $event->virtual_url ) . '" style="color: #2271b1;">Join Online Meeting</a></p>';
    }

    $html .= '</div>';
    return $html;
}


/**
 * Send registration confirmation or waitlist placement email.
 *
 * WHY: Immediate confirmation gives registrants confidence their registration
 *      went through. For waitlisted registrants, it sets expectations that
 *      they'll be notified if a spot opens up.
 *
 * @param object $event           The event database row.
 * @param int    $registration_id The new registration row ID.
 * @param string $status          'confirmed' or 'waitlisted'.
 * @param string $email           Recipient email address.
 * @param int    $party_size      Number of people in the party.
 * @param float  $fee_amount      Total fee for the registration.
 */
function sp_send_registration_email( object $event, int $registration_id, string $status, string $email, int $party_size, float $fee_amount ): void {
    $settings = get_option( 'societypress_settings', [] );

    if ( $status === 'waitlisted' ) {
        $subject = 'Waitlist Confirmation: ' . $event->title;
        $heading = 'You\'re on the Waitlist';
        $intro   = '<p>Your waitlist registration has been received. We\'ll notify you by email if a spot opens up.</p>';
    } else {
        $subject_template = $settings['events_confirmation_subject'] ?? 'Registration Confirmed: {event_title}';
        $subject = str_replace( '{event_title}', $event->title, $subject_template );
        $heading = 'Registration Confirmed';
        $intro   = '<p>You\'re all set! Your registration has been confirmed.</p>';
    }

    $body = $intro;
    $body .= sp_email_event_details_block( $event );

    // Registration summary
    $body .= '<table style="width: 100%; border-collapse: collapse; margin: 16px 0; font-size: 14px;">';
    if ( $party_size > 1 ) {
        $body .= '<tr><td style="padding: 6px 0; color: #555;">Attending:</td><td style="padding: 6px 0;">' . $party_size . ' people</td></tr>';
    }
    if ( $fee_amount > 0 ) {
        $body .= '<tr><td style="padding: 6px 0; color: #555;">Fee:</td><td style="padding: 6px 0;">$' . number_format( $fee_amount, 2 ) . '</td></tr>';
    }
    $body .= '<tr><td style="padding: 6px 0; color: #555;">Status:</td><td style="padding: 6px 0;"><strong>' . ucfirst( $status ) . '</strong></td></tr>';
    $body .= '</table>';

    // Contact info if available
    if ( ! empty( $event->contact_name ) || ! empty( $event->contact_email ) ) {
        $body .= '<p style="font-size: 14px; color: #555;">Questions? Contact ';
        if ( ! empty( $event->contact_name ) ) {
            $body .= esc_html( $event->contact_name );
        }
        if ( ! empty( $event->contact_email ) ) {
            $body .= ' at <a href="mailto:' . esc_attr( $event->contact_email ) . '" style="color: #2271b1;">' . esc_html( $event->contact_email ) . '</a>';
        }
        $body .= '.</p>';
    }

    $html = sp_build_email_html( $heading, $body );

    add_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
    wp_mail( $email, $subject, $html );
    remove_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
}


/**
 * Send waitlist promotion email — "A spot opened up!"
 *
 * WHY: When a confirmed registrant cancels and a waitlisted person gets
 *      promoted, they need to know so they can plan to attend. This is
 *      exciting news — the email should feel positive and informative.
 *
 * @param object $event           The event database row.
 * @param int    $registration_id The promoted registration row ID.
 */
function sp_send_waitlist_promotion_email( object $event, int $registration_id ): void {
    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Fetch registration to get recipient email
    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT r.*, u.user_email AS wp_email
         FROM {$reg_table} r
         LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
         WHERE r.id = %d",
        $registration_id
    ) );

    if ( ! $reg ) {
        return;
    }

    $email = $reg->user_id ? ( $reg->wp_email ?? '' ) : ( $reg->guest_email ?? '' );
    if ( empty( $email ) ) {
        return;
    }

    $subject = 'Good News — You Got a Spot: ' . $event->title;
    $heading = 'A Spot Opened Up!';

    $body = '<p>Great news! A spot has opened up and your registration has been moved from the waitlist to <strong>confirmed</strong>.</p>';
    $body .= sp_email_event_details_block( $event );
    $body .= '<p>We look forward to seeing you!</p>';

    $html = sp_build_email_html( $heading, $body );

    add_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
    wp_mail( $email, $subject, $html );
    remove_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
}


/**
 * Send cancellation emails to all registrants when an event is cancelled.
 *
 * WHY: If Harold cancels an event, everyone who registered needs to know ASAP
 *      so they don't show up to an empty room. We email all confirmed and
 *      waitlisted registrants (not already-cancelled ones).
 *
 * @param int    $event_id    The cancelled event ID.
 * @param string $event_title The event title (captured before status change).
 */
function sp_send_event_cancellation_emails( int $event_id, string $event_title ): void {
    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $evt_table = $wpdb->prefix . 'sp_events';

    // Get updated event for details block
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$evt_table} WHERE id = %d", $event_id
    ) );

    // Get all active registrants (confirmed + waitlisted)
    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, u.user_email AS wp_email
         FROM {$reg_table} r
         LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
         WHERE r.event_id = %d AND r.status IN ('confirmed', 'waitlisted')",
        $event_id
    ) );

    if ( empty( $registrations ) ) {
        return;
    }

    $subject = 'Event Cancelled: ' . $event_title;
    $heading = 'Event Cancelled';

    $body = '<p>We\'re sorry to let you know that the following event has been <strong>cancelled</strong>:</p>';
    if ( $event ) {
        $body .= sp_email_event_details_block( $event );
    } else {
        $body .= '<p style="font-weight: 600;">' . esc_html( $event_title ) . '</p>';
    }
    $body .= '<p>If you have any questions, please contact the event organizer.';
    if ( $event && ! empty( $event->contact_email ) ) {
        $body .= ' You can reach them at <a href="mailto:' . esc_attr( $event->contact_email ) . '" style="color: #2271b1;">' . esc_html( $event->contact_email ) . '</a>.';
    }
    $body .= '</p>';

    $html = sp_build_email_html( $heading, $body );

    add_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );

    foreach ( $registrations as $reg ) {
        $email = $reg->user_id ? ( $reg->wp_email ?? '' ) : ( $reg->guest_email ?? '' );
        if ( ! empty( $email ) ) {
            wp_mail( $email, $subject, $html );
        }
    }

    remove_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
}


/**
 * Send update emails when event date, time, or location changes.
 *
 * WHY: If an event is moved to a different day or venue, registrants need to
 *      know. We only send these when the event is still scheduled (not when
 *      it's being cancelled — that has its own email above).
 *
 * @param object $event          The updated event row (with new data).
 * @param array  $changed_fields Which fields changed: 'date', 'time', 'location'.
 */
function sp_send_event_update_emails( object $event, array $changed_fields ): void {
    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Get all active registrants
    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, u.user_email AS wp_email
         FROM {$reg_table} r
         LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
         WHERE r.event_id = %d AND r.status IN ('confirmed', 'waitlisted')",
        $event->id
    ) );

    if ( empty( $registrations ) ) {
        return;
    }

    $subject = 'Event Updated: ' . $event->title;
    $heading = 'Event Details Updated';

    // Build a human-readable list of what changed
    $change_labels = [
        'date'     => 'Date',
        'time'     => 'Time',
        'location' => 'Location',
    ];
    $changed_list = array_map( function ( $f ) use ( $change_labels ) {
        return $change_labels[ $f ] ?? $f;
    }, $changed_fields );

    $body = '<p>The <strong>' . implode( ', ', $changed_list ) . '</strong> for this event ';
    $body .= ( count( $changed_fields ) === 1 ? 'has' : 'have' ) . ' been updated:</p>';
    $body .= sp_email_event_details_block( $event );
    $body .= '<p>Please make note of the updated details. We look forward to seeing you!</p>';

    $html = sp_build_email_html( $heading, $body );

    add_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );

    foreach ( $registrations as $reg ) {
        $email = $reg->user_id ? ( $reg->wp_email ?? '' ) : ( $reg->guest_email ?? '' );
        if ( ! empty( $email ) ) {
            wp_mail( $email, $subject, $html );
        }
    }

    remove_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
}


/**
 * Content type filter for HTML emails.
 *
 * WHY: WordPress sends plain text by default. We add this filter temporarily
 *      around wp_mail() calls to switch to HTML, then remove it immediately
 *      so we don't affect other plugins' emails.
 */
function sp_email_content_type_html(): string {
    return 'text/html';
}


// ============================================================================
// EVENTS — REMINDER CRON JOB
// ============================================================================
//
// WHY: People forget about events they signed up for weeks ago. Automated
//      reminders 1 day, 3 days, or 1 week before an event dramatically
//      reduce no-shows. wp_cron runs this daily, checks which reminders
//      are due, and sends them. The sp_event_reminders table prevents
//      duplicate sends even if cron fires multiple times.
// ============================================================================

/**
 * Schedule the daily reminder cron if not already scheduled.
 *
 * WHY: wp_cron needs a scheduled event to trigger our reminder check.
 *      We check on admin_init (covers both fresh installs and upgrades
 *      where the plugin was already active). 'daily' is frequent enough —
 *      events are by-the-day, not by-the-minute.
 */
add_action( 'admin_init', function () {
    if ( ! wp_next_scheduled( 'sp_event_reminder_cron' ) ) {
        wp_schedule_event( time(), 'daily', 'sp_event_reminder_cron' );
    }
} );

// Clean up cron on deactivation so we don't leave orphaned schedules
register_deactivation_hook( __FILE__, function () {
    wp_clear_scheduled_hook( 'sp_event_reminder_cron' );
} );


/**
 * Cron handler: Send event reminders.
 *
 * WHY: Runs once daily via wp_cron. For each active reminder timing (1 day,
 *      3 days, 1 week before), finds events on that target date, then sends
 *      reminders to confirmed registrants who haven't already received
 *      that particular reminder (checked via sp_event_reminders table).
 */
add_action( 'sp_event_reminder_cron', 'sp_send_event_reminders' );

function sp_send_event_reminders(): void {
    global $wpdb;
    $settings  = get_option( 'societypress_settings', [] );
    $evt_table = $wpdb->prefix . 'sp_events';
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $rem_table = $wpdb->prefix . 'sp_event_reminders';

    // Build the list of reminder timings that are enabled in Settings
    // WHY: Harold configures which reminders to send. We check each enabled
    //      timing against today's date to find events on the matching date.
    $timings = [];
    if ( ! empty( $settings['events_reminder_1_day'] ) ) {
        $timings['1_day_before'] = 1;
    }
    if ( ! empty( $settings['events_reminder_3_days'] ) ) {
        $timings['3_days_before'] = 3;
    }
    if ( ! empty( $settings['events_reminder_1_week'] ) ) {
        $timings['1_week_before'] = 7;
    }

    if ( empty( $timings ) ) {
        return; // No reminders enabled — nothing to do
    }

    $subject_template = $settings['events_reminder_subject'] ?? 'Reminder: {event_title} is coming up';

    foreach ( $timings as $reminder_type => $days_before ) {
        // Find events happening exactly $days_before days from now
        $target_date = date( 'Y-m-d', strtotime( "+{$days_before} days" ) );

        $events = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$evt_table}
             WHERE event_date = %s AND status = 'scheduled' AND registration_enabled = 1",
            $target_date
        ) );

        foreach ( $events as $event ) {
            // Get confirmed registrants for this event
            $registrations = $wpdb->get_results( $wpdb->prepare(
                "SELECT r.id AS reg_id, r.user_id, r.guest_email, u.user_email AS wp_email
                 FROM {$reg_table} r
                 LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
                 WHERE r.event_id = %d AND r.status = 'confirmed'",
                $event->id
            ) );

            foreach ( $registrations as $reg ) {
                // Check if this specific reminder was already sent
                // WHY: Prevents duplicate sends if cron fires multiple times
                //      in the same day (which wp_cron can do under load).
                $already_sent = $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$rem_table}
                     WHERE event_id = %d AND registration_id = %d AND reminder_type = %s",
                    $event->id, $reg->reg_id, $reminder_type
                ) );

                if ( $already_sent ) {
                    continue;
                }

                $email = $reg->user_id ? ( $reg->wp_email ?? '' ) : ( $reg->guest_email ?? '' );
                if ( empty( $email ) ) {
                    continue;
                }

                // Build the reminder email
                $subject = str_replace( '{event_title}', $event->title, $subject_template );

                $time_label = $days_before === 1 ? 'tomorrow' : "in {$days_before} days";
                $heading = 'Event Reminder';

                $body = '<p>Just a friendly reminder that you\'re registered for an event coming up <strong>' . $time_label . '</strong>:</p>';
                $body .= sp_email_event_details_block( $event );
                $body .= '<p>We look forward to seeing you!</p>';

                $html = sp_build_email_html( $heading, $body );

                add_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );
                wp_mail( $email, $subject, $html );
                remove_filter( 'wp_mail_content_type', 'sp_email_content_type_html' );

                // Log the reminder to prevent duplicate sends
                // WHY: Even if the email fails to send, we log it so we don't
                //      retry endlessly. Better to miss one reminder than spam
                //      someone with 50 copies.
                $wpdb->insert( $rem_table, [
                    'event_id'        => $event->id,
                    'registration_id' => $reg->reg_id,
                    'reminder_type'   => $reminder_type,
                    'sent_at'         => current_time( 'mysql' ),
                ] );
            }
        }
    }
}
// END sp_send_event_reminders


// ============================================================================
// SPEAKERS — ADMIN LIST TABLE
// ============================================================================
//
// WHY: Harold manages a roster of speakers/instructors who present at events.
//      Rather than retyping names and bios, they're maintained in a central
//      list and assigned to events via the event edit page.
// ============================================================================

/**
 * WP_List_Table subclass for the speakers admin page.
 */
class SP_Speakers_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'speaker',
            'plural'   => 'speakers',
            'ajax'     => false,
        ] );
    }

    public function get_columns(): array {
        return [
            'name'    => 'Name',
            'title'   => 'Title',
            'email'   => 'Email',
            'events'  => 'Events',
            'active'  => 'Active',
        ];
    }

    public function prepare_items(): void {
        global $wpdb;
        $table   = $wpdb->prefix . 'sp_event_speakers';
        $assign  = $wpdb->prefix . 'sp_event_speaker_assignments';
        $per_page = 20;
        $paged   = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
        $offset  = ( $paged - 1 ) * $per_page;

        // Search filter
        $where = '';
        $search = sanitize_text_field( $_GET['s'] ?? '' );
        if ( $search ) {
            $like  = '%' . $wpdb->esc_like( $search ) . '%';
            $where = $wpdb->prepare( " WHERE s.name LIKE %s OR s.title LIKE %s OR s.email LIKE %s", $like, $like, $like );
        }

        $total = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$table} s {$where}" );

        $this->items = $wpdb->get_results(
            "SELECT s.*, (SELECT COUNT(*) FROM {$assign} WHERE speaker_id = s.id) AS event_count
             FROM {$table} s {$where}
             ORDER BY s.name ASC
             LIMIT {$per_page} OFFSET {$offset}"
        );

        $this->set_pagination_args( [
            'total_items' => $total,
            'per_page'    => $per_page,
        ] );

        $this->_column_headers = [ $this->get_columns(), [], [] ];
    }

    protected function column_name( $item ): string {
        $edit_url = admin_url( 'admin.php?page=sp-speaker-edit&speaker_id=' . $item->id );
        $actions  = [
            'edit'   => '<a href="' . esc_url( $edit_url ) . '">Edit</a>',
            'delete' => '<a href="' . esc_url( wp_nonce_url( admin_url( 'admin.php?page=sp-speakers&action=delete&speaker_id=' . $item->id ), 'sp_delete_speaker_' . $item->id ) ) . '" style="color: #d63638;" onclick="return confirm(\'Delete this speaker?\');">Delete</a>',
        ];

        $photo = '';
        if ( $item->photo_id ) {
            $url = wp_get_attachment_image_url( $item->photo_id, 'thumbnail' );
            if ( $url ) {
                $photo = '<img src="' . esc_url( $url ) . '" style="width: 32px; height: 32px; border-radius: 50%; object-fit: cover; vertical-align: middle; margin-right: 8px;">';
            }
        }

        return $photo . '<a class="row-title" href="' . esc_url( $edit_url ) . '">' . esc_html( $item->name ) . '</a>'
             . $this->row_actions( $actions );
    }

    protected function column_title( $item ): string {
        return esc_html( $item->title ?: '—' );
    }

    protected function column_email( $item ): string {
        return $item->email ? '<a href="mailto:' . esc_attr( $item->email ) . '">' . esc_html( $item->email ) . '</a>' : '—';
    }

    protected function column_events( $item ): string {
        return (int) $item->event_count;
    }

    protected function column_active( $item ): string {
        return $item->active
            ? '<span style="color: #00a32a; font-weight: 500;">Active</span>'
            : '<span style="color: #787c82;">Inactive</span>';
    }

    protected function column_default( $item, $column_name ): string {
        return esc_html( $item->$column_name ?? '' );
    }
}


/**
 * Render the speakers admin list page.
 */
function sp_render_speakers_page(): void {
    global $wpdb;

    // Handle delete action
    if ( ( $_GET['action'] ?? '' ) === 'delete' && ! empty( $_GET['speaker_id'] ) ) {
        $speaker_id = (int) $_GET['speaker_id'];
        if ( wp_verify_nonce( $_GET['_wpnonce'] ?? '', 'sp_delete_speaker_' . $speaker_id ) ) {
            // Check if speaker is assigned to any events
            $assignment_count = (int) $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$wpdb->prefix}sp_event_speaker_assignments WHERE speaker_id = %d",
                $speaker_id
            ) );
            if ( $assignment_count > 0 ) {
                echo '<div class="notice notice-error"><p>Cannot delete — this speaker is assigned to ' . $assignment_count . ' event(s). Remove assignments first.</p></div>';
            } else {
                $wpdb->delete( $wpdb->prefix . 'sp_event_speakers', [ 'id' => $speaker_id ], [ '%d' ] );
                echo '<div class="notice notice-success is-dismissible"><p>Speaker deleted.</p></div>';
            }
        }
    }

    $table = new SP_Speakers_List_Table();
    $table->prepare_items();

    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Speakers</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-speaker-edit' ) ); ?>" class="page-title-action">Add New Speaker</a>
        <hr class="wp-header-end">

        <form method="get">
            <input type="hidden" name="page" value="sp-speakers">
            <?php $table->search_box( 'Search Speakers', 'sp-speaker-search' ); ?>
        </form>

        <form method="post">
            <?php $table->display(); ?>
        </form>
    </div>
    <?php
}


// ============================================================================
// SPEAKERS — ADD/EDIT PAGE
// ============================================================================

/**
 * Handle speaker save on admin_init (before output, allows redirect).
 */
add_action( 'admin_init', function () {
    if ( ! isset( $_POST['sp_speaker_nonce'] ) ) {
        return;
    }
    if ( ! wp_verify_nonce( $_POST['sp_speaker_nonce'], 'sp_save_speaker' ) ) {
        wp_die( 'Security check failed.' );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'Unauthorized.' );
    }

    global $wpdb;
    $speakers_table = $wpdb->prefix . 'sp_event_speakers';
    $speaker_id     = (int) ( $_POST['speaker_id'] ?? 0 );

    $data = [
        'name'     => sanitize_text_field( $_POST['speaker_name'] ?? '' ),
        'title'    => sanitize_text_field( $_POST['speaker_title'] ?? '' ),
        'bio'      => sanitize_textarea_field( $_POST['speaker_bio'] ?? '' ),
        'email'    => sanitize_email( $_POST['speaker_email'] ?? '' ),
        'phone'    => sanitize_text_field( $_POST['speaker_phone'] ?? '' ),
        'website'  => esc_url_raw( $_POST['speaker_website'] ?? '' ),
        'photo_id' => ! empty( $_POST['speaker_photo_id'] ) ? (int) $_POST['speaker_photo_id'] : null,
        'active'   => ! empty( $_POST['speaker_active'] ) ? 1 : 0,
    ];

    if ( empty( $data['name'] ) ) {
        // Can't save without a name — redirect back with error
        wp_redirect( admin_url( 'admin.php?page=sp-speaker-edit&speaker_id=' . $speaker_id . '&error=name' ) );
        exit;
    }

    if ( $speaker_id > 0 ) {
        $wpdb->update( $speakers_table, $data, [ 'id' => $speaker_id ] );
    } else {
        $wpdb->insert( $speakers_table, $data );
        $speaker_id = $wpdb->insert_id;
    }

    wp_redirect( admin_url( 'admin.php?page=sp-speakers&saved=1' ) );
    exit;
} );


