                </tr>
                <tr>
                    <th scope="row"><label for="speaker_email">Email</label></th>
                    <td><input type="email" id="speaker_email" name="speaker_email" value="<?php echo esc_attr( $val( 'email' ) ); ?>" class="regular-text"></td>
