                    <th scope="row"><label for="speaker_website">Website</label></th>
                    <td><input type="url" id="speaker_website" name="speaker_website" value="<?php echo esc_attr( $val( 'website' ) ); ?>" class="regular-text" placeholder="https://"></td>
                </tr>
                <tr>
                    <th scope="row">Photo</th>
                    <td>
                        <input type="hidden" id="speaker_photo_id" name="speaker_photo_id" value="<?php echo esc_attr( $val( 'photo_id' ) ); ?>">
                        <div id="sp-speaker-photo-preview" style="margin-bottom: 8px;">
                            <?php
                            if ( $val( 'photo_id' ) ) {
                                $url = wp_get_attachment_image_url( $val( 'photo_id' ), 'medium' );
                                if ( $url ) {
                                    echo '<img src="' . esc_url( $url ) . '" style="max-width: 200px; height: auto; border-radius: 4px;">';
                                }
                            }
                            ?>
                        </div>
                        <button type="button" class="button" id="sp-speaker-photo-btn">
                            <?php echo $val( 'photo_id' ) ? 'Change Photo' : 'Select Photo'; ?>
                        </button>
                        <button type="button" class="button" id="sp-speaker-photo-remove"
                                style="<?php echo $val( 'photo_id' ) ? '' : 'display: none;'; ?> color: #d63638;">
                            Remove Photo
                        </button>
                    </td>
                </tr>
                <tr>
                    <th scope="row">Status</th>
                    <td>
                        <label>
                            <input type="checkbox" name="speaker_active" value="1"
                                <?php checked( $val( 'active', 1 ), 1 ); ?>>
                            Active (shown in speaker selection dropdowns)
                        </label>
                    </td>
                </tr>
            </table>

            <?php submit_button( $speaker ? 'Update Speaker' : 'Add Speaker' ); ?>
        </form>
    </div>

    <script>
    (function() {
        'use strict';
        // ---- Photo picker (WordPress Media Library) ----
        var photoBtn    = document.getElementById('sp-speaker-photo-btn');
        var photoRemove = document.getElementById('sp-speaker-photo-remove');
        var photoInput  = document.getElementById('speaker_photo_id');
        var photoPreview = document.getElementById('sp-speaker-photo-preview');

        if (photoBtn && typeof wp !== 'undefined' && wp.media) {
            var frame;
            photoBtn.addEventListener('click', function(e) {
                e.preventDefault();
                if (frame) { frame.open(); return; }

                frame = wp.media({
                    title:    'Select Speaker Photo',
                    button:   { text: 'Use this photo' },
                    multiple: false,
                    library:  { type: 'image' }
                });

                frame.on('select', function() {
                    var attachment = frame.state().get('selection').first().toJSON();
                    photoInput.value = attachment.id;
                    var url = attachment.sizes && attachment.sizes.medium
                            ? attachment.sizes.medium.url : attachment.url;
                    photoPreview.innerHTML = '<img src="' + url + '" style="max-width: 200px; height: auto; border-radius: 4px;">';
                    photoBtn.textContent = 'Change Photo';
                    if (photoRemove) photoRemove.style.display = '';
                });

                frame.open();
            });

            if (photoRemove) {
                photoRemove.addEventListener('click', function(e) {
                    e.preventDefault();
                    photoInput.value = '';
                    photoPreview.innerHTML = '';
                    photoBtn.textContent = 'Select Photo';
                    this.style.display = 'none';
                });
            }
        }
    })();
    </script>
    <?php
    wp_enqueue_media();
}


// ============================================================================
// RECURRING EVENTS — AJAX HANDLERS
// ============================================================================
//
// WHY: Recurring events (monthly SIG meetings, weekly classes) are managed as
//      a parent event with a recurrence rule. "Generate Occurrences" creates
//      child event rows for each date in the series. Each child is independently
//      editable (can change title, description, speakers, etc.) but stays
//      linked to the parent for management. Regenerating only creates future
//      dates that don't already exist — it never overwrites modified children.
// ============================================================================

/**
 * AJAX: Generate recurring event occurrences.
 *
 * WHY: When Harold sets up a monthly SIG meeting, he creates one event with a
 *      recurrence rule, then clicks "Generate Occurrences" to create individual
 *      event rows for each date. This is parent+child, not a virtual expansion,
 *      so each occurrence can be independently edited (different speaker for
 *      the April meeting, cancelled the December one, etc.).
 */
add_action( 'wp_ajax_sp_regenerate_occurrences', 'sp_ajax_regenerate_occurrences' );

function sp_ajax_regenerate_occurrences(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Unauthorized.' );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_recurrence' ) ) {
        wp_send_json_error( 'Security check failed.' );
    }

    global $wpdb;
    $evt_table = $wpdb->prefix . 'sp_events';

    $event_id = (int) ( $_POST['event_id'] ?? 0 );
    $parent   = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$evt_table} WHERE id = %d", $event_id
    ) );

    if ( ! $parent || empty( $parent->recurrence_rule ) ) {
        wp_send_json_error( 'Event has no recurrence rule.' );
    }

    // Parse the recurrence rule
    $rule = $parent->recurrence_rule;
    $end_date = $parent->recurrence_end_date
        ? strtotime( $parent->recurrence_end_date )
        : strtotime( '+12 months', strtotime( $parent->event_date ) );

    // Get existing child dates so we don't duplicate
    $existing_dates = $wpdb->get_col( $wpdb->prepare(
        "SELECT event_date FROM {$evt_table} WHERE recurrence_parent_id = %d",
        $event_id
    ) );
    $existing_set = array_flip( $existing_dates );

    // Also skip the parent's own date
    $existing_set[ $parent->event_date ] = true;

    // Generate dates based on rule type
    $dates = [];
    $start_ts = strtotime( $parent->event_date );

    if ( strpos( $rule, 'weekly:' ) === 0 ) {
        // weekly:N — every week on day N (0=Sun through 6=Sat)
        $interval_ts = $start_ts;
        while ( true ) {
            $interval_ts = strtotime( '+1 week', $interval_ts );
            if ( $interval_ts > $end_date ) break;
            $dates[] = date( 'Y-m-d', $interval_ts );
        }
    } elseif ( strpos( $rule, 'monthly-nth:' ) === 0 ) {
        // monthly-nth:W-D — Wth day-D of each month (e.g., 2nd Saturday = 2-6)
        $parts = explode( ':', $rule );
        $wd    = explode( '-', $parts[1] );
        $week_num    = (int) $wd[0]; // 1-5
        $day_of_week = (int) $wd[1]; // 0-6
        $day_names   = [ 'Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday' ];
        $day_name    = $day_names[ $day_of_week ] ?? 'Monday';

        // Start from the month after the parent event
        $month_ts = strtotime( 'first day of +1 month', $start_ts );
        while ( $month_ts <= $end_date ) {
            $year  = date( 'Y', $month_ts );
            $month = date( 'n', $month_ts );

            // Find the Nth day_name of this month
            // WHY: "2nd Saturday" means we find the first Saturday, then add
            //      (N-1) weeks. If that's still in the same month, it's valid.
            $first_of_month = mktime( 0, 0, 0, $month, 1, $year );
            $first_target_day = strtotime( "first {$day_name} of " . date( 'F Y', $first_of_month ) );

            if ( $first_target_day ) {
                $target_date = strtotime( '+' . ( $week_num - 1 ) . ' weeks', $first_target_day );
                // Make sure it's still in the same month
                if ( (int) date( 'n', $target_date ) === $month && $target_date <= $end_date ) {
                    $dates[] = date( 'Y-m-d', $target_date );
                }
            }

            $month_ts = strtotime( 'first day of +1 month', $month_ts );
        }
    } elseif ( strpos( $rule, 'monthly-date:' ) === 0 ) {
        // monthly-date:D — same day of each month (e.g., the 15th)
        $parts     = explode( ':', $rule );
        $target_day = (int) $parts[1];

        $month_ts = strtotime( 'first day of +1 month', $start_ts );
        while ( $month_ts <= $end_date ) {
            $year       = (int) date( 'Y', $month_ts );
            $month      = (int) date( 'n', $month_ts );
            $days_in_mo = (int) date( 't', $month_ts );

            // If the target day exceeds this month's length, use last day
            $actual_day = min( $target_day, $days_in_mo );
            $target_ts  = mktime( 0, 0, 0, $month, $actual_day, $year );

            if ( $target_ts <= $end_date ) {
                $dates[] = date( 'Y-m-d', $target_ts );
            }

            $month_ts = strtotime( 'first day of +1 month', $month_ts );
        }
    }

    // Only keep future dates that don't already exist
    $today = current_time( 'Y-m-d' );
    $created = 0;
    foreach ( $dates as $date ) {
        if ( $date < $today ) continue;
        if ( isset( $existing_set[ $date ] ) ) continue;

        // Create child event — copies most fields from parent
        $child_data = [
            'title'                => $parent->title,
            'slug'                 => $parent->slug . '-' . $date,
            'description'          => $parent->description,
            'category_id'          => $parent->category_id,
            'status'               => 'scheduled',
            'event_date'           => $date,
            'start_time'           => $parent->start_time,
            'end_time'             => $parent->end_time,
            'location_name'        => $parent->location_name,
            'location_address'     => $parent->location_address,
            'is_virtual'           => $parent->is_virtual,
            'virtual_url'          => $parent->virtual_url,
            'visibility'           => $parent->visibility,
            'registration_enabled' => $parent->registration_enabled,
            'registration_limit'   => $parent->registration_limit,
            'guest_registration'   => $parent->guest_registration,
            'member_price'         => $parent->member_price,
            'nonmember_price'      => $parent->nonmember_price,
            'payment_mode'         => $parent->payment_mode,
            'price_description'    => $parent->price_description,
            'contact_name'         => $parent->contact_name,
            'contact_email'        => $parent->contact_email,
            'contact_phone'        => $parent->contact_phone,
            'recurrence_parent_id' => $event_id,
            'created_by'           => get_current_user_id(),
        ];

        $wpdb->insert( $evt_table, $child_data );

        // Copy speaker assignments from parent to child
        if ( $wpdb->insert_id ) {
            $child_id = $wpdb->insert_id;
            $parent_speakers = $wpdb->get_results( $wpdb->prepare(
                "SELECT speaker_id, role, sort_order FROM {$wpdb->prefix}sp_event_speaker_assignments
                 WHERE event_id = %d",
                $event_id
            ) );
            foreach ( $parent_speakers as $ps ) {
                $wpdb->insert( $wpdb->prefix . 'sp_event_speaker_assignments', [
                    'event_id'   => $child_id,
                    'speaker_id' => $ps->speaker_id,
                    'role'       => $ps->role,
                    'sort_order' => $ps->sort_order,
                ] );
            }
        }

        $created++;
    }

    wp_send_json_success( [ 'created' => $created ] );
}


/**
 * AJAX: Detach an event from its recurring series.
 *
 * WHY: Sometimes a child event has been modified enough that it should no
 *      longer be linked to the parent. Detaching clears the parent_id so
 *      future "Regenerate" operations won't touch it, and the series UI
 *      disappears from its edit page.
 */
add_action( 'wp_ajax_sp_detach_from_series', 'sp_ajax_detach_from_series' );

function sp_ajax_detach_from_series(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Unauthorized.' );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_recurrence' ) ) {
        wp_send_json_error( 'Security check failed.' );
    }

    global $wpdb;
    $event_id = (int) ( $_POST['event_id'] ?? 0 );

    if ( ! $event_id ) {
        wp_send_json_error( 'Invalid event.' );
    }

    $wpdb->update(
        $wpdb->prefix . 'sp_events',
        [ 'recurrence_parent_id' => null ],
        [ 'id' => $event_id ]
    );

    wp_send_json_success();
}


// ============================================================================
// PAGE BUILDER — UPCOMING EVENTS WIDGET (FRONTEND RENDERER)
// ============================================================================

/**
 * Render the Upcoming Events page builder widget on the frontend.
 *
 * WHY: Lets societies drop a compact event listing onto any page-builder page
 * (e.g., their homepage) without needing a separate Events page. Pulls live
 * data from sp_events so it always shows the next N upcoming events.
 *
 * The widget finds the first page using the sp-events template to build
 * detail links (?sp_event=slug). If no events page exists, links are omitted.
 */
function sp_render_builder_widget_upcoming_events( array $s ): void {
    global $wpdb;

    $count         = (int) ( $s['count'] ?? 5 );
    $category_id   = (int) ( $s['category_id'] ?? 0 );
    $show_date     = ! empty( $s['show_date'] );
    $show_time     = ! empty( $s['show_time'] );
    $show_location = ! empty( $s['show_location'] );

    // Build the query — only future, scheduled, public events
    $where  = "WHERE e.event_date >= CURDATE() AND e.status = 'scheduled' AND e.visibility = 'public'";
    $params = [];

    if ( $category_id > 0 ) {
        $where   .= ' AND e.category_id = %d';
        $params[] = $category_id;
    }

    $sql = "SELECT e.*, c.name AS category_name, c.color AS category_color
            FROM {$wpdb->prefix}sp_events e
            LEFT JOIN {$wpdb->prefix}sp_event_categories c ON e.category_id = c.id
            {$where}
            ORDER BY e.event_date ASC, e.start_time ASC
            LIMIT %d";
    $params[] = $count;

    if ( count( $params ) > 1 ) {
        $events = $wpdb->get_results( $wpdb->prepare( $sql, ...$params ) );
    } else {
        $events = $wpdb->get_results( $wpdb->prepare( $sql, $params[0] ) );
    }

    // Find the Events listing page so we can build detail links
    // WHY: We look for any page using the sp-events template. If it exists,
    // we can link each event title to its detail page (?sp_event=slug).
    $events_page_id = 0;
    $pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $pages ) ) {
        $events_page_id = $pages[0]->ID;
    }
    $events_page_url = $events_page_id ? get_permalink( $events_page_id ) : '';

    // --- Inline styles for this widget ---
    ?>
    <style>
        .sp-upcoming-events-list {
            list-style: none;
            margin: 0;
            padding: 0;
        }
        .sp-upcoming-event-card {
            display: flex;
            align-items: flex-start;
            gap: 16px;
            padding: 16px 0;
            border-bottom: 1px solid #e5e7eb;
        }
        .sp-upcoming-event-card:last-child {
            border-bottom: none;
        }
        /* Date block — compact calendar-style square */
        .sp-ue-date-block {
            flex-shrink: 0;
            width: 56px;
            text-align: center;
            background: #f0f4f8;
            border-radius: 8px;
            padding: 8px 4px;
            line-height: 1.2;
        }
        .sp-ue-date-block .sp-ue-month {
            display: block;
            font-size: 11px;
            font-weight: 700;
            text-transform: uppercase;
            color: var(--sp-color-primary);
            letter-spacing: 0.5px;
        }
        .sp-ue-date-block .sp-ue-day {
            display: block;
            font-size: 22px;
            font-weight: 700;
            color: #1d2327;
        }
        .sp-ue-date-block .sp-ue-weekday {
            display: block;
            font-size: 10px;
            color: #666;
            text-transform: uppercase;
        }
        .sp-ue-details {
            flex: 1;
            min-width: 0;
        }
        .sp-ue-title {
            font-size: 16px;
            font-weight: 600;
            margin: 0 0 4px;
            line-height: 1.3;
        }
        .sp-ue-title a {
            color: #1d2327;
            text-decoration: none;
        }
        .sp-ue-title a:hover {
            color: var(--sp-color-primary);
        }
        .sp-ue-meta {
            font-size: 13px;
            color: #666;
            margin: 0;
            line-height: 1.5;
        }
        .sp-ue-meta span {
            display: inline-block;
            margin-right: 12px;
        }
        .sp-ue-category-badge {
            display: inline-block;
            font-size: 11px;
            font-weight: 600;
            padding: 2px 8px;
            border-radius: 10px;
            color: #fff;
            margin-top: 4px;
        }
        .sp-ue-view-all {
            display: block;
            text-align: center;
            margin-top: 20px;
            padding: 10px 20px;
            font-size: 14px;
            font-weight: 600;
            color: var(--sp-color-primary);
            text-decoration: none;
            border: 2px solid var(--sp-color-primary);
            border-radius: 6px;
            transition: all 0.2s;
        }
        .sp-ue-view-all:hover {
            background: var(--sp-color-primary);
            color: #fff;
        }
        .sp-ue-empty {
            text-align: center;
            padding: 24px;
            color: #666;
            font-style: italic;
        }
    </style>
    <?php

    echo '<div class="sp-upcoming-events-widget">';

    if ( empty( $events ) ) {
        echo '<p class="sp-ue-empty">No upcoming events scheduled.</p>';
    } else {
        echo '<ul class="sp-upcoming-events-list">';

        foreach ( $events as $event ) {
            $ts        = strtotime( $event->event_date );
            $month     = date( 'M', $ts );
            $day       = date( 'j', $ts );
            $weekday   = date( 'D', $ts );
            $full_date = date( 'l, F j, Y', $ts );

            // Build detail page URL if events page exists
            $detail_url = '';
            if ( $events_page_url && ! empty( $event->slug ) ) {
                $detail_url = add_query_arg( 'sp_event', $event->slug, $events_page_url );
            }

            echo '<li class="sp-upcoming-event-card">';

            // Date block (always shown — it's the visual anchor)
            if ( $show_date ) {
                echo '<div class="sp-ue-date-block">';
                echo '<span class="sp-ue-month">' . esc_html( $month ) . '</span>';
                echo '<span class="sp-ue-day">' . esc_html( $day ) . '</span>';
                echo '<span class="sp-ue-weekday">' . esc_html( $weekday ) . '</span>';
                echo '</div>';
            }

            echo '<div class="sp-ue-details">';

            // Title — linked to detail page if available
            echo '<h4 class="sp-ue-title">';
            if ( $detail_url ) {
                echo '<a href="' . esc_url( $detail_url ) . '">' . esc_html( $event->title ) . '</a>';
            } else {
                echo esc_html( $event->title );
            }
            echo '</h4>';

            // Meta line — time and/or location
            $meta_parts = [];
            if ( $show_time && $event->start_time ) {
                $time_str = date( 'g:i A', strtotime( $event->start_time ) );
                if ( $event->end_time ) {
                    $time_str .= ' – ' . date( 'g:i A', strtotime( $event->end_time ) );
                }
                $meta_parts[] = '<span>🕐 ' . esc_html( $time_str ) . '</span>';
            }
            if ( $show_location && $event->location_name ) {
                $meta_parts[] = '<span>📍 ' . esc_html( $event->location_name ) . '</span>';
            }
            if ( ! $show_date ) {
                // If date block is hidden, show date inline so people still know when
                $meta_parts[] = '<span>📅 ' . esc_html( $full_date ) . '</span>';
            }
            if ( ! empty( $meta_parts ) ) {
                echo '<p class="sp-ue-meta">' . implode( '', $meta_parts ) . '</p>';
            }

            // Category badge
            if ( ! empty( $event->category_name ) ) {
                $color = $event->category_color ?: '#2271b1';
                echo '<span class="sp-ue-category-badge" style="background:' . esc_attr( $color ) . ';">'
                     . esc_html( $event->category_name ) . '</span>';
            }

            // Price badge — show both member and non-member when applicable
            $m_price  = (float) $event->member_price;
            $nm_price = (float) $event->nonmember_price;

            if ( $m_price > 0 && $nm_price > 0 ) {
                echo '<span class="sp-ue-category-badge" style="background:#555;">'
                     . esc_html__( 'Members', 'societypress' ) . ' $' . esc_html( number_format( $m_price, 2 ) )
                     . ' / ' . esc_html__( 'Non-Members', 'societypress' ) . ' $' . esc_html( number_format( $nm_price, 2 ) )
                     . '</span>';
            } elseif ( $m_price > 0 ) {
                echo '<span class="sp-ue-category-badge" style="background:#555;">$'
                     . esc_html( number_format( $m_price, 2 ) ) . '</span>';
            } elseif ( $nm_price > 0 ) {
                echo '<span class="sp-ue-category-badge" style="background:#555;">'
                     . esc_html__( 'Free for Members', 'societypress' )
                     . ' / ' . esc_html__( 'Non-Members', 'societypress' ) . ' $' . esc_html( number_format( $nm_price, 2 ) )
                     . '</span>';
            }

            echo '</div>'; // .sp-ue-details
            echo '</li>';
        }

        echo '</ul>';
    }

    // "View All Events" link — only if an events page exists
    if ( $events_page_url ) {
        echo '<a href="' . esc_url( $events_page_url ) . '" class="sp-ue-view-all">View All Events →</a>';
    }

    echo '</div>'; // .sp-upcoming-events-widget
}


/**
 * Render: Events Calendar
 *
 * WHY: Lets Harold drop a full monthly calendar onto any Page Builder page.
 *      Uses the shared sp_render_calendar_grid() function so the calendar
 *      looks and behaves identically everywhere — events listing page,
 *      standalone calendar template, or embedded in a builder page.
 *
 *      CSS and JS for the calendar are already output by sp_events_frontend_styles()
 *      and sp_events_frontend_scripts() respectively. We enqueue both here
 *      so the calendar works standalone without needing the events page.
 */
function sp_render_builder_widget_event_calendar( array $s ): void {
    $category_id = (int) ( $s['category_id'] ?? 0 );
    $heading     = $s['heading'] ?? '';

    // WHY: The calendar CSS and mobile-tap JS normally only load on the events
    //      page template. When the calendar is embedded via Page Builder, we
    //      need those styles and scripts available too. wp_head has already
    //      fired by the time widget rendering happens, so we output them inline.
    //      The calendar CSS is already in sp_events_frontend_styles() and we
    //      hook the JS to wp_footer via an action that only fires once.
    static $calendar_assets_enqueued = false;
    if ( ! $calendar_assets_enqueued ) {
        $calendar_assets_enqueued = true;
        // Output calendar CSS inline (since wp_head has already fired)
        sp_events_calendar_styles();
        // Queue mobile tap JS for footer
        add_action( 'wp_footer', 'sp_events_calendar_scripts', 50 );
    }

    // Optional heading above the calendar
    if ( ! empty( $heading ) ) {
        echo '<h2 style="margin:0 0 16px; font-size:22px; font-weight:600; color:#1d2327;">'
             . esc_html( $heading ) . '</h2>';
    }

    // Render the calendar grid — the base URL is the current page so month
    // nav links keep the user on the same builder page.
    sp_render_calendar_grid( $category_id, get_permalink() );
}


