/**
 * Output the calendar mobile-tap JavaScript.
 *
 * WHY: On mobile, the full event titles are hidden and replaced with dots.
 *      Tapping a day cell opens a panel below the calendar that lists the
 *      day's events. This JS is identical to what's in sp_events_frontend_scripts()
 *      but isolated so it can be loaded independently for the Page Builder
 *      widget and standalone calendar template.
 */
function sp_events_calendar_scripts(): void {
    ?>
    <script id="sp-calendar-widget-js">
    (function() {
        'use strict';

        // ---- Calendar mobile: tap day to show events panel ----
        var calDays = document.querySelectorAll('.sp-cal-has-events');
        var panel   = document.getElementById('sp-cal-mobile-panel');
        var panelDate   = document.getElementById('sp-cal-mobile-date');
        var panelEvents = document.getElementById('sp-cal-mobile-events');
        var closeBtn    = document.getElementById('sp-cal-mobile-close');

        if (calDays.length && panel) {
            calDays.forEach(function(day) {
                day.addEventListener('click', function(e) {
                    // Only on mobile (when dots are visible)
                    if (window.innerWidth > 768) return;

                    // Don't intercept link clicks inside event titles
                    if (e.target.closest('.sp-cal-event')) return;

                    var dayNum = this.querySelector('.sp-cal-day-num').textContent;
                    var monthLabel = document.querySelector('.sp-cal-month-label');
                    panelDate.textContent = monthLabel ? monthLabel.textContent + ' ' + dayNum : 'Day ' + dayNum;

                    // Build event list from the hidden .sp-cal-events links
                    var events = this.querySelectorAll('.sp-cal-event');
                    var html = '';
                    events.forEach(function(ev) {
                        var title = ev.querySelector('.sp-cal-event-title');
                        var time  = ev.querySelector('.sp-cal-event-time');
                        var href  = ev.href || '#';
                        html += '<a class="sp-cal-mobile-event" href="' + href + '">';
                        html += '<div class="sp-cal-mobile-event-title">' + (title ? title.textContent : '') + '</div>';
                        if (time) {
                            html += '<div class="sp-cal-mobile-event-time">' + time.textContent + '</div>';
                        }
                        html += '</a>';
                    });
                    panelEvents.innerHTML = html;
                    panel.style.display = 'block';
                    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                });
            });

            if (closeBtn) {
                closeBtn.addEventListener('click', function() {
                    panel.style.display = 'none';
                });
            }
        }
    })();
    </script>
    <?php
}


// ============================================================================
// STRIPE PAYMENT INTEGRATION
// ============================================================================
//
// WHY: Societies that charge for workshops, seminars, or annual events need a
//      way to collect payment online. We use Stripe Checkout (hosted) — the
//      registrant clicks "Pay Now," gets redirected to Stripe's secure page,
//      enters their card, and comes back. The society's site never touches
//      credit card numbers, which means zero PCI compliance work.
//
// ARCHITECTURE:
//   1. sp_stripe_is_configured() — checks if API keys exist
//   2. sp_stripe_get_secret_key() — returns the active secret key (test/live)
//   3. sp_create_stripe_checkout_session() — calls Stripe API to create session
//   4. sp_handle_stripe_return() — processes the redirect back from Stripe
//   5. sp_test_stripe_connection AJAX — admin "Test Connection" button
//   6. sp_admin_refund_payment AJAX — admin refund button
//
// The society admin provides their own Stripe API keys in Settings > Events.
// SocietyPress never touches the money — it goes straight to the society's
// Stripe account.
// ============================================================================


/**
 * Check whether Stripe API keys are configured.
 *
 * WHY: Several places need to know if Stripe is ready — the registration form
 *      (to decide which buttons to show), the AJAX handler (to validate), and
 *      the settings page (to show connection status). One function, one truth.
 *
 * @param array $settings The societypress_settings option array.
 * @return bool True if both publishable and secret keys are set.
 */
function sp_stripe_is_configured( array $settings ): bool {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    $pub_key   = $test_mode
        ? ( $settings['stripe_test_publishable_key'] ?? '' )
        : ( $settings['stripe_live_publishable_key'] ?? '' );
    $secret    = $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
    return ! empty( $pub_key ) && ! empty( $secret );
}


/**
 * Get the active Stripe secret key (test or live depending on mode).
 *
 * @param array $settings The societypress_settings option array.
 * @return string The secret key, or empty string if not configured.
 */
function sp_stripe_get_secret_key( array $settings ): string {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    return $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
}


/**
 * Create a Stripe Checkout Session for an event registration payment.
 *
 * WHY: Stripe Checkout is a hosted payment page. We tell Stripe "charge $X for
 *      event Y" and it gives us a URL. The registrant goes there, enters their
 *      card on Stripe's secure page, and Stripe redirects them back to our site
 *      when done. This eliminates PCI compliance entirely — our server never
 *      sees a credit card number.
 *
 * We use the Stripe REST API directly via wp_remote_post() instead of the PHP
 * SDK to avoid adding a Composer dependency. The API is simple enough for our
 * use case — we only need Checkout Sessions and Refunds.
 *
 * @param object $event            The event row from sp_events.
 * @param int    $registration_id  The new registration ID.
 * @param float  $fee_amount       Total fee to charge.
 * @param array  $settings         The societypress_settings option array.
 * @return string|WP_Error         The checkout URL on success, WP_Error on failure.
 */
function sp_create_stripe_checkout_session( object $event, int $registration_id, float $fee_amount, array $settings ) {
    $secret_key = sp_stripe_get_secret_key( $settings );
    if ( empty( $secret_key ) ) {
        return new WP_Error( 'stripe_not_configured', 'Stripe is not configured.' );
    }

    $currency = $settings['stripe_currency'] ?? 'usd';

    // Stripe expects amounts in the smallest currency unit (cents for USD)
    // WHY: $25.00 becomes 2500. This is a Stripe convention to avoid
    //      floating-point rounding issues.
    $amount_cents = (int) round( $fee_amount * 100 );

    // Build the return URLs
    // WHY: After the customer pays (or cancels), Stripe redirects them back to
    //      our event detail page with query parameters so we know what happened.
    //      We include the registration_id so we can look up and update the record.
    $events_page_id = 0;
    $pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $pages ) ) {
        $events_page_id = $pages[0]->ID;
    }

    $base_url = $events_page_id
        ? add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) )
        : home_url();

    $success_url = add_query_arg( [
        'sp_payment' => 'success',
        'sp_session' => '{CHECKOUT_SESSION_ID}',
    ], $base_url );

    $cancel_url = add_query_arg( [
        'sp_payment' => 'cancelled',
    ], $base_url );

    // Build the line item description
    $site_name = get_bloginfo( 'name' );
    $line_item_name = $event->title;
    if ( strlen( $line_item_name ) > 100 ) {
        $line_item_name = substr( $line_item_name, 0, 97 ) . '...';
    }

    // Call the Stripe API to create a Checkout Session
    $response = wp_remote_post( 'https://api.stripe.com/v1/checkout/sessions', [
        'timeout' => 30,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body' => [
            'payment_method_types[0]' => 'card',
            'mode'                    => 'payment',
            'success_url'             => $success_url,
            'cancel_url'              => $cancel_url,
            'client_reference_id'     => (string) $registration_id,
            'metadata[registration_id]' => (string) $registration_id,
            'metadata[event_id]'        => (string) $event->id,
            'metadata[site_url]'        => home_url(),
            'line_items[0][price_data][currency]'     => $currency,
            'line_items[0][price_data][unit_amount]'   => $amount_cents,
            'line_items[0][price_data][product_data][name]' => $line_item_name,
            'line_items[0][price_data][product_data][description]' =>
                sprintf( 'Registration for %s — %s', $event->title, $site_name ),
            'line_items[0][quantity]' => 1,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        return new WP_Error( 'stripe_api_error', 'Could not connect to payment processor. Please try again.' );
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    if ( $code !== 200 || empty( $body['url'] ) ) {
        $error_msg = $body['error']['message'] ?? 'Payment setup failed. Please try again.';
        error_log( 'SocietyPress Stripe error: ' . $error_msg );
        return new WP_Error( 'stripe_session_error', 'Could not set up payment. Please try again or choose to pay at the door.' );
    }

    // Store the Stripe session ID on the registration for later verification
    global $wpdb;
    $wpdb->update(
        $wpdb->prefix . 'sp_event_registrations',
        [ 'notes' => 'stripe_session:' . $body['id'] ],
        [ 'id' => $registration_id ]
    );

    return $body['url'];
}


/**
 * Handle the return from Stripe Checkout.
 *
 * WHY: After paying on Stripe's page, the customer is redirected back to the
 *      event detail page with ?sp_payment=success&sp_session=cs_xxx in the URL.
 *      We verify the session with Stripe's API, confirm the payment actually
 *      went through, and update the registration record accordingly.
 *
 *      This runs early (on template_redirect) so the registration is already
 *      updated by the time the page renders — the frontend JS just shows a
 *      "Payment received" message based on the URL parameter.
 */
add_action( 'template_redirect', function () {
    // Only process Stripe returns on the events page
    if ( ! is_page() || get_page_template_slug() !== 'sp-events' ) return;

    $payment_status = sanitize_text_field( $_GET['sp_payment'] ?? '' );
    $session_id     = sanitize_text_field( $_GET['sp_session'] ?? '' );

    // Only handle successful returns with a session ID
    if ( $payment_status !== 'success' || empty( $session_id ) ) return;

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) return;

    // Verify the Checkout Session with Stripe
    // WHY: We never trust the URL parameters alone — an attacker could craft a
    //      fake success URL. We call Stripe's API to confirm the session exists
    //      and payment actually succeeded before marking anything as paid.
    $response = wp_remote_get( 'https://api.stripe.com/v1/checkout/sessions/' . $session_id, [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) return;

    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( empty( $body['payment_status'] ) || $body['payment_status'] !== 'paid' ) return;

    // Find the registration from the session metadata
    $registration_id = (int) ( $body['client_reference_id'] ?? 0 );
    if ( ! $registration_id ) return;

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Only update if still in pending payment status
    // WHY: Prevents double-processing if the user refreshes the success page
    //      or if a webhook fires at the same time (future enhancement).
    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg || $reg->payment_status === 'paid' ) return;

    $wpdb->update(
        $reg_table,
        [
            'payment_status' => 'paid',
            'payment_method' => 'stripe',
            'payment_date'   => current_time( 'mysql' ),
            'notes'          => 'stripe_session:' . $session_id . '|stripe_pi:' . ( $body['payment_intent'] ?? '' ),
        ],
        [ 'id' => $registration_id ]
    );

    // Send confirmation email now that payment is confirmed
    // WHY: For Stripe payments, we hold the confirmation email until payment
    //      actually goes through. Nobody wants a "you're registered!" email
    //      followed by "just kidding, your card was declined."
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d", $reg->event_id
    ) );

    if ( $event ) {
        $recipient_email = '';
        if ( $reg->user_id ) {
            $user = get_userdata( $reg->user_id );
            $recipient_email = $user ? $user->user_email : '';
        } elseif ( $reg->guest_email ) {
            $recipient_email = $reg->guest_email;
        }
        if ( $recipient_email ) {
            sp_send_registration_email(
                $event, $registration_id, 'confirmed',
                $recipient_email, (int) $reg->party_size, (float) $reg->fee_amount
            );
        }
    }
} );


// ============================================================================
// STRIPE — TEST CONNECTION AJAX HANDLER
// ============================================================================

/**
 * AJAX: Test that the saved Stripe API keys are valid.
 *
 * WHY: Harold just pasted two cryptic strings and has no idea if they work.
 *      This makes a tiny API call to Stripe (retrieve account balance) that
 *      will succeed with valid keys and fail with invalid ones. The admin gets
 *      an instant green checkmark or red X — no guessing.
 */
add_action( 'wp_ajax_sp_test_stripe_connection', function () {
    if ( ! check_ajax_referer( 'sp_stripe_test', 'nonce', false ) ) {
        wp_send_json_error( 'Security check failed.' );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Permission denied.' );
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) {
        wp_send_json_error( 'No API keys found. Please enter your keys and save settings first.' );
    }

    // Call Stripe's /v1/balance endpoint — the simplest authenticated call
    // WHY: If we can retrieve the account balance, the key is valid. This
    //      endpoint is cheap, fast, and doesn't create or modify anything.
    $response = wp_remote_get( 'https://api.stripe.com/v1/balance', [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        wp_send_json_error( 'Could not reach Stripe. Please check your internet connection.' );
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code === 200 ) {
        wp_send_json_success();
    } elseif ( $code === 401 ) {
        wp_send_json_error( 'Invalid API key. Please double-check your keys in Stripe dashboard.' );
    } else {
        $msg = $body['error']['message'] ?? 'Unexpected error (HTTP ' . $code . ')';
        wp_send_json_error( $msg );
    }
} );


// ============================================================================
// STRIPE — ADMIN REFUND HANDLER
// ============================================================================

/**
 * AJAX: Issue a full refund for a Stripe payment.
 *
 * WHY: Sometimes an event gets cancelled, someone can't make it after paying,
 *      or there's a billing dispute. The admin needs a one-click refund button
 *      right in the registrations table — they shouldn't have to log into
 *      Stripe's dashboard to find the payment and refund it manually.
 */
add_action( 'wp_ajax_sp_admin_refund_payment', function () {
    if ( ! check_ajax_referer( 'sp_admin_registration', 'nonce', false ) ) {
        wp_send_json_error( 'Security check failed.' );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Permission denied.' );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    if ( ! $registration_id ) {
        wp_send_json_error( 'Invalid registration.' );
    }

    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg ) {
        wp_send_json_error( 'Registration not found.' );
    }

    if ( $reg->payment_status !== 'paid' || $reg->payment_method !== 'stripe' ) {
        wp_send_json_error( 'This registration was not paid via Stripe.' );
    }

    // Extract the Stripe PaymentIntent ID from the notes field
    // WHY: We stored it as "stripe_session:cs_xxx|stripe_pi:pi_xxx" when the
    //      payment was confirmed. The PaymentIntent ID is what Stripe needs to
    //      process a refund.
    $payment_intent = '';
    if ( preg_match( '/stripe_pi:(\S+)/', $reg->notes ?? '', $matches ) ) {
        $payment_intent = $matches[1];
    }

    if ( empty( $payment_intent ) ) {
        wp_send_json_error( 'Could not find payment reference. Please refund manually in Stripe dashboard.' );
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) {
        wp_send_json_error( 'Stripe is not configured.' );
    }

    // Call Stripe's Refund API
    $response = wp_remote_post( 'https://api.stripe.com/v1/refunds', [
        'timeout' => 30,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body' => [
            'payment_intent' => $payment_intent,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        wp_send_json_error( 'Could not connect to Stripe. Please try again.' );
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    if ( $code === 200 && ( $body['status'] ?? '' ) === 'succeeded' ) {
        // Update registration to reflect the refund
        $wpdb->update(
            $reg_table,
            [
                'payment_status' => 'refunded',
                'notes'          => $reg->notes . '|refund:' . ( $body['id'] ?? 'unknown' ),
            ],
            [ 'id' => $registration_id ]
        );
        wp_send_json_success( [ 'message' => 'Refund processed successfully.' ] );
    } else {
        $error_msg = $body['error']['message'] ?? 'Refund failed (HTTP ' . $code . ')';
        wp_send_json_error( $error_msg );
    }
} );


// ============================================================================
// PAGE BUILDER — FRONTEND WIDGET RENDERERS (NEW FEATURES)
// ============================================================================

/**
 * Render: Community Link
 *
 * WHY: Feature 1 — a simple styled card/button that links to an external
 *      community forum (Facebook group, Discord, etc.). If no URL is configured
 *      in Settings > Organization, visitors see nothing and admins see a notice.
 */
function sp_render_builder_widget_community_link( array $s ): void {
    $settings = get_option( 'societypress_settings', [] );
    $url      = $settings['community_forum_url'] ?? '';
    $label    = $s['label'] ?? 'Join Our Community';
    $desc     = $s['description'] ?? 'Connect with fellow members in our online community.';
    $style    = $s['button_style'] ?? 'primary';

    if ( empty( $url ) ) {
        // Only show a notice to admins — visitors see nothing
        if ( current_user_can( 'manage_options' ) ) {
            echo '<div class="sp-widget-community-link" style="padding:20px; background:#fef9e7; border:1px dashed #d4a017; border-radius:8px; text-align:center;">';
            echo '<p style="margin:0; color:#8a6d00;">Community Forum URL not configured. <a href="' . esc_url( admin_url( 'admin.php?page=sp-settings-organization' ) ) . '">Set it in Settings &rarr; Organization</a>.</p>';
            echo '</div>';
        }
        return;
    }

    echo '<div class="sp-widget-community-link" style="text-align:center; padding:32px; background:linear-gradient(135deg, #f0f7ff 0%, #e8f4f8 100%); border-radius:12px;">';
    echo '<h3 style="margin:0 0 8px; font-size:22px; color:#1d2327;">' . esc_html( $label ) . '</h3>';
    if ( $desc ) {
        echo '<p style="margin:0 0 20px; color:#555; font-size:16px;">' . esc_html( $desc ) . '</p>';
    }
    echo '<a href="' . esc_url( $url ) . '" target="_blank" rel="noopener noreferrer" class="sp-btn sp-btn-' . esc_attr( $style ) . '" style="font-size:16px;">';
    echo esc_html( $label ) . ' &rarr;</a>';
    echo '</div>';
}

/**
 * Render: Newsletter Archive
 *
 * WHY: Feature 8 — shows recent posts from the "Newsletter" category so
 *      Harold can publish newsletter summaries as regular blog posts and
 *      have them appear on any page via the Page Builder.
 */
function sp_render_builder_widget_newsletter_archive( array $s ): void {
    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to view newsletters.</p>';
        echo '</div>';
        return;
    }

    $count        = max( 1, (int) ( $s['count'] ?? 5 ) );
    $show_excerpt = $s['show_excerpt'] ?? true;
    $show_date    = $s['show_date'] ?? true;

    // Get the Newsletter category — created on activation
    $cat = get_category_by_slug( 'newsletter' );
    if ( ! $cat ) {
        if ( current_user_can( 'manage_options' ) ) {
            echo '<p style="color:#8a6d00; padding:12px; background:#fef9e7; border-radius:6px;">Newsletter category not found. Try deactivating and reactivating the plugin.</p>';
        }
        return;
    }

    $posts = get_posts( [
        'category'       => $cat->term_id,
        'posts_per_page' => $count,
        'post_status'    => 'publish',
        'orderby'        => 'date',
        'order'          => 'DESC',
    ] );

    echo '<div class="sp-widget-newsletter-archive">';
    if ( empty( $posts ) ) {
        echo '<p style="color:#666; font-style:italic;">No newsletters published yet.</p>';
    } else {
        echo '<ul style="list-style:none; margin:0; padding:0;">';
        foreach ( $posts as $post ) {
            echo '<li style="padding:16px 0; border-bottom:1px solid #eee;">';
            echo '<a href="' . esc_url( get_permalink( $post ) ) . '" style="font-size:17px; font-weight:600; color:var(--sp-color-primary); text-decoration:none;">';
            echo esc_html( $post->post_title ) . '</a>';
            if ( $show_date ) {
                echo '<span style="display:block; color:#999; font-size:13px; margin-top:2px;">'
                   . esc_html( get_the_date( '', $post ) ) . '</span>';
            }
            if ( $show_excerpt && $post->post_excerpt ) {
                echo '<p style="margin:6px 0 0; color:#555; font-size:14px;">' . esc_html( $post->post_excerpt ) . '</p>';
            }
            echo '</li>';
        }
        echo '</ul>';
    }
    echo '</div>';
}

/**
 * Render: Volunteer Stats
 *
 * WHY: Feature 4 — a public-facing widget showing volunteer activity.
 *      Highlights the community's collective effort with total hours,
 *      active volunteer count, and optionally top contributors.
 */
function sp_render_builder_widget_volunteer_stats( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $show_count = $s['show_count'] ?? true;
    $show_hours = $s['show_hours'] ?? true;
    $show_top   = $s['show_top_volunteers'] ?? false;
    $period     = $s['time_period'] ?? 'year';

    // Build date constraint based on time period
    $date_clause = '';
    if ( $period === 'year' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', date( 'Y-01-01' ) );
    } elseif ( $period === 'month' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', date( 'Y-m-01' ) );
    }
    // 'all' = no date constraint

    $stats_html = [];

    if ( $show_count ) {
        $active_count = (int) $wpdb->get_var(
            "SELECT COUNT(DISTINCT vr.user_id) FROM {$prefix}volunteer_roles vr WHERE vr.status = 'active'"
        );
        $stats_html[] = '<div style="text-align:center; flex:1; min-width:140px;">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $active_count ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">Active Volunteers</div></div>';
    }

    if ( $show_hours ) {
        $total_hours = (float) $wpdb->get_var(
            "SELECT COALESCE(SUM(vh.hours), 0) FROM {$prefix}volunteer_hours vh WHERE 1=1{$date_clause}"
        );
        $period_label = $period === 'year' ? 'This Year' : ( $period === 'month' ? 'This Month' : 'All Time' );
        $stats_html[] = '<div style="text-align:center; flex:1; min-width:140px;">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $total_hours, 1 ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">Hours ' . esc_html( $period_label ) . '</div></div>';
    }

    echo '<div class="sp-widget-volunteer-stats">';
    if ( ! empty( $stats_html ) ) {
        echo '<div style="display:flex; flex-wrap:wrap; gap:24px; justify-content:center; margin-bottom:' . ( $show_top ? '24px' : '0' ) . ';">';
        echo implode( '', $stats_html );
        echo '</div>';
    }

    if ( $show_top ) {
        $top = $wpdb->get_results(
            "SELECT vh.user_id, m.first_name, m.last_name, SUM(vh.hours) as total_hours
             FROM {$prefix}volunteer_hours vh
             INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
             WHERE 1=1{$date_clause}
             GROUP BY vh.user_id, m.first_name, m.last_name
             ORDER BY total_hours DESC
             LIMIT 5"
        );
        if ( ! empty( $top ) ) {
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327;">Top Contributors</h4>';
            echo '<ol style="margin:0; padding:0 0 0 20px;">';
            foreach ( $top as $v ) {
                echo '<li style="padding:4px 0; font-size:15px;">';
                echo esc_html( $v->first_name . ' ' . $v->last_name );
                echo ' <span style="color:#666;">(' . number_format( (float) $v->total_hours, 1 ) . ' hrs)</span>';
                echo '</li>';
            }
            echo '</ol>';
        }
    }
    echo '</div>';
}


/**
 * Render: Photo Gallery
 *
 * WHY: Feature 5 — displays photo albums or a single album's images on the
 *      frontend. Uses a pure CSS :target lightbox so it works without
 *      JavaScript and is fully accessible.
 */
function sp_render_builder_widget_photo_gallery( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to view photos.</p>';
        echo '</div>';
        return;
    }

    $display_mode = $s['display_mode'] ?? 'albums';
    $album_id     = absint( $s['album_id'] ?? 0 );
    $columns      = max( 2, min( 6, (int) ( $s['columns'] ?? 3 ) ) );
    $count        = max( 1, (int) ( $s['count'] ?? 12 ) );

    echo '<div class="sp-widget-photo-gallery">';

    if ( $display_mode === 'single' && $album_id ) {
        // Single album view — show photos in a grid
        $album = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_albums WHERE id = %d", $album_id
        ) );
        if ( ! $album ) {
            echo '<p style="color:#666;">Album not found.</p></div>';
            return;
        }

        // Visibility check
        if ( $album->visibility === 'members_only' && ! is_user_logged_in() ) {
            echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to view this album.</p></div>';
            return;
        }

        if ( $album->title ) {
            echo '<h3 style="margin:0 0 16px;">' . esc_html( $album->title ) . '</h3>';
        }
        if ( $album->description ) {
            echo '<p style="color:#555; margin:0 0 16px;">' . esc_html( $album->description ) . '</p>';
        }

        $items = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_album_items WHERE album_id = %d ORDER BY sort_order ASC LIMIT %d",
            $album_id, $count
        ) );

        if ( empty( $items ) ) {
            echo '<p style="color:#666; font-style:italic;">No photos in this album yet.</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );
            echo '<div style="display:flex; flex-wrap:wrap; gap:8px;">';
            foreach ( $items as $i => $item ) {
                $img_url   = wp_get_attachment_image_url( $item->attachment_id, 'medium' );
                $full_url  = wp_get_attachment_image_url( $item->attachment_id, 'full' );
                $target_id = 'sp-photo-' . $album_id . '-' . $item->id;

                if ( ! $img_url ) continue;

                // Thumbnail
                echo '<a href="#' . esc_attr( $target_id ) . '" style="width:calc(' . $col_width . '% - 8px); aspect-ratio:1; overflow:hidden; border-radius:6px; display:block;">';
                echo '<img src="' . esc_url( $img_url ) . '" alt="' . esc_attr( $item->caption ?: 'Photo ' . ( $i + 1 ) ) . '" style="width:100%; height:100%; object-fit:cover;" loading="lazy">';
                echo '</a>';

                // CSS :target lightbox — appears when the thumbnail's anchor is clicked
                echo '<div id="' . esc_attr( $target_id ) . '" class="sp-lightbox" style="display:none; position:fixed; inset:0; z-index:100000; background:rgba(0,0,0,0.9); align-items:center; justify-content:center;">';
                echo '<a href="#" style="position:absolute; inset:0; z-index:1;"></a>';
                echo '<img src="' . esc_url( $full_url ?: $img_url ) . '" alt="' . esc_attr( $item->caption ) . '" style="max-width:90vw; max-height:90vh; object-fit:contain; position:relative; z-index:2; border-radius:4px;">';
                if ( $item->caption ) {
                    echo '<p style="position:absolute; bottom:20px; left:50%; transform:translateX(-50%); color:#fff; font-size:14px; z-index:2; background:rgba(0,0,0,0.6); padding:6px 16px; border-radius:4px;">' . esc_html( $item->caption ) . '</p>';
                }
                echo '</div>';
            }
            echo '</div>';

            // CSS for the :target lightbox
            echo '<style>.sp-lightbox:target{display:flex!important;}</style>';
        }
    } else {
        // Albums grid view — show album covers
        $visibility_clause = is_user_logged_in() ? '' : " AND visibility = 'public'";
        $albums = $wpdb->get_results(
            "SELECT * FROM {$prefix}photo_albums WHERE 1=1{$visibility_clause} ORDER BY sort_order ASC, created_at DESC LIMIT {$count}"
        );

        if ( empty( $albums ) ) {
            echo '<p style="color:#666; font-style:italic;">No photo albums yet.</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );
            echo '<div style="display:flex; flex-wrap:wrap; gap:16px;">';
            foreach ( $albums as $album ) {
                $cover_url = $album->cover_image_id
                    ? wp_get_attachment_image_url( $album->cover_image_id, 'medium' )
                    : '';
                $photo_count = (int) $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = %d", $album->id
                ) );

                echo '<div style="width:calc(' . $col_width . '% - 16px); min-width:200px;">';
                if ( $cover_url ) {
                    echo '<div style="aspect-ratio:4/3; overflow:hidden; border-radius:8px; margin-bottom:8px;">';
                    echo '<img src="' . esc_url( $cover_url ) . '" alt="' . esc_attr( $album->title ) . '" style="width:100%; height:100%; object-fit:cover;" loading="lazy">';
                    echo '</div>';
                } else {
                    echo '<div style="aspect-ratio:4/3; background:#f0f0f0; border-radius:8px; margin-bottom:8px; display:flex; align-items:center; justify-content:center; color:#999;">';
                    echo '<span class="dashicons dashicons-format-gallery" style="font-size:48px; width:48px; height:48px;"></span>';
                    echo '</div>';
                }
                echo '<h4 style="margin:0 0 4px; font-size:16px;">' . esc_html( $album->title ) . '</h4>';
                echo '<span style="color:#666; font-size:13px;">' . $photo_count . ' photo' . ( $photo_count !== 1 ? 's' : '' ) . '</span>';
                echo '</div>';
            }
            echo '</div>';
        }
    }
    echo '</div>';
}

/**
 * Render: Resource Links
 *
 * WHY: Feature 6 — displays useful genealogy links grouped by category.
 *      Helps members discover external research databases, archives, and
 *      tools that the society recommends.
 */
function sp_render_builder_widget_resource_links( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to view resources.</p>';
        echo '</div>';
        return;
    }

    $category_id    = absint( $s['category_id'] ?? 0 );
    $featured_only  = $s['featured_only'] ?? false;
    $count          = max( 1, (int) ( $s['count'] ?? 50 ) );
    $show_desc      = $s['show_descriptions'] ?? true;

    $where = [ 'r.active = 1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'r.category_id = %d', $category_id );
    }
    if ( $featured_only ) {
        $where[] = 'r.featured = 1';
    }
    $where_sql = implode( ' AND ', $where );

    $resources = $wpdb->get_results(
        "SELECT r.*, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         WHERE {$where_sql}
         ORDER BY rc.sort_order ASC, rc.name ASC, r.sort_order ASC, r.title ASC
         LIMIT {$count}"
    );

    echo '<div class="sp-widget-resource-links">';
    if ( empty( $resources ) ) {
        echo '<p style="color:#666; font-style:italic;">No resources available yet.</p>';
    } else {
        // Group by category for display
        $grouped = [];
        foreach ( $resources as $r ) {
            $cat_name = $r->category_name ?: 'Uncategorized';
            $grouped[ $cat_name ][] = $r;
        }

        foreach ( $grouped as $cat_name => $items ) {
            echo '<div style="margin-bottom:24px;">';
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327; border-bottom:2px solid #eee; padding-bottom:8px;">' . esc_html( $cat_name ) . '</h4>';
            echo '<ul style="list-style:none; margin:0; padding:0;">';
            foreach ( $items as $item ) {
                echo '<li style="padding:8px 0; border-bottom:1px solid #f0f0f0;">';
                echo '<a href="' . esc_url( $item->url ) . '" target="_blank" rel="noopener noreferrer" style="font-weight:600; color:var(--sp-color-primary); text-decoration:none; font-size:15px;">';
                echo esc_html( $item->title );
                if ( $item->featured ) {
                    echo ' <span style="background:#fef0c7; color:#92400e; font-size:11px; padding:2px 6px; border-radius:4px; font-weight:500; margin-left:4px;">Featured</span>';
                }
                echo '</a>';
                if ( $show_desc && $item->description ) {
                    echo '<p style="margin:4px 0 0; color:#555; font-size:13px;">' . esc_html( $item->description ) . '</p>';
                }
                echo '</li>';
            }
            echo '</ul></div>';
        }
    }
    echo '</div>';
}

/**
 * Render: Library Catalog
 *
 * WHY: Feature 7 — displays a searchable table of library items so members
 *      can browse the society's book/periodical/media collection.
 */
function sp_render_builder_widget_library_catalog( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to browse the catalog.</p>';
        echo '</div>';
        return;
    }

    $show_search    = $s['show_search'] ?? true;
    $category_id    = absint( $s['category_id'] ?? 0 );
    $available_only = $s['available_only'] ?? false;
    $per_page       = max( 1, (int) ( $s['count'] ?? 25 ) );

    // Read all filter/search/sort/page params from the URL
    $search       = isset( $_GET['sp_lib_search'] ) ? sanitize_text_field( $_GET['sp_lib_search'] ) : '';
    $media_filter = isset( $_GET['sp_lib_media'] ) ? sanitize_text_field( $_GET['sp_lib_media'] ) : '';
    $subj_filter  = isset( $_GET['sp_lib_subject'] ) ? sanitize_text_field( $_GET['sp_lib_subject'] ) : '';
    $acq_filter   = isset( $_GET['sp_lib_acq'] ) ? sanitize_text_field( $_GET['sp_lib_acq'] ) : '';
    $sort_by      = isset( $_GET['sp_lib_sort'] ) ? sanitize_text_field( $_GET['sp_lib_sort'] ) : 'title';
    $page_num     = max( 1, absint( $_GET['sp_lib_pg'] ?? 1 ) );

    // Validate sort column
    $allowed_sorts = [ 'title', 'author', 'pub_year', 'call_number', 'media_type' ];
    if ( ! in_array( $sort_by, $allowed_sorts, true ) ) {
        $sort_by = 'title';
    }
    $order_sql = 'li.' . $sort_by . ' ASC';
    // For pub_year, newest first is more useful
    if ( $sort_by === 'pub_year' ) {
        $order_sql = 'li.pub_year DESC';
    }

    // Build WHERE clause
    $where = [ '1=1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'li.category_id = %d', $category_id );
    }
    if ( $available_only ) {
        $where[] = 'li.available = 1';
    }
    if ( $search ) {
        // Use LIKE for broad search across title, author, call #, subject, surname, description
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare(
            '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s OR li.description LIKE %s)',
            $like, $like, $like, $like, $like, $like
        );
    }
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    if ( $subj_filter ) {
        // Subject is comma-separated — match as substring
        $like = '%' . $wpdb->esc_like( $subj_filter ) . '%';
        $where[] = $wpdb->prepare( 'li.subject LIKE %s', $like );
    }
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    // Get distinct values for filter dropdowns (from the full catalog, not filtered)
    $media_types = $wpdb->get_col( "SELECT DISTINCT media_type FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' ORDER BY media_type ASC" );
    $acq_codes   = $wpdb->get_col( "SELECT DISTINCT acq_code FROM {$prefix}library_items WHERE acq_code IS NOT NULL AND acq_code != '' ORDER BY acq_code ASC" );

    // Count + fetch
    $offset = ( $page_num - 1 ) * $per_page;
    $total  = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items li WHERE {$where_sql}" );
    $items  = $wpdb->get_results(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE {$where_sql}
         ORDER BY {$order_sql}
         LIMIT {$per_page} OFFSET {$offset}"
    );
    $total_pages = (int) ceil( $total / $per_page );

    // Unique ID so multiple catalog widgets on one page don't collide
    $uid = 'sp-catalog-' . wp_rand( 1000, 9999 );

    echo '<div class="sp-widget-library-catalog" id="' . esc_attr( $uid ) . '">';

    // ---- Inline styles for the enhanced catalog ----
    // WHY: Scoped inside the widget so they don't leak into the rest of the page.
    //      Uses CSS custom properties from the design system where available.
    ?>
    <style>
        .sp-widget-library-catalog { font-family: var(--sp-font-body, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif); }

        /* Search + filter bar */
        .sp-catalog-filters { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 20px; align-items: flex-end; }
        .sp-catalog-filters input[type="text"] { flex: 1; min-width: 200px; padding: 10px 14px; border: 1px solid #d0d5dd; border-radius: 6px; font-size: 15px; }
        .sp-catalog-filters select { padding: 10px 12px; border: 1px solid #d0d5dd; border-radius: 6px; font-size: 14px; background: #fff; min-width: 140px; }
        .sp-catalog-filters .sp-btn { white-space: nowrap; }

        /* Results count + active filters */
        .sp-catalog-status { display: flex; flex-wrap: wrap; align-items: center; gap: 8px; margin-bottom: 14px; color: #555; font-size: 14px; }
        .sp-catalog-active-filter { display: inline-flex; align-items: center; gap: 4px; background: var(--sp-color-accent, #667eea); color: #fff; padding: 3px 10px; border-radius: 12px; font-size: 12px; font-weight: 500; }
        .sp-catalog-active-filter a { color: #fff; text-decoration: none; font-weight: 700; margin-left: 2px; }
        .sp-catalog-active-filter a:hover { opacity: 0.8; }

        /* Table */
        .sp-catalog-table { width: 100%; border-collapse: collapse; }
        .sp-catalog-table thead th { padding: 10px 14px; text-align: left; border-bottom: 2px solid #d0d5dd; background: #f8f9fa; font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.03em; color: #555; }
        .sp-catalog-table tbody td { padding: 10px 14px; border-bottom: 1px solid #eee; font-size: 14px; vertical-align: top; }
        .sp-catalog-table tbody tr:hover { background: #f8f9fa; }
        .sp-catalog-table .sp-item-title { color: var(--sp-color-primary, #2271b1); cursor: pointer; font-weight: 600; text-decoration: none; }
        .sp-catalog-table .sp-item-title:hover { text-decoration: underline; }
        .sp-catalog-table .sp-item-condition { font-size: 11px; font-weight: 500; }
        .sp-catalog-table .sp-item-media-type { font-size: 12px; color: #666; background: #f0f0f0; padding: 2px 8px; border-radius: 10px; display: inline-block; }

        /* Expandable detail row */
        .sp-catalog-detail-row td { padding: 0 !important; border-bottom: 2px solid var(--sp-color-accent, #667eea) !important; }
        .sp-catalog-detail { padding: 20px 24px; background: #fafbfc; animation: spDetailSlide 0.25s ease-out; }
        @keyframes spDetailSlide { from { opacity: 0; max-height: 0; } to { opacity: 1; max-height: 600px; } }
        .sp-catalog-detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px 32px; }
        .sp-catalog-detail-field { }
        .sp-catalog-detail-field dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 2px; font-weight: 600; }
        .sp-catalog-detail-field dd { margin: 0; font-size: 14px; color: #333; }
        .sp-catalog-detail-desc { grid-column: 1 / -1; margin-top: 8px; }
        .sp-catalog-detail-desc dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 4px; font-weight: 600; }
        .sp-catalog-detail-desc dd { margin: 0; font-size: 14px; color: #333; line-height: 1.6; }

        /* Subject / surname tags */
        .sp-catalog-tag { display: inline-block; background: var(--sp-color-primary, #2271b1); color: #fff; padding: 2px 10px; border-radius: 12px; font-size: 12px; margin: 2px 3px 2px 0; text-decoration: none; cursor: pointer; }
        .sp-catalog-tag:hover { opacity: 0.85; color: #fff; }
        .sp-catalog-tag.sp-tag-surname { background: #6b7280; }

        /* Pagination */
        .sp-catalog-pagination { display: flex; justify-content: center; align-items: center; gap: 4px; margin-top: 20px; flex-wrap: wrap; }
        .sp-catalog-pagination a, .sp-catalog-pagination span { display: inline-block; padding: 6px 12px; border: 1px solid #d0d5dd; border-radius: 4px; font-size: 14px; text-decoration: none; color: #333; }
        .sp-catalog-pagination a:hover { background: #f0f0f0; }
        .sp-catalog-pagination .current { background: var(--sp-color-primary, #2271b1); color: #fff; border-color: var(--sp-color-primary, #2271b1); }
        .sp-catalog-pagination .dots { border: none; color: #999; }

        @media (max-width: 768px) {
            .sp-catalog-filters { flex-direction: column; }
            .sp-catalog-filters input[type="text"] { min-width: 100%; }
            .sp-catalog-table thead { display: none; }
            .sp-catalog-table tbody tr { display: block; padding: 12px 0; border-bottom: 1px solid #eee; }
            .sp-catalog-table tbody td { display: block; padding: 3px 0 !important; border-bottom: none !important; }
            .sp-catalog-table tbody td:before { content: attr(data-label); font-weight: 600; font-size: 11px; text-transform: uppercase; color: #888; display: block; }
            .sp-catalog-detail-grid { grid-template-columns: 1fr; }
        }
    </style>
    <?php

    // ---- Search + filter bar ----
    if ( $show_search ) {
        // Build base URL preserving non-catalog query params
        $base_params = [];
        foreach ( $_GET as $k => $v ) {
            if ( strpos( $k, 'sp_lib_' ) !== 0 ) {
                $base_params[ $k ] = $v;
            }
        }

        echo '<form method="get" class="sp-catalog-filters">';
        foreach ( $base_params as $k => $v ) {
            echo '<input type="hidden" name="' . esc_attr( $k ) . '" value="' . esc_attr( $v ) . '">';
        }

        echo '<input type="text" name="sp_lib_search" value="' . esc_attr( $search ) . '" placeholder="Search titles, authors, subjects, surnames...">';

        // Media type filter
        echo '<select name="sp_lib_media">';
        echo '<option value="">All Types</option>';
        foreach ( $media_types as $mt ) {
            $sel = ( $media_filter === $mt ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $mt ) . '"' . $sel . '>' . esc_html( $mt ) . '</option>';
        }
        echo '</select>';

        // Acquisition code filter
        echo '<select name="sp_lib_acq">';
        echo '<option value="">All Sources</option>';
        foreach ( $acq_codes as $ac ) {
            $sel = ( $acq_filter === $ac ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $ac ) . '"' . $sel . '>' . esc_html( $ac ) . '</option>';
        }
        echo '</select>';

        // Sort
        echo '<select name="sp_lib_sort">';
        $sort_options = [
            'title'      => 'Sort: Title',
            'author'     => 'Sort: Author',
            'pub_year'   => 'Sort: Year Published',
            'call_number' => 'Sort: Call Number',
            'media_type' => 'Sort: Media Type',
        ];
        foreach ( $sort_options as $val => $label ) {
            $sel = ( $sort_by === $val ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $val ) . '"' . $sel . '>' . esc_html( $label ) . '</option>';
        }
        echo '</select>';

        echo '<button type="submit" class="sp-btn sp-btn-primary">Search</button>';
        echo '</form>';
    }

    // ---- Results status + active filter chips ----
    echo '<div class="sp-catalog-status">';
    echo '<span>' . number_format( $total ) . ' item' . ( $total !== 1 ? 's' : '' ) . ' found</span>';
    // Show active filter chips with remove links
    $remove_base = remove_query_arg( [ 'sp_lib_pg' ] ); // always reset page when removing filter
    if ( $search ) {
        $remove_url = remove_query_arg( 'sp_lib_search', $remove_base );
        echo '<span class="sp-catalog-active-filter">Search: ' . esc_html( $search ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $media_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_media', $remove_base );
        echo '<span class="sp-catalog-active-filter">Type: ' . esc_html( $media_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $subj_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_subject', $remove_base );
        echo '<span class="sp-catalog-active-filter">Subject: ' . esc_html( $subj_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $acq_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_acq', $remove_base );
        echo '<span class="sp-catalog-active-filter">Source: ' . esc_html( $acq_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $search || $media_filter || $subj_filter || $acq_filter ) {
        $clear_url = remove_query_arg( [ 'sp_lib_search', 'sp_lib_media', 'sp_lib_subject', 'sp_lib_acq', 'sp_lib_sort', 'sp_lib_pg' ] );
        echo '<a href="' . esc_url( $clear_url ) . '" style="font-size:13px; color:#b32d2e;">Clear all</a>';
    }
    echo '</div>';

    // ---- Results table ----
    if ( empty( $items ) ) {
        echo '<p style="color:#666; font-style:italic; padding:20px 0;">No items match your search. Try broadening your filters.</p>';
    } else {
        echo '<table class="sp-catalog-table">';
        echo '<thead><tr>';
        echo '<th>Title</th>';
        echo '<th>Author</th>';
        echo '<th>Type</th>';
        echo '<th>Call #</th>';
        echo '<th>Year</th>';
        echo '<th style="text-align:center;">Status</th>';
        echo '</tr></thead><tbody>';

        foreach ( $items as $item ) {
            $condition_colors = [
                'good'      => '#0a6b2e',
                'fair'      => '#92400e',
                'poor'      => '#b32d2e',
                'reference' => '#2271b1',
            ];
            $cond_color = $condition_colors[ $item->item_condition ] ?? '#666';

            echo '<tr class="sp-catalog-item-row" data-item-id="' . esc_attr( $item->id ) . '">';

            // Title cell — clickable to expand detail
            echo '<td data-label="Title">';
            echo '<a class="sp-item-title" data-item-id="' . esc_attr( $item->id ) . '">' . esc_html( $item->title ) . '</a>';
            if ( $item->item_condition ) {
                echo ' <span class="sp-item-condition" style="color:' . esc_attr( $cond_color ) . ';">(' . esc_html( ucfirst( $item->item_condition ) ) . ')</span>';
            }
            echo '</td>';

            echo '<td data-label="Author">' . esc_html( $item->author ?: '—' ) . '</td>';
            echo '<td data-label="Type">';
            if ( $item->media_type ) {
                echo '<span class="sp-item-media-type">' . esc_html( $item->media_type ) . '</span>';
            } else {
                echo '—';
            }
            echo '</td>';
            echo '<td data-label="Call #">' . esc_html( $item->call_number ?: '—' ) . '</td>';
            echo '<td data-label="Year">' . esc_html( $item->pub_year ?: '—' ) . '</td>';
            echo '<td data-label="Status" style="text-align:center;">';
            echo $item->available
                ? '<span style="color:#0a6b2e; font-weight:600;">Available</span>'
                : '<span style="color:#b32d2e;">Checked Out</span>';
            echo '</td>';
            echo '</tr>';
        }
        echo '</tbody></table>';

        // ---- Pagination ----
        if ( $total_pages > 1 ) {
            echo '<div class="sp-catalog-pagination">';
            $base_url = remove_query_arg( 'sp_lib_pg' );

            // Previous
            if ( $page_num > 1 ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num - 1, $base_url ) ) . '">&laquo; Prev</a>';
            }

            // Page numbers with smart truncation for large catalogs
            $range = 2; // show 2 pages on each side of current
            for ( $i = 1; $i <= $total_pages; $i++ ) {
                if ( $i === 1 || $i === $total_pages || abs( $i - $page_num ) <= $range ) {
                    if ( $i === $page_num ) {
                        echo '<span class="current">' . $i . '</span>';
                    } else {
                        echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $i, $base_url ) ) . '">' . $i . '</a>';
                    }
                } elseif ( $i === 2 && $page_num > $range + 2 ) {
                    echo '<span class="dots">&hellip;</span>';
                } elseif ( $i === $total_pages - 1 && $page_num < $total_pages - $range - 1 ) {
                    echo '<span class="dots">&hellip;</span>';
                }
            }

            // Next
            if ( $page_num < $total_pages ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num + 1, $base_url ) ) . '">Next &raquo;</a>';
            }
            echo '</div>';
        }
    }

    // ---- AJAX expand/collapse script ----
    // WHY: Clicking a title row fetches full item details via AJAX and injects
    //      a detail panel below the row. Clicking again collapses it. No page
    //      reload, no separate URL — the member stays in context of their results.
    //      Subject tags are rendered as clickable filter chips that re-run the search.
    ?>
    <script>
    (function() {
        var container = document.getElementById('<?php echo esc_js( $uid ); ?>');
        if ( ! container ) return;

        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';
        var openRow = null; // track which detail row is currently open

        container.addEventListener('click', function(e) {
            var titleLink = e.target.closest('.sp-item-title');
            if ( ! titleLink ) return;
            e.preventDefault();

            var itemId = titleLink.getAttribute('data-item-id');
            var parentRow = titleLink.closest('tr');
            if ( ! parentRow ) return;

            // If this row's detail is already open, close it
            var existingDetail = parentRow.nextElementSibling;
            if ( existingDetail && existingDetail.classList.contains('sp-catalog-detail-row') ) {
                existingDetail.remove();
                openRow = null;
                return;
            }

            // Close any other open detail row
            if ( openRow ) {
                openRow.remove();
                openRow = null;
            }

            // Create placeholder row
            var detailRow = document.createElement('tr');
            detailRow.className = 'sp-catalog-detail-row';
            var detailCell = document.createElement('td');
            detailCell.setAttribute('colspan', '6');
            detailCell.innerHTML = '<div class="sp-catalog-detail" style="text-align:center; padding:30px;">Loading...</div>';
            detailRow.appendChild(detailCell);
            parentRow.after(detailRow);
            openRow = detailRow;

            // Fetch item details
            fetch(ajaxUrl + '?action=sp_library_item_detail&item_id=' + itemId, { credentials: 'same-origin' })
                .then(function(r) { return r.json(); })
                .then(function(resp) {
                    if ( ! resp.success || ! resp.data ) {
                        detailCell.innerHTML = '<div class="sp-catalog-detail"><p>Unable to load details.</p></div>';
                        return;
                    }
                    var d = resp.data;

                    // Build the detail panel HTML
                    var html = '<div class="sp-catalog-detail">';
                    html += '<div class="sp-catalog-detail-grid">';

                    // Helper to add a field if it has a value
                    function field(label, value) {
                        if ( ! value ) return '';
                        return '<dl class="sp-catalog-detail-field"><dt>' + label + '</dt><dd>' + escHtml(value) + '</dd></dl>';
                    }

                    html += field('Title', d.title);
                    html += field('Author', d.author);
                    html += field('Publisher', d.publisher);
                    html += field('Publisher Location', d.publisher_location);
                    html += field('Published', d.pub_date);
                    html += field('Media Type', d.media_type);
                    html += field('Category', d.category_name);
                    html += field('Call Number', d.call_number);
                    html += field('ISBN', d.isbn);
                    html += field('LCCN', d.lccn);
                    html += field('Shelf Location', d.shelf_location);
                    html += field('Geographic Coverage', d.geographic_location);
                    html += field('County', d.county);
                    html += field('State', d.state);
                    html += field('Condition', d.item_condition ? d.item_condition.charAt(0).toUpperCase() + d.item_condition.slice(1) : '');
                    html += field('Status', d.available ? 'Available' : 'Checked Out');
                    html += field('Acquisition', [d.acq_code, d.acq_date].filter(Boolean).join(' — '));
                    html += field('Donor', d.donor);
                    html += field('Value', d.item_value);
                    html += field('Acquisition #', d.acquisition_number);
                    html += field('System ID', d.system_id);

                    // Subject tags — clickable to filter
                    if ( d.subjects && d.subjects.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt>Subjects</dt><dd>';
                        d.subjects.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_subject', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Surname tags
                    if ( d.surnames && d.surnames.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt>Surnames</dt><dd>';
                        d.surnames.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_search', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag sp-tag-surname">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Description — full width
                    if ( d.description ) {
                        html += '<div class="sp-catalog-detail-desc"><dt>Description</dt><dd>' + escHtml(d.description) + '</dd></div>';
                    }

                    html += '</div>'; // close grid
                    html += '</div>'; // close detail

                    detailCell.innerHTML = html;
                })
                .catch(function() {
                    detailCell.innerHTML = '<div class="sp-catalog-detail"><p>Unable to load details.</p></div>';
                });
        });

        // Utility: escape HTML
        function escHtml(str) {
            var div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }
        // Utility: escape attribute
        function escAttr(str) {
            return str.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }
        // Utility: add or replace a URL param
        function addOrReplaceParam(url, key, value) {
            var u = new URL(url);
            u.searchParams.set(key, value);
            return u.toString();
        }
        // Utility: remove a URL param
        function removeParam(url, key) {
            var u = new URL(url);
            u.searchParams.delete(key);
            return u.toString();
        }
    })();
    </script>
    <?php
    echo '</div>'; // close .sp-widget-library-catalog
}

/**
 * Render: Hero Slider
 *
 * WHY: A full-width image slider is the centerpiece of many society homepages.
 *      This uses lightweight CSS transitions + vanilla JS for auto-advancing.
 *      No jQuery, no external libraries.
 */
function sp_render_builder_widget_hero_slider( array $s ): void {
    $slides   = $s['slides'] ?? [];
    $height   = (int) ( $s['height'] ?? 400 );
    $autoplay = (int) ( $s['autoplay'] ?? 1 );
    $interval = max( 2, (int) ( $s['interval'] ?? 5 ) ) * 1000;
    $overlay  = (int) ( $s['overlay'] ?? 1 );
    $uid      = 'sp-slider-' . wp_rand( 1000, 9999 );

    if ( empty( $slides ) ) {
        echo '<p style="text-align:center; padding:40px; color:#646970;">No slides configured.</p>';
        return;
    }

    ?>
    <style>
        /* WHY the viewport-width trick: The slider sits inside nested content
           wrappers that cap the width. This breaks out to full viewport width
           regardless of how many max-width containers wrap it. */
        .sp-widget--hero_slider { width: 100vw; position: relative; left: 50%; right: 50%; margin-left: -50vw; margin-right: -50vw; margin-top: -130px; }
        .sp-hero-slider { position: relative; overflow: hidden; width: 100%; }
        .sp-hero-slider .sp-slide { position: absolute; top: 0; left: 0; width: 100%; height: 100%; opacity: 0; transition: opacity 0.8s ease; background-size: cover; background-position: center; display: flex; align-items: center; justify-content: center; }
        .sp-hero-slider .sp-slide.active { opacity: 1; position: relative; }
        .sp-hero-slider .sp-slide video.sp-slide-video { position: absolute; top: 50%; left: 50%; min-width: 100%; min-height: 100%; width: auto; height: auto; transform: translate(-50%, -50%); object-fit: cover; z-index: 0; }
        .sp-hero-slider .sp-slide-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
        .sp-hero-slider .sp-slide-content { position: relative; z-index: 2; text-align: center; color: #fff; padding: 20px; max-width: 900px; }
        /* WHY: Per-line styling is now inline on each .sp-slide-line element
           (font-size, font-weight, color). This rule just handles margin and
           text-shadow — the shared bits that don't vary per line. */
        .sp-hero-slider .sp-slide-content .sp-slide-line { margin: 0 0 6px; text-shadow: 0 2px 8px rgba(0,0,0,0.5); }
        .sp-hero-slider .sp-slide-btn { display: inline-block; padding: 12px 28px; background: var(--sp-color-accent, #667eea); color: #fff; text-decoration: none; border-radius: 4px; font-size: 16px; font-weight: 600; transition: background 0.2s; }
        .sp-hero-slider .sp-slide-btn:hover { background: var(--sp-color-primary, #2271b1); }
        .sp-slider-dots { display: none; }
        .sp-slider-arrows { display: none; }
        /* WHY: Mobile sizes are applied via a CSS class on each line element
           rather than inline styles, so the media query can override them.
           .sp-line-small = 16px, .sp-line-medium = 22px, .sp-line-large = 30px */
        @media (max-width: 768px) {
            .sp-hero-slider .sp-slide-content .sp-line-small  { font-size: 16px !important; }
            .sp-hero-slider .sp-slide-content .sp-line-medium { font-size: 22px !important; }
            .sp-hero-slider .sp-slide-content .sp-line-large  { font-size: 30px !important; }
        }
    </style>

    <div class="sp-hero-slider" id="<?php echo esc_attr( $uid ); ?>" style="height: <?php echo $height; ?>px;">
        <?php foreach ( $slides as $i => $slide ) :
            $media_url = esc_url( $slide['image'] ?? '' );
            // WHY: Detect video files so we can render a <video> element instead
            // of a CSS background-image. Videos need autoplay + muted + loop to
            // behave like a background — muted is required by browsers for
            // autoplay to work without user interaction.
            $is_video  = (bool) preg_match( '/\.(mp4|webm|ogg)(\?|$)/i', $media_url );
        ?>
            <div class="sp-slide <?php echo $i === 0 ? 'active' : ''; ?>"
                 <?php if ( ! $is_video && $media_url ) : ?>
                     style="background-image: url('<?php echo $media_url; ?>');"
                 <?php endif; ?>>
                <?php if ( $is_video && $media_url ) : ?>
                    <video class="sp-slide-video" autoplay muted loop playsinline>
                        <source src="<?php echo $media_url; ?>" type="video/<?php echo esc_attr( pathinfo( parse_url( $media_url, PHP_URL_PATH ), PATHINFO_EXTENSION ) ); ?>">
                    </video>
                <?php endif; ?>
                <?php if ( $overlay ) : ?>
                    <div class="sp-slide-overlay" style="background: rgba(0,0,0,0.35);"></div>
                <?php endif; ?>
                <div class="sp-slide-content">
                    <?php
                    // WHY: Per-line repeater data provides independent styling
                    // for each text line (size, weight, color). Falls back to
                    // legacy overlay_text format for slides saved before this
                    // change — auto-migrates on next save.
                    $slide_lines = $slide['lines'] ?? [];

                    // WHY: Legacy migration — if old overlay_text exists but no
                    // lines array, convert it. Line 1 → large/bold, line 2+ →
                    // medium/light, line 3+ → small/light. All white by default.
                    if ( empty( $slide_lines ) && ! empty( $slide['overlay_text'] ) ) {
                        $raw = array_filter( array_map( 'trim', explode( "\n", $slide['overlay_text'] ) ), 'strlen' );
                        $slide_lines = [];
                        foreach ( array_values( $raw ) as $li => $text ) {
                            if ( $li === 0 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'large',  'weight' => 'bold',  'color' => 'white' ];
                            } elseif ( $li === 1 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'medium', 'weight' => 'light', 'color' => 'white' ];
                            } else {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'small',  'weight' => 'light', 'color' => 'white' ];
                            }
                        }
                    }

                    // WHY: Size/weight/color maps translate dropdown values to
                    // actual CSS values. Using a class for size so the media
                    // query can override it on mobile (inline styles beat MQs).
                    $size_map   = [ 'small' => '22px', 'medium' => '30px', 'large' => '44px' ];
                    $weight_map = [ 'light' => '300', 'bold' => '700' ];
                    $color_map  = [ 'white' => '#fff', 'dark' => '#1a1a1a', 'accent' => 'var(--sp-color-accent)' ];

                    foreach ( $slide_lines as $line ) {
                        $text   = esc_html( $line['text'] ?? '' );
                        if ( '' === $text ) continue;
                        $sz     = $size_map[ $line['size'] ?? 'medium' ] ?? '30px';
                        $wt     = $weight_map[ $line['weight'] ?? 'light' ] ?? '300';
                        $cl     = $color_map[ $line['color'] ?? 'white' ] ?? '#fff';
                        $szClass = 'sp-line-' . ( $line['size'] ?? 'medium' );
                        printf(
                            '<p class="sp-slide-line %s" style="font-size:%s; font-weight:%s; color:%s;">%s</p>',
                            esc_attr( $szClass ),
                            esc_attr( $sz ),
                            esc_attr( $wt ),
                            esc_attr( $cl ),
                            $text
                        );
                    }
                    ?>
                    <?php if ( ! empty( $slide['btn_text'] ) && ! empty( $slide['btn_url'] ) ) : ?>
                        <a href="<?php echo esc_url( $slide['btn_url'] ); ?>" class="sp-slide-btn"><?php echo esc_html( $slide['btn_text'] ); ?></a>
                    <?php endif; ?>
                </div>
            </div>
        <?php endforeach; ?>

        <?php if ( count( $slides ) > 1 ) : ?>
            <div class="sp-slider-arrows">
                <button type="button" class="sp-slider-arrow sp-slider-prev">&lsaquo;</button>
                <button type="button" class="sp-slider-arrow sp-slider-next">&rsaquo;</button>
            </div>
        <?php endif; ?>
    </div>

    <?php if ( count( $slides ) > 1 ) : ?>
        <div class="sp-slider-dots" data-slider="<?php echo esc_attr( $uid ); ?>">
            <?php for ( $i = 0; $i < count( $slides ); $i++ ) : ?>
                <button type="button" class="sp-slider-dot <?php echo $i === 0 ? 'active' : ''; ?>" data-index="<?php echo $i; ?>"></button>
            <?php endfor; ?>
        </div>

        <script>
        (function() {
            var slider   = document.getElementById('<?php echo esc_js( $uid ); ?>');
            var slides   = slider.querySelectorAll('.sp-slide');
            var dots     = document.querySelectorAll('[data-slider="<?php echo esc_js( $uid ); ?>"] .sp-slider-dot');
            var current  = 0;
            var total    = slides.length;
            var auto     = <?php echo $autoplay ? 'true' : 'false'; ?>;
            var interval = <?php echo $interval; ?>;
            var timer    = null;

            function goTo(idx) {
                slides[current].classList.remove('active');
                dots[current].classList.remove('active');
                current = (idx + total) % total;
                slides[current].classList.add('active');
                dots[current].classList.add('active');
            }

            function next() { goTo(current + 1); }
            function prev() { goTo(current - 1); }

            function startAuto() {
                if (auto && total > 1) {
                    timer = setInterval(next, interval);
                }
            }
            function stopAuto() {
                if (timer) { clearInterval(timer); timer = null; }
            }

            // Arrow buttons
            var prevBtn = slider.querySelector('.sp-slider-prev');
            var nextBtn = slider.querySelector('.sp-slider-next');
            if (prevBtn) prevBtn.addEventListener('click', function() { stopAuto(); prev(); startAuto(); });
            if (nextBtn) nextBtn.addEventListener('click', function() { stopAuto(); next(); startAuto(); });

            // Dot buttons
            dots.forEach(function(dot) {
                dot.addEventListener('click', function() {
                    stopAuto();
                    goTo(parseInt(this.getAttribute('data-index'), 10));
                    startAuto();
                });
            });

            // Pause on hover
            slider.addEventListener('mouseenter', stopAuto);
            slider.addEventListener('mouseleave', startAuto);

            startAuto();
        })();
        </script>
    <?php endif; ?>
    <?php
}


// ============================================================================
// SURNAME CONTACT — AJAX HANDLER
// ============================================================================
//
// WHY: Feature 2 — lets logged-in members contact a surname researcher without
//      exposing the researcher's email address. The sender's email goes in
//      Reply-To so the researcher can respond directly if they choose.

add_action( 'wp_ajax_sp_surname_contact', 'sp_handle_surname_contact' );

function sp_handle_surname_contact(): void {
    if ( ! check_ajax_referer( 'sp_surname_contact', 'sp_surname_contact_nonce', false ) ) {
        wp_send_json_error( 'Security check failed. Please refresh and try again.' );
    }
    if ( ! is_user_logged_in() ) {
        wp_send_json_error( 'You must be logged in to contact a researcher.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $researcher_id = absint( $_POST['researcher_id'] ?? 0 );
    $sender_name   = sanitize_text_field( $_POST['sender_name'] ?? '' );
    $sender_email  = sanitize_email( $_POST['sender_email'] ?? '' );
    $message       = sanitize_textarea_field( $_POST['message'] ?? '' );

    if ( ! $researcher_id || ! $sender_name || ! $sender_email || ! $message ) {
        wp_send_json_error( 'Please fill in all fields.' );
    }
    if ( ! is_email( $sender_email ) ) {
        wp_send_json_error( 'Please enter a valid email address.' );
    }

    // Look up the researcher's email from the contact table
    $researcher_email = $wpdb->get_var( $wpdb->prepare(
        "SELECT email FROM {$prefix}member_contact WHERE user_id = %d",
        $researcher_id
    ) );

    if ( ! $researcher_email || ! is_email( $researcher_email ) ) {
        wp_send_json_error( 'Unable to contact this researcher at this time.' );
    }

    // Check opt-out preference
    $opted_out = $wpdb->get_var( $wpdb->prepare(
        "SELECT meta_value FROM {$prefix}member_meta
         WHERE user_id = %d AND meta_key = 'pref_email_surnames'",
        $researcher_id
    ) );
    if ( $opted_out === '0' ) {
        wp_send_json_error( 'This researcher has opted out of contact messages.' );
    }

    // Build and send the email
    $site_name = get_bloginfo( 'name' );
    $body_html = '<p>' . esc_html( $sender_name ) . ' is researching a surname you have listed '
               . 'and would like to connect with you.</p>'
               . '<div style="background:#f6f7f7; border:1px solid #e0e0e0; border-radius:6px; padding:16px; margin:16px 0;">'
               . '<p style="margin:0; white-space:pre-wrap;">' . esc_html( $message ) . '</p>'
               . '</div>'
               . '<p style="color:#666; font-size:13px;">To reply, simply respond to this email. '
               . 'Your email address has not been shared with the sender.</p>';

    $html = sp_build_email_html( 'Surname Research Inquiry', $body_html );

    $headers = [
        'Content-Type: text/html; charset=UTF-8',
        sprintf( 'Reply-To: %s <%s>', $sender_name, $sender_email ),
    ];

    $sent = wp_mail(
        $researcher_email,
        sprintf( '[%s] Surname research inquiry from %s', $site_name, $sender_name ),
        $html,
        $headers
    );

    if ( $sent ) {
        wp_send_json_success( [ 'message' => 'Your message has been sent! The researcher can reply directly to your email.' ] );
    } else {
        wp_send_json_error( 'There was a problem sending your message. Please try again later.' );
    }
}


// ============================================================================
