/**
 * Render: Library Categories Page
 *
 * WHY: Manage categories for library items (Books, Periodicals, Maps, etc.).
 *      Same two-column layout as resource categories.
 */
function sp_render_library_categories_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    if ( isset( $_POST['sp_save_library_cat'] ) && check_admin_referer( 'sp_library_cat_save' ) ) {
        $cat_id = absint( $_POST['cat_id'] ?? 0 );
        $data = [
            'name'       => sanitize_text_field( $_POST['name'] ?? '' ),
            'slug'       => sanitize_title( $_POST['name'] ?? '' ),
            'sort_order' => absint( $_POST['sort_order'] ?? 0 ),
            'active'     => ! empty( $_POST['active'] ) ? 1 : 0,
        ];
        if ( ! empty( $data['name'] ) ) {
            if ( $cat_id ) {
                $wpdb->update( $prefix . 'library_categories', $data, [ 'id' => $cat_id ] );
            } else {
                $wpdb->insert( $prefix . 'library_categories', $data );
            }
            echo '<div class="notice notice-success"><p>Category saved.</p></div>';
        }
    }

    if ( ( $_GET['action'] ?? '' ) === 'delete' && ! empty( $_GET['cat_id'] ) ) {
        $cat_id = absint( $_GET['cat_id'] );
        check_admin_referer( 'sp_delete_library_cat_' . $cat_id );
        $wpdb->update( $prefix . 'library_items', [ 'category_id' => null ], [ 'category_id' => $cat_id ] );
        $wpdb->delete( $prefix . 'library_categories', [ 'id' => $cat_id ] );
        echo '<div class="notice notice-success"><p>Category deleted.</p></div>';
    }

    $categories = $wpdb->get_results( "SELECT * FROM {$prefix}library_categories ORDER BY sort_order ASC, name ASC" );
    $editing = null;
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['cat_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare( "SELECT * FROM {$prefix}library_categories WHERE id = %d", absint( $_GET['cat_id'] ) ) );
    }
    ?>
    <div class="wrap">
        <h1>Library Categories</h1>
        <div style="display:flex; gap:24px; margin-top:16px;">
            <div style="flex:0 0 350px; background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:20px;">
                <h3 style="margin-top:0;"><?php echo $editing ? 'Edit Category' : 'Add Category'; ?></h3>
                <form method="post">
                    <?php wp_nonce_field( 'sp_library_cat_save' ); ?>
                    <input type="hidden" name="cat_id" value="<?php echo $editing ? $editing->id : 0; ?>">
                    <p><label style="font-weight:600;">Name</label><br>
                        <input type="text" name="name" value="<?php echo esc_attr( $editing->name ?? '' ); ?>" class="regular-text" required></p>
                    <p><label style="font-weight:600;">Sort Order</label><br>
                        <input type="number" name="sort_order" value="<?php echo esc_attr( $editing->sort_order ?? 0 ); ?>" min="0" style="width:80px;"></p>
                    <p><label><input type="checkbox" name="active" value="1" <?php checked( $editing->active ?? 1 ); ?>> Active</label></p>
                    <p><input type="submit" name="sp_save_library_cat" class="button button-primary" value="<?php echo $editing ? 'Update' : 'Add Category'; ?>">
                        <?php if ( $editing ) : ?><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library-categories' ) ); ?>" class="button">Cancel</a><?php endif; ?></p>
                </form>
            </div>
            <div style="flex:1;">
                <table class="wp-list-table widefat striped">
                    <thead><tr><th>Name</th><th>Slug</th><th>Order</th><th>Active</th></tr></thead>
                    <tbody>
                        <?php foreach ( $categories as $cat ) :
                            $edit_url   = admin_url( 'admin.php?page=sp-library-categories&action=edit&cat_id=' . $cat->id );
                            $delete_url = wp_nonce_url( admin_url( 'admin.php?page=sp-library-categories&action=delete&cat_id=' . $cat->id ), 'sp_delete_library_cat_' . $cat->id );
                        ?>
                            <tr>
                                <td><strong><a href="<?php echo esc_url( $edit_url ); ?>"><?php echo esc_html( $cat->name ); ?></a></strong>
                                    <div class="row-actions"><span><a href="<?php echo esc_url( $edit_url ); ?>">Edit</a> | </span><span><a href="<?php echo esc_url( $delete_url ); ?>" style="color:#b32d2e;" onclick="return confirm('Delete?');">Delete</a></span></div>
                                </td>
                                <td><?php echo esc_html( $cat->slug ); ?></td>
                                <td><?php echo $cat->sort_order; ?></td>
                                <td><?php echo $cat->active ? 'Yes' : 'No'; ?></td>
                            </tr>
                        <?php endforeach; ?>
                    </tbody>
                </table>
            </div>
        </div>
    </div>
    <?php
}


// ============================================================================
// LIBRARY IMPORT — CSV IMPORT FOR LIBRARY CATALOG
// ============================================================================
//
// WHY: Genealogical society libraries can have 10,000–20,000+ items in their
//      catalog. Nobody's entering those one by one. This importer handles CSV
//      exports from legacy systems (EasyNetSites, LibraryThing, custom DBs)
//      and maps them into sp_library_items.
//
//      The SAGHS export is the reference format: 30 columns including
//      publication info, acquisition history, shelf locations, geographic
//      coverage, subjects, and librarian notes. The importer handles all
//      the quirks — duplicate column names, dead columns, date normalization,
//      shelf location typo cleanup.

/**
 * Process a library CSV import.
 *
 * WHY: Separated from the render function so it can be tested independently
 *      and so the rendering logic doesn't get buried in data processing.
 *
 * @param  string $file_path Path to the CSV file.
 * @param  array  $field_map CSV column name → target field key.
 * @return array  Results: imported, skipped, errors.
 */
function sp_process_library_import( string $file_path, array $field_map ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $results = [
        'imported' => 0,
        'skipped'  => 0,
        'errors'   => [],
    ];

    $handle = fopen( $file_path, 'r' );
    if ( ! $handle ) {
        $results['errors'][] = 'Could not open the CSV file.';
        return $results;
    }

    // Read the header row
    $headers = fgetcsv( $handle );
    if ( ! $headers ) {
        fclose( $handle );
        $results['errors'][] = 'CSV file is empty or has no header row.';
        return $results;
    }

    // Strip BOM and whitespace
    $headers = array_map( function( $h ) {
        return trim( $h, "\xEF\xBB\xBF \t\n\r" );
    }, $headers );

    // Build a reverse map: target_key → csv column INDEX.
    // WHY: The field_map is csv_column_name → target_key, but when there are
    //      duplicate column names (the SAGHS export has two "Media Type" and
    //      two "Location" columns), we need to map by index, not name. The
    //      field_map keys include an index suffix for duplicates: "Location__29".
    $target_to_index = [];
    foreach ( $field_map as $csv_key => $target ) {
        if ( $target === '__skip' || empty( $target ) ) {
            continue;
        }
        // Check for index suffix (e.g., "Location__29")
        if ( preg_match( '/__(\d+)$/', $csv_key, $m ) ) {
            $target_to_index[ $target ] = (int) $m[1];
        } else {
            // Find the first matching header
            $idx = array_search( $csv_key, $headers, true );
            if ( $idx !== false ) {
                $target_to_index[ $target ] = $idx;
            }
        }
    }

    // Helper to get a value from a row by target key
    $get = function( array $row, string $target ) use ( $target_to_index ) {
        if ( ! isset( $target_to_index[ $target ] ) ) {
            return '';
        }
        $idx = $target_to_index[ $target ];
        return isset( $row[ $idx ] ) ? trim( $row[ $idx ] ) : '';
    };

    // ---------------------------------------------------------------
    // Shelf location normalization map
    // WHY: Legacy exports are full of typos and inconsistent casing.
    //      We normalize these so filtering and grouping actually work.
    //      All values get uppercased first, then we fix known typos.
    // ---------------------------------------------------------------
    $shelf_fixes = [
        'LOUISANA'           => 'LOUISIANA',
        'LOUSIANA'           => 'LOUISIANA',
        'NORTH CAROLINIA'    => 'NORTH CAROLINA',
        'FAMIY HISTORY'      => 'FAMILY HISTORY',
        'FAMILY HSTORY'      => 'FAMILY HISTORY',
        'FAMILY hISTORY'     => 'FAMILY HISTORY',
        'FAMILY HISTOR'      => 'FAMILY HISTORY',
        'REFERENCSE'         => 'REFERENCE',
        'REFERERNCE'         => 'REFERENCE',
        'REFERNCE'           => 'REFERENCE',
        'DGITIAL BOOKS ICON' => 'DIGITAL BOOKS ICON',
        'OVERSIZE BOOKS'     => 'OVERSIZED BOOKS',
    ];

    // Pre-load existing system_ids to detect duplicates
    // WHY: If the same catalog is imported twice, we don't want 40,000
    //      records. We skip any row whose system_id already exists.
    $existing_ids = [];
    $id_rows = $wpdb->get_col( "SELECT system_id FROM {$prefix}library_items WHERE system_id IS NOT NULL" );
    foreach ( $id_rows as $eid ) {
        $existing_ids[ (int) $eid ] = true;
    }

    $row_num    = 1; // For error reporting (1 = first data row after header)
    $batch      = [];
    $batch_size = 100;

    while ( ( $row = fgetcsv( $handle ) ) !== false ) {
        $row_num++;

        $title = $get( $row, 'title' );
        if ( empty( $title ) ) {
            $results['skipped']++;
            continue;
        }

        // Duplicate detection by system_id
        $system_id = $get( $row, 'system_id' );
        if ( $system_id !== '' ) {
            $system_id = (int) $system_id;
            if ( isset( $existing_ids[ $system_id ] ) ) {
                $results['skipped']++;
                continue;
            }
        } else {
            $system_id = null;
        }

        // Normalize shelf location
        $shelf = strtoupper( trim( $get( $row, 'shelf_location' ) ) );
        if ( isset( $shelf_fixes[ $shelf ] ) ) {
            $shelf = $shelf_fixes[ $shelf ];
        }

        // Normalize date — convert 0000-00-00 to null
        $last_updated = $get( $row, 'last_updated_date' );
        if ( $last_updated === '0000-00-00' || $last_updated === '' ) {
            $last_updated = null;
        }

        // Parse numeric fields safely
        $parse_int = function( $val ) {
            $val = trim( $val );
            return ( $val !== '' && is_numeric( $val ) ) ? (int) $val : null;
        };
        $parse_decimal = function( $val ) {
            $val = trim( $val );
            return ( $val !== '' && is_numeric( $val ) ) ? (float) $val : null;
        };

        $data = [
            'system_id'           => $system_id,
            'title'               => mb_substr( $title, 0, 500 ),
            'author'              => mb_substr( $get( $row, 'author' ), 0, 255 ) ?: null,
            'description'         => $get( $row, 'description' ) ?: null,
            'publisher'           => mb_substr( $get( $row, 'publisher' ), 0, 200 ) ?: null,
            'publisher_location'  => mb_substr( $get( $row, 'publisher_location' ), 0, 100 ) ?: null,
            'pub_year'            => $parse_int( $get( $row, 'pub_year' ) ),
            'pub_month'           => $parse_int( $get( $row, 'pub_month' ) ),
            'pub_day'             => $parse_int( $get( $row, 'pub_day' ) ),
            'media_type'          => mb_substr( $get( $row, 'media_type' ), 0, 50 ) ?: null,
            'use_serials'         => $get( $row, 'use_serials' ) === '1' ? 1 : 0,
            'isbn'                => mb_substr( $get( $row, 'isbn' ), 0, 20 ) ?: null,
            'call_number'         => mb_substr( $get( $row, 'call_number' ), 0, 50 ) ?: null,
            'lccn'                => mb_substr( $get( $row, 'lccn' ), 0, 20 ) ?: null,
            'shelf_location'      => $shelf ? mb_substr( $shelf, 0, 100 ) : null,
            'geographic_location' => mb_substr( $get( $row, 'geographic_location' ), 0, 200 ) ?: null,
            'acquisition_number'  => $parse_int( $get( $row, 'acquisition_number' ) ),
            'acq_year'            => $parse_int( $get( $row, 'acq_year' ) ),
            'acq_month'           => $parse_int( $get( $row, 'acq_month' ) ),
            'acq_day'             => $parse_int( $get( $row, 'acq_day' ) ),
            'acq_code'            => mb_substr( $get( $row, 'acq_code' ), 0, 30 ) ?: null,
            'donor'               => mb_substr( $get( $row, 'donor' ), 0, 100 ) ?: null,
            'item_value'          => $parse_decimal( $get( $row, 'value' ) ),
            'county'              => mb_substr( $get( $row, 'county' ), 0, 200 ) ?: null,
            'state'               => mb_substr( $get( $row, 'state' ), 0, 100 ) ?: null,
            'surname'             => mb_substr( $get( $row, 'surname' ), 0, 255 ) ?: null,
            'subject'             => mb_substr( $get( $row, 'subject' ), 0, 250 ) ?: null,
            'librarian_notes'     => $get( $row, 'librarian_notes' ) ?: null,
            'updated_by'          => mb_substr( $get( $row, 'updated_by' ), 0, 50 ) ?: null,
            'last_updated_date'   => $last_updated,
            'item_condition'      => 'good',
            'available'           => 1,
        ];

        $wpdb->insert( $prefix . 'library_items', $data );

        if ( $wpdb->last_error ) {
            $results['errors'][] = "Row {$row_num}: " . $wpdb->last_error;
            // Don't let errors pile up endlessly — cap at 50 reported
            if ( count( $results['errors'] ) >= 50 ) {
                $results['errors'][] = '(Error reporting capped at 50. There may be more.)';
                break;
            }
        } else {
            $results['imported']++;
            // Track for duplicate detection within the same import
            if ( $system_id !== null ) {
                $existing_ids[ $system_id ] = true;
            }
        }
    }

    fclose( $handle );
    return $results;
}


/**
 * Render: Library Import Page
 *
 * WHY: Two-step CSV import for library catalog items. Step 1: upload and
 *      preview with field mapping. Step 2: run the actual import. Same
 *      pattern as the member import but tuned for library data.
 */
function sp_render_library_import_page(): void {
    global $wpdb;

    $results = null;
    $preview = null;

    // ------------------------------------------------------------------
    // STEP 2: Run the actual import from the temp file
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'run_import' ) {
        check_admin_referer( 'sp_import_library' );

        $temp_file = sanitize_text_field( $_POST['sp_import_temp_file'] ?? '' );

        $raw_map = isset( $_POST['sp_field_map'] ) && is_array( $_POST['sp_field_map'] )
                 ? $_POST['sp_field_map']
                 : [];
        $import_field_map = [];
        foreach ( $raw_map as $csv_col => $target ) {
            $import_field_map[ sanitize_text_field( $csv_col ) ] = sanitize_text_field( $target );
        }

        if ( ! empty( $temp_file ) && file_exists( $temp_file ) ) {
            $results = sp_process_library_import( $temp_file, $import_field_map );
            @unlink( $temp_file );
        } else {
            $results = [
                'imported' => 0, 'skipped' => 0,
                'errors'   => [ 'The uploaded file has expired. Please upload again.' ],
            ];
        }
    }

    // ------------------------------------------------------------------
    // STEP 1: Upload CSV and show preview / field mapping
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'preview' ) {
        check_admin_referer( 'sp_import_library' );

        if ( ! empty( $_FILES['import_file']['tmp_name'] ) ) {
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }

            $temp_file = $temp_dir . '/library-import-' . wp_generate_password( 12, false ) . '.csv';
            move_uploaded_file( $_FILES['import_file']['tmp_name'], $temp_file );

            $handle  = fopen( $temp_file, 'r' );
            $headers = fgetcsv( $handle );

            if ( $headers ) {
                $headers = array_map( function( $h ) {
                    return trim( $h, "\xEF\xBB\xBF \t\n\r" );
                }, $headers );

                $row_count   = 0;
                $sample_rows = [];
                while ( ( $row = fgetcsv( $handle ) ) !== false ) {
                    $row_count++;
                    if ( count( $sample_rows ) < 5 ) {
                        $sample_rows[] = $row;
                    }
                }

                $preview = [
                    'headers'     => $headers,
                    'sample_rows' => $sample_rows,
                    'row_count'   => $row_count,
                    'temp_file'   => $temp_file,
                ];
            } else {
                @unlink( $temp_file );
            }
            fclose( $handle );
        }
    }

    // ------------------------------------------------------------------
    // Target fields — the library_items columns available for mapping.
    // ------------------------------------------------------------------
    $target_fields = [
        'system_id'           => 'System ID (legacy catalog #)',
        'title'               => 'Title',
        'author'              => 'Author',
        'description'         => 'Description / Physical Notes',
        'publisher'           => 'Publisher',
        'publisher_location'  => 'Publisher Location',
        'pub_year'            => 'Publication Year',
        'pub_month'           => 'Publication Month',
        'pub_day'             => 'Publication Day',
        'media_type'          => 'Media Type (Book, Map, etc.)',
        'use_serials'         => 'Use Serials (0/1)',
        'isbn'                => 'ISBN',
        'call_number'         => 'Call Number',
        'lccn'                => 'LCCN',
        'shelf_location'      => 'Shelf Location (section in library)',
        'geographic_location' => 'Geographic Coverage (region/state)',
        'acquisition_number'  => 'Acquisition Number',
        'acq_year'            => 'Acquisition Year',
        'acq_month'           => 'Acquisition Month',
        'acq_day'             => 'Acquisition Day',
        'acq_code'            => 'Acquisition Code (Gift, Purchase, etc.)',
        'donor'               => 'Donor',
        'value'               => 'Value ($)',
        'county'              => 'County',
        'state'               => 'State',
        'surname'             => 'Surname',
        'subject'             => 'Subject Tags',
        'librarian_notes'     => 'Librarian Notes',
        'updated_by'          => 'Updated By (name)',
        'last_updated_date'   => 'Last Updated Date',
    ];

    // ------------------------------------------------------------------
    // Auto-mapping — known column names from common exports (EasyNetSites/SAGHS).
    // WHY: If we recognize the CSV headers, we pre-select the right target
    //      fields so the admin doesn't have to map 30 columns by hand.
    //      The key is the CSV header name; the value is our target key.
    //      For duplicate-name columns, the auto-map uses the LAST occurrence
    //      since that's where the real data lives in the SAGHS export.
    // ------------------------------------------------------------------
    $auto_map = [
        'System ID'          => 'system_id',
        'Title'              => 'title',
        'Author'             => 'author',
        'Description'        => 'description',
        'Publisher'          => 'publisher',
        'Publisher Location' => 'publisher_location',
        'Pub. Year'          => 'pub_year',
        'Pub. Month'         => 'pub_month',
        'Pub. Day'           => 'pub_day',
        'Use Serials'        => 'use_serials',
        'Call Number'        => 'call_number',
        'LCCN'               => 'lccn',
        'Acquisition Number' => 'acquisition_number',
        'Acq. Year'          => 'acq_year',
        'Acq. Month'         => 'acq_month',
        'Acq. Day'           => 'acq_day',
        'Acq. Code'          => 'acq_code',
        'Donor'              => 'donor',
        'Value'              => 'value',
        'County'             => 'county',
        'State'              => 'state',
        'Surname'            => 'surname',
        'Librarian Notes'    => 'librarian_notes',
        'updatedByName'      => 'updated_by',
        'Last Updated Date'  => 'last_updated_date',
        'Subject'            => 'subject',
    ];

    ?>
    <div class="wrap">
        <h1>Import Library Catalog</h1>

        <?php if ( $results ) : ?>
            <!-- ============================================================
                 IMPORT RESULTS
                 ============================================================ -->
            <div class="notice notice-<?php echo $results['imported'] > 0 ? 'success' : 'warning'; ?>">
                <p>
                    <strong>Import complete.</strong>
                    <?php echo number_format( $results['imported'] ); ?> item<?php echo $results['imported'] !== 1 ? 's' : ''; ?> imported.
                    <?php if ( $results['skipped'] > 0 ) : ?>
                        <?php echo number_format( $results['skipped'] ); ?> skipped (duplicates or missing title).
                    <?php endif; ?>
                </p>
            </div>
            <?php if ( ! empty( $results['errors'] ) ) : ?>
                <div class="notice notice-error">
                    <p><strong>Errors:</strong></p>
                    <ul style="margin-left:20px; list-style:disc;">
                        <?php foreach ( $results['errors'] as $err ) : ?>
                            <li><?php echo esc_html( $err ); ?></li>
                        <?php endforeach; ?>
                    </ul>
                </div>
            <?php endif; ?>

            <?php
            // Show current catalog count after import
            $total_items = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$wpdb->prefix}sp_library_items" );
            ?>
            <p>
                Your catalog now has <strong><?php echo number_format( $total_items ); ?></strong> items.
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library-catalog' ) ); ?>">View Catalog &rarr;</a>
            </p>
        <?php endif; ?>

        <?php if ( $preview ) : ?>
            <!-- ============================================================
                 STEP 2: FIELD MAPPING PREVIEW
                 Shows the detected CSV columns, sample data, and dropdowns
                 for mapping each column to a library_items field.
                 ============================================================ -->
            <div class="card" style="max-width:100%; padding:20px; margin-top:16px;">
                <h2 style="margin-top:0;">Map CSV Columns</h2>
                <p class="description">
                    We detected <strong><?php echo number_format( $preview['row_count'] ); ?></strong> data rows
                    and <strong><?php echo count( $preview['headers'] ); ?></strong> columns.
                    Verify the mapping below, then click <em>Run Import</em>.
                </p>

                <form method="post">
                    <?php wp_nonce_field( 'sp_import_library' ); ?>
                    <input type="hidden" name="sp_import_action" value="run_import">
                    <input type="hidden" name="sp_import_temp_file" value="<?php echo esc_attr( $preview['temp_file'] ); ?>">

                    <table class="wp-list-table widefat striped" style="margin:16px 0;">
                        <thead>
                            <tr>
                                <th style="width:30px;">#</th>
                                <th>CSV Column</th>
                                <th>Sample Data</th>
                                <th style="width:280px;">Map To</th>
                            </tr>
                        </thead>
                        <tbody>
                            <?php foreach ( $preview['headers'] as $idx => $header ) :
                                // Collect sample values for this column
                                $samples = [];
                                foreach ( $preview['sample_rows'] as $sr ) {
                                    $val = isset( $sr[ $idx ] ) ? trim( $sr[ $idx ] ) : '';
                                    if ( $val !== '' ) {
                                        $samples[] = mb_substr( $val, 0, 60 );
                                    }
                                }
                                $sample_str = implode( ' | ', array_slice( $samples, 0, 3 ) );

                                // For duplicate column names, append __index to the key
                                // so the form can distinguish them. The first occurrence
                                // of a name keeps its plain name; later ones get __index.
                                $seen_before = false;
                                for ( $prev = 0; $prev < $idx; $prev++ ) {
                                    if ( $preview['headers'][ $prev ] === $header ) {
                                        $seen_before = true;
                                        break;
                                    }
                                }
                                $form_key = $seen_before ? $header . '__' . $idx : $header;

                                // Auto-detect mapping.
                                // Handle duplicate column names first (Media Type and
                                // Location both appear twice in the SAGHS export), then
                                // fall back to the auto_map dictionary.
                                $auto_target = '__skip';
                                if ( $header === 'Media Type' ) {
                                    // First occurrence (col 9) is always empty — skip.
                                    // Second occurrence (col 27) has the real data.
                                    $auto_target = $seen_before ? 'media_type' : '__skip';
                                } elseif ( $header === 'Location' ) {
                                    // First occurrence (col 13) = shelf/section location.
                                    // Second occurrence (col 29) = geographic coverage.
                                    $auto_target = $seen_before ? 'geographic_location' : 'shelf_location';
                                } elseif ( isset( $auto_map[ $header ] ) ) {
                                    $auto_target = $auto_map[ $header ];
                                }
                            ?>
                                <tr>
                                    <td><?php echo $idx; ?></td>
                                    <td><strong><?php echo esc_html( $header ); ?></strong></td>
                                    <td style="color:#666; font-size:12px;"><?php echo esc_html( $sample_str ); ?></td>
                                    <td>
                                        <select name="sp_field_map[<?php echo esc_attr( $form_key ); ?>]" style="width:100%;">
                                            <option value="__skip">— Skip —</option>
                                            <?php foreach ( $target_fields as $key => $label ) : ?>
                                                <option value="<?php echo esc_attr( $key ); ?>" <?php selected( $auto_target, $key ); ?>>
                                                    <?php echo esc_html( $label ); ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </td>
                                </tr>
                            <?php endforeach; ?>
                        </tbody>
                    </table>

                    <p class="submit">
                        <input type="submit" class="button button-primary button-hero" value="Run Import (<?php echo number_format( $preview['row_count'] ); ?> rows)">
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-library' ) ); ?>" class="button button-hero">Cancel</a>
                    </p>
                </form>
            </div>

        <?php else : ?>
            <!-- ============================================================
                 STEP 1: UPLOAD FORM
                 ============================================================ -->
            <div class="card" style="max-width:600px; padding:20px; margin-top:16px;">
                <h2 style="margin-top:0;">Upload Library CSV</h2>
                <p class="description">
                    Upload a CSV file exported from your library catalog system.
                    The importer will detect columns automatically and let you
                    map them before importing.
                </p>

                <form method="post" enctype="multipart/form-data">
                    <?php wp_nonce_field( 'sp_import_library' ); ?>
                    <input type="hidden" name="sp_import_action" value="preview">

                    <table class="form-table">
                        <tr>
                            <th><label for="import_file">CSV File</label></th>
                            <td>
                                <input type="file" name="import_file" id="import_file" accept=".csv" required>
                                <p class="description">Maximum file size: <?php echo size_format( wp_max_upload_size() ); ?></p>
                            </td>
                        </tr>
                    </table>

                    <p class="submit">
                        <input type="submit" class="button button-primary" value="Upload &amp; Preview">
                    </p>
                </form>

                <?php
                // Show current catalog count so the admin knows if they're starting fresh or adding
                $total_items = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$wpdb->prefix}sp_library_items" );
                if ( $total_items > 0 ) : ?>
                    <hr style="margin:20px 0;">
                    <p>
                        Your catalog currently has <strong><?php echo number_format( $total_items ); ?></strong> items.
                        Duplicate items (matched by System ID) will be skipped during import.
                    </p>
                <?php endif; ?>
            </div>
        <?php endif; ?>
    </div>
    <?php
}


