/**
 * Render: Resources List Page
 *
 * WHY: CRUD list for resource links with inline add/edit form. Resources
 *      are grouped by category in the frontend widget but listed flat here
 *      for easier management.
 */
function sp_render_resources_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( ( $_GET['action'] ?? '' ) === 'delete' && ! empty( $_GET['resource_id'] ) ) {
        $rid = absint( $_GET['resource_id'] );
        check_admin_referer( 'sp_delete_resource_' . $rid );
        $wpdb->delete( $prefix . 'resources', [ 'id' => $rid ] );
        echo '<div class="notice notice-success"><p>Resource deleted.</p></div>';
    }

    // Handle save
    if ( isset( $_POST['sp_save_resource'] ) && check_admin_referer( 'sp_resource_save' ) ) {
        $rid  = absint( $_POST['resource_id'] ?? 0 );
        $data = [
            'title'       => sanitize_text_field( $_POST['title'] ?? '' ),
            'url'         => esc_url_raw( $_POST['url'] ?? '' ),
            'description' => sanitize_textarea_field( $_POST['description'] ?? '' ),
            'category_id' => absint( $_POST['category_id'] ?? 0 ) ?: null,
            'featured'    => ! empty( $_POST['featured'] ) ? 1 : 0,
            'active'      => ! empty( $_POST['active'] ) ? 1 : 0,
            'sort_order'  => absint( $_POST['sort_order'] ?? 0 ),
        ];

        if ( ! empty( $data['title'] ) && ! empty( $data['url'] ) ) {
            if ( $rid ) {
                $wpdb->update( $prefix . 'resources', $data, [ 'id' => $rid ] );
                echo '<div class="notice notice-success"><p>Resource updated.</p></div>';
            } else {
                $wpdb->insert( $prefix . 'resources', $data );
                echo '<div class="notice notice-success"><p>Resource added.</p></div>';
            }
        } else {
            echo '<div class="notice notice-error"><p>Title and URL are required.</p></div>';
        }
    }

    $editing = null;
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['resource_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}resources WHERE id = %d", absint( $_GET['resource_id'] )
        ) );
    }

    $categories = $wpdb->get_results( "SELECT * FROM {$prefix}resource_categories WHERE active = 1 ORDER BY sort_order ASC, name ASC" );
    $resources  = $wpdb->get_results(
        "SELECT r.*, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         ORDER BY r.sort_order ASC, r.title ASC"
    );
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Resource Links</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-links' ) ); ?>" class="page-title-action">Import CSV</a>
        <hr class="wp-header-end">

        <div style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:20px; margin:16px 0;">
            <h3 style="margin-top:0;"><?php echo $editing ? 'Edit Resource' : 'Add Resource'; ?></h3>
            <form method="post">
                <?php wp_nonce_field( 'sp_resource_save' ); ?>
                <input type="hidden" name="resource_id" value="<?php echo $editing ? $editing->id : 0; ?>">

                <table class="form-table">
                    <tr>
                        <th><label for="title">Title</label></th>
                        <td><input type="text" name="title" id="title" class="regular-text" value="<?php echo esc_attr( $editing->title ?? '' ); ?>" required></td>
                    </tr>
                    <tr>
                        <th><label for="url">URL</label></th>
                        <td><input type="url" name="url" id="url" class="regular-text" value="<?php echo esc_attr( $editing->url ?? '' ); ?>" required placeholder="https://"></td>
                    </tr>
                    <tr>
                        <th><label for="description">Description</label></th>
                        <td><textarea name="description" id="description" rows="2" class="large-text"><?php echo esc_textarea( $editing->description ?? '' ); ?></textarea></td>
                    </tr>
                    <tr>
                        <th><label for="category_id">Category</label></th>
                        <td>
                            <select name="category_id" id="category_id">
                                <option value="0">— None —</option>
                                <?php foreach ( $categories as $cat ) : ?>
                                    <option value="<?php echo $cat->id; ?>" <?php selected( $editing->category_id ?? 0, $cat->id ); ?>><?php echo esc_html( $cat->name ); ?></option>
                                <?php endforeach; ?>
                            </select>
                        </td>
                    </tr>
                    <tr>
                        <th>Options</th>
                        <td>
                            <label><input type="checkbox" name="featured" value="1" <?php checked( $editing->featured ?? 0 ); ?>> Featured</label>
                            &nbsp;&nbsp;
                            <label><input type="checkbox" name="active" value="1" <?php checked( $editing->active ?? 1 ); ?>> Active</label>
                        </td>
                    </tr>
                    <tr>
                        <th><label for="sort_order">Sort Order</label></th>
                        <td><input type="number" name="sort_order" id="sort_order" value="<?php echo esc_attr( $editing->sort_order ?? 0 ); ?>" min="0" style="width:80px;"></td>
                    </tr>
                </table>
                <p class="submit">
                    <input type="submit" name="sp_save_resource" class="button button-primary" value="<?php echo $editing ? 'Update Resource' : 'Add Resource'; ?>">
                    <?php if ( $editing ) : ?>
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library' ) ); ?>" class="button">Cancel</a>
                    <?php endif; ?>
                </p>
            </form>
        </div>

        <!-- Resources list -->
        <table class="wp-list-table widefat striped">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Category</th>
                    <th>Featured</th>
                    <th>Active</th>
                    <th>Order</th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $resources ) ) : ?>
                    <tr><td colspan="5">No resources yet.</td></tr>
                <?php else : ?>
                    <?php foreach ( $resources as $r ) :
                        $edit_url   = admin_url( 'admin.php?page=sp-library&action=edit&resource_id=' . $r->id );
                        $delete_url = wp_nonce_url(
                            admin_url( 'admin.php?page=sp-library&action=delete&resource_id=' . $r->id ),
                            'sp_delete_resource_' . $r->id
                        );
                    ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo esc_url( $edit_url ); ?>"><?php echo esc_html( $r->title ); ?></a></strong>
                                <br><a href="<?php echo esc_url( $r->url ); ?>" target="_blank" style="color:#666; font-size:12px;"><?php echo esc_html( $r->url ); ?></a>
                                <div class="row-actions">
                                    <span class="edit"><a href="<?php echo esc_url( $edit_url ); ?>">Edit</a> | </span>
                                    <span class="delete"><a href="<?php echo esc_url( $delete_url ); ?>" style="color:#b32d2e;" onclick="return confirm('Delete this resource?');">Delete</a></span>
                                </div>
                            </td>
                            <td><?php echo esc_html( $r->category_name ?: '—' ); ?></td>
                            <td><?php echo $r->featured ? '<span style="color:#0a6b2e;">Yes</span>' : '—'; ?></td>
                            <td><?php echo $r->active ? '<span style="color:#0a6b2e;">Yes</span>' : '<span style="color:#b32d2e;">No</span>'; ?></td>
                            <td><?php echo $r->sort_order; ?></td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Render: Resource Categories Page
 *
 * WHY: Simple CRUD for resource categories. Seeded with defaults on
 *      activation but Harold can add, rename, reorder, or disable them.
 */
function sp_render_resource_categories_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle save
    if ( isset( $_POST['sp_save_resource_cat'] ) && check_admin_referer( 'sp_resource_cat_save' ) ) {
        $cat_id = absint( $_POST['cat_id'] ?? 0 );
        $data = [
            'name'       => sanitize_text_field( $_POST['name'] ?? '' ),
            'slug'       => sanitize_title( $_POST['name'] ?? '' ),
            'sort_order' => absint( $_POST['sort_order'] ?? 0 ),
            'active'     => ! empty( $_POST['active'] ) ? 1 : 0,
        ];
        if ( ! empty( $data['name'] ) ) {
            if ( $cat_id ) {
                $wpdb->update( $prefix . 'resource_categories', $data, [ 'id' => $cat_id ] );
            } else {
                $wpdb->insert( $prefix . 'resource_categories', $data );
            }
            echo '<div class="notice notice-success"><p>Category saved.</p></div>';
        }
    }

    // Handle delete
    if ( ( $_GET['action'] ?? '' ) === 'delete' && ! empty( $_GET['cat_id'] ) ) {
        $cat_id = absint( $_GET['cat_id'] );
        check_admin_referer( 'sp_delete_resource_cat_' . $cat_id );
        // Nullify category_id on resources that use this category
        $wpdb->update( $prefix . 'resources', [ 'category_id' => null ], [ 'category_id' => $cat_id ] );
        $wpdb->delete( $prefix . 'resource_categories', [ 'id' => $cat_id ] );
        echo '<div class="notice notice-success"><p>Category deleted.</p></div>';
    }

    $categories = $wpdb->get_results( "SELECT * FROM {$prefix}resource_categories ORDER BY sort_order ASC, name ASC" );
    $editing = null;
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['cat_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare( "SELECT * FROM {$prefix}resource_categories WHERE id = %d", absint( $_GET['cat_id'] ) ) );
    }
    ?>
    <div class="wrap">
        <h1>Resource Categories</h1>

        <div style="display:flex; gap:24px; margin-top:16px;">
            <!-- Add/Edit form -->
            <div style="flex:0 0 350px; background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:20px;">
                <h3 style="margin-top:0;"><?php echo $editing ? 'Edit Category' : 'Add Category'; ?></h3>
                <form method="post">
                    <?php wp_nonce_field( 'sp_resource_cat_save' ); ?>
                    <input type="hidden" name="cat_id" value="<?php echo $editing ? $editing->id : 0; ?>">
                    <p>
                        <label style="font-weight:600;">Name</label><br>
                        <input type="text" name="name" value="<?php echo esc_attr( $editing->name ?? '' ); ?>" class="regular-text" required>
                    </p>
                    <p>
                        <label style="font-weight:600;">Sort Order</label><br>
                        <input type="number" name="sort_order" value="<?php echo esc_attr( $editing->sort_order ?? 0 ); ?>" min="0" style="width:80px;">
                    </p>
                    <p>
                        <label><input type="checkbox" name="active" value="1" <?php checked( $editing->active ?? 1 ); ?>> Active</label>
                    </p>
                    <p>
                        <input type="submit" name="sp_save_resource_cat" class="button button-primary" value="<?php echo $editing ? 'Update' : 'Add Category'; ?>">
                        <?php if ( $editing ) : ?>
                            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-resource-categories' ) ); ?>" class="button">Cancel</a>
                        <?php endif; ?>
                    </p>
                </form>
            </div>

            <!-- Categories list -->
            <div style="flex:1;">
                <table class="wp-list-table widefat striped">
                    <thead><tr><th>Name</th><th>Slug</th><th>Order</th><th>Active</th></tr></thead>
                    <tbody>
                        <?php foreach ( $categories as $cat ) :
                            $edit_url   = admin_url( 'admin.php?page=sp-resource-categories&action=edit&cat_id=' . $cat->id );
                            $delete_url = wp_nonce_url( admin_url( 'admin.php?page=sp-resource-categories&action=delete&cat_id=' . $cat->id ), 'sp_delete_resource_cat_' . $cat->id );
                        ?>
                            <tr>
                                <td>
                                    <strong><a href="<?php echo esc_url( $edit_url ); ?>"><?php echo esc_html( $cat->name ); ?></a></strong>
                                    <div class="row-actions">
                                        <span><a href="<?php echo esc_url( $edit_url ); ?>">Edit</a> | </span>
                                        <span><a href="<?php echo esc_url( $delete_url ); ?>" style="color:#b32d2e;" onclick="return confirm('Delete?');">Delete</a></span>
                                    </div>
                                </td>
                                <td><?php echo esc_html( $cat->slug ); ?></td>
                                <td><?php echo $cat->sort_order; ?></td>
                                <td><?php echo $cat->active ? 'Yes' : 'No'; ?></td>
                            </tr>
                        <?php endforeach; ?>
                    </tbody>
