    <!-- Volunteer Opportunities JS -->
    <script>
    (function() {
        'use strict';
        var nonce = '<?php echo esc_js( $nonce ); ?>';
        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';

        // Signup buttons
        document.querySelectorAll('.sp-vol-signup-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var oppId = this.getAttribute('data-opp-id');
                var origText = this.textContent;
                this.disabled = true;
                this.textContent = 'Signing up\u2026';

                var fd = new FormData();
                fd.append('action', 'sp_volunteer_signup');
                fd.append('opportunity_id', oppId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            var icon = data.data.status === 'waitlisted' ? '\uD83D\uDCCB Waitlisted' : '\u2705 Signed Up';
                            btn.parentNode.innerHTML = '<span style="font-weight:600;color:' +
                                (data.data.status === 'confirmed' ? '#00a32a' : '#dba617') + ';">' + icon + '</span>' +
                                ' <em style="font-size:0.85em;color:#787c82;">(reload to update)</em>';
                        } else {
                            alert(data.data || 'Could not sign up.');
                            btn.disabled = false;
                            btn.textContent = origText;
                        }
                    })
                    .catch(function() {
                        alert('Something went wrong.');
                        btn.disabled = false;
                        btn.textContent = origText;
                    });
            });
        });

        // Cancel buttons
        document.querySelectorAll('.sp-vol-cancel-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                if (!confirm('Cancel your volunteer signup?')) return;
                var signupId = this.getAttribute('data-signup-id');
                this.disabled = true;
                this.textContent = 'Cancelling\u2026';

                var fd = new FormData();
                fd.append('action', 'sp_volunteer_cancel');
                fd.append('signup_id', signupId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            btn.parentNode.innerHTML = '<em style="color:#787c82;">Cancelled (reload to update)</em>';
                        } else {
                            alert(data.data || 'Could not cancel.');
                            btn.disabled = false;
                            btn.textContent = 'Cancel';
                        }
                    });
            });
        });

        // Client-side filters
        var filterCommittee = document.getElementById('sp-vol-filter-committee');
        var filterType      = document.getElementById('sp-vol-filter-type');
        function applyFilters() {
            var cVal = filterCommittee ? filterCommittee.value : '';
            var tVal = filterType ? filterType.value : '';
            document.querySelectorAll('.sp-vol-card').forEach(function(card) {
                var matchC = !cVal || card.getAttribute('data-committee') === cVal;
                var matchT = !tVal || card.getAttribute('data-type') === tVal;
                card.style.display = (matchC && matchT) ? '' : 'none';
            });
        }
        if (filterCommittee) filterCommittee.addEventListener('change', applyFilters);
        if (filterType) filterType.addEventListener('change', applyFilters);
    })();
    </script>
    <?php
    return ob_get_clean();
}


// ============================================================================
// VOLUNTEER OPPORTUNITIES — ADMIN LIST PAGE
// ============================================================================

function sp_render_volunteer_opportunities_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete' && ! empty( $_GET['opp_id'] ) ) {
        if ( check_admin_referer( 'sp_delete_opp_' . $_GET['opp_id'] ) ) {
            $opp_id = absint( $_GET['opp_id'] );
            $wpdb->delete( $prefix . 'volunteer_signups', [ 'opportunity_id' => $opp_id ] );
            $wpdb->delete( $prefix . 'volunteer_opportunities', [ 'id' => $opp_id ] );
            echo '<div class="notice notice-success is-dismissible"><p>Opportunity deleted.</p></div>';
        }
    }

    $opportunities = $wpdb->get_results(
        "SELECT o.*, c.name AS committee_name,
                (SELECT COUNT(*) FROM {$prefix}volunteer_signups s WHERE s.opportunity_id = o.id AND s.status = 'confirmed') AS signup_count,
                (SELECT COUNT(*) FROM {$prefix}volunteer_signups s WHERE s.opportunity_id = o.id AND s.status = 'waitlisted') AS waitlist_count
         FROM {$prefix}volunteer_opportunities o
         LEFT JOIN {$prefix}committees c ON o.committee_id = c.id
         ORDER BY o.status ASC, o.event_date ASC, o.sort_order ASC"
    );

    $status_colors = [ 'open' => '#00a32a', 'filled' => '#dba617', 'closed' => '#787c82', 'cancelled' => '#d63638' ];
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Volunteer Opportunities</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit' ) ); ?>" class="page-title-action">Add New</a>
        <hr class="wp-header-end">

        <p class="description">Post volunteer needs for your members to browse and sign up for.</p>

        <?php if ( empty( $opportunities ) ) : ?>
            <p style="color: #787c82; font-style: italic; margin-top: 20px;">
                No opportunities yet. <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit' ) ); ?>">Create your first one.</a>
            </p>
        <?php else : ?>
            <table class="wp-list-table widefat fixed striped" style="margin-top: 16px;">
                <thead>
                    <tr>
                        <th style="width:25%;">Title</th>
                        <th style="width:12%;">Type</th>
                        <th style="width:15%;">Committee</th>
                        <th style="width:12%;">Date</th>
                        <th style="width:10%;">Signups</th>
                        <th style="width:10%;">Status</th>
                        <th style="width:16%;">Actions</th>
                    </tr>
                </thead>
                <tbody>
                    <?php foreach ( $opportunities as $opp ) :
                        $badge_color = $status_colors[ $opp->status ] ?? '#787c82';
                        $type_labels = [ 'one_time' => 'One-Time', 'recurring' => 'Recurring', 'ongoing' => 'Ongoing' ];
                    ?>
                    <tr>
                        <td><strong><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit&opp_id=' . $opp->id ) ); ?>"><?php echo esc_html( $opp->title ); ?></a></strong></td>
                        <td><?php echo esc_html( $type_labels[ $opp->opportunity_type ] ?? $opp->opportunity_type ); ?></td>
                        <td><?php echo esc_html( $opp->committee_name ?: 'Society-Wide' ); ?></td>
                        <td><?php echo $opp->event_date ? esc_html( date_i18n( 'M j, Y', strtotime( $opp->event_date ) ) ) : '—'; ?></td>
                        <td>
                            <?php echo (int) $opp->signup_count; ?>
                            <?php if ( $opp->capacity ) echo ' / ' . (int) $opp->capacity; ?>
                            <?php if ( (int) $opp->waitlist_count > 0 ) : ?>
                                <span style="color: #dba617; font-size: 12px;">(+<?php echo (int) $opp->waitlist_count; ?> waitlisted)</span>
                            <?php endif; ?>
                        </td>
                        <td>
                            <span style="display:inline-block;padding:2px 8px;border-radius:3px;background:<?php echo $badge_color; ?>22;color:<?php echo $badge_color; ?>;font-size:12px;font-weight:500;">
                                <?php echo esc_html( ucfirst( $opp->status ) ); ?>
                            </span>
                        </td>
                        <td>
                            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit&opp_id=' . $opp->id ) ); ?>">Edit</a>
                            |
                            <a href="<?php echo esc_url( wp_nonce_url( admin_url( 'admin.php?page=sp-volunteer-opportunities&action=delete&opp_id=' . $opp->id ), 'sp_delete_opp_' . $opp->id ) ); ?>"
                               style="color: #b32d2e;"
                               onclick="return confirm('Delete this opportunity and all signups?');">Delete</a>
                        </td>
                    </tr>
                    <?php endforeach; ?>
                </tbody>
            </table>
        <?php endif; ?>
    </div>
    <?php
}


// ============================================================================
// VOLUNTEER OPPORTUNITIES — ADD/EDIT PAGE
// ============================================================================

function sp_render_volunteer_opportunity_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $opp_id = (int) ( $_GET['opp_id'] ?? 0 );
    $opp    = null;

    // Handle save
    if ( isset( $_POST['sp_save_opp_nonce'] ) && wp_verify_nonce( $_POST['sp_save_opp_nonce'], 'sp_save_opportunity' ) ) {
        $data = [
            'title'            => sanitize_text_field( $_POST['opp_title'] ?? '' ),
            'description'      => wp_kses_post( $_POST['opp_description'] ?? '' ),
            'committee_id'     => ! empty( $_POST['opp_committee_id'] ) ? (int) $_POST['opp_committee_id'] : null,
            'opportunity_type' => in_array( $_POST['opp_type'] ?? '', [ 'one_time', 'recurring', 'ongoing' ], true )
                                  ? $_POST['opp_type'] : 'one_time',
            'event_date'       => ! empty( $_POST['opp_date'] ) ? sanitize_text_field( $_POST['opp_date'] ) : null,
            'start_time'       => ! empty( $_POST['opp_start_time'] ) ? sanitize_text_field( $_POST['opp_start_time'] ) : null,
            'end_time'         => ! empty( $_POST['opp_end_time'] ) ? sanitize_text_field( $_POST['opp_end_time'] ) : null,
            'location'         => sanitize_text_field( $_POST['opp_location'] ?? '' ),
            'capacity'         => $_POST['opp_capacity'] !== '' ? absint( $_POST['opp_capacity'] ) : null,
            'skills_needed'    => sanitize_textarea_field( $_POST['opp_skills'] ?? '' ),
            'contact_user_id'  => ! empty( $_POST['opp_contact'] ) ? (int) $_POST['opp_contact'] : null,
            'status'           => in_array( $_POST['opp_status'] ?? '', [ 'open', 'filled', 'closed', 'cancelled' ], true )
                                  ? $_POST['opp_status'] : 'open',
        ];

        if ( $opp_id > 0 ) {
            $wpdb->update( $prefix . 'volunteer_opportunities', $data, [ 'id' => $opp_id ] );
            echo '<div class="notice notice-success"><p>Opportunity updated.</p></div>';
        } else {
            $data['created_by'] = get_current_user_id();
            $wpdb->insert( $prefix . 'volunteer_opportunities', $data );
            $opp_id = $wpdb->insert_id;
            echo '<div class="notice notice-success"><p>Opportunity created.</p></div>';
        }
    }

    // Load existing
    if ( $opp_id > 0 ) {
        $opp = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}volunteer_opportunities WHERE id = %d", $opp_id
        ) );
    }

    $val = function ( string $field, $default = '' ) use ( $opp ) {
        if ( $opp && isset( $opp->$field ) ) return $opp->$field;
        return $default;
    };

    $committees = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}committees WHERE active = 1 ORDER BY name"
    );
    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name"
    );

    $page_title = $opp ? 'Edit Opportunity' : 'Add Volunteer Opportunity';
    ?>
    <div class="wrap">
        <h1><?php echo esc_html( $page_title ); ?></h1>

        <form method="post">
            <?php wp_nonce_field( 'sp_save_opportunity', 'sp_save_opp_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="opp_title">Title <span style="color:#d63638;">*</span></label></th>
                    <td><input type="text" id="opp_title" name="opp_title" value="<?php echo esc_attr( $val('title') ); ?>" class="large-text" required></td>
                </tr>
                <tr>
                    <th><label for="opp_type">Type</label></th>
                    <td>
                        <select id="opp_type" name="opp_type">
                            <option value="one_time" <?php selected( $val('opportunity_type', 'one_time'), 'one_time' ); ?>>One-Time</option>
                            <option value="recurring" <?php selected( $val('opportunity_type'), 'recurring' ); ?>>Recurring</option>
                            <option value="ongoing" <?php selected( $val('opportunity_type'), 'ongoing' ); ?>>Ongoing</option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_committee_id">Committee</label></th>
                    <td>
                        <select id="opp_committee_id" name="opp_committee_id">
                            <option value="">Society-Wide (no committee)</option>
                            <?php foreach ( $committees as $c ) : ?>
                                <option value="<?php echo esc_attr( $c->id ); ?>" <?php selected( $val('committee_id'), $c->id ); ?>><?php echo esc_html( $c->name ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_description">Description</label></th>
                    <td><textarea id="opp_description" name="opp_description" rows="5" class="large-text"><?php echo esc_textarea( $val('description') ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="opp_date">Date</label></th>
                    <td><input type="date" id="opp_date" name="opp_date" value="<?php echo esc_attr( $val('event_date') ); ?>">
                        <p class="description">For one-time opportunities. Leave blank for ongoing.</p></td>
                </tr>
                <tr>
                    <th><label for="opp_start_time">Time</label></th>
                    <td>
                        <input type="time" id="opp_start_time" name="opp_start_time" value="<?php echo esc_attr( $val('start_time') ); ?>">
                        to
                        <input type="time" id="opp_end_time" name="opp_end_time" value="<?php echo esc_attr( $val('end_time') ); ?>">
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_location">Location</label></th>
                    <td><input type="text" id="opp_location" name="opp_location" value="<?php echo esc_attr( $val('location') ); ?>" class="regular-text"></td>
                </tr>
                <tr>
                    <th><label for="opp_capacity">Capacity</label></th>
                    <td><input type="number" id="opp_capacity" name="opp_capacity" value="<?php echo $val('capacity') !== null ? esc_attr( $val('capacity') ) : ''; ?>" min="0" class="small-text">
                        <p class="description">Leave blank for unlimited.</p></td>
                </tr>
                <tr>
                    <th><label for="opp_skills">Skills/Requirements</label></th>
                    <td><textarea id="opp_skills" name="opp_skills" rows="2" class="large-text"><?php echo esc_textarea( $val('skills_needed') ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="opp_contact">Contact Person</label></th>
                    <td>
                        <select id="opp_contact" name="opp_contact">
                            <option value="">— None —</option>
                            <?php foreach ( $members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>" <?php selected( $val('contact_user_id'), $m->user_id ); ?>>
                                    <?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?>
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_status">Status</label></th>
                    <td>
                        <select id="opp_status" name="opp_status">
                            <option value="open" <?php selected( $val('status', 'open'), 'open' ); ?>>Open</option>
                            <option value="filled" <?php selected( $val('status'), 'filled' ); ?>>Filled</option>
                            <option value="closed" <?php selected( $val('status'), 'closed' ); ?>>Closed</option>
                            <option value="cancelled" <?php selected( $val('status'), 'cancelled' ); ?>>Cancelled</option>
                        </select>
                    </td>
                </tr>
            </table>

            <?php submit_button( $opp ? 'Update Opportunity' : 'Create Opportunity' ); ?>
        </form>

        <?php
        // Show signups for existing opportunity
        if ( $opp ) {
            $signups = $wpdb->get_results( $wpdb->prepare(
                "SELECT s.*, u.display_name, m.first_name, m.last_name
                 FROM {$prefix}volunteer_signups s
                 LEFT JOIN {$wpdb->users} u ON s.user_id = u.ID
                 LEFT JOIN {$prefix}members m ON s.user_id = m.user_id
                 WHERE s.opportunity_id = %d
                 ORDER BY FIELD(s.status, 'confirmed', 'waitlisted', 'cancelled'), s.signed_up_at ASC",
                $opp->id
            ) );
            if ( ! empty( $signups ) ) : ?>
                <h2 style="margin-top: 30px; border-bottom: 1px solid #c3c4c7; padding-bottom: 8px;">Signups (<?php echo count( $signups ); ?>)</h2>
                <table class="wp-list-table widefat fixed striped">
                    <thead><tr><th>Name</th><th>Status</th><th>Signed Up</th></tr></thead>
                    <tbody>
                    <?php foreach ( $signups as $s ) :
                        $name = $s->first_name ? $s->first_name . ' ' . $s->last_name : $s->display_name;
                        $badge = [ 'confirmed' => '#00a32a', 'waitlisted' => '#dba617', 'cancelled' => '#d63638' ];
                    ?>
                        <tr>
                            <td><?php echo esc_html( $name ); ?></td>
                            <td><span style="display:inline-block;padding:2px 8px;border-radius:3px;background:<?php echo ($badge[$s->status] ?? '#787c82') . '22'; ?>;color:<?php echo $badge[$s->status] ?? '#787c82'; ?>;font-size:12px;"><?php echo esc_html( ucfirst( $s->status ) ); ?></span></td>
                            <td><?php echo esc_html( date_i18n( 'M j, Y g:i A', strtotime( $s->signed_up_at ) ) ); ?></td>
                        </tr>
                    <?php endforeach; ?>
                    </tbody>
                </table>
            <?php endif;
        }
        ?>
    </div>
    <?php
}


// ============================================================================
// VOLUNTEERS — ADMIN PAGE (existing roles roster)
// ============================================================================

function sp_render_volunteers_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle form submission for add/edit
    if ( isset( $_POST['sp_save_volunteer_role'] ) && check_admin_referer( 'sp_volunteer_role_save' ) ) {
        $role_id    = absint( $_POST['role_id'] ?? 0 );
        $user_id    = absint( $_POST['user_id'] ?? 0 );
        $role_title = sanitize_text_field( $_POST['role_title'] ?? '' );
        $committee  = sanitize_text_field( $_POST['committee'] ?? '' );
        $start_date = sanitize_text_field( $_POST['start_date'] ?? '' );
        $end_date   = sanitize_text_field( $_POST['end_date'] ?? '' );
        $status     = sanitize_text_field( $_POST['status'] ?? 'active' );

        if ( $user_id && $role_title ) {
            $data = [
                'user_id'    => $user_id,
                'role_title' => $role_title,
                'committee'  => $committee,
                'start_date' => $start_date ?: null,
                'end_date'   => $end_date ?: null,
                'status'     => $status,
            ];

            if ( $role_id ) {
                $wpdb->update( $prefix . 'volunteer_roles', $data, [ 'id' => $role_id ] );
                echo '<div class="notice notice-success"><p>Volunteer role updated.</p></div>';
            } else {
                $wpdb->insert( $prefix . 'volunteer_roles', $data );
                echo '<div class="notice notice-success"><p>Volunteer role added.</p></div>';
            }
        } else {
            echo '<div class="notice notice-error"><p>Please select a member and enter a role title.</p></div>';
        }
    }

    // Load edit data if editing
    $editing = null;
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['role_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}volunteer_roles WHERE id = %d", absint( $_GET['role_id'] )
        ) );
    }

    // Get members for the dropdown
    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name ASC"
    );

    $table = new SP_Volunteers_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Volunteer Roster</h1>
        <hr class="wp-header-end">

        <!-- Add/Edit form -->
        <div style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:20px; margin:16px 0;">
            <h3 style="margin-top:0;"><?php echo $editing ? 'Edit Role Assignment' : 'Add Volunteer Role'; ?></h3>
            <form method="post">
                <?php wp_nonce_field( 'sp_volunteer_role_save' ); ?>
                <input type="hidden" name="role_id" value="<?php echo $editing ? $editing->id : 0; ?>">

                <table class="form-table">
                    <tr>
                        <th><label for="user_id">Member</label></th>
                        <td>
                            <select name="user_id" id="user_id" required style="min-width:250px;">
                                <option value="">— Select Member —</option>
                                <?php foreach ( $members as $m ) : ?>
                                    <option value="<?php echo $m->user_id; ?>" <?php selected( $editing->user_id ?? 0, $m->user_id ); ?>>
                                        <?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?>
                                    </option>
                                <?php endforeach; ?>
                            </select>
                        </td>
                    </tr>
                    <tr>
                        <th><label for="role_title">Role Title</label></th>
                        <td><input type="text" name="role_title" id="role_title" value="<?php echo esc_attr( $editing->role_title ?? '' ); ?>" class="regular-text" required placeholder="e.g., Event Coordinator"></td>
                    </tr>
                    <tr>
                        <th><label for="committee">Committee</label></th>
                        <td><input type="text" name="committee" id="committee" value="<?php echo esc_attr( $editing->committee ?? '' ); ?>" class="regular-text" placeholder="e.g., Programs Committee"></td>
                    </tr>
                    <tr>
                        <th><label for="start_date">Start Date</label></th>
                        <td><input type="date" name="start_date" id="start_date" value="<?php echo esc_attr( $editing->start_date ?? '' ); ?>"></td>
                    </tr>
                    <tr>
                        <th><label for="end_date">End Date</label></th>
                        <td><input type="date" name="end_date" id="end_date" value="<?php echo esc_attr( $editing->end_date ?? '' ); ?>"> <span class="description">Leave blank for ongoing roles.</span></td>
                    </tr>
                    <tr>
                        <th><label for="vstatus">Status</label></th>
                        <td>
                            <select name="status" id="vstatus">
                                <option value="active" <?php selected( $editing->status ?? 'active', 'active' ); ?>>Active</option>
                                <option value="inactive" <?php selected( $editing->status ?? '', 'inactive' ); ?>>Inactive</option>
                            </select>
                        </td>
                    </tr>
                </table>
                <p class="submit">
                    <input type="submit" name="sp_save_volunteer_role" class="button button-primary" value="<?php echo $editing ? 'Update Role' : 'Add Role'; ?>">
                    <?php if ( $editing ) : ?>
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-governance' ) ); ?>" class="button">Cancel</a>
                    <?php endif; ?>
                </p>
            </form>
        </div>

        <!-- Volunteer roster table -->
        <form method="get">
            <input type="hidden" name="page" value="sp-governance">
            <?php
            $table->search_box( 'Search Volunteers', 'volunteer_search' );
            $table->display();
            ?>
        </form>
    </div>
    <?php
}

/**
 * Render: Volunteer Hours Page
 *
 * WHY: Admin page for logging and viewing volunteer hours. Has an inline
 *      add form and a summary stats bar at the top showing totals.
 */
function sp_render_volunteer_hours_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle form submission
    if ( isset( $_POST['sp_log_volunteer_hours'] ) && check_admin_referer( 'sp_volunteer_hours_save' ) ) {
        $user_id       = absint( $_POST['user_id'] ?? 0 );
        $activity      = sanitize_text_field( $_POST['activity'] ?? '' );
        $committee     = sanitize_text_field( $_POST['committee'] ?? '' );
        $hours         = floatval( $_POST['hours'] ?? 0 );
        $activity_date = sanitize_text_field( $_POST['activity_date'] ?? '' );

        if ( $user_id && $hours > 0 ) {
            $wpdb->insert( $prefix . 'volunteer_hours', [
                'user_id'       => $user_id,
                'activity'      => $activity,
                'committee'     => $committee,
                'hours'         => $hours,
                'activity_date' => $activity_date ?: current_time( 'Y-m-d' ),
                'recorded_by'   => get_current_user_id(),
            ] );
            echo '<div class="notice notice-success"><p>Hours logged successfully.</p></div>';
        } else {
            echo '<div class="notice notice-error"><p>Please select a member and enter hours greater than 0.</p></div>';
        }
    }

    // Summary stats
    $year_start   = date( 'Y-01-01' );
    $total_hours  = (float) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(hours), 0) FROM {$prefix}volunteer_hours WHERE activity_date >= %s", $year_start
    ) );
    $total_volunteers = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(DISTINCT user_id) FROM {$prefix}volunteer_hours WHERE activity_date >= %s", $year_start
    ) );

    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name ASC"
    );

    $table = new SP_VolunteerHours_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Volunteer Hours</h1>

        <!-- Export CSV link -->
        <a href="<?php echo esc_url( wp_nonce_url( admin_url( 'admin.php?page=sp-volunteer-hours&action=export_csv' ), 'sp_export_volunteer_hours' ) ); ?>" class="page-title-action">Export CSV</a>
        <hr class="wp-header-end">

        <!-- Summary stats -->
        <div style="display:flex; gap:16px; margin:16px 0;">
            <div style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:16px 24px; flex:1; text-align:center;">
                <div style="font-size:28px; font-weight:700; color:var(--sp-color-primary);"><?php echo number_format( $total_hours, 1 ); ?></div>
                <div style="color:#666; font-size:13px;">Hours This Year</div>
            </div>
            <div style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:16px 24px; flex:1; text-align:center;">
                <div style="font-size:28px; font-weight:700; color:var(--sp-color-primary);"><?php echo $total_volunteers; ?></div>
                <div style="color:#666; font-size:13px;">Active Volunteers</div>
            </div>
        </div>

        <!-- Log hours form -->
        <div style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:20px; margin:16px 0;">
            <h3 style="margin-top:0;">Log Hours</h3>
            <form method="post" style="display:flex; flex-wrap:wrap; gap:12px; align-items:flex-end;">
                <?php wp_nonce_field( 'sp_volunteer_hours_save' ); ?>
                <div>
                    <label style="display:block; font-weight:600; margin-bottom:4px;">Member</label>
                    <select name="user_id" required style="min-width:200px;">
                        <option value="">— Select —</option>
                        <?php foreach ( $members as $m ) : ?>
                            <option value="<?php echo $m->user_id; ?>"><?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?></option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <div>
                    <label style="display:block; font-weight:600; margin-bottom:4px;">Activity</label>
                    <input type="text" name="activity" placeholder="e.g., Library shelving" style="width:200px;">
                </div>
                <div>
                    <label style="display:block; font-weight:600; margin-bottom:4px;">Committee</label>
                    <input type="text" name="committee" placeholder="Optional" style="width:150px;">
                </div>
                <div>
                    <label style="display:block; font-weight:600; margin-bottom:4px;">Hours</label>
                    <input type="number" name="hours" step="0.5" min="0.5" required style="width:80px;">
                </div>
                <div>
                    <label style="display:block; font-weight:600; margin-bottom:4px;">Date</label>
                    <input type="date" name="activity_date" value="<?php echo date( 'Y-m-d' ); ?>">
                </div>
                <div>
                    <input type="submit" name="sp_log_volunteer_hours" class="button button-primary" value="Log Hours">
                </div>
            </form>
        </div>

        <!-- Hours log table -->
        <form method="get">
            <input type="hidden" name="page" value="sp-volunteer-hours">
            <?php $table->display(); ?>
        </form>
    </div>
    <?php
}

// Handle volunteer hours CSV export
add_action( 'admin_init', function() {
    if ( ( $_GET['page'] ?? '' ) !== 'sp-volunteer-hours' || ( $_GET['action'] ?? '' ) !== 'export_csv' ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;
    check_admin_referer( 'sp_export_volunteer_hours' );

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $rows = $wpdb->get_results(
        "SELECT m.first_name, m.last_name, vh.activity, vh.committee, vh.hours, vh.activity_date
         FROM {$prefix}volunteer_hours vh
         INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
         ORDER BY vh.activity_date DESC"
    );

    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename=volunteer-hours-' . date( 'Y-m-d' ) . '.csv' );
    $out = fopen( 'php://output', 'w' );
    fputcsv( $out, [ 'First Name', 'Last Name', 'Activity', 'Committee', 'Hours', 'Date' ] );
    foreach ( $rows as $row ) {
        fputcsv( $out, [ $row->first_name, $row->last_name, $row->activity, $row->committee, $row->hours, $row->activity_date ] );
    }
    fclose( $out );
    exit;
} );


// ============================================================================
// AUTOMATED RENEWAL REMINDERS — DAILY CRON
// ============================================================================
//
// WHY: Feature 3 — sends email reminders at 30, 15, and 7 days before a
//      member's expiration date. Each reminder is logged to sp_renewal_reminders
//      with a unique key (e.g., "30d_2026-03-20") so the same reminder is
//      never sent twice, even if cron runs multiple times.

// Schedule the cron event on plugin activation (done in register_activation_hook)
// and clear it on deactivation (done in register_deactivation_hook).

add_action( 'sp_renewal_reminder_cron', 'sp_process_renewal_reminders' );

function sp_process_renewal_reminders(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Prevent concurrent runs — if another cron instance is already processing,
    // bail out. The transient auto-expires after 5 minutes as a safety net.
    if ( get_transient( 'sp_notification_batch_running' ) ) {
        return;
    }
    set_transient( 'sp_notification_batch_running', true, 5 * MINUTE_IN_SECONDS );

    // Check which reminder intervals are enabled
    $intervals = [];
    if ( ! empty( $settings['renewal_reminder_30d'] ) ) $intervals[] = 30;
    if ( ! empty( $settings['renewal_reminder_15d'] ) ) $intervals[] = 15;
    if ( ! empty( $settings['renewal_reminder_7d'] ) )  $intervals[] = 7;

    $site_name        = get_bloginfo( 'name' );
    $subject_template = $settings['renewal_reminder_subject'] ?? 'Your membership expires soon';

    // ---- Send renewal reminders for each enabled interval ----
    foreach ( $intervals as $days ) {
        $target_date  = date( 'Y-m-d', strtotime( "+{$days} days" ) );
        $reminder_key = "{$days}d_{$target_date}";

        // WHY: Join wp_users to get the email address. The old code joined a
        //      member_contact table that doesn't exist. Members link to WP users
        //      via user_id, and the WP user record holds the email.
        $members = $wpdb->get_results( $wpdb->prepare(
            "SELECT m.user_id, m.first_name, m.last_name, m.expiration_date,
                    m.pref_email_notices, u.user_email
             FROM {$prefix}members m
             INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
             LEFT JOIN {$prefix}renewal_reminders rr
                 ON rr.user_id = m.user_id AND rr.reminder_type = %s
             WHERE m.expiration_date = %s
               AND m.status = 'active'
               AND u.user_email IS NOT NULL AND u.user_email != ''
               AND rr.id IS NULL
             LIMIT 100",
            $reminder_key,
            $target_date
        ) );

        foreach ( $members as $member ) {
            if ( ! is_email( $member->user_email ) ) continue;

            // Respect communication preferences — if member opted out of notices, skip
            if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) {
                continue;
            }

            // Use merge tags for personalized content
            $body_html = sp_replace_merge_tags(
                sp_get_default_email_template( 'renewal_reminder' ),
                $member,
                [ 'days_until_expiration' => $days ]
            );

            $subject = sp_replace_merge_tags( $subject_template, $member, [ 'days_until_expiration' => $days ] );
            $html    = sp_build_email_html( $subject, $body_html );

            wp_mail(
                $member->user_email,
                sprintf( '[%s] %s', $site_name, $subject ),
                $html,
                sp_get_email_headers()
            );

            // Log reminder to prevent re-sending
            $wpdb->insert( $prefix . 'renewal_reminders', [
                'user_id'       => $member->user_id,
                'reminder_type' => $reminder_key,
                'sent_at'       => current_time( 'mysql' ),
            ] );
        }
    }

    // ---- Send expired membership notices ----
    sp_process_expired_notices();

    delete_transient( 'sp_notification_batch_running' );
}

/**
 * Send expired membership notices to members whose membership lapsed yesterday.
 *
 * WHY: Members who just expired deserve a prompt, personalized nudge to renew.
 *      Sent once (day after expiration), tracked in renewal_reminders to prevent
 *      duplicate sends. Also updates member status to 'expired' so the admin
 *      list table reflects reality without manual intervention.
 */
function sp_process_expired_notices(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Only send if expired notices are enabled (default: off)
    if ( empty( $settings['expired_notice_enabled'] ) ) {
        return;
    }

    $yesterday    = date( 'Y-m-d', strtotime( '-1 day' ) );
    $reminder_key = 'expired_' . $yesterday;
    $site_name    = get_bloginfo( 'name' );
    $subject      = $settings['expired_notice_subject'] ?? 'Your {{organization_name}} membership has expired';

    $members = $wpdb->get_results( $wpdb->prepare(
        "SELECT m.user_id, m.first_name, m.last_name, m.expiration_date,
                m.pref_email_notices, u.user_email
         FROM {$prefix}members m
         INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
         LEFT JOIN {$prefix}renewal_reminders rr
             ON rr.user_id = m.user_id AND rr.reminder_type = %s
         WHERE m.expiration_date = %s
           AND m.status = 'active'
           AND u.user_email IS NOT NULL AND u.user_email != ''
           AND rr.id IS NULL
         LIMIT 100",
        $reminder_key,
        $yesterday
    ) );

    foreach ( $members as $member ) {
        if ( ! is_email( $member->user_email ) ) continue;
        if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) continue;

        $body_html = sp_replace_merge_tags(
            sp_get_default_email_template( 'expired' ),
            $member
        );

        $member_subject = sp_replace_merge_tags( $subject, $member );
        $html           = sp_build_email_html( $member_subject, $body_html );

        wp_mail(
            $member->user_email,
            sprintf( '[%s] %s', $site_name, $member_subject ),
            $html,
            sp_get_email_headers()
        );

        // Log to prevent re-sending
        $wpdb->insert( $prefix . 'renewal_reminders', [
            'user_id'       => $member->user_id,
            'reminder_type' => $reminder_key,
            'sent_at'       => current_time( 'mysql' ),
        ] );

        // Auto-update member status to expired
        $wpdb->update(
            $prefix . 'members',
            [ 'status' => 'expired', 'updated_at' => current_time( 'mysql' ) ],
            [ 'user_id' => $member->user_id ],
            [ '%s', '%s' ],
            [ '%d' ]
        );
    }
}

/**
 * Send a welcome email to a newly created member.
 *
 * WHY: Automated onboarding improves member experience and confirms that
 *      their information was received. Called when a new member record is
 *      created in the admin (or via future join form).
 *
 * @param int $user_id The WP user ID of the new member.
 */
function sp_send_welcome_email( int $user_id ): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Only send if welcome emails are enabled
    if ( empty( $settings['welcome_email_enabled'] ) ) {
        return;
    }

    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT m.*, u.user_email
         FROM {$prefix}members m
         INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
         WHERE m.user_id = %d",
        $user_id
    ) );

    if ( ! $member || ! is_email( $member->user_email ) ) {
        return;
    }

    // Respect communication preference
    if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) {
        return;
    }

    $site_name = get_bloginfo( 'name' );
    $subject   = $settings['welcome_email_subject'] ?? 'Welcome to {{organization_name}}!';
    $subject   = sp_replace_merge_tags( $subject, $member );

    $body_html = sp_replace_merge_tags(
        sp_get_default_email_template( 'welcome' ),
        $member
    );

    $html = sp_build_email_html( $subject, $body_html );

    wp_mail(
        $member->user_email,
        sprintf( '[%s] %s', $site_name, $subject ),
        $html,
        sp_get_email_headers()
    );
}

/**
 * Replace merge tags in email content.
 *
 * WHY: Personalized emails improve engagement. Admins can customize email
 *      templates using simple {{tag}} syntax without knowing HTML or PHP.
 *      Tags are replaced with real member/organization data at send time.
 *
 * @param string      $content  Content with {{merge_tags}}.
 * @param object      $member   Member row (from sp_members JOIN wp_users).
 * @param array       $extra    Additional tag values (e.g., days_until_expiration).
 * @return string Content with tags replaced.
 */
function sp_replace_merge_tags( string $content, object $member, array $extra = [] ): string {
    $settings = get_option( 'societypress_settings', [] );

    // Calculate days until expiration if applicable
    $days_until = 0;
    if ( ! empty( $member->expiration_date ) ) {
        $days_until = max( 0, (int) ceil( ( strtotime( $member->expiration_date ) - time() ) / DAY_IN_SECONDS ) );
    }

    // Get tier name if tier_id is set
    $tier_name = '';
    if ( ! empty( $member->tier_id ) ) {
        global $wpdb;
        $tier_name = $wpdb->get_var( $wpdb->prepare(
            "SELECT name FROM {$wpdb->prefix}sp_membership_tiers WHERE id = %d",
            $member->tier_id
        ) ) ?: '';
    }

    // Build the tag map
    $tags = [
        '{{first_name}}'            => $member->first_name ?? '',
        '{{last_name}}'             => $member->last_name ?? '',
        '{{full_name}}'             => trim( ( $member->first_name ?? '' ) . ' ' . ( $member->last_name ?? '' ) ),
        '{{preferred_name}}'        => $member->preferred_name ?: ( $member->first_name ?? '' ),
        '{{email}}'                 => $member->user_email ?? '',
        '{{tier}}'                  => $tier_name,
        '{{status}}'                => ucfirst( $member->status ?? '' ),
        '{{join_date}}'             => ! empty( $member->join_date ) ? date_i18n( 'F j, Y', strtotime( $member->join_date ) ) : '',
        '{{expiration_date}}'       => ! empty( $member->expiration_date ) ? date_i18n( 'F j, Y', strtotime( $member->expiration_date ) ) : '',
        '{{days_until_expiration}}' => $extra['days_until_expiration'] ?? $days_until,
        '{{days}}'                  => $extra['days_until_expiration'] ?? $days_until,
        '{{organization_name}}'     => $settings['organization_name'] ?? get_bloginfo( 'name' ),
        '{{site_url}}'              => home_url(),
        '{{admin_email}}'           => $settings['organization_email'] ?? get_option( 'admin_email' ),
        '{{organization_name}}'     => $settings['organization_name'] ?? get_bloginfo( 'name' ),
    ];

    return str_replace( array_keys( $tags ), array_values( $tags ), $content );
}

/**
 * Get default email template content by type.
 *
 * WHY: Admins need a starting point — staring at an empty textarea is paralyzing.
 *      These defaults use merge tags so they work for any society out of the box.
 *      Admins can customize them from the Email settings page.
 *
 * @param string $type Template type: welcome, renewal_reminder, expired.
 * @return string HTML template content.
 */
function sp_get_default_email_template( string $type ): string {
    switch ( $type ) {
        case 'welcome':
            return '<p>Dear {{preferred_name}},</p>
<p>Welcome to {{organization_name}}! We\'re glad to have you as a member.</p>
<p><strong>Your Membership Details:</strong></p>
<ul>
    <li>Membership Level: {{tier}}</li>
    <li>Joined: {{join_date}}</li>
    <li>Expires: {{expiration_date}}</li>
</ul>
<p>If you have any questions, feel free to reach out to us at {{admin_email}}.</p>
<p>We look forward to seeing you at our events!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        case 'renewal_reminder':
            return '<p>Dear {{preferred_name}},</p>
<p>Your membership with {{organization_name}} expires on <strong>{{expiration_date}}</strong> — that\'s {{days_until_expiration}} days from now.</p>
<p>To continue enjoying your member benefits, please renew at your earliest convenience.</p>
<p><a href="{{site_url}}" style="display:inline-block; padding:12px 24px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px; font-weight:600;">Visit Our Website</a></p>
<p>Questions? Contact us at {{admin_email}}.</p>
<p>Thank you for being a valued member!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        case 'expired':
            return '<p>Dear {{preferred_name}},</p>
<p>Your membership with {{organization_name}} expired on {{expiration_date}}.</p>
<p>We\'d love to have you back! Renewing is easy — just contact us at {{admin_email}} or visit our website.</p>
<p><a href="{{site_url}}" style="display:inline-block; padding:12px 24px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px; font-weight:600;">Visit Our Website</a></p>
<p>We hope to see you again soon!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        default:
            return '';
    }
}

/**
 * Build email headers with configurable From and Reply-To.
 *
 * WHY: Societies need emails to come from their organization name and address,
 *      not "WordPress <wordpress@server>". The from_name, from_email, and
 *      reply_to are configurable in Settings > Email.
 *
 * @return array Email headers for wp_mail.
 */
function sp_get_email_headers(): array {
    $settings   = get_option( 'societypress_settings', [] );
    $from_name  = $settings['email_from_name']  ?? get_bloginfo( 'name' );
    $from_email = $settings['email_from_email'] ?? get_option( 'admin_email' );
    $reply_to   = $settings['email_reply_to']   ?? $from_email;

    return [
        'Content-Type: text/html; charset=UTF-8',
        'From: ' . $from_name . ' <' . $from_email . '>',
        'Reply-To: ' . $reply_to,
    ];
}

// Schedule daily notification cron if not already scheduled
add_action( 'init', function() {
    if ( ! wp_next_scheduled( 'sp_renewal_reminder_cron' ) ) {
        wp_schedule_event( time(), 'daily', 'sp_renewal_reminder_cron' );
    }
} );



