/**
 * Send donation acknowledgment emails for selected donation IDs.
 *
 * WHY: The treasurer needs to send thank-you emails for tax-deductible
 *      donations. This function handles the batch: builds the email from
 *      the donation record, sends via wp_mail, logs to sp_email_log,
 *      and marks the donation as acknowledged.
 *
 * @param array $donation_ids Array of donation row IDs.
 */
function sp_send_donation_acknowledgments( array $donation_ids ): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );
    $org_name = $settings['organization_name'] ?? get_bloginfo( 'name' );
    $headers  = sp_get_email_headers();

    foreach ( $donation_ids as $did ) {
        $donation = $wpdb->get_row( $wpdb->prepare(
            "SELECT d.*, c.name AS campaign_name
             FROM {$prefix}donations d
             LEFT JOIN {$prefix}campaigns c ON d.campaign_id = c.id
             WHERE d.id = %d", $did
        ) );

        if ( ! $donation || ! $donation->donor_email || $donation->acknowledgment_sent ) {
            continue; // Skip if no email or already acknowledged
        }

        $subject = 'Thank You for Your Donation — ' . $org_name;

        $body_html = '<p>Dear ' . esc_html( $donation->donor_name ) . ',</p>';
        $body_html .= '<p>Thank you for your generous donation';

        if ( $donation->type !== 'in_kind' ) {
            $body_html .= ' of <strong>$' . number_format( (float) $donation->amount, 2 ) . '</strong>';
        }

        if ( $donation->campaign_name ) {
            $body_html .= ' to our <strong>' . esc_html( $donation->campaign_name ) . '</strong> campaign';
        }

        $body_html .= ' on ' . date( 'F j, Y', strtotime( $donation->date ) ) . '.</p>';

        if ( $donation->type === 'in_kind' && $donation->in_kind_description ) {
            $body_html .= '<p>In-kind contribution: ' . esc_html( $donation->in_kind_description ) . '</p>';
        }

        $body_html .= '<p>Your support helps ' . esc_html( $org_name ) . ' continue its mission. '
                    . 'Please keep this email for your tax records.</p>';
        $body_html .= '<p>With gratitude,<br>' . esc_html( $org_name ) . '</p>';

        $full_html = sp_build_email_html( 'Donation Acknowledgment', $body_html );

        $sent = wp_mail( $donation->donor_email, $subject, $full_html, $headers );

        // Log to email log
        sp_email_log_insert(
            $donation->donor_email,
            $subject,
            $full_html,
            implode( "\n", $headers ),
            $sent ? 'sent' : 'failed',
            $sent ? null : 'wp_mail() returned false',
            $donation->user_id ? (int) $donation->user_id : null,
            'donation_acknowledgment'
        );

        // Mark as acknowledged
        if ( $sent ) {
            $wpdb->update( $prefix . 'donations', [
                'acknowledgment_sent' => 1,
                'acknowledgment_date' => current_time( 'mysql' ),
            ], [ 'id' => $did ] );
        }
    }
}


/**
 * Render the Campaigns list page.
 *
 * WHY: Campaigns organize donations around specific fundraising goals.
 *      The list shows each campaign's name, goal, amount raised, status,
 *      and date range. The raised amount is a live sum from sp_donations.
 */
function sp_render_campaigns_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_GET['action'] ) && $_GET['action'] === 'delete' && isset( $_GET['campaign_id'] ) ) {
        check_admin_referer( 'sp_delete_campaign_' . $_GET['campaign_id'] );
        // Don't delete donations — just unlink them
        $wpdb->update( $prefix . 'donations', [ 'campaign_id' => null ], [ 'campaign_id' => (int) $_GET['campaign_id'] ] );
        $wpdb->delete( $prefix . 'campaigns', [ 'id' => (int) $_GET['campaign_id'] ] );
        wp_redirect( admin_url( 'admin.php?page=sp-campaigns&deleted=1' ) );
        exit;
    }

    $campaigns = $wpdb->get_results(
        "SELECT c.*,
                u.display_name AS created_by_name,
                COALESCE((SELECT SUM(d.amount) FROM {$prefix}donations d WHERE d.campaign_id = c.id), 0) AS raised,
                (SELECT COUNT(*) FROM {$prefix}donations d WHERE d.campaign_id = c.id) AS donation_count
         FROM {$prefix}campaigns c
         LEFT JOIN {$wpdb->users} u ON c.created_by = u.ID
         ORDER BY c.status ASC, c.created_at DESC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline">Campaigns</h1>
        <a href="<?php echo admin_url( 'admin.php?page=sp-campaign-edit' ); ?>" class="page-title-action">Add New</a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p>Campaign deleted. Donations have been unlinked.</p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p>Campaign saved.</p></div>
        <?php endif; ?>

        <table class="widefat striped" style="margin-top: 16px;">
            <thead>
                <tr>
                    <th>Campaign</th>
                    <th>Goal</th>
                    <th>Raised</th>
                    <th>Progress</th>
                    <th>Status</th>
                    <th>Date Range</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $campaigns ) ) : ?>
                    <tr><td colspan="7" style="text-align: center; padding: 20px;">No campaigns yet. <a href="<?php echo admin_url( 'admin.php?page=sp-campaign-edit' ); ?>">Create one</a>.</td></tr>
                <?php else : ?>
                    <?php foreach ( $campaigns as $c ) : ?>
                        <?php
                        $raised    = (float) $c->raised;
                        $goal      = (float) ( $c->goal_amount ?? 0 );
                        $pct       = $goal > 0 ? min( 100, round( ( $raised / $goal ) * 100 ) ) : 0;
                        $bar_color = $pct >= 100 ? '#00a32a' : '#2271b1';
                        ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo admin_url( 'admin.php?page=sp-campaign-edit&campaign_id=' . $c->id ); ?>"><?php echo esc_html( $c->name ); ?></a></strong>
                                <?php if ( $c->description ) : ?>
                                    <br><span style="color: #646970; font-size: 12px;"><?php echo esc_html( wp_trim_words( $c->description, 15 ) ); ?></span>
                                <?php endif; ?>
                            </td>
                            <td><?php echo $goal > 0 ? '$' . number_format( $goal, 2 ) : '—'; ?></td>
                            <td style="font-weight: 600; color: #00a32a;">$<?php echo number_format( $raised, 2 ); ?> <span style="font-weight: normal; color: #787c82;">(<?php echo (int) $c->donation_count; ?>)</span></td>
                            <td style="width: 120px;">
                                <?php if ( $goal > 0 ) : ?>
                                    <div style="background: #e5e7eb; border-radius: 4px; height: 16px; overflow: hidden;">
                                        <div style="background: <?php echo $bar_color; ?>; height: 100%; width: <?php echo $pct; ?>%; border-radius: 4px;"></div>
                                    </div>
                                    <span style="font-size: 11px; color: #787c82;"><?php echo $pct; ?>%</span>
                                <?php else : ?>
                                    —
                                <?php endif; ?>
                            </td>
                            <td>
                                <?php
                                $status_colors = [ 'active' => '#00a32a', 'closed' => '#787c82', 'draft' => '#dba617' ];
                                $color = $status_colors[ $c->status ] ?? '#787c82';
                                printf( '<span style="color: %s; font-weight: 600;">%s</span>', esc_attr( $color ), esc_html( ucfirst( $c->status ) ) );
                                ?>
                            </td>
                            <td>
                                <?php
                                $dates = [];
                                if ( $c->start_date ) $dates[] = date_i18n( 'M j, Y', strtotime( $c->start_date ) );
                                if ( $c->end_date )   $dates[] = date_i18n( 'M j, Y', strtotime( $c->end_date ) );
                                echo $dates ? implode( ' — ', $dates ) : '—';
                                ?>
                            </td>
                            <td>
                                <a href="<?php echo admin_url( 'admin.php?page=sp-campaign-edit&campaign_id=' . $c->id ); ?>">Edit</a>
                                |
                                <a href="<?php echo admin_url( 'admin.php?page=sp-donations&campaign=' . $c->id ); ?>">Donations</a>
                                |
                                <a href="<?php echo wp_nonce_url( admin_url( 'admin.php?page=sp-campaigns&action=delete&campaign_id=' . $c->id ), 'sp_delete_campaign_' . $c->id ); ?>"
                                   onclick="return confirm('Delete this campaign? Donations will be unlinked, not deleted.');"
                                   style="color: #b32d2e;">Delete</a>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Render the Campaign edit/add page.
 *
 * WHY: Simple form for creating or editing a fundraising campaign.
 *      Name and status are required; goal, description, and dates are optional.
 */
function sp_render_campaign_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $campaign_id = (int) ( $_GET['campaign_id'] ?? 0 );
    $campaign    = null;

    if ( $campaign_id ) {
        $campaign = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}campaigns WHERE id = %d", $campaign_id
        ) );
        if ( ! $campaign ) {
            echo '<div class="wrap"><h1>Campaign Not Found</h1><p><a href="' . admin_url( 'admin.php?page=sp-campaigns' ) . '">&larr; Back</a></p></div>';
            return;
        }
    }

    // Handle save
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_campaign_nonce'] ) ) {
        check_admin_referer( 'sp_save_campaign', 'sp_campaign_nonce' );

        $name = sanitize_text_field( $_POST['name'] ?? '' );
        if ( ! $name ) {
            echo '<div class="notice notice-error"><p>Campaign name is required.</p></div>';
        } else {
            $data = [
                'name'        => $name,
                'slug'        => sanitize_title( $name ),
                'description' => sanitize_textarea_field( $_POST['description'] ?? '' ) ?: null,
                'goal_amount' => (float) ( $_POST['goal_amount'] ?? 0 ) ?: null,
                'start_date'  => sanitize_text_field( $_POST['start_date'] ?? '' ) ?: null,
                'end_date'    => sanitize_text_field( $_POST['end_date'] ?? '' ) ?: null,
                'status'      => sanitize_text_field( $_POST['campaign_status'] ?? 'active' ),
                'updated_at'  => current_time( 'mysql' ),
            ];

            if ( $campaign_id ) {
                $wpdb->update( $prefix . 'campaigns', $data, [ 'id' => $campaign_id ] );
            } else {
                $data['created_by']  = get_current_user_id();
                $data['created_at']  = current_time( 'mysql' );
                $wpdb->insert( $prefix . 'campaigns', $data );
            }

            wp_redirect( admin_url( 'admin.php?page=sp-campaigns&saved=1' ) );
            exit;
        }
    }

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php echo $campaign_id ? 'Edit Campaign' : 'Add New Campaign'; ?></h1>
        <p><a href="<?php echo admin_url( 'admin.php?page=sp-campaigns' ); ?>">&larr; Back to Campaigns</a></p>

        <form method="post" style="max-width: 600px;">
            <?php wp_nonce_field( 'sp_save_campaign', 'sp_campaign_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-c-name">Campaign Name <span style="color: #d63638;">*</span></label></th>
                    <td><input type="text" name="name" id="sp-c-name" value="<?php echo esc_attr( $campaign->name ?? '' ); ?>" required style="width: 100%;"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-desc">Description</label></th>
                    <td><textarea name="description" id="sp-c-desc" rows="4" style="width: 100%;"><?php echo esc_textarea( $campaign->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="sp-c-goal">Goal Amount</label></th>
                    <td><input type="number" name="goal_amount" id="sp-c-goal" value="<?php echo esc_attr( $campaign->goal_amount ?? '' ); ?>" step="0.01" min="0" style="width: 150px;" placeholder="0.00"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-start">Start Date</label></th>
                    <td><input type="date" name="start_date" id="sp-c-start" value="<?php echo esc_attr( $campaign->start_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-end">End Date</label></th>
                    <td><input type="date" name="end_date" id="sp-c-end" value="<?php echo esc_attr( $campaign->end_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-status">Status</label></th>
                    <td>
                        <select name="campaign_status" id="sp-c-status">
                            <option value="active" <?php selected( $campaign->status ?? 'active', 'active' ); ?>>Active</option>
                            <option value="draft" <?php selected( $campaign->status ?? '', 'draft' ); ?>>Draft</option>
                            <option value="closed" <?php selected( $campaign->status ?? '', 'closed' ); ?>>Closed</option>
                        </select>
                    </td>
                </tr>
            </table>

            <p class="submit">
                <button type="submit" class="button button-primary"><?php echo $campaign_id ? 'Save Changes' : 'Create Campaign'; ?></button>
                <a href="<?php echo admin_url( 'admin.php?page=sp-campaigns' ); ?>" class="button">Cancel</a>
            </p>
        </form>
    </div>
    <?php
}


// ============================================================================
// GDPR COMPLIANCE — PRIVACY POLICY, DATA EXPORT, DATA ERASURE
// ============================================================================
//
// WHY: SocietyPress stores personal data in custom database tables that
//      WordPress doesn't know about. Without these hooks:
//        - The Privacy Policy page has no idea we collect member data
//        - "Export Personal Data" finds nothing in our tables
//        - "Erase Personal Data" leaves our records untouched
//
//      This is a legal problem under GDPR, CCPA, and similar regulations.
//      These three hooks make SocietyPress a good citizen of the WordPress
//      privacy framework.
// ============================================================================


// --------------------------------------------------------------------------
// 1. SUGGESTED PRIVACY POLICY CONTENT
// --------------------------------------------------------------------------
//
// WHY: WordPress's Privacy page has a "Policy Guide" tab where plugins can
//      contribute suggested text. Harold can copy it into his Privacy Policy
//      page — or adapt it. This saves him from having to figure out what
//      data we collect and how to describe it. We register it once; WordPress
//      shows it on wp-admin/privacy-policy-guide.php.
// --------------------------------------------------------------------------

add_action( 'admin_init', function () {
    $content = <<<'POLICY'
<h2>Membership Data</h2>
<p>When you register as a member, we collect your name, email address, mailing address, phone number, and optional information such as date of birth, maiden name, and preferred name. This data is stored in our membership database and is used to manage your membership, communicate with you about society activities, and (if you opt in) display your information in the member directory.</p>
<p>You can control which personal details appear in the member directory through your profile settings. You can request a full export or deletion of your membership data at any time by contacting us.</p>

<h2>Event Registration</h2>
<p>When you register for an event, we collect your name, email address, and optionally your phone number. If you register as a guest (non-member), this information is stored separately from our membership database. We use it to manage event attendance, send confirmation and reminder emails, and track capacity.</p>
<p>Registration data is retained for historical and reporting purposes. You can request deletion of your registration history by contacting us.</p>

<h2>Payments</h2>
<p>For paid events, we offer online payment through Stripe. When you pay online, your payment is processed entirely by Stripe — we never see, store, or have access to your credit card number. We do store a record of the transaction amount, date, and Stripe reference ID for bookkeeping purposes.</p>
<p>For more information about how Stripe handles your payment data, please see <a href="https://stripe.com/privacy" target="_blank">Stripe's Privacy Policy</a>.</p>

<h2>Contact Form Submissions</h2>
<p>If you use a contact form on this site, the information you submit (name, email, message) is sent via email to our organization and is not stored in a database.</p>

<h2>Cookies</h2>
<p>This site uses standard cookies for login sessions and site preferences. We do not use tracking cookies, advertising cookies, or third-party analytics cookies beyond what the underlying platform provides.</p>

<h2>Data Retention</h2>
<p>Membership records are retained for the duration of your membership and for a reasonable period afterward for administrative continuity. Event registration records are retained indefinitely for historical reporting. You may request deletion at any time.</p>
POLICY;

    wp_add_privacy_policy_content(
        'SocietyPress',
        wp_kses_post( $content )
    );
} );


// --------------------------------------------------------------------------
// 2. PERSONAL DATA EXPORTER
// --------------------------------------------------------------------------
//
// WHY: Under Tools > Export Personal Data, WordPress lets an admin fulfill
//      "give me all my data" requests. But it only knows about wp_users and
//      wp_comments. We need to register exporters that find personal data in
//      our custom tables (sp_members, sp_event_registrations, sp_event_speakers)
//      and include it in the export ZIP.
//
//      The exporter receives an email address and returns structured data.
//      WordPress handles the rest — packaging it into a nice HTML/JSON export.
// --------------------------------------------------------------------------

add_filter( 'wp_privacy_personal_data_exporters', function ( $exporters ) {

    // Membership data exporter
    $exporters['societypress-members'] = [
        'exporter_friendly_name' => 'SocietyPress Membership Data',
        'callback'               => 'sp_privacy_export_member_data',
    ];

    // Event registration exporter
    $exporters['societypress-registrations'] = [
        'exporter_friendly_name' => 'SocietyPress Event Registrations',
        'callback'               => 'sp_privacy_export_registration_data',
    ];

    // Speaker data exporter (in case a speaker requests their data)
    $exporters['societypress-speakers'] = [
        'exporter_friendly_name' => 'SocietyPress Speaker Profile',
        'callback'               => 'sp_privacy_export_speaker_data',
    ];

    // Volunteer data exporter
    $exporters['societypress-volunteers'] = [
        'exporter_friendly_name' => 'SocietyPress Volunteer Data',
        'callback'               => 'sp_privacy_export_volunteer_data',
    ];

    // Help requests exporter
    $exporters['societypress-help-requests'] = [
        'exporter_friendly_name' => 'SocietyPress Help Requests',
        'callback'               => 'sp_privacy_export_help_data',
    ];

    return $exporters;
} );


/**
 * Export membership data for a given email address.
 *
 * WHY: The sp_members table is keyed by user_id, not email. So we look up
 *      the WordPress user by email first, then find their member record.
 */
function sp_privacy_export_member_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_members WHERE user_id = %d",
        $user->ID
    ) );

    if ( ! $member ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    // Build the export data array — every personal field we store
    $data = [
        [ 'name' => 'Member Type',      'value' => ucfirst( $member->member_type ?? 'individual' ) ],
        [ 'name' => 'Organization Name','value' => $member->organization_name ?: '(none)' ],
        [ 'name' => 'Member Number',    'value' => $member->member_number ?: '(none)' ],
        [ 'name' => 'Status',           'value' => ucfirst( $member->status ) ],
        [ 'name' => 'Name',             'value' => trim( $member->prefix . ' ' . $member->first_name . ' ' . $member->middle_name . ' ' . $member->last_name . ' ' . $member->suffix ) ],
        [ 'name' => 'Preferred Name',   'value' => $member->preferred_name ?: '(none)' ],
        [ 'name' => 'Maiden Name',      'value' => $member->maiden_name ?: '(none)' ],
        [ 'name' => 'Date of Birth',    'value' => $member->date_of_birth ?: '(not provided)' ],
        [ 'name' => 'Join Date',        'value' => $member->join_date ],
        [ 'name' => 'Expiration Date',  'value' => $member->expiration_date ?: '(none)' ],
        [ 'name' => 'Address',          'value' => implode( ', ', array_filter( [
            $member->address_1, $member->address_2, $member->city,
            $member->state, $member->postal_code, $member->country,
        ] ) ) ?: '(none)' ],
        [ 'name' => 'Phone',            'value' => $member->phone ?: '(none)' ],
        [ 'name' => 'Cell',             'value' => $member->cell ?: '(none)' ],
        [ 'name' => 'Website',          'value' => $member->website ?: '(none)' ],
    ];

    // Include seasonal address if they have one
    if ( $member->seasonal ) {
        $data[] = [ 'name' => 'Seasonal Address', 'value' => implode( ', ', array_filter( [
            $member->seasonal_address_1, $member->seasonal_city,
            $member->seasonal_state, $member->seasonal_postal_code, $member->seasonal_country,
        ] ) ) ];
        $data[] = [ 'name' => 'Seasonal Period', 'value' => ( $member->seasonal_from ?: '?' ) . ' to ' . ( $member->seasonal_to ?: '?' ) ];
    }

    // Communication preferences
    $prefs = [];
    if ( $member->pref_email_notices )      $prefs[] = 'General Notices';
    if ( $member->pref_email_events )       $prefs[] = 'Events';
    if ( $member->pref_email_newsletters )  $prefs[] = 'Newsletters';
    if ( $member->pref_email_surnames )     $prefs[] = 'Surname Alerts';
    $data[] = [ 'name' => 'Email Preferences', 'value' => $prefs ? implode( ', ', $prefs ) : '(all disabled)' ];

    // Directory visibility settings
    $dir = [];
    if ( $member->dir_show_name )    $dir[] = 'Name';
    if ( $member->dir_show_address ) $dir[] = 'Address';
    if ( $member->dir_show_phone )   $dir[] = 'Phone';
    if ( $member->dir_show_email )   $dir[] = 'Email';
    if ( $member->dir_show_website ) $dir[] = 'Website';
    if ( $member->dir_show_photo )   $dir[] = 'Photo';
    $data[] = [ 'name' => 'Directory Visibility', 'value' => $dir ? implode( ', ', $dir ) : '(all hidden)' ];

    $export_items[] = [
        'group_id'          => 'societypress-member',
        'group_label'       => 'Membership Profile',
        'group_description' => 'Your membership information stored by this site.',
        'item_id'           => 'member-' . $member->user_id,
        'data'              => $data,
    ];

    return [ 'data' => $export_items, 'done' => true ];
}


/**
 * Export event registration data for a given email address.
 *
 * WHY: Registrations can be tied to a user_id (members) or a guest_email
 *      (non-members). We check both — the same email might appear in both
 *      contexts if someone registered as a guest before becoming a member.
 */
function sp_privacy_export_registration_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';
    $evt_table    = $wpdb->prefix . 'sp_events';

    // Find registrations by user email (member) OR guest email
    $user = get_user_by( 'email', $email_address );
    $user_id = $user ? $user->ID : 0;

    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, e.title AS event_title, e.event_date
         FROM {$reg_table} r
         LEFT JOIN {$evt_table} e ON r.event_id = e.id
         WHERE r.user_id = %d OR r.guest_email = %s
         ORDER BY r.registered_at DESC",
        $user_id, $email_address
    ) );

    foreach ( $registrations as $reg ) {
        $data = [
            [ 'name' => 'Event',            'value' => $reg->event_title ?: '(deleted event)' ],
            [ 'name' => 'Event Date',       'value' => $reg->event_date ?: '(unknown)' ],
            [ 'name' => 'Registration Type', 'value' => $reg->user_id ? 'Member' : 'Guest' ],
            [ 'name' => 'Status',           'value' => ucfirst( $reg->status ) ],
            [ 'name' => 'Party Size',       'value' => (string) $reg->party_size ],
            [ 'name' => 'Fee',              'value' => $reg->fee_amount > 0 ? '$' . number_format( $reg->fee_amount, 2 ) : 'Free' ],
            [ 'name' => 'Payment Status',   'value' => ucfirst( $reg->payment_status ) ],
            [ 'name' => 'Registered At',    'value' => $reg->registered_at ],
        ];

        // Include guest fields if this was a guest registration
        if ( ! $reg->user_id ) {
            $data[] = [ 'name' => 'Guest Name',  'value' => $reg->guest_name ?: '' ];
            $data[] = [ 'name' => 'Guest Email', 'value' => $reg->guest_email ?: '' ];
            $data[] = [ 'name' => 'Guest Phone', 'value' => $reg->guest_phone ?: '' ];
        }

        $export_items[] = [
            'group_id'          => 'societypress-registrations',
            'group_label'       => 'Event Registrations',
            'group_description' => 'Your event registration history on this site.',
            'item_id'           => 'registration-' . $reg->id,
            'data'              => $data,
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}


/**
 * Export speaker profile data for a given email address.
 *
 * WHY: If someone is listed as a speaker and requests their data, we need to
 *      include their speaker profile (name, bio, email, phone, website).
 */
function sp_privacy_export_speaker_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];

    $speaker = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_event_speakers WHERE email = %s",
        $email_address
    ) );

    if ( ! $speaker ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    $data = [
        [ 'name' => 'Name',    'value' => $speaker->name ],
        [ 'name' => 'Title',   'value' => $speaker->title ?: '(none)' ],
        [ 'name' => 'Bio',     'value' => $speaker->bio ?: '(none)' ],
        [ 'name' => 'Email',   'value' => $speaker->email ?: '(none)' ],
        [ 'name' => 'Phone',   'value' => $speaker->phone ?: '(none)' ],
        [ 'name' => 'Website', 'value' => $speaker->website ?: '(none)' ],
    ];

    $export_items[] = [
        'group_id'          => 'societypress-speakers',
        'group_label'       => 'Speaker Profile',
        'group_description' => 'Your speaker profile stored by this site.',
        'item_id'           => 'speaker-' . $speaker->id,
        'data'              => $data,
    ];

    return [ 'data' => $export_items, 'done' => true ];
}


// --------------------------------------------------------------------------
// 3. PERSONAL DATA ERASER
// --------------------------------------------------------------------------
//
// WHY: Under Tools > Erase Personal Data, WordPress lets an admin fulfill
//      "delete my data" requests (right to be forgotten). We register erasers
//      that remove or anonymize personal data in our custom tables.
//
//      For members: We remove the member record entirely (they can re-join).
//      For registrations: We anonymize guest fields but keep the record for
//        event capacity/financial reporting (replace name with "Deleted User",
//        clear email, phone, and notes).
//      For speakers: We anonymize the speaker record but keep the link to
//        events for historical accuracy.
// --------------------------------------------------------------------------

add_filter( 'wp_privacy_personal_data_erasers', function ( $erasers ) {

    $erasers['societypress-members'] = [
        'eraser_friendly_name' => 'SocietyPress Membership Data',
        'callback'             => 'sp_privacy_erase_member_data',
    ];

    $erasers['societypress-registrations'] = [
        'eraser_friendly_name' => 'SocietyPress Event Registrations',
        'callback'             => 'sp_privacy_erase_registration_data',
    ];

    $erasers['societypress-speakers'] = [
        'eraser_friendly_name' => 'SocietyPress Speaker Profile',
        'callback'             => 'sp_privacy_erase_speaker_data',
    ];

    // Volunteer data eraser
    $erasers['societypress-volunteers'] = [
        'eraser_friendly_name' => 'SocietyPress Volunteer Data',
        'callback'             => 'sp_privacy_erase_volunteer_data',
    ];

    // Help requests eraser
    $erasers['societypress-help-requests'] = [
        'eraser_friendly_name' => 'SocietyPress Help Requests',
        'callback'             => 'sp_privacy_erase_help_data',
    ];

    return $erasers;
} );


/**
 * Erase membership data for a given email address.
 *
 * WHY: When someone exercises their right to be forgotten, we delete their
 *      member record entirely. The WordPress user account is handled by core;
 *      we just clean up our custom table.
 */
function sp_privacy_erase_member_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( $user ) {
        $deleted = $wpdb->delete(
            $wpdb->prefix . 'sp_members',
            [ 'user_id' => $user->ID ],
            [ '%d' ]
        );
        if ( $deleted ) {
            $items_removed = 1;
        }
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed ? [ 'Membership profile deleted.' ] : [],
        'done'           => true,
    ];
}


/**
 * Erase (anonymize) event registration data for a given email address.
 *
 * WHY: We can't just delete registration rows because the society needs them
 *      for financial reporting (who paid what) and capacity history. Instead,
 *      we anonymize: replace the name with "Deleted User," clear the email,
 *      phone, and notes. The registration record stays but is no longer tied
 *      to an identifiable person.
 */
function sp_privacy_erase_registration_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $reg_table      = $wpdb->prefix . 'sp_event_registrations';
    $items_removed  = 0;
    $items_retained = 0;

    // Anonymize guest registrations (matched by guest_email)
    $guest_regs = $wpdb->get_results( $wpdb->prepare(
        "SELECT id FROM {$reg_table} WHERE guest_email = %s",
        $email_address
    ) );

    foreach ( $guest_regs as $reg ) {
        $wpdb->update(
            $reg_table,
            [
                'guest_name'  => 'Deleted User',
                'guest_email' => '',
                'guest_phone' => '',
                'notes'       => '',
            ],
            [ 'id' => $reg->id ]
        );
        $items_removed++;
    }

    // Anonymize member registrations (matched by user_id via email lookup)
    $user = get_user_by( 'email', $email_address );
    if ( $user ) {
        $member_regs = $wpdb->get_results( $wpdb->prepare(
            "SELECT id FROM {$reg_table} WHERE user_id = %d",
            $user->ID
        ) );

        foreach ( $member_regs as $reg ) {
            $wpdb->update(
                $reg_table,
                [
                    'user_id' => null,
                    'notes'   => '',
                ],
                [ 'id' => $reg->id ]
            );
            $items_removed++;
        }
    }

    // The registration rows themselves are retained for financial records
    if ( $items_removed > 0 ) {
        $items_retained = $items_removed;
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => $items_retained,
        'messages'       => $items_removed
            ? [ sprintf( '%d registration(s) anonymized. Records retained for financial reporting.', $items_removed ) ]
            : [],
        'done'           => true,
    ];
}


/**
 * Erase (anonymize) speaker data for a given email address.
 *
 * WHY: A speaker might request deletion. We anonymize their profile (clear
 *      bio, email, phone, website) but keep the name and event assignments
 *      so the society's event history still makes sense. If they want the
 *      name removed too, the admin can manually edit the speaker record.
 */
function sp_privacy_erase_speaker_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $items_removed = 0;

    $speaker = $wpdb->get_row( $wpdb->prepare(
        "SELECT id FROM {$wpdb->prefix}sp_event_speakers WHERE email = %s",
        $email_address
    ) );

    if ( $speaker ) {
        $wpdb->update(
            $wpdb->prefix . 'sp_event_speakers',
            [
                'bio'     => '',
                'email'   => '',
                'phone'   => '',
                'website' => '',
            ],
            [ 'id' => $speaker->id ]
        );
        $items_removed = 1;
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => $items_removed ? 1 : 0,
        'messages'       => $items_removed
            ? [ 'Speaker profile anonymized. Name and event assignments retained for historical records.' ]
            : [],
        'done'           => true,
    ];
}


/**
 * Export volunteer data for GDPR requests.
 *
 * WHY: Volunteer hours and role assignments are personal data — they show
 *      what someone did, when, and for how long. Must be exportable.
 */
function sp_privacy_export_volunteer_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'data' => $export_items, 'done' => true ];

    // Volunteer roles
    $roles = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}volunteer_roles WHERE user_id = %d", $user->ID
    ) );
    foreach ( $roles as $role ) {
        $export_items[] = [
            'group_id'    => 'sp-volunteer-roles',
            'group_label' => 'Volunteer Roles',
            'item_id'     => 'sp-volunteer-role-' . $role->id,
            'data'        => [
                [ 'name' => 'Role', 'value' => $role->role_title ],
                [ 'name' => 'Committee', 'value' => $role->committee ?: '(none)' ],
                [ 'name' => 'Start Date', 'value' => $role->start_date ?: '(none)' ],
                [ 'name' => 'End Date', 'value' => $role->end_date ?: 'Ongoing' ],
                [ 'name' => 'Status', 'value' => ucfirst( $role->status ) ],
            ],
        ];
    }

    // Volunteer hours
    $hours = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}volunteer_hours WHERE user_id = %d ORDER BY activity_date DESC", $user->ID
    ) );
    foreach ( $hours as $entry ) {
        $export_items[] = [
            'group_id'    => 'sp-volunteer-hours',
            'group_label' => 'Volunteer Hours',
            'item_id'     => 'sp-volunteer-hour-' . $entry->id,
            'data'        => [
                [ 'name' => 'Activity', 'value' => $entry->activity ?: '(none)' ],
                [ 'name' => 'Committee', 'value' => $entry->committee ?: '(none)' ],
                [ 'name' => 'Hours', 'value' => $entry->hours ],
                [ 'name' => 'Date', 'value' => $entry->activity_date ],
            ],
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}

/**
 * Export help request data for GDPR requests.
 */
function sp_privacy_export_help_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'data' => $export_items, 'done' => true ];

    // Questions asked
    $requests = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}help_requests WHERE user_id = %d", $user->ID
    ) );
    foreach ( $requests as $req ) {
        $export_items[] = [
            'group_id'    => 'sp-help-requests',
            'group_label' => 'Research Help Requests',
            'item_id'     => 'sp-help-request-' . $req->id,
            'data'        => [
                [ 'name' => 'Title', 'value' => $req->title ],
                [ 'name' => 'Description', 'value' => $req->description ],
                [ 'name' => 'Status', 'value' => ucfirst( $req->status ) ],
                [ 'name' => 'Date', 'value' => $req->created_at ],
            ],
        ];
    }

    // Responses given
    $responses = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}help_responses WHERE user_id = %d", $user->ID
    ) );
    foreach ( $responses as $resp ) {
        $export_items[] = [
            'group_id'    => 'sp-help-responses',
            'group_label' => 'Research Help Responses',
            'item_id'     => 'sp-help-response-' . $resp->id,
            'data'        => [
                [ 'name' => 'Content', 'value' => $resp->content ],
                [ 'name' => 'Date', 'value' => $resp->created_at ],
            ],
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}

/**
 * Erase volunteer data for GDPR requests.
 */
function sp_privacy_erase_volunteer_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'items_removed' => 0, 'items_retained' => 0, 'messages' => [], 'done' => true ];

    $items_removed += (int) $wpdb->delete( $prefix . 'volunteer_roles', [ 'user_id' => $user->ID ] );
    $items_removed += (int) $wpdb->delete( $prefix . 'volunteer_hours', [ 'user_id' => $user->ID ] );

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed > 0 ? [ 'Volunteer roles and hours deleted.' ] : [],
        'done'           => true,
    ];
}

/**
 * Erase help request data for GDPR requests.
 */
function sp_privacy_erase_help_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'items_removed' => 0, 'items_retained' => 0, 'messages' => [], 'done' => true ];

    // Delete responses first (FK integrity)
    $request_ids = $wpdb->get_col( $wpdb->prepare(
        "SELECT id FROM {$prefix}help_requests WHERE user_id = %d", $user->ID
    ) );
    if ( ! empty( $request_ids ) ) {
        $placeholders = implode( ',', array_fill( 0, count( $request_ids ), '%d' ) );
        $wpdb->query( $wpdb->prepare(
            "DELETE FROM {$prefix}help_responses WHERE request_id IN ({$placeholders})", ...$request_ids
        ) );
    }
    $items_removed += (int) $wpdb->delete( $prefix . 'help_requests', [ 'user_id' => $user->ID ] );
    $items_removed += (int) $wpdb->delete( $prefix . 'help_responses', [ 'user_id' => $user->ID ] );

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed > 0 ? [ 'Research help requests and responses deleted.' ] : [],
        'done'           => true,
    ];
}

// ============================================================================
// AJAX: Library Item Detail (frontend expandable row)
//
// WHY: When a member clicks an item in the catalog, we fetch the full record
//      via AJAX and slide open a detail panel below the row — no page reload,
//      no separate URL. Keeps the user in context of their search results.
//      Accessible to logged-in users (wp_ajax_) only, matching catalog access.
// ============================================================================
add_action( 'wp_ajax_sp_library_item_detail', 'sp_ajax_library_item_detail' );
function sp_ajax_library_item_detail(): void {
    $item_id = absint( $_GET['item_id'] ?? 0 );
    if ( ! $item_id ) {
        wp_send_json_error( 'Missing item ID.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $item = $wpdb->get_row( $wpdb->prepare(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE li.id = %d",
        $item_id
    ) );

    if ( ! $item ) {
        wp_send_json_error( 'Item not found.' );
    }

    // Build a clean publication date string from year/month/day parts
    $pub_date = '';
    if ( $item->pub_year ) {
        $pub_date = (string) $item->pub_year;
        if ( $item->pub_month ) {
            $pub_date = $item->pub_month . '/' . $pub_date;
            if ( $item->pub_day ) {
                $pub_date = $item->pub_day . '/' . $pub_date;
            }
        }
    }

    // Build acquisition date
    $acq_date = '';
    if ( $item->acq_year ) {
        $acq_date = (string) $item->acq_year;
        if ( $item->acq_month ) {
            $acq_date = $item->acq_month . '/' . $acq_date;
            if ( $item->acq_day ) {
                $acq_date = $item->acq_day . '/' . $acq_date;
            }
        }
    }

    // Parse subject field into array of individual tags
    $subjects = [];
    if ( $item->subject ) {
        $subjects = array_map( 'trim', explode( ',', $item->subject ) );
        $subjects = array_filter( $subjects );
        $subjects = array_values( $subjects );
    }

    // Parse surnames similarly
    $surnames = [];
    if ( $item->surname ) {
        $surnames = array_map( 'trim', explode( ',', $item->surname ) );
        $surnames = array_filter( $surnames );
        $surnames = array_values( $surnames );
    }

    wp_send_json_success( [
        'id'                  => $item->id,
        'system_id'           => $item->system_id,
        'title'               => $item->title,
        'author'              => $item->author ?: '',
        'description'         => $item->description ?: '',
        'publisher'           => $item->publisher ?: '',
        'publisher_location'  => $item->publisher_location ?: '',
        'pub_date'            => $pub_date,
        'pub_year'            => $item->pub_year ?: '',
        'media_type'          => $item->media_type ?: '',
        'isbn'                => $item->isbn ?: '',
        'call_number'         => $item->call_number ?: '',
        'lccn'                => $item->lccn ?: '',
        'category_name'       => $item->category_name ?: '',
        'shelf_location'      => $item->shelf_location ?: '',
        'geographic_location' => $item->geographic_location ?: '',
        'county'              => $item->county ?: '',
        'state'               => $item->state ?: '',
        'subjects'            => $subjects,
        'surnames'            => $surnames,
        'acq_code'            => $item->acq_code ?: '',
        'acq_date'            => $acq_date,
        'donor'               => $item->donor ?: '',
        'item_value'          => $item->item_value ? '$' . number_format( (float) $item->item_value, 2 ) : '',
        'item_condition'      => $item->item_condition ?: '',
        'available'           => (bool) $item->available,
        'librarian_notes'     => $item->librarian_notes ?: '',
        'acquisition_number'  => $item->acquisition_number ?: '',
    ] );
}

// ============================================================================
// AJAX: CSV Export of Library Catalog (admin)
//
// WHY: Admins need to export their catalog for backup, sharing with other
//      societies, or migration. This mirrors the import field mapping so
//      a CSV exported here can be re-imported cleanly.
// ============================================================================
add_action( 'wp_ajax_sp_export_library', 'sp_ajax_export_library' );
function sp_ajax_export_library(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'Unauthorized.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Apply same filters the admin catalog page uses, so "export what you see"
    $where = [ '1=1' ];
    $search = isset( $_GET['s'] ) ? sanitize_text_field( $_GET['s'] ) : '';
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare(
            '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s)',
            $like, $like, $like, $like, $like
        );
    }
    $media_filter = isset( $_GET['media_type'] ) ? sanitize_text_field( $_GET['media_type'] ) : '';
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    $shelf_filter = isset( $_GET['shelf'] ) ? sanitize_text_field( $_GET['shelf'] ) : '';
    if ( $shelf_filter ) {
        $where[] = $wpdb->prepare( 'li.shelf_location = %s', $shelf_filter );
    }
    $acq_filter = isset( $_GET['acq_code'] ) ? sanitize_text_field( $_GET['acq_code'] ) : '';
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    $items = $wpdb->get_results(
        "SELECT li.* FROM {$prefix}library_items li WHERE {$where_sql} ORDER BY li.title ASC"
    );

    // CSV headers match the import target fields
    $headers = [
        'System ID', 'Title', 'Author', 'Description', 'Publisher',
        'Publisher Location', 'Pub. Year', 'Pub. Month', 'Pub. Day',
        'Media Type', 'Use Serials', 'ISBN', 'Call Number', 'LCCN',
        'Shelf Location', 'Geographic Location', 'Acquisition Number',
        'Acq. Year', 'Acq. Month', 'Acq. Day', 'Acq. Code', 'Donor',
        'Value', 'County', 'State', 'Surname', 'Subject',
        'Librarian Notes', 'Updated By', 'Last Updated Date',
        'Condition', 'Available',
    ];

    $filename = 'library-catalog-' . gmdate( 'Y-m-d' ) . '.csv';

    // Stream CSV output directly — no buffering the whole result set
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );
    // BOM for Excel UTF-8 compatibility
    fwrite( $out, "\xEF\xBB\xBF" );
    fputcsv( $out, $headers );

    foreach ( $items as $item ) {
        fputcsv( $out, [
            $item->system_id,
            $item->title,
            $item->author,
            $item->description,
            $item->publisher,
            $item->publisher_location,
            $item->pub_year,
            $item->pub_month,
            $item->pub_day,
            $item->media_type,
            $item->use_serials,
            $item->isbn,
            $item->call_number,
            $item->lccn,
            $item->shelf_location,
            $item->geographic_location,
            $item->acquisition_number,
            $item->acq_year,
            $item->acq_month,
            $item->acq_day,
            $item->acq_code,
            $item->donor,
            $item->item_value,
            $item->county,
            $item->state,
            $item->surname,
            $item->subject,
            $item->librarian_notes,
            $item->updated_by,
            $item->last_updated_date,
            $item->item_condition,
            $item->available,
        ] );
    }

    fclose( $out );
    exit;
}


// ============================================================================
// NEWSLETTER ARCHIVE
//
// WHY: Societies produce regular newsletters (monthly, quarterly, etc.) and
//      members expect to find an archive of past issues. Admins upload PDFs,
//      the system auto-generates a cover thumbnail from page 1, and members
//      can browse, preview in an inline viewer, and download. Non-members
//      can see the archive grid (for marketing value) but cannot open or
//      download the actual files.
// ============================================================================


/**
 * Render: Newsletter Archive Admin Page (Card Grid)
 *
 * WHY: Card grid matches the Gallery pattern — newsletters are visual items
 *      (cover thumbnails) so a card layout is more intuitive than a table.
 *      Shows cover image, title, date, volume/issue, visibility badge, and
 *      Edit/Delete action links. Sorted newest-first by publication date.
 */
function sp_render_newsletter_archive_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ========== HANDLE DELETE ==========
    if ( ( $_GET['action'] ?? '' ) === 'delete' && ! empty( $_GET['newsletter_id'] ) ) {
        $newsletter_id = absint( $_GET['newsletter_id'] );
        check_admin_referer( 'sp_delete_newsletter_' . $newsletter_id );
        $wpdb->delete( $prefix . 'newsletters', [ 'id' => $newsletter_id ] );
        echo '<div class="notice notice-success"><p>Newsletter deleted.</p></div>';
    }

    // ========== SEARCH FILTER ==========
    $search = sanitize_text_field( $_GET['s'] ?? '' );

    // ========== FETCH NEWSLETTERS ==========
    $sql = "SELECT * FROM {$prefix}newsletters";
    if ( $search ) {
        $sql .= $wpdb->prepare( " WHERE title LIKE %s", '%' . $wpdb->esc_like( $search ) . '%' );
    }
    $sql .= " ORDER BY pub_date DESC, created_at DESC";

    $newsletters = $wpdb->get_results( $sql );
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline">Newsletter Archive</h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>" class="page-title-action">Add New</a>
        <hr class="wp-header-end">

        <!-- Search bar -->
        <form method="get" style="margin:16px 0;">
            <input type="hidden" name="page" value="sp-newsletter-archive">
            <p class="search-box">
                <input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="Search newsletters…">
                <input type="submit" class="button" value="Search">
                <?php if ( $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>" class="button">Clear</a>
                <?php endif; ?>
            </p>
        </form>

        <?php if ( empty( $newsletters ) ) : ?>
            <p>No newsletters yet. <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>">Upload your first newsletter</a>.</p>
        <?php else : ?>
            <div style="display:flex; flex-wrap:wrap; gap:20px; margin-top:20px;">
                <?php foreach ( $newsletters as $nl ) :
                    // Cover thumbnail — use auto-generated cover, fall back to placeholder
                    $cover_url = $nl->cover_image_id
                        ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' )
                        : '';

                    $edit_url   = admin_url( 'admin.php?page=sp-newsletter-edit&newsletter_id=' . $nl->id );
                    $delete_url = wp_nonce_url(
                        admin_url( 'admin.php?page=sp-newsletter-archive&action=delete&newsletter_id=' . $nl->id ),
                        'sp_delete_newsletter_' . $nl->id
                    );

                    // Format the volume/issue line (e.g. "Vol. 3, No. 2")
                    $vol_issue = '';
                    if ( $nl->volume )       $vol_issue .= 'Vol.&nbsp;' . $nl->volume;
                    if ( $nl->issue_number ) $vol_issue .= ( $vol_issue ? ', ' : '' ) . 'No.&nbsp;' . $nl->issue_number;

                    // Format the publication date
                    $date_display = $nl->pub_date ? date( 'M j, Y', strtotime( $nl->pub_date ) ) : '';
                ?>
                    <div style="width:220px; background:#fff; border:1px solid #ccd0d4; border-radius:8px; overflow:hidden;">
                        <!-- Cover image area -->
                        <a href="<?php echo esc_url( $edit_url ); ?>" style="display:block;">
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" alt="" style="width:100%; height:280px; object-fit:cover;">
                            <?php else : ?>
                                <div style="width:100%; height:280px; background:#f0f0f0; display:flex; align-items:center; justify-content:center;">
                                    <span class="dashicons dashicons-media-document" style="font-size:48px; width:48px; height:48px; color:#ccc;"></span>
                                </div>
                            <?php endif; ?>
                        </a>
                        <!-- Card body -->
                        <div style="padding:12px;">
                            <h4 style="margin:0 0 4px;">
                                <a href="<?php echo esc_url( $edit_url ); ?>" style="text-decoration:none; color:#1d2327;">
                                    <?php echo esc_html( $nl->title ); ?>
                                </a>
                            </h4>
                            <?php if ( $date_display ) : ?>
                                <span style="color:#666; font-size:12px;"><?php echo $date_display; ?></span><br>
                            <?php endif; ?>
                            <?php if ( $vol_issue ) : ?>
                                <span style="color:#666; font-size:12px;"><?php echo $vol_issue; ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'members_only' ) : ?>
                                <span style="background:#fef0c7; color:#92400e; font-size:10px; padding:2px 6px; border-radius:3px; margin-left:4px;">Members Only</span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'public' ) : ?>
                                <span style="background:#d1fae5; color:#065f46; font-size:10px; padding:2px 6px; border-radius:3px; margin-left:4px;">Public</span>
                            <?php endif; ?>
                            <div style="margin-top:8px; font-size:12px;">
                                <a href="<?php echo esc_url( $edit_url ); ?>">Edit</a> |
                                <a href="<?php echo esc_url( $delete_url ); ?>" style="color:#b32d2e;" onclick="return confirm('Delete this newsletter?');">Delete</a>
                            </div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>
    </div>
    <?php
}
// WHY: Newsletter save must happen on admin_init (before any output) because
// wp_redirect() requires headers not yet sent. The page render callback fires
// after admin_head has already output CSS, so redirect would silently fail.
add_action( 'admin_init', function () {
    // Only run on the newsletter edit page when the save button was clicked.
    if ( ! isset( $_POST['sp_save_newsletter'] ) ) return;
    if ( ( $_GET['page'] ?? '' ) !== 'sp-newsletter-edit' ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;

    check_admin_referer( 'sp_newsletter_save' );

    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );

    $data = [
        'title'          => sanitize_text_field( $_POST['title'] ?? '' ),
        'slug'           => sanitize_title( $_POST['title'] ?? '' ),
        'description'    => sanitize_textarea_field( $_POST['description'] ?? '' ),
        'pub_date'       => sanitize_text_field( $_POST['pub_date'] ?? '' ) ?: null,
        'volume'         => absint( $_POST['volume'] ?? 0 ) ?: null,
        'issue_number'   => absint( $_POST['issue_number'] ?? 0 ) ?: null,
        'file_id'        => absint( $_POST['file_id'] ?? 0 ) ?: null,
        'cover_image_id' => absint( $_POST['cover_image_id'] ?? 0 ) ?: null,
        'visibility'     => sanitize_text_field( $_POST['visibility'] ?? 'members_only' ),
    ];

    if ( $newsletter_id ) {
        $wpdb->update( $prefix . 'newsletters', $data, [ 'id' => $newsletter_id ] );
    } else {
        $data['created_by'] = get_current_user_id();
        $wpdb->insert( $prefix . 'newsletters', $data );
    }

    wp_redirect( admin_url( 'admin.php?page=sp-newsletter-archive&sp_notice=newsletter_saved' ) );
    exit;
} );



/**
 * Render: Newsletter Edit Page (Add / Edit)
 *
 * WHY: Single form handles both creation and editing. Uses the WordPress
 *      media library picker for PDF upload. On PDF selection, fires an AJAX
 *      request to auto-generate a cover thumbnail from the first page using
 *      Imagick. If Imagick isn't available or fails, admin can manually pick
 *      a cover image. The wp.media picker is deferred to window.load to
 *      avoid conflicts with other media-related scripts.
 */
function sp_render_newsletter_edit_page(): void {
    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );

    // ========== LOAD DATA ==========
    $nl = $newsletter_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}newsletters WHERE id = %d", $newsletter_id
    ) ) : null;

    // Get existing attachment URLs for display
    $pdf_url   = ( $nl && $nl->file_id )        ? wp_get_attachment_url( $nl->file_id )                        : '';
    $pdf_name  = ( $nl && $nl->file_id )        ? basename( get_attached_file( $nl->file_id ) )               : '';
    $cover_url = ( $nl && $nl->cover_image_id ) ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' ) : '';

    // WordPress media uploader needs this
    wp_enqueue_media();
    ?>
    <div class="wrap">
        <h1><?php echo $nl ? 'Edit Newsletter' : 'Add New Newsletter'; ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>">&larr; Back to Newsletter Archive</a>

        <form method="post" style="margin-top:20px;">
            <?php wp_nonce_field( 'sp_newsletter_save' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="title">Title</label></th>
                    <td><input type="text" name="title" id="title" class="regular-text" value="<?php echo esc_attr( $nl->title ?? '' ); ?>" required></td>
                </tr>
                <tr>
                    <th><label for="description">Description</label></th>
                    <td><textarea name="description" id="description" rows="3" class="large-text"><?php echo esc_textarea( $nl->description ?? '' ); ?></textarea>
                    <p class="description">Optional summary shown on the frontend archive.</p></td>
                </tr>
                <tr>
                    <th><label for="pub_date">Publication Date</label></th>
                    <td><input type="date" name="pub_date" id="pub_date" value="<?php echo esc_attr( $nl->pub_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th>Volume &amp; Issue</th>
                    <td>
                        <label for="volume" style="margin-right:8px;">Vol.</label>
                        <input type="number" name="volume" id="volume" value="<?php echo esc_attr( $nl->volume ?? '' ); ?>" min="1" style="width:80px; margin-right:16px;">
                        <label for="issue_number" style="margin-right:8px;">No.</label>
                        <input type="number" name="issue_number" id="issue_number" value="<?php echo esc_attr( $nl->issue_number ?? '' ); ?>" min="1" style="width:80px;">
                    </td>
                </tr>
                <tr>
                    <th><label for="visibility">Visibility</label></th>
                    <td>
                        <select name="visibility" id="visibility">
                            <option value="members_only" <?php selected( $nl->visibility ?? 'members_only', 'members_only' ); ?>>Members Only</option>
                            <option value="public" <?php selected( $nl->visibility ?? '', 'public' ); ?>>Public</option>
                        </select>
                        <p class="description">Members Only: grid is visible to everyone, but only logged-in members can view/download the PDF.</p>
                    </td>
                </tr>
                <tr>
                    <th>PDF File</th>
                    <td>
                        <input type="hidden" name="file_id" id="file_id" value="<?php echo esc_attr( $nl->file_id ?? 0 ); ?>">
                        <div id="pdf-preview" style="margin-bottom:8px;">
                            <?php if ( $pdf_name ) : ?>
                                <span class="dashicons dashicons-media-document" style="color:#0073aa; vertical-align:middle;"></span>
                                <a href="<?php echo esc_url( $pdf_url ); ?>" target="_blank"><?php echo esc_html( $pdf_name ); ?></a>
                            <?php endif; ?>
                        </div>
                        <button type="button" class="button" id="select-pdf-btn">Select PDF</button>
                        <button type="button" class="button" id="remove-pdf-btn" <?php if ( empty( $nl->file_id ) ) echo 'style="display:none;"'; ?>>Remove</button>
                        <span id="cover-generating" style="display:none; margin-left:12px; color:#666;">
                            <span class="spinner is-active" style="float:none; margin:0 4px 0 0;"></span> Generating cover…
                        </span>
                    </td>
                </tr>
                <tr>
                    <th>Cover Image</th>
                    <td>
                        <input type="hidden" name="cover_image_id" id="cover_image_id" value="<?php echo esc_attr( $nl->cover_image_id ?? 0 ); ?>">
                        <div id="cover-preview" style="margin-bottom:8px;">
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" style="max-width:200px; border:1px solid #ddd; border-radius:4px;">
                            <?php endif; ?>
                        </div>
                        <button type="button" class="button" id="select-cover-btn">Choose Cover Image</button>
                        <button type="button" class="button" id="remove-cover-btn" <?php if ( empty( $nl->cover_image_id ) ) echo 'style="display:none;"'; ?>>Remove</button>
                        <p class="description">Auto-generated from the PDF. Use this to override with a custom image if needed.</p>
                    </td>
                </tr>
            </table>

            <p class="submit">
                <input type="submit" name="sp_save_newsletter" class="button button-primary" value="Save Newsletter">
            </p>
        </form>
    </div>

    <script>
    /**
     * Newsletter Edit Page — Media Pickers & Auto Thumbnail
     *
     * WHY: Deferred to window.load because wp.media can conflict with other
     *      scripts if initialized too early. PDF picker filters to application/pdf
     *      only. On PDF selection, fires AJAX to sp_generate_newsletter_cover
     *      to auto-generate a cover thumbnail via Imagick. Cover image picker
     *      lets the admin manually choose or override the auto-generated cover.
     */
    window.addEventListener('load', function() {

        // ========== PDF PICKER ==========
        var selectPdfBtn  = document.getElementById('select-pdf-btn');
        var removePdfBtn  = document.getElementById('remove-pdf-btn');
        var fileIdInput   = document.getElementById('file_id');
        var pdfPreview    = document.getElementById('pdf-preview');
        var coverGen      = document.getElementById('cover-generating');

        selectPdfBtn.addEventListener('click', function() {
            var frame = wp.media({
                title:    'Select Newsletter PDF',
                button:   { text: 'Use This PDF' },
                multiple: false,
                library:  { type: 'application/pdf' }
            });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                fileIdInput.value = att.id;
                pdfPreview.innerHTML = '<span class="dashicons dashicons-media-document" style="color:#0073aa; vertical-align:middle;"></span> '
                    + '<a href="' + att.url + '" target="_blank">' + att.filename + '</a>';
                removePdfBtn.style.display = '';

                // Auto-generate cover thumbnail via AJAX
                coverGen.style.display = 'inline';
                var formData = new FormData();
                formData.append('action', 'sp_generate_newsletter_cover');
                formData.append('pdf_id', att.id);
                formData.append('_ajax_nonce', '<?php echo wp_create_nonce( 'sp_newsletter_cover' ); ?>');

                fetch(ajaxurl, { method: 'POST', body: formData })
                    .then(function(r) { return r.json(); })
                    .then(function(resp) {
                        coverGen.style.display = 'none';
                        if (resp.success && resp.data.cover_id) {
                            document.getElementById('cover_image_id').value = resp.data.cover_id;
                            document.getElementById('cover-preview').innerHTML =
                                '<img src="' + resp.data.cover_url + '" style="max-width:200px; border:1px solid #ddd; border-radius:4px;">';
                            document.getElementById('remove-cover-btn').style.display = '';
                        }
                    })
                    .catch(function() {
                        coverGen.style.display = 'none';
                    });
            });
            frame.open();
        });

        removePdfBtn.addEventListener('click', function() {
            fileIdInput.value = 0;
            pdfPreview.innerHTML = '';
            this.style.display = 'none';
        });

        // ========== COVER IMAGE PICKER (manual override) ==========
        var selectCoverBtn = document.getElementById('select-cover-btn');
        var removeCoverBtn = document.getElementById('remove-cover-btn');
        var coverIdInput   = document.getElementById('cover_image_id');
        var coverPreview   = document.getElementById('cover-preview');

        selectCoverBtn.addEventListener('click', function() {
            var frame = wp.media({
                title:    'Select Cover Image',
                button:   { text: 'Set as Cover' },
                multiple: false
            });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                coverIdInput.value = att.id;
                var thumbUrl = (att.sizes && att.sizes.medium) ? att.sizes.medium.url : att.url;
                coverPreview.innerHTML = '<img src="' + thumbUrl + '" style="max-width:200px; border:1px solid #ddd; border-radius:4px;">';
                removeCoverBtn.style.display = '';
            });
            frame.open();
        });

        removeCoverBtn.addEventListener('click', function() {
            coverIdInput.value = 0;
            coverPreview.innerHTML = '';
            this.style.display = 'none';
        });
    });
    </script>
    <?php
}


// ============================================================================
// AJAX: Generate Newsletter Cover Thumbnail from PDF
//
// WHY: When an admin uploads a PDF newsletter, we want to auto-generate a
//      cover thumbnail from page 1 so the archive grid looks good without
//      requiring manual screenshot work. Uses Imagick (ImageMagick PHP
//      extension) which needs Ghostscript installed on the server to handle
//      PDF rendering. Falls back gracefully if either is missing.
// ============================================================================
add_action( 'wp_ajax_sp_generate_newsletter_cover', 'sp_ajax_generate_newsletter_cover' );

function sp_ajax_generate_newsletter_cover(): void {
    check_ajax_referer( 'sp_newsletter_cover' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( 'Permission denied.' );
    }

    $pdf_id = absint( $_POST['pdf_id'] ?? 0 );
    if ( ! $pdf_id ) {
        wp_send_json_error( 'Missing PDF ID.' );
    }

    $pdf_path = get_attached_file( $pdf_id );
    if ( ! $pdf_path || ! file_exists( $pdf_path ) ) {
        wp_send_json_error( 'PDF file not found.' );
    }

    // Check that Imagick is available and can handle PDFs
    if ( ! class_exists( 'Imagick' ) ) {
        wp_send_json_error( 'Imagick extension not available. Upload a cover image manually.' );
    }

    try {
        $im = new Imagick();

        // Set resolution BEFORE reading so Ghostscript renders at this DPI
        // WHY: 150 DPI gives a good balance between quality and file size for
        //      a cover thumbnail. Higher DPI would be wasteful for a 200–300px
        //      wide preview image.
        $im->setResolution( 150, 150 );

        // Read only the first page (index [0]) of the PDF
        $im->readImage( $pdf_path . '[0]' );

        // Flatten to remove alpha channel (PDFs can have transparency)
        $im->setImageBackgroundColor( 'white' );
        $im->setImageAlphaChannel( Imagick::ALPHACHANNEL_REMOVE );
        $im = $im->mergeImageLayers( Imagick::LAYERMETHOD_FLATTEN );

        // Convert to JPEG for web display
        $im->setImageFormat( 'jpg' );
        $im->setImageCompressionQuality( 85 );

        // Generate unique filename and save to uploads directory
        $upload_dir = wp_upload_dir();
        $filename   = 'newsletter-cover-' . $pdf_id . '-' . time() . '.jpg';
        $filepath   = $upload_dir['path'] . '/' . $filename;
        $fileurl    = $upload_dir['url'] . '/' . $filename;

        $im->writeImage( $filepath );
        $im->clear();
        $im->destroy();

        // Register as a WordPress attachment so it shows up in the media library
        // and gets cleaned up properly if the newsletter is deleted
        $attachment_id = wp_insert_attachment( [
            'post_mime_type' => 'image/jpeg',
            'post_title'     => 'Newsletter Cover — ' . basename( $pdf_path, '.pdf' ),
            'post_status'    => 'inherit',
        ], $filepath );

        if ( is_wp_error( $attachment_id ) ) {
            wp_send_json_error( 'Failed to register cover image attachment.' );
        }

        // Generate standard WP image sizes (thumbnail, medium, etc.)
        require_once ABSPATH . 'wp-admin/includes/image.php';
        $metadata = wp_generate_attachment_metadata( $attachment_id, $filepath );
        wp_update_attachment_metadata( $attachment_id, $metadata );

        wp_send_json_success( [
            'cover_id'  => $attachment_id,
            'cover_url' => $fileurl,
        ] );

    } catch ( Exception $e ) {
        wp_send_json_error( 'Imagick error: ' . $e->getMessage() . '. Upload a cover image manually.' );
    }
}


// ============================================================================
// AJAX: Newsletter PDF Download
//
// WHY: Rather than exposing the raw wp-content/uploads URL (which anyone could
//      guess or share), downloads go through this endpoint which checks that
//      the user is logged in before serving the file. For public newsletters,
//      anyone can download. This also lets us log downloads in the future if
//      we ever want analytics on newsletter engagement.
// ============================================================================
add_action( 'wp_ajax_sp_newsletter_download',        'sp_ajax_newsletter_download' );
add_action( 'wp_ajax_nopriv_sp_newsletter_download', 'sp_ajax_newsletter_download' );

function sp_ajax_newsletter_download(): void {
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );
    if ( ! $newsletter_id ) {
        wp_die( 'Invalid newsletter.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $nl = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}newsletters WHERE id = %d", $newsletter_id
    ) );

    if ( ! $nl || ! $nl->file_id ) {
        wp_die( 'Newsletter not found.' );
    }

    // Members-only newsletters require login
    if ( $nl->visibility === 'members_only' && ! is_user_logged_in() ) {
        wp_redirect( wp_login_url( add_query_arg( [] ) ) );
        exit;
    }

    $file_path = get_attached_file( $nl->file_id );
    if ( ! $file_path || ! file_exists( $file_path ) ) {
        wp_die( 'PDF file not found on server.' );
    }

    // Serve the file with proper headers for download
    header( 'Content-Type: application/pdf' );
    header( 'Content-Disposition: attachment; filename="' . sanitize_file_name( $nl->title ) . '.pdf"' );
    header( 'Content-Length: ' . filesize( $file_path ) );
    header( 'Cache-Control: private, max-age=0' );
    header( 'Pragma: public' );

    readfile( $file_path );
    exit;
}


// ============================================================================
// FRONTEND: Newsletter Archive Page Template
//
// WHY: Registered as a page template so Harold can create a "Newsletters"
//      page and select this template. Shows a grid of newsletter cards with
//      cover thumbnails, titles, dates, and volume/issue info. Clicking a
//      card opens an inline PDF viewer (modal with iframe) for logged-in
//      members. Non-members see the grid but get a "Members Only" message
//      instead of the viewer/download.
// ============================================================================

// Register the template in the page template dropdown
add_filter( 'theme_page_templates', function( $templates ) {
    $templates['sp-newsletter-archive'] = 'Newsletter Archive';
    return $templates;
} );

// Intercept template loading and render our custom output
add_filter( 'template_include', function( $template ) {
    if ( ! is_page() ) return $template;

    $page_template = get_page_template_slug();
    if ( $page_template !== 'sp-newsletter-archive' ) {
        return $template;
    }

    // Newsletter archive is visible to everyone — login is only required
    // for viewing/downloading members-only PDFs, not for seeing the grid.
    get_header();
    echo '<div class="site-content"><div class="content-area-full" style="max-width:var(--sp-content-width,1100px);">';
    sp_frontend_newsletter_archive();
    echo '</div></div>';
    get_footer();
    return '';
}, 98 ); // Priority 98 — just before the existing 99 hook for other templates


/**
 * Frontend: Newsletter Archive Grid + PDF Viewer Modal
 *
 * WHY: The archive grid is the public-facing view of all newsletters. Cards
 *      show the cover thumbnail, title, date, and volume/issue. The grid is
 *      visible to everyone (good for marketing — prospective members can see
 *      the society produces quality content). But the viewer modal and download
 *      button only work for logged-in members when visibility is members_only.
 */
function sp_frontend_newsletter_archive(): void {
    global $wpdb;
    $prefix    = $wpdb->prefix . 'sp_';
    $logged_in = is_user_logged_in();

    // Fetch all newsletters, newest first
    $newsletters = $wpdb->get_results(
        "SELECT * FROM {$prefix}newsletters ORDER BY pub_date DESC, created_at DESC"
    );
    ?>
    <div class="sp-newsletter-archive">
        <h1 class="entry-title" style="margin-bottom:8px;">Newsletter Archive</h1>

        <!-- Search bar -->
        <div style="margin-bottom:24px;">
            <input type="text" id="sp-nl-search" placeholder="Search newsletters…"
                   style="width:100%; max-width:400px; padding:10px 14px; border:2px solid #dee2e6; border-radius:6px; font-size:16px;">
        </div>

        <?php if ( empty( $newsletters ) ) : ?>
            <p>No newsletters have been published yet. Check back soon!</p>
        <?php else : ?>
            <div class="sp-newsletter-grid" id="sp-nl-grid">
                <?php foreach ( $newsletters as $nl ) :
                    $cover_url = $nl->cover_image_id
                        ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' )
                        : '';

                    $pdf_url = $nl->file_id ? wp_get_attachment_url( $nl->file_id ) : '';

                    // Can this user view/download?
                    $can_access = ( $nl->visibility === 'public' ) || $logged_in;

                    // Format volume/issue
                    $vol_issue = '';
                    if ( $nl->volume )       $vol_issue .= 'Vol.&nbsp;' . $nl->volume;
                    if ( $nl->issue_number ) $vol_issue .= ( $vol_issue ? ', ' : '' ) . 'No.&nbsp;' . $nl->issue_number;

                    // Format date
                    $date_display = $nl->pub_date ? date( 'F Y', strtotime( $nl->pub_date ) ) : '';

                    // Download URL goes through our AJAX endpoint for access control
                    $download_url = admin_url( 'admin-ajax.php?action=sp_newsletter_download&newsletter_id=' . $nl->id );
                ?>
                    <div class="sp-newsletter-card" data-title="<?php echo esc_attr( strtolower( $nl->title ) ); ?>">
                        <!-- Cover image -->
                        <div class="sp-newsletter-card-cover"
                             <?php if ( $can_access && $pdf_url ) : ?>
                                 data-pdf="<?php echo esc_url( $pdf_url ); ?>"
                                 data-title="<?php echo esc_attr( $nl->title ); ?>"
                                 data-download="<?php echo esc_url( $download_url ); ?>"
                                 style="cursor:pointer;"
                                 title="Click to preview"
                             <?php endif; ?>>
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" alt="<?php echo esc_attr( $nl->title ); ?>">
                            <?php else : ?>
                                <div class="sp-newsletter-card-placeholder">
                                    <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#ccc" stroke-width="1.5">
                                        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                                        <polyline points="14 2 14 8 20 8"></polyline>
                                    </svg>
                                </div>
                            <?php endif; ?>
                        </div>

                        <!-- Card body -->
                        <div class="sp-newsletter-card-body">
                            <h3 class="sp-newsletter-card-title"><?php echo esc_html( $nl->title ); ?></h3>
                            <?php if ( $date_display ) : ?>
                                <span class="sp-newsletter-card-date"><?php echo $date_display; ?></span>
                            <?php endif; ?>
                            <?php if ( $vol_issue ) : ?>
                                <span class="sp-newsletter-card-issue"><?php echo $vol_issue; ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->description ) : ?>
                                <p class="sp-newsletter-card-desc"><?php echo esc_html( $nl->description ); ?></p>
                            <?php endif; ?>

                            <!-- Action buttons -->
                            <div class="sp-newsletter-card-actions">
                                <?php if ( $can_access && $pdf_url ) : ?>
                                    <a href="<?php echo esc_url( $download_url ); ?>" class="sp-newsletter-btn sp-newsletter-btn-download">Download</a>
                                <?php else : ?>
                                    <span class="sp-newsletter-members-badge">Members Only</span>
                                <?php endif; ?>
                            </div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>
    </div>

    <!-- PDF Viewer Modal -->
    <div id="sp-pdf-modal" class="sp-pdf-modal" style="display:none;">
        <div class="sp-pdf-modal-overlay"></div>
        <div class="sp-pdf-modal-content">
            <div class="sp-pdf-modal-header">
                <h3 id="sp-pdf-modal-title"></h3>
                <div class="sp-pdf-modal-actions">
                    <a href="#" id="sp-pdf-modal-download" class="sp-newsletter-btn sp-newsletter-btn-download" target="_blank">Download</a>
                    <button type="button" id="sp-pdf-modal-close" class="sp-newsletter-btn sp-newsletter-btn-close">&times;</button>
                </div>
            </div>
            <div class="sp-pdf-modal-body">
                <iframe id="sp-pdf-modal-iframe" src="" frameborder="0"></iframe>
            </div>
        </div>
    </div>

    <script>
    /**
     * Newsletter Archive — Frontend Interactions
     *
     * WHY: Three pieces of interactivity:
     * 1. Search filter — instant client-side filtering by title as the user types
     * 2. PDF viewer modal — clicking a card cover opens an iframe modal with the
     *    browser's native PDF renderer (no PDF.js dependency needed)
     * 3. Escape key / overlay click closes the modal
     */
    (function() {
        'use strict';

        // ========== SEARCH FILTER ==========
        var searchInput = document.getElementById('sp-nl-search');
        if (searchInput) {
            searchInput.addEventListener('input', function() {
                var query = this.value.toLowerCase().trim();
                var cards = document.querySelectorAll('.sp-newsletter-card');
                cards.forEach(function(card) {
                    var title = card.getAttribute('data-title') || '';
                    card.style.display = (!query || title.indexOf(query) !== -1) ? '' : 'none';
                });
            });
        }

        // ========== PDF VIEWER MODAL ==========
        var modal       = document.getElementById('sp-pdf-modal');
        var modalTitle  = document.getElementById('sp-pdf-modal-title');
        var modalIframe = document.getElementById('sp-pdf-modal-iframe');
        var modalDL     = document.getElementById('sp-pdf-modal-download');
        var modalClose  = document.getElementById('sp-pdf-modal-close');
        var overlay     = modal ? modal.querySelector('.sp-pdf-modal-overlay') : null;

        // Open modal when clicking a card cover that has a data-pdf attribute
        document.addEventListener('click', function(e) {
            var cover = e.target.closest('.sp-newsletter-card-cover[data-pdf]');
            if (!cover || !modal) return;
            e.preventDefault();

            var pdfUrl      = cover.getAttribute('data-pdf');
            var title       = cover.getAttribute('data-title');
            var downloadUrl = cover.getAttribute('data-download');

            modalTitle.textContent = title;
            modalIframe.src        = pdfUrl;
            modalDL.href           = downloadUrl;
            modal.style.display    = 'flex';
            document.body.style.overflow = 'hidden'; // Prevent background scrolling
        });

        // Close modal
        function closeModal() {
            if (!modal) return;
            modal.style.display          = 'none';
            modalIframe.src              = '';
            document.body.style.overflow = '';
        }

        if (modalClose) modalClose.addEventListener('click', closeModal);
        if (overlay)    overlay.addEventListener('click', closeModal);

        // Escape key closes modal
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape' && modal && modal.style.display !== 'none') {
                closeModal();
            }
        });
    })();
    </script>
    <?php
}


// ============================================================================
// SITE SEARCH — Unified search across all modules
//
// WHY: Each module (library, events, members, newsletters) has its own isolated
//      search. But Harold's members need a way to search across everything from
//      one place — a search box in the header that returns results from all
//      modules on a single page. This is the "Google for the society site."
//
// Architecture:
// 1. sp_get_search_page_url() — finds the page with the sp-search template
// 2. theme_page_templates filter — adds "Site Search" to the template dropdown
// 3. template_include filter — renders sp_render_search_page() when loaded
// 4. sp_render_search_page() — queries all modules, groups results by type
// 5. sp_unified_search() — AJAX endpoint returning JSON (for future live search)
// 6. sp_do_unified_search() — shared query logic used by both render + AJAX
// ============================================================================


/**
 * Returns the permalink to the page using the sp-search template.
 *
 * WHY: The search form in the header needs to know where to submit. Rather
 *      than hardcoding a URL, we find the actual page Harold created and
 *      assigned the "Site Search" template to. Falls back to home_url()
 *      if no page has been assigned yet — the form won't break, it just
 *      won't go to a dedicated search page.
 */
function sp_get_search_page_url(): string {
    // Cache the result so we don't hit the DB on every page load for every
    // header render. Transient expires after 1 hour — if Harold creates or
    // reassigns the page, it'll pick up within an hour (or on next save).
    $cached = get_transient( 'sp_search_page_url' );
    if ( $cached !== false ) {
        return $cached;
    }

    // Find a published page with the sp-search template assigned
    $pages = get_pages([
        'meta_key'   => '_wp_page_template',
        'meta_value' => 'sp-search',
        'number'     => 1,
    ]);

    $url = ! empty( $pages ) ? get_permalink( $pages[0]->ID ) : home_url( '/' );
    set_transient( 'sp_search_page_url', $url, HOUR_IN_SECONDS );

    return $url;
}

/**
 * Clear the search page URL cache whenever a page is saved.
 *
 * WHY: If Harold creates a new page and assigns the sp-search template,
 *      or changes which page uses it, we need the header form to pick up
 *      the new URL promptly instead of waiting for the transient to expire.
 */
add_action( 'save_post_page', function () {
    delete_transient( 'sp_search_page_url' );
} );


// Register the "Site Search" template in the page template dropdown
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-search'] = 'Site Search';
    return $templates;
} );

// Intercept template loading and render the search results page
add_filter( 'template_include', function ( $template ) {
    if ( ! is_page() ) return $template;

    $page_template = get_page_template_slug();
    if ( $page_template !== 'sp-search' ) {
        return $template;
    }

    get_header();
    echo '<div class="site-content"><div class="content-area-full" style="max-width:var(--sp-content-width,1100px);">';
    sp_render_search_page();
    echo '</div></div>';
    get_footer();
    return '';
}, 97 ); // Priority 97 — before newsletter archive (98) and other templates (99)


/**
 * Finds the permalink to a page using a specific SP template slug.
 *
 * WHY: The "View all X results" links in search results need to link to
 *      the correct module page (e.g., the Events page, Library Catalog page).
 *      Each module uses a template slug like 'sp-events' or 'sp-library-catalog'.
 *      This helper finds the page Harold assigned that template to.
 *
 * @param  string $template_slug  The SP template slug (e.g., 'sp-events')
 * @return string                 Page permalink, or empty string if not found
 */
function sp_get_template_page_url( string $template_slug ): string {
    $pages = get_pages([
        'meta_key'   => '_wp_page_template',
        'meta_value' => $template_slug,
        'number'     => 1,
    ]);

    return ! empty( $pages ) ? get_permalink( $pages[0]->ID ) : '';
}


/**
 * Shared search logic — queries all modules and returns structured results.
 *
 * WHY: Both the page render (sp_render_search_page) and the AJAX endpoint
 *      (sp_unified_search) need the same query logic. Centralizing it here
 *      means one set of queries to maintain, one set of visibility rules,
 *      and consistent results regardless of how the search is invoked.
 *
 * @param  string $query      The sanitized search term
 * @param  int    $per_module Max results per module (default 5 for page, more for AJAX)
 * @return array              Keyed by module name, each containing 'items' and 'total'
 */
function sp_do_unified_search( string $query, int $per_module = 5 ): array {
    global $wpdb;
    $prefix    = $wpdb->prefix . 'sp_';
    $logged_in = is_user_logged_in();
    $results   = [];

    // Prepare LIKE pattern once — used by every module query below
    $like = '%' . $wpdb->esc_like( $query ) . '%';

    // =====================================================================
    // EVENTS — Search title, description, location
    // WHY visibility check: Public events are visible to everyone. Members-
    //     only events should only appear for logged-in users. Cancelled
    //     events are excluded entirely — nobody needs to find those.
    // =====================================================================
    $events_where = $wpdb->prepare(
        "WHERE status != 'cancelled'
         AND (title LIKE %s OR description LIKE %s OR location_name LIKE %s)",
        $like, $like, $like
    );

    // Non-logged-in visitors only see public events
    if ( ! $logged_in ) {
        $events_where .= " AND visibility = 'public'";
    }

    $events_total = (int) $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}events {$events_where}"
    );

    $events_items = $wpdb->get_results(
        "SELECT id, title, description, event_date, start_time, location_name, visibility
         FROM {$prefix}events {$events_where}
         ORDER BY event_date DESC
         LIMIT {$per_module}"
    );

    if ( $events_total > 0 ) {
        $results['events'] = [
            'label'    => __( 'Events', 'societypress' ),
            'total'    => $events_total,
            'items'    => $events_items,
            'page_url' => sp_get_template_page_url( 'sp-events' ),
        ];
    }

    // =====================================================================
    // LIBRARY — Search title, author, call number, subject, surname, description
    // WHY no visibility check: The library catalog is public — it's a selling
    //     point for prospective members to see the society's collection.
    // =====================================================================
    $library_where = $wpdb->prepare(
        "WHERE (title LIKE %s OR author LIKE %s OR call_number LIKE %s
               OR subject LIKE %s OR surname LIKE %s OR description LIKE %s)",
        $like, $like, $like, $like, $like, $like
    );

    $library_total = (int) $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}library_items {$library_where}"
    );

    $library_items = $wpdb->get_results(
        "SELECT id, title, author, call_number, media_type
         FROM {$prefix}library_items {$library_where}
         ORDER BY title ASC
         LIMIT {$per_module}"
    );

    if ( $library_total > 0 ) {
        $results['library'] = [
            'label'    => __( 'Library', 'societypress' ),
            'total'    => $library_total,
            'items'    => $library_items,
            'page_url' => sp_get_template_page_url( 'sp-library-catalog' ),
        ];
    }

    // =====================================================================
    // RESOURCES — Search title, url, description
    // WHY no visibility check: Resource links are public — they're curated
    //     external URLs (genealogy databases, county records, etc.) that
    //     benefit everyone, not member-only content.
    // =====================================================================
    $resources_where = $wpdb->prepare(
        "WHERE active = 1 AND (title LIKE %s OR url LIKE %s OR description LIKE %s)",
        $like, $like, $like
    );

    $resources_total = (int) $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}resources {$resources_where}"
    );

    $resource_items = $wpdb->get_results(
        "SELECT r.id, r.title, r.url, r.description, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         {$resources_where}
         ORDER BY r.title ASC
         LIMIT {$per_module}"
    );

    if ( $resources_total > 0 ) {
        $results['resources'] = [
            'label'    => __( 'Resource Links', 'societypress' ),
            'total'    => $resources_total,
            'items'    => $resource_items,
            'page_url' => sp_get_template_page_url( 'sp-resources' ),
        ];
    }

    // =====================================================================
    // MEMBERS — Search first_name, last_name, preferred_name, organization_name
    // WHY logged-in only: The membership directory is private. Non-members
    //     shouldn't be able to search for member names.
    // WHY active-only: Expired/inactive members shouldn't appear in search.
    // WHY privacy check: Members who've opted out of the directory (dir_show_name=0)
    //     shouldn't be discoverable through search either.
    // =====================================================================
    if ( $logged_in ) {
        $members_where = $wpdb->prepare(
            "WHERE status = 'active' AND dir_show_name = 1
             AND (first_name LIKE %s OR last_name LIKE %s
                  OR preferred_name LIKE %s OR organization_name LIKE %s)",
            $like, $like, $like, $like
        );

        $members_total = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$prefix}members {$members_where}"
        );

        $members_items = $wpdb->get_results(
            "SELECT user_id, first_name, last_name, preferred_name,
                    organization_name, member_type, city, state
             FROM {$prefix}members {$members_where}
             ORDER BY last_name ASC, first_name ASC
             LIMIT {$per_module}"
        );

        if ( $members_total > 0 ) {
            $results['members'] = [
                'label'    => __( 'Members', 'societypress' ),
                'total'    => $members_total,
                'items'    => $members_items,
                'page_url' => sp_get_template_page_url( 'sp-directory' ),
            ];
        }
    }

    // =====================================================================
    // NEWSLETTERS — Search title, description
    // WHY logged-in only: Newsletters are member content. The archive grid
    //     is visible publicly (for marketing), but search results showing
    //     newsletter titles/descriptions should be member-only to be
    //     consistent with the download access control.
    // =====================================================================
    if ( $logged_in ) {
        $nl_where = $wpdb->prepare(
            "WHERE (title LIKE %s OR description LIKE %s)",
            $like, $like
        );

        $nl_total = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$prefix}newsletters {$nl_where}"
        );

        $nl_items = $wpdb->get_results(
            "SELECT id, title, description, pub_date, volume, issue_number
             FROM {$prefix}newsletters {$nl_where}
             ORDER BY pub_date DESC
             LIMIT {$per_module}"
        );

        if ( $nl_total > 0 ) {
            $results['newsletters'] = [
                'label'    => __( 'Newsletters', 'societypress' ),
                'total'    => $nl_total,
                'items'    => $nl_items,
                'page_url' => sp_get_template_page_url( 'sp-newsletter-archive' ),
            ];
        }
    }

    // =====================================================================
    // PAGES — Standard WordPress content pages
    // WHY WP_Query: Pages are regular WordPress posts, not custom tables.
    //     WP_Query handles searching post_title and post_content natively.
    // WHY exclude SP template pages: Pages like "Events" or "Directory" are
    //     just containers for plugin output — their content is empty. Including
    //     them in search results would be confusing.
    // =====================================================================
    $wp_query = new WP_Query([
        's'              => $query,
        'post_type'      => 'page',
        'post_status'    => 'publish',
        'posts_per_page' => $per_module,
    ]);

    // Filter out pages that use SP templates (they're just containers)
    $sp_templates = array_keys( sp_get_page_type_labels() );
    $page_items   = [];
    $page_total   = 0;

    if ( $wp_query->have_posts() ) {
        while ( $wp_query->have_posts() ) {
            $wp_query->the_post();
            $tmpl = get_page_template_slug();
            if ( ! empty( $tmpl ) && in_array( $tmpl, $sp_templates, true ) ) {
                continue; // Skip SP template pages
            }
            $page_items[] = (object) [
                'ID'      => get_the_ID(),
                'title'   => get_the_title(),
                'excerpt' => wp_trim_words( get_the_excerpt(), 20, '…' ),
                'url'     => get_permalink(),
            ];
            $page_total++;
        }
        wp_reset_postdata();
    }

    if ( $page_total > 0 ) {
        $results['pages'] = [
            'label'    => __( 'Pages', 'societypress' ),
            'total'    => $page_total,
            'items'    => $page_items,
        ];
    }

    return $results;
}


/**
 * Render the Site Search results page.
 *
 * WHY: This is the frontend output for pages using the "Site Search" template.
 *      It shows a search field at the top (pre-filled with the query so the user
 *      can refine), followed by results grouped by module. Each section shows up
 *      to 5 results with a "View all X results" link to the module's own page.
 */
function sp_render_search_page(): void {
    $raw_query = isset( $_GET['sp_q'] ) ? trim( $_GET['sp_q'] ) : '';
    $query     = sanitize_text_field( $raw_query );
    $has_query = strlen( $query ) >= 2;

    ?>
    <div class="sp-search-page">
        <h1 class="entry-title" style="margin-bottom:8px;">
            <?php esc_html_e( 'Search', 'societypress' ); ?>
        </h1>

        <!-- Search form — pre-filled with current query so the user can refine -->
        <form class="sp-search-form" action="" method="get" style="margin-bottom:32px;">
            <div style="display:flex; gap:8px; max-width:500px;">
                <input type="text" name="sp_q"
                       value="<?php echo esc_attr( $query ); ?>"
                       placeholder="<?php esc_attr_e( 'Search events, library, members, newsletters…', 'societypress' ); ?>"
                       autocomplete="off" required minlength="2"
                       style="flex:1; padding:10px 14px; border:2px solid #dee2e6; border-radius:6px; font-size:16px;">
                <button type="submit"
                        style="padding:10px 20px; background:var(--sp-color-primary,#1e3a5f); color:#fff; border:none; border-radius:6px; font-size:16px; cursor:pointer;">
                    <?php esc_html_e( 'Search', 'societypress' ); ?>
                </button>
            </div>
        </form>

        <?php if ( ! $has_query && ! empty( $raw_query ) ) : ?>
            <!-- User typed something but it's too short -->
            <p style="color:var(--sp-color-text-secondary,#6b7280);">
                <?php esc_html_e( 'Please enter at least 2 characters to search.', 'societypress' ); ?>
            </p>

        <?php elseif ( $has_query ) :
            $results = sp_do_unified_search( $query, 5 );

            if ( empty( $results ) ) : ?>
                <div class="sp-search-no-results" style="text-align:center; padding:48px 20px;">
                    <p style="font-size:1.1rem; color:var(--sp-color-text-secondary,#6b7280);">
                        <?php
                        printf(
                            /* translators: %s is the search query */
                            esc_html__( 'No results found for "%s". Try a different search term.', 'societypress' ),
                            esc_html( $query )
                        );
                        ?>
                    </p>
                </div>
            <?php else :
                // Loop through each module's results and render a section
                foreach ( $results as $module_key => $module ) :
                    ?>
                    <div class="sp-search-section" style="margin-bottom:32px;">
                        <h2 style="font-size:1.2rem; margin-bottom:12px; padding-bottom:8px; border-bottom:2px solid var(--sp-color-border,#e5e7eb);">
                            <?php echo esc_html( $module['label'] ); ?>
                            <span style="font-weight:400; font-size:0.85rem; color:var(--sp-color-text-secondary,#6b7280);">
                                (<?php echo esc_html( $module['total'] ); ?>)
                            </span>
                        </h2>

                        <div class="sp-search-results-list">
                            <?php
                            switch ( $module_key ) {
                                case 'events':
                                    sp_render_search_events( $module['items'] );
                                    break;
                                case 'library':
                                    sp_render_search_library( $module['items'] );
                                    break;
                                case 'resources':
                                    sp_render_search_resources( $module['items'] );
                                    break;
                                case 'members':
                                    sp_render_search_members( $module['items'] );
                                    break;
                                case 'newsletters':
                                    sp_render_search_newsletters( $module['items'] );
                                    break;
                                case 'pages':
                                    sp_render_search_pages( $module['items'] );
                                    break;
                            }
                            ?>
                        </div>

                        <?php
                        // "View all X results" link — only show if there are more results
                        // than we're displaying, and we have a page URL to link to
                        if ( $module['total'] > 5 && ! empty( $module['page_url'] ?? '' ) ) :
                            // Append the search query so the module page can pre-fill its search
                            $view_all_url = add_query_arg( 's', urlencode( $query ), $module['page_url'] );
                            ?>
                            <a href="<?php echo esc_url( $view_all_url ); ?>"
                               style="display:inline-block; margin-top:8px; font-weight:600; font-size:0.9rem;">
                                <?php
                                printf(
                                    /* translators: %d is the total number of results */
                                    esc_html__( 'View all %d results →', 'societypress' ),
                                    $module['total']
                                );
                                ?>
                            </a>
                        <?php endif; ?>
                    </div>
                    <?php
                endforeach;
            endif;
        endif; ?>
    </div>

    <style id="sp-search-page-css">
        /* Search result items — clean card-style rows */
        .sp-search-item {
            padding: 12px 16px;
            border-radius: 6px;
            margin-bottom: 4px;
            transition: background 0.15s ease;
        }

        .sp-search-item:hover {
            background: rgba(0, 0, 0, 0.03);
        }

        .sp-search-item-title {
            font-weight: 600;
            font-size: 1rem;
            color: var(--sp-color-primary, #1e3a5f);
            margin-bottom: 2px;
        }

        .sp-search-item-title a {
            color: inherit;
            text-decoration: none;
        }

        .sp-search-item-title a:hover {
            color: var(--sp-color-primary-hover, #2c5282);
            text-decoration: underline;
        }

        .sp-search-item-meta {
            font-size: 0.85rem;
            color: var(--sp-color-text-secondary, #6b7280);
        }
    </style>
    <?php
}


/**
 * Render event search results.
 *
 * WHY individual render functions: Each module has different data to display.
 *     Events show date + location, library shows author + call number, etc.
 *     Separate functions keep each module's output clean and maintainable.
 */
function sp_render_search_events( array $items ): void {
    foreach ( $items as $event ) {
        $date_str = '';
        if ( ! empty( $event->event_date ) ) {
            $date_str = date_i18n( get_option( 'date_format', 'F j, Y' ), strtotime( $event->event_date ) );
            if ( ! empty( $event->start_time ) ) {
                $date_str .= ' · ' . date_i18n( get_option( 'time_format', 'g:i A' ), strtotime( $event->start_time ) );
            }
        }
        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <?php echo esc_html( $event->title ); ?>
                <?php if ( $event->visibility === 'members_only' ) : ?>
                    <span style="font-size:0.75rem; font-weight:400; color:var(--sp-color-text-secondary,#6b7280);">
                        (<?php esc_html_e( 'Members Only', 'societypress' ); ?>)
                    </span>
                <?php endif; ?>
            </div>
            <div class="sp-search-item-meta">
                <?php
                $meta_parts = [];
                if ( $date_str ) $meta_parts[] = $date_str;
                if ( ! empty( $event->location_name ) ) $meta_parts[] = esc_html( $event->location_name );
                echo implode( ' · ', $meta_parts );
                ?>
            </div>
        </div>
        <?php
    }
}


/**
 * Render library search results.
 */
function sp_render_search_library( array $items ): void {
    foreach ( $items as $item ) {
        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <?php echo esc_html( $item->title ); ?>
            </div>
            <div class="sp-search-item-meta">
                <?php
                $meta_parts = [];
                if ( ! empty( $item->author ) )      $meta_parts[] = esc_html( $item->author );
                if ( ! empty( $item->call_number ) )  $meta_parts[] = esc_html( $item->call_number );
                if ( ! empty( $item->media_type ) )   $meta_parts[] = esc_html( $item->media_type );
                echo implode( ' · ', $meta_parts );
                ?>
            </div>
        </div>
        <?php
    }
}


/**
 * Render resource link search results.
 *
 * WHY links open in new tab: These are external URLs — genealogy databases,
 *     county records offices, etc. Opening in a new tab keeps the user on the
 *     society site while still letting them access the resource.
 */
function sp_render_search_resources( array $items ): void {
    foreach ( $items as $resource ) {
        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <a href="<?php echo esc_url( $resource->url ); ?>" target="_blank" rel="noopener noreferrer">
                    <?php echo esc_html( $resource->title ); ?>
                </a>
            </div>
            <div class="sp-search-item-meta">
                <?php
                $meta_parts = [];
                if ( ! empty( $resource->category_name ) ) {
                    $meta_parts[] = esc_html( $resource->category_name );
                }
                if ( ! empty( $resource->description ) ) {
                    // Truncate long descriptions to keep search results scannable
                    $desc = wp_strip_all_tags( $resource->description );
                    if ( mb_strlen( $desc ) > 120 ) {
                        $desc = mb_substr( $desc, 0, 120 ) . '…';
                    }
                    $meta_parts[] = esc_html( $desc );
                }
                echo implode( ' · ', $meta_parts );
                ?>
            </div>
        </div>
        <?php
    }
}


/**
 * Render member search results.
 *
 * WHY minimal info: We only show name and city/state — enough to identify
 *     someone without exposing contact details. Members who want full info
 *     go to the directory.
 */
function sp_render_search_members( array $items ): void {
    foreach ( $items as $member ) {
        // Use preferred name if set — Charles' preference is to show what
        // the member wants to be called, not necessarily their legal name.
        $display_name = ! empty( $member->preferred_name )
            ? $member->preferred_name . ' ' . $member->last_name
            : $member->first_name . ' ' . $member->last_name;

        // Organizations show the org name instead
        if ( $member->member_type === 'organization' && ! empty( $member->organization_name ) ) {
            $display_name = $member->organization_name;
        }

        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <?php echo esc_html( $display_name ); ?>
            </div>
            <div class="sp-search-item-meta">
                <?php
                $meta_parts = [];
                if ( $member->member_type === 'organization' ) {
                    $meta_parts[] = esc_html__( 'Organization', 'societypress' );
                }
                $location_parts = array_filter( [
                    $member->city ?? '',
                    $member->state ?? '',
                ] );
                if ( $location_parts ) {
                    $meta_parts[] = esc_html( implode( ', ', $location_parts ) );
                }
                echo implode( ' · ', $meta_parts );
                ?>
            </div>
        </div>
        <?php
    }
}


/**
 * Render newsletter search results.
 */
function sp_render_search_newsletters( array $items ): void {
    foreach ( $items as $nl ) {
        $date_str = '';
        if ( ! empty( $nl->pub_date ) ) {
            $date_str = date_i18n( 'F Y', strtotime( $nl->pub_date ) );
        }

        $vol_issue = '';
        if ( $nl->volume )       $vol_issue .= 'Vol. ' . $nl->volume;
        if ( $nl->issue_number ) $vol_issue .= ( $vol_issue ? ', ' : '' ) . 'No. ' . $nl->issue_number;

        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <?php echo esc_html( $nl->title ); ?>
            </div>
            <div class="sp-search-item-meta">
                <?php
                $meta_parts = [];
                if ( $date_str )   $meta_parts[] = $date_str;
                if ( $vol_issue )  $meta_parts[] = $vol_issue;
                echo implode( ' · ', $meta_parts );
                ?>
            </div>
        </div>
        <?php
    }
}


/**
 * Render page search results.
 */
function sp_render_search_pages( array $items ): void {
    foreach ( $items as $page ) {
        ?>
        <div class="sp-search-item">
            <div class="sp-search-item-title">
                <a href="<?php echo esc_url( $page->url ); ?>">
                    <?php echo esc_html( $page->title ); ?>
                </a>
            </div>
            <?php if ( ! empty( $page->excerpt ) ) : ?>
                <div class="sp-search-item-meta">
                    <?php echo esc_html( $page->excerpt ); ?>
                </div>
            <?php endif; ?>
        </div>
        <?php
    }
}


// ============================================================================
// AJAX ENDPOINT — Unified search (for future live search-as-you-type)
//
// WHY build this now: The backend work is identical to the page render. By
//     exposing the same data as JSON, we can add a live search dropdown to
//     the header in a future iteration without any backend changes — just
//     a JS fetch() call to this endpoint.
// ============================================================================

add_action( 'wp_ajax_sp_unified_search', 'sp_unified_search' );
add_action( 'wp_ajax_nopriv_sp_unified_search', 'sp_unified_search' );

/**
 * AJAX handler for unified search — returns JSON grouped by module.
 */
function sp_unified_search(): void {
    $query = isset( $_GET['sp_q'] ) ? sanitize_text_field( trim( $_GET['sp_q'] ) ) : '';

    if ( strlen( $query ) < 2 ) {
        wp_send_json_error( [ 'message' => 'Query must be at least 2 characters.' ] );
    }

    $results = sp_do_unified_search( $query, 5 );
    wp_send_json_success( $results );
}
